window.APP_BANK = [{"id":"web-j1-1","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於 AI，下列敘述何者正確？","options":{"A":"AI 僅能處理結構化數據的分析","B":"AI 涵蓋多種專業領域與技術","C":"AI 系統只能在學術研究中應用","D":"AI 無法應用於金融領域"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"AI 是涵蓋機器學習、自然語言處理、電腦視覺等多種專業領域與技術的總稱，並非單一技術。它既能處理結構化也能處理非結構化資料，且早已廣泛應用於金融、醫療等產業，故其餘選項中「僅能」「只能」「無法」的說法皆屬過度限縮。","concept":"AI範疇與應用","aiExplained":true},{"id":"web-j1-2","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"下列何者最適合訓練電腦下圍棋、自動駕駛等動態重複地互動的問題？","options":{"A":"監督式學習(Supervised Learning)","B":"非監督式學習(Unsupervised Learning)","C":"半監督式學習(Semi-supervised Learning)","D":"強化學習(Reinforcement Learning)"},"answer":"D","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"強化學習透過代理人與環境反覆互動，依據獎勵訊號不斷調整策略，特別適合下圍棋、自動駕駛這類需要連續決策的動態問題。監督式與非監督式學習主要仰賴既有資料集訓練，缺乏這種「行動—回饋—修正」的互動迴圈。","concept":"強化學習","aiExplained":true},{"id":"web-j1-3","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"深度學習模型中，下列哪一項通常用來降低過擬合（Overfitting）問題？","options":{"A":"增加訓練數據量","B":"增加模型的複雜度","C":"增加學習率","D":"增加正則化項"},"answer":"D","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"正則化項會對過大的模型權重施加懲罰，等於在模型內部直接限制複雜度，是深度學習中對抗過擬合的標準手段。相對地，提高模型複雜度或加大學習率反而可能使過擬合惡化或訓練不穩定。","concept":"正則化抗過擬合","aiExplained":true},{"id":"web-j1-4","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列哪一項敘述符合 AI 治理的核心原則？","options":{"A":"AI 系統的風險等級應在設計階段預先評估，並於部署後持續監控","B":"只要 AI 模型輸出結果準確，是否公平或透明並非治理重點","C":"AI 治理應聚焦在企業內部自行負責，不需外部規範參與","D":"對於低風險 AI 系統皆可免除透明性與問責機制之要求"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"AI 治理強調風險導向：在設計階段就預先評估系統的風險等級，部署後仍須持續監控，形成全生命週期的管理。其餘選項忽視公平與透明、排除外部規範參與，或對低風險系統全面免除問責，都違背治理的核心精神。","concept":"AI治理原則","aiExplained":true},{"id":"web-j1-5","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"若要設計一個能夠辨識並過濾垃圾郵件的系統，應該選擇下列哪一種機器學習演算法以實現最佳效果？","options":{"A":"監督式學習（Supervised Learning）","B":"非監督式學習（Unsupervised Learning）","C":"半監督式學習（Semi-supervised Learning）","D":"強化式學習（Reinforcement Learning）"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"垃圾郵件過濾是典型的二元分類問題，可利用大量已標記「垃圾／正常」的郵件作為訓練資料，因此監督式學習最能達到最佳效果。非監督式與強化學習缺乏明確標籤或獎勵設計，較不適合此情境。","concept":"監督式學習應用","aiExplained":true},{"id":"web-j1-6","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"假設某國正在考慮使用 AI 技術來進行社會信用評分，並根據年齡、缺陷、種族等特徵來評定個人的信用；同時，該國計劃在公眾場所使用遠程生物辨識系統進行執法，目的在於提高社會秩序和安全。上述 AI 應用可能會引發對隱私和個人權利的重大關注，根據歐盟《人工智慧法》（Artificial Intelligence Act, AIA）的風險分級，這類應用屬於哪一風險等級？","options":{"A":"不可接受風險","B":"高風險","C":"有限風險","D":"小或低風險"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"依歐盟《人工智慧法》，以個人特徵進行社會信用評分，以及在公共場所為執法目的使用遠端生物辨識，皆屬於明文禁止的「不可接受風險」應用。此等級的系統因嚴重威脅基本權利與隱私，原則上不得投入使用。","concept":"歐盟AI法分級","aiExplained":true},{"id":"web-j1-7","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某生成式 AI 模型接收一段語音輸入：「一隻戴著太空帽的企鵝正在火星上跳舞」，並根據該語音內容產生一張圖像呈現相對應的場景。此類模型最符合下列哪一種生成任務分類？","options":{"A":"語音生成圖片","B":"圖像生成語音","C":"語音翻譯","D":"圖像標註"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"此模型的輸入是語音、輸出是對應場景的圖像，屬於跨模態的「語音生成圖片」任務。圖像生成語音與圖像標註的輸入輸出方向相反，語音翻譯則僅在語言之間轉換，皆不符合題意。","concept":"跨模態生成","aiExplained":true},{"id":"web-j1-8","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"下列何者非大數據時代資料的特性？","options":{"A":"資料量大","B":"資料變動速度快","C":"資料多樣性","D":"資料存儲位置固定"},"answer":"D","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"大數據時代資料的特性通常以資料量大（Volume）、變動速度快（Velocity）與多樣性（Variety）來描述。大數據的來源與儲存方式高度分散且多元，「存儲位置固定」並非其特性。","concept":"大數據3V特性","aiExplained":true},{"id":"web-j1-9","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"關於 K 平均法(K-means)，下列敘述何者「不」正確？","options":{"A":"希望找出 k 個互不交集的群集","B":"不同的起始群集中心，可能會造成不同的分群結果","C":"容易受雜訊與離群值(Outlier)影響其群集中心","D":"可以處理類別型資料"},"answer":"D","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"K-means 以計算數值平均作為群集中心，因此僅適用於數值型資料，無法直接處理類別型資料，D 的敘述錯誤。其餘敘述皆正確：它尋找 k 個互不交集的群集、分群結果受初始中心影響，且群集中心容易被雜訊與離群值拉偏。","concept":"K-means限制","aiExplained":true},{"id":"web-j1-10","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在公司財務資料中，發現某筆支出金額達 1,000,000 元，若希望合理判斷該筆資料是否為異常值，下列哪一種處理方式最為合適？","options":{"A":"以 Z-score 方法量化異常程度，判斷是否為極端值","B":"以資料中的眾數作為參考基準，判斷其是否異常","C":"先透過主成分分析（PCA）降低維度，再進行異常值判定","D":"直接將該筆金額替換為資料中位數，以降低其對分析結果的影響"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"Z-score 以該筆金額偏離平均數多少個標準差來量化異常程度，可提供客觀的判斷門檻，最適合評估單筆支出是否為極端值。眾數不適用於連續金額的判斷，而未經判定就以中位數取代該筆資料，等於先竄改資料再談分析，順序顛倒。","concept":"Z-score異常偵測","aiExplained":true},{"id":"web-j1-11","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"下列哪一種資料類型不屬於非結構化資料？","options":{"A":"X 光醫學影像","B":"監控錄影畫面","C":"客服電話錄音","D":"組織內部的關係型資料庫記錄"},"answer":"D","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"關係型資料庫的記錄依照預先定義的欄位與資料表結構儲存，屬於典型的結構化資料。醫學影像、監控錄影與電話錄音都沒有固定欄位結構，才是非結構化資料。","concept":"非結構化資料","aiExplained":true},{"id":"web-j1-12","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列資料型態，何者最常用來儲存員工年齡、員工年資、貨品銷售量等資料？","options":{"A":"文字型（Text）","B":"數值型（Numeric）","C":"日期型（Date）","D":"布林型（Boolean）"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"年齡、年資、銷售量都是可以計算與比較大小的量化資料，最適合以數值型儲存，方便後續進行加總、平均等運算。文字型、日期型與布林型分別用於字串、時間點與真偽值，皆不符合這類量化需求。","concept":"資料型態選擇","aiExplained":true},{"id":"web-j1-13","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某行銷公司欲針對新客戶進行「行銷活動推播」，目前擁有資料包含：客戶基本資料（尚未有購買紀錄）、客戶過往點擊行為（未標記是否完成購買）、類似客戶是否曾購買過（已標記「有/無購買」標籤）。若該公司希望預測新的單一客戶是否可能完成購買行為，下列哪一種學習方式與資料搭配最合適？","options":{"A":"使用非監督式學習，分析所有客戶點擊路徑進行異常偵測","B":"使用非監督式學習，將客戶分群後預測其轉換率","C":"使用監督式學習，針對未標記資料直接預測轉換可能性","D":"使用監督式學習，以已知購買結果作為標籤進行訓練"},"answer":"D","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"題目中「類似客戶是否曾購買」已具備明確的「有／無購買」標籤，正好可作為監督式學習的訓練目標，讓模型從客戶特徵學會預測購買行為。非監督式學習無法直接輸出「是否購買」的預測，對未標記資料直接預測也缺乏訓練依據。","concept":"監督式學習","aiExplained":true},{"id":"web-j1-14","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在品質管理中，若一產品的生產過程中標準差顯著偏大，通常意味著什麼？","options":{"A":"資料點高度集中，產品質量穩定","B":"生產過程波動大，產品品質不穩定","C":"資料無法反映產品實際狀況","D":"中位數數值高，品質良率較高"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"標準差衡量資料相對於平均值的離散程度，標準差顯著偏大代表生產數據波動劇烈、產品品質不穩定。資料點高度集中對應的是標準差小，而標準差高低與中位數、良率並無直接關聯。","concept":"標準差意義","aiExplained":true},{"id":"web-j1-15","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某 AI 團隊在分析一組連續型數據時，發現部分紀錄的數值明顯高於其他資料點。若專案目標是識別高價值客戶的行為模式，下列哪一種處理方式最為合適？","options":{"A":"立即刪除離群值，以避免模型訓練時出現偏差","B":"視為錯誤值並全部替換為平均值","C":"保留離群值並標註為高價值異常點，納入後續模型訓練考量","D":"將離群值全數轉換為中位數，避免影響平均計算"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"專案目標是識別高價值客戶的行為模式，明顯偏高的數值很可能正是目標客群的行為訊號，應保留並標註為高價值異常點納入建模。若貿然刪除或以平均值、中位數取代，反而會抹除最有分析價值的資訊。","concept":"離群值處理策略","aiExplained":true},{"id":"web-j1-16","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在檢視資料品質時，可參考資料的變異程度及資料的集中趨勢。下列何者不屬於資料集中趨勢衡量的方法？","options":{"A":"平均數（Mean）","B":"中位數（Median）","C":"眾數（Mode）","D":"標準差（Standard Deviation）"},"answer":"D","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"集中趨勢衡量資料的中心位置，常用平均數、中位數與眾數三種量數。標準差衡量的是資料偏離平均值的離散程度，屬於變異程度指標而非集中趨勢。","concept":"集中趨勢量數","aiExplained":true},{"id":"web-j1-17","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某醫院研究特定心血管疾病的成因，收集了 50 名病患與 150 名正常人的年齡、血壓、血型等三項屬性變數。此研究適合使用下列哪一種機器學習模型來建立？","options":{"A":"決策樹（Decision Tree）","B":"線性廻歸（Linear Regression）","C":"基於密度之含噪空間聚類法（Density-Based Spatial Clustering of Application with Noise, DBSCAN）","D":"K-means 聚類（K-means Clustering）"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"此研究已有「病患／正常人」的明確類別標籤，屬於監督式分類問題，且屬性中含血型這類類別型變數，決策樹能同時處理數值與類別特徵，最為合適。線性迴歸適用於連續值預測，DBSCAN 與 K-means 則是非監督式聚類，無法利用既有標籤。","concept":"分類模型選擇","aiExplained":true},{"id":"web-j1-18","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"公司在整合資料時，發現同一客戶的姓名在不同系統中拼寫不一致（例如「陳大文」與「陳大文先生」），導致資料無法正確對應。請問此類資料品質問題應該在 ETL 哪一個流程步驟中進行處理？","options":{"A":"資料轉換（Data Transformation）","B":"資料擷取（Data Extraction）","C":"資料載入（Data Loading）","D":"型態轉換（Type Conversion）"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"姓名拼寫不一致屬於資料清理與標準化問題，應在 ETL 的「資料轉換」階段統一格式，使不同系統的紀錄能正確對應。擷取只負責從來源取出資料，載入只負責寫入目的地，型態轉換處理的是資料型別而非內容一致性。","concept":"ETL轉換階段","aiExplained":true},{"id":"web-j1-19","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"銀行想建立聊天機器人，可透過下列哪一種領域技術來達成？","options":{"A":"資料庫管理技術","B":"機器學習與自然語言處理","C":"網頁開發技術","D":"網路安全技術"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"聊天機器人必須理解客戶的自然語言並產生合適回覆，核心是自然語言處理技術，並搭配機器學習持續優化對話品質。資料庫、網頁開發與網路安全屬於支援性技術，無法直接實現語言理解與對話能力。","concept":"NLP應用","aiExplained":true},{"id":"web-j1-20","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"線性迴歸模型最適合解決哪種類型的問題？","options":{"A":"圖像分類","B":"銷售額預測","C":"聚類分析","D":"遊戲策略學習"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"線性迴歸的輸出是連續數值，最適合銷售額預測這類迴歸問題。圖像分類屬於分類任務，聚類分析屬於非監督式學習，遊戲策略學習則是強化學習的範疇。","concept":"迴歸問題辨識","aiExplained":true},{"id":"web-j1-21","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某金融機構已部署的 AI 模型遭客戶抱怨有不公平情形，經數據分析發現不同族群之間的模型預測結果存在顯著差異。根據金融監督管理委員會發布之《金融業運用人工智慧（AI）指引》，此情形下最適當的處置方式為何？","options":{"A":"重新訓練新的模型，並重新部署以修正結果","B":"啟動人工覆核與調整機制，並持續監控族群間預測效果","C":"記錄模型預測結果並提交備查，待未來法規修正後再行處理","D":"若模型偏誤屬於高風險用途，可由風控或合規單位先行審視其公平性影響，再決定是否啟動調整機制"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"依金管會《金融業運用人工智慧（AI）指引》，發現模型對不同族群產生顯著預測差異時，應啟動人工覆核與調整機制即時介入，並持續監控族群間的預測效果，落實公平性與問責。僅重新訓練未必能消除偏誤，記錄備查更是消極拖延，皆非最適當處置。","concept":"金融AI公平性","aiExplained":true},{"id":"web-j1-22","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"請問下列何者不是常見的特徵選取技術或方法？","options":{"A":"皮爾森積差相關分析（Pearson Correlation）","B":"主成分分析（Principal Components Analysis, PCA）","C":"迴歸分析（Regression Analysis）","D":"隨機森林（Random Forest）"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"皮爾森相關分析可篩選與目標高度相關的變數，PCA 可萃取主要成分降低維度，隨機森林能輸出特徵重要性排序，三者都是常見的特徵選取或降維手段。迴歸分析是建立變數間關係以進行預測的建模方法，本身並非特徵選取技術。","concept":"特徵選取方法","aiExplained":true},{"id":"web-j1-23","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"交叉驗證的主要目的是什麼？","options":{"A":"提高模型的訓練速度","B":"驗證數據是否線性可分","C":"減少模型的過擬合風險","D":"測試模型的容錯能力"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"交叉驗證將資料分成多折，輪流作為訓練與驗證集，藉此評估模型在未見過資料上的表現，避免模型只擬合單一切分而過擬合。它不會提高訓練速度，也與檢驗線性可分或容錯能力無關。","concept":"交叉驗證目的","aiExplained":true},{"id":"web-j1-24","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"一家智慧工廠使用機器學習分類模型預測關鍵設備是否會異常停機。完成模型訓練後，團隊希望全面評估模型在不同面向的表現。請問下列哪項指標最適合用來衡量模型在偵測異常停機時的「漏報率」（即未能正確偵測出異常事件的比例）？","options":{"A":"準確率（Accuracy），即模型整體預測正確的比例","B":"召回率（Recall），即模型能正確找出異常停機的比例","C":"F1 分數（F1 Score），準確率與召回率的調和平均數","D":"假陽性率（False Positive Rate），即將正常事件誤判為異常的比例"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"召回率衡量所有實際異常停機事件中被模型正確偵測出的比例，召回率愈低代表漏報愈多，因此最適合用來檢視漏報率。準確率會被大量正常樣本稀釋，假陽性率關注的則是誤報而非漏報。","concept":"召回率與漏報","aiExplained":true},{"id":"web-j1-25","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"神經網路與傳統機器學習模型的主要區別是什麼？","options":{"A":"神經網路無法處理非線性數據","B":"神經網路透過多層結構學習複雜特徵","C":"神經網路只適用於迴歸問題","D":"神經網路不需要大量數據支持"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"神經網路透過多層非線性結構自動學習由淺到深的複雜特徵表示，這是它與依賴人工特徵工程的傳統機器學習最大的區別。其餘選項顛倒事實：神經網路擅長非線性問題、分類與迴歸皆可應用，且通常需要大量資料支撐。","concept":"神經網路特性","aiExplained":true},{"id":"web-j1-26","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"下列關於生成對抗網路(GAN)的描述正確的是哪一項？","options":{"A":"GAN 僅用於分類問題","B":"GAN 由生成器和鑑別器組成","C":"GAN 的結果始終高度可解釋","D":"GAN 不能生成高品質的數據"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"GAN 由生成器與鑑別器組成，生成器負責產生以假亂真的樣本，鑑別器負責分辨真偽，兩者對抗訓練、共同進步。它是生成模型而非僅用於分類，能生成高品質數據，但內部運作的可解釋性並不高。","concept":"GAN架構","aiExplained":true},{"id":"web-j1-27","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"一位資料分析師希望減少輸入特徵的維度，以提升模型運算效率，並觀察變數間潛在的整體結構關係。若欲保留最大資訊量、同時減少特徵數量，下列哪一項方法最適合？","options":{"A":"套用主成分分析（PCA）以擷取主要變異方向並轉換新變數","B":"利用離散化方法將連續變數轉為分類型欄位","C":"使用標準化方法將所有特徵縮放至相同數值區間","D":"以 ETL 技術移除空值欄位並改儲為 JSON 格式"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"PCA 沿著資料變異最大的方向建立新的主成分變數，能在大幅減少特徵數量的同時保留最多資訊量，並呈現變數間的整體結構關係。離散化與標準化都不會減少特徵數量，移除空值欄位更與降維目的無關。","concept":"PCA降維","aiExplained":true},{"id":"web-j1-28","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於目前生成式 AI 的主要應用，不包括下列哪一項？","options":{"A":"創建合成數據樣本","B":"模擬數據分佈","C":"分類醫學影像","D":"生成文本"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"生成式 AI 的核心在於「產生新內容」，例如生成文本、創建合成數據樣本與模擬數據分佈。分類醫學影像是判斷輸入屬於哪個類別的鑑別式任務，不屬於生成式 AI 的主要應用。","concept":"生成式AI應用","aiExplained":true},{"id":"web-j1-29","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"下列哪項是生成式 AI 支援鑑別式 AI 的典型案例？","options":{"A":"模擬交通場景以訓練自動駕駛模型","B":"使用 CNN 對腫瘤分類","C":"使用 SVM 分析風險","D":"創建更好的分類演算法"},"answer":"A","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"以生成式 AI 模擬多樣的交通場景，可產生大量合成訓練資料，供自動駕駛的鑑別式模型學習辨識與決策，是「生成式支援鑑別式」的典型案例。CNN 分類腫瘤與 SVM 風險分析本身就是鑑別式應用，並未借助生成式 AI 的產出。","concept":"合成資料訓練","aiExplained":true},{"id":"web-j1-30","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於自然語言處理（NLP）核心技術，下列敘述何者不正確？","options":{"A":"語音識別技術將語音轉換為文本，並用於語音助理和語音輸入","B":"自然語言生成技術可以生成自然流暢的文本，用於聊天機器人和自動文案生成","C":"語意分析技術理解文本的語意，並主要用於語音識別和機器翻譯","D":"機器翻譯技術自動翻譯文本，促進多語言支援和全球溝通"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"語意分析的目標是理解文本的語意，主要應用於情感分析、意圖辨識等文本理解任務，說它「主要用於語音識別和機器翻譯」是張冠李戴，故 C 不正確。其餘關於語音識別、自然語言生成與機器翻譯的敘述均符合各技術的定位。","concept":"NLP核心技術","aiExplained":true},{"id":"web-j1-31","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於「負責任的 AI」，下列敘述何者較為正確？","options":{"A":"AI 系統的開發者對 AI 系統的行為負責","B":"AI 系統的使用者對 AI 系統的結果負責","C":"AI 系統本身對其行為負責","D":"政府對 AI 系統的發展負責"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"負責任的 AI 強調系統行為的後果須有明確的責任歸屬，而開發者對系統的設計、訓練與行為擁有最直接的控制力，因此由開發者負責是各選項中較正確的敘述。AI 系統本身不具法律人格，無法自負其責。","concept":"負責任AI","aiExplained":true},{"id":"web-j1-32","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"關於生成式 AI 的基本原理，下列敘述何者較正確？","options":{"A":"生成式 AI 通過分析大量數據來生成新數據，模擬數據分佈以創造與訓練數據相似的結果","B":"生成式 AI 主要通過預定義的規則來進行數據處理和分類","C":"生成式 AI 專注於數據分類和迴歸預測，幫助識別已知數據中的模式","D":"生成式 AI 通過自動化的方式清洗數據，提升數據分析的準確性"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"生成式 AI 透過分析大量訓練資料、學習其資料分佈，進而生成與訓練資料相似但全新的內容，這正是它的基本原理。依預定義規則處理、專注分類與迴歸預測，或自動清洗資料，描述的都不是生成式模型的運作方式。","concept":"生成式AI原理","aiExplained":true},{"id":"web-j1-33","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"關於下列模型在生成式人工智慧（Generative AI）中的角色，何者並非以「產生新資料」為主要設計目的？","options":{"A":"支援向量機（Support Vector Machine）","B":"變分自編碼器（Variational Autoencoder）","C":"自迴歸模型（Autoregressive Model）","D":"擴散模型（Diffusion Model）"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"支援向量機是尋找最佳決策邊界的鑑別式模型，用於分類與迴歸，並非以產生新資料為設計目的。變分自編碼器、自迴歸模型與擴散模型則都是典型的生成式模型，核心任務就是生成新樣本。","concept":"生成vs鑑別模型","aiExplained":true},{"id":"web-j1-34","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某份資料中出現多個欄位（如 score1、score2、score3）儲存相同的成績資訊，造成資料結構重複與使用混淆，此種情形屬於下列哪一種資料品質問題？","options":{"A":"重複資料（Duplicate Data）","B":"冗餘資料（Redundant Data）","C":"格式錯誤資料（Malformed Data）","D":"缺失資料（Missing Data）"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"以 score1、score2、score3 等多個欄位儲存相同的成績資訊，屬於同一資訊在資料結構中被重複設計的「冗餘資料」問題。重複資料指的是整筆紀錄重複出現，與此處欄位層級的結構性重複不同。","concept":"冗餘資料","aiExplained":true},{"id":"web-j1-35","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某電商平台希望預測商品的退貨機率，以協助降低營運風險。若模型使用的輸入資料包含「商品售價」、「顧客年齡」、「運送天數」，而模型的輸出為是否退貨（是/否）。請問在此模型中，「是否退貨」應歸類為下列哪一類變數？","options":{"A":"特徵（Feature）","B":"標籤（Label / Target）","C":"超參數（Hyperparameter）","D":"正則化係數（Regularization Coefficient）"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"「是否退貨」是模型要預測的輸出結果，屬於標籤（Label / Target）；售價、顧客年齡、運送天數這些輸入變數才是特徵。超參數與正則化係數是訓練前設定的模型參數，與資料變數的角色無關。","concept":"標籤與特徵","aiExplained":true},{"id":"web-j2-36","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"下列何者最能表達 No Code / Low Code 平台的主要特色？","options":{"A":"需要撰寫大量程式碼","B":"運用模板快速建立應用程式","C":"僅供專業開發人員使用","D":"只能製作靜態網站"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"No Code / Low Code 平台的主要特色是提供現成模板與視覺化元件，讓使用者以拖拉組裝方式快速建立應用程式，大幅降低撰寫程式的需求。其餘選項強調大量寫碼、僅限專業開發者或只能做靜態網站，皆與其降低開發門檻的定位相反。","concept":"低程式碼平台","aiExplained":true},{"id":"web-j2-37","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"下列何者不是推理模型（Reasoning Model）的主要特點？","options":{"A":"具備多步驟邏輯推理能力","B":"具備良好的可解釋性與邏輯一致性","C":"採用強化式學習的訓練方式","D":"回應內容結構清晰、推理脈絡完整"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"推理模型的主要特點在於具備多步驟邏輯推理能力、推理脈絡完整、回應結構清晰，以及由此帶來的可解釋性與邏輯一致性，這些都是描述其推理輸出的特徵。訓練方式並非定義推理模型的必要條件，「採用強化式學習的訓練方式」不屬於其主要特點。","concept":"推理模型特性","aiExplained":true},{"id":"web-j2-38","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"下列哪種情況，選擇 Low Code 平台可能比 No Code 平台更為適合？","options":{"A":"需要非技術人員快速進行開發與應用","B":"應用需求簡單，無需自訂功能","C":"需要較複雜的業務邏輯並使用自訂整合功能","D":"預算和時間極度有限"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"Low Code 平台允許開發者在視覺化開發之外自行撰寫程式碼，因此當應用涉及較複雜的業務邏輯並需要自訂整合功能時，比純拖拉組裝的 No Code 平台更為適合。若需求簡單、預算時間有限或使用者不具技術背景，反而是 No Code 的強項。","concept":"LowCode適用情境","aiExplained":true},{"id":"web-j2-39","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"關於生成式 AI 與 No Code / Low Code 平台的應用，下列何者最不適合？","options":{"A":"自動生成程式碼","B":"自動化生成行銷文案","C":"快速開發個人化 App","D":"自動化生成法律判決"},"answer":"D","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"法律判決涉及高度專業判斷、法律責任與當事人權益，生成式 AI 可能產生錯誤或偏頗內容且難以問責，因此「自動化生成法律判決」是最不適合的應用。自動生成程式碼、行銷文案與快速開發個人化 App 都有人工把關空間，屬於常見且合適的應用。","concept":"生成式AI風險","aiExplained":true},{"id":"web-j2-40","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"關於 No Code / Low Code 平台，下列敘述何者較正確？","options":{"A":"兩者完全相同","B":"Low Code 平台不需要任何程式設計知識","C":"Low Code 平台更適合開發靈活且可擴展的解決方案","D":"No Code 平台可以無限客製化"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"Low Code 平台保留撰寫程式碼的彈性，能因應客製需求並隨業務擴充，故更適合開發靈活且可擴展的解決方案。兩者並不相同：Low Code 仍需要一定程式知識，而 No Code 的客製化能力有限而非無限。","concept":"平台比較","aiExplained":true},{"id":"web-j2-41","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在使用生成式 AI 模型解決數學或邏輯問題時，若希望引導模型逐步推理以提升答案的準確性與可解釋性，應設計具備思維鏈（Chain-of-Thought）推理特性的提示語。下列哪一組提示語最能有效啟用模型的 Chain-of-Thought 推理能力？","options":{"A":"請回答這個數學問題，並直接給出答案","B":"幫我算出 125 × 12 是多少？","C":"請詳細列出每一個思考步驟，最後再給出答案","D":"請用一句話簡要回答問題"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"思維鏈（Chain-of-Thought）提示的核心在於明確要求模型先逐步展開推理過程，再給出最終結論。選項C「請詳細列出每一個思考步驟，最後再給出答案」正是這種引導方式，能促使模型將複雜問題拆解為連續步驟，提升準確性與可解釋性。其他選項只要求直接作答或簡短回答，無法啟動逐步推理。","concept":"思維鏈提示","aiExplained":true},{"id":"web-j2-42","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"使用 Low-Code 平台進行開發時，企業應特別留意下列哪一項潛在風險？","options":{"A":"可能造成企業內部敏感資料的洩露","B":"難以進行大規模的應用擴展和維護","C":"開發成本將大幅增加","D":"可能有未經 IT 部門管理的應用程式擴散"},"answer":"D","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"Low-Code 平台讓非 IT 人員也能快速開發應用，最典型的治理風險是「影子 IT」：業務單位繞過 IT 部門自行建置應用，導致未受管理的應用程式在企業內擴散，形成資安與維運盲點。因此選項D是企業導入 Low-Code 時應特別留意的潛在風險。","concept":"影子IT風險","aiExplained":true},{"id":"web-j2-43","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"下列哪一種技術方案適用於改善客戶體驗？","options":{"A":"預測性維護工具","B":"自然語言處理(NLP)和生成式回應模組","C":"智慧排程系統","D":"消費行為洞察模型"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"改善客戶體驗的關鍵在於能即時理解顧客需求並給予貼切回應。自然語言處理（NLP）搭配生成式回應模組可分析客戶的提問語意並自動生成合適的回覆，直接作用於客戶互動場景。預測性維護、智慧排程與消費行為洞察偏向生產維運與行銷分析，並非直接面向客戶互動體驗。","concept":"客戶體驗技術方案","aiExplained":true},{"id":"web-j2-44","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司擬將客戶個人資料傳輸至國外進行雲端儲存，依據《個人資料保護法》規定，下列哪一種情況下，中央目的事業主管機關有權對該國際資料傳輸行為進行限制？","options":{"A":"公司規模未達主管機關要求標準，管理能力存疑","B":"公司曾發生個人資料外洩事件紀錄，造成用戶信任流失","C":"傳輸資料包含當事人已公開資訊，但仍涉及隱私風險","D":"接收國家之個人資料保護法規尚未完善，可能損害當事人權益"},"answer":"D","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"依《個人資料保護法》規定，接受國對個人資料之保護若未有完善之法規，致有害當事人權益之虞時，中央目的事業主管機關得限制國際傳輸。選項D正對應此法定限制事由。其餘選項如公司規模、外洩紀錄或資料是否公開，均非法條明定的國際傳輸限制情形。","concept":"個資國際傳輸限制","aiExplained":true},{"id":"web-j2-45","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"下列哪一項技術是生成式 AI 的基礎？","options":{"A":"決策樹模型","B":"生成對抗網路","C":"聚類演算法","D":"隨機森林技術"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"生成對抗網路（GAN）透過生成器與判別器相互對抗訓練，使模型能產生逼真的新內容，是生成式 AI 的代表性基礎技術之一。決策樹、隨機森林屬於傳統判別式模型，聚類演算法則是非監督式分析方法，皆不以「生成新內容」為目標。","concept":"生成對抗網路","aiExplained":true},{"id":"web-j2-46","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"能使用 DALL·E-2 生成各式逼真的圖片，最關鍵的應用技術為何？","options":{"A":"卷積神經網絡（CNN）","B":"生成對抗網絡（GAN）","C":"擴散模型（Diffusion Model）","D":"自然語言處理（NLP）"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"DALL·E-2 生成逼真圖片的關鍵技術是擴散模型（Diffusion Model）：先將影像逐步加入雜訊，再學習逆向去噪的過程，從隨機雜訊逐步還原出高品質影像。CNN 是影像特徵萃取的基礎架構、GAN 是另一類生成技術，但 DALL·E-2 的核心生成機制是擴散模型。","concept":"擴散模型","aiExplained":true},{"id":"web-j2-47","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"在企業級數據管道（ETL）中，No Code / Low Code 平台的主要角色為何？","options":{"A":"可作為前端數據可視化工具，協助展示與分析結果","B":"取代部分傳統 ETL 解決方案，但可能無法處理過於客製化的邏輯","C":"僅適用於小型數據應用，對大型數據處理的效率較低","D":"無法應用於任何數據處理場景，因整合難度過高"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"No Code / Low Code 平台在企業級 ETL 管道中能以視覺化方式快速搭建資料擷取、轉換與載入流程，可取代部分傳統 ETL 解決方案；但面對高度客製化的商業邏輯時，仍可能受限於平台的擴充彈性。選項B同時點出其價值與侷限，是最貼切的描述。","concept":"低程式碼ETL","aiExplained":true},{"id":"web-j2-48","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"下列何者不是生成式 AI 核心技術？","options":{"A":"Variational Autoencoders（VAE）","B":"Generative Adversarial Networks（GAN）","C":"Visual Geometry Group（VGG）","D":"Autoregressive Models（AR Model）"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"VGG（Visual Geometry Group）是經典的卷積神經網路架構，主要用於影像分類等判別式任務，並非生成式 AI 的核心技術。相對地，VAE、GAN 與自迴歸模型（AR Model）都是以生成新資料為目標的代表性生成式技術，因此不屬於核心技術的是選項C。","concept":"生成式AI核心技術","aiExplained":true},{"id":"web-j2-49","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"使用生成式 AI 技術或工具生成內容時，應採取下列哪一項措施以確保內容品質？","options":{"A":"使用內容直接進行學術報告","B":"適當標注引用來源","C":"減少人工參與的審查過程","D":"排除所有生成的資料"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"生成式 AI 的內容可能引用或改寫既有資料，適當標注引用來源既能提升內容的可信度與可查證性，也符合學術與著作權倫理，是確保內容品質的重要措施。直接拿來交報告或減少人工審查反而增加錯誤與抄襲風險，全面排除生成資料則失去使用工具的意義。","concept":"生成內容品質管理","aiExplained":true},{"id":"web-j2-50","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"小莉老師準備使用生成式 AI 製作個人化學習系統，以下為她設計系統時可能採取的操作步驟，請依其邏輯順序排列：a.根據學生學習歷程與成績，輸入學生特徵 b.根據教材主題，指示 AI 生成適合的練習題與即時回饋 c.生成適應性學習計畫，讓每位學生依進度與弱點調整練習方式 d.匯入課綱與教學單元內容，建立知識結構圖","options":{"A":"d → a → c → b","B":"a → d → b → c","C":"d → a → b → c","D":"a → b → c → d"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"建置個人化學習系統應先匯入課綱與教學單元內容建立知識結構圖（d），再輸入學生的學習歷程與成績等特徵（a），接著依教材主題讓 AI 生成練習題與即時回饋（b），最後根據練習所累積的進度與弱點生成適應性學習計畫（c）。因此正確順序為 d→a→b→c。","concept":"個人化學習設計","aiExplained":true},{"id":"web-j2-51","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"下列哪一項不是生成式 AI 工具在使用體驗方面的優化方向？","options":{"A":"提供更直觀的操作設計","B":"支援自然語言指令","C":"提供智慧化的參數調整建議","D":"限制使用者自訂生成內容"},"answer":"D","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"生成式 AI 工具的使用體驗優化方向包括更直觀的操作介面、支援自然語言指令，以及提供智慧化的參數調整建議，都是降低使用門檻、提升效率的作法。限制使用者自訂生成內容反而削弱了工具的彈性與可用性，與優化使用體驗的目標背道而馳。","concept":"使用體驗優化","aiExplained":true},{"id":"web-j2-52","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"學校教師如何引導學生正確使用生成式 AI 工具？","options":{"A":"不應使用 AI 工具於教學場域","B":"無限制地使用 AI 工具","C":"訂立清晰的使用規範並進行說明","D":"僅鼓勵學生利用 AI 完成課堂作業"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"引導學生正確使用生成式 AI，關鍵在於訂立清晰的使用規範並向學生說明，讓學生知道何時可用、如何標注與查證，培養負責任的使用習慣。全面禁止會錯失學習機會，毫無限制或只鼓勵用 AI 完成作業則容易造成依賴與學術誠信問題。","concept":"AI使用規範","aiExplained":true},{"id":"web-j2-53","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"若企業使用第三方 AI API（如 OpenAI、Claude、Gemini 等），協助處理內部資料，為避免敏感資訊遭模型記憶或進一步分析，應優先採取下列哪一種作法？","options":{"A":"啟用 Zero-Retention 模式或採用具企業資安保障的 API 服務","B":"使用虛擬機建立隔離環境，以模擬匿名資料操作流程","C":"將原始數據進行視覺化轉換，以避免直接暴露文本內容","D":"將輸入資料轉換為向量嵌入後，再傳輸至語言模型進行處理"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"要避免敏感資料被第三方模型記憶或再利用，最直接有效的作法是啟用 Zero-Retention（零留存）模式，或選用具企業級資安保障的 API 服務，從服務條款與技術面確保輸入資料不被保存與訓練。虛擬機隔離、資料視覺化或向量嵌入都無法阻止資料一旦送出後被服務端留存的風險。","concept":"零留存API資安","aiExplained":true},{"id":"web-j2-54","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"企業若要有效支援生成式 AI 的運行，內部 IT 環境最需要具備下列何種條件？","options":{"A":"提供更多的辦公設備，以提升員工生產力","B":"精簡企業內部流程，以加速決策效率","C":"擁有高效能運算資源與彈性儲存空間，以支援 AI 模型訓練與推理","D":"增加部門之間的交流機會，以促進跨部門合作"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"生成式 AI 的訓練與推論需要大量運算能力與資料存取，因此企業內部 IT 環境最關鍵的條件是具備高效能運算資源（如 GPU）與彈性儲存空間。辦公設備、流程精簡與跨部門交流雖有助於營運，但並非支撐 AI 模型運行的技術基礎。","concept":"AI基礎設施需求","aiExplained":true},{"id":"web-j2-55","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"A 企業想要實現客服自動化，希望透過 AI 理解客戶發送的文本訊息，並根據文本內容調用相對應的圖片和影片進行回覆，A 企業應該選擇哪一種模型？","options":{"A":"強化學習模型","B":"多模態模型","C":"圖像分類模型","D":"單模態大語言模型"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"此情境需要 AI 同時理解文字訊息，並調用圖片、影片等不同型態的內容進行回覆，涉及文字、影像、影片多種資料型態的整合處理，正是多模態模型的定位。單模態語言模型只能處理文字，圖像分類與強化學習模型則不具備跨模態理解與調用能力。","concept":"多模態模型","aiExplained":true},{"id":"web-j2-56","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"下列哪一種情境最能展現提示工程（Prompt Engineering）的價值？","options":{"A":"使用者輸入一個模糊的問題，AI 給出一個非常確定的答案","B":"使用者輸入一個非常具體的問題，AI 給出一個相關但不完全符合的答案","C":"使用者輸入一個精準有架構的問題，AI 生成符合架構的答案","D":"使用者輸入一個簡單的問題，AI 給出一個非常複雜的答案"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"提示工程的價值在於：使用者以精準、有架構的方式描述需求，模型便能生成符合該架構的高品質回應，展現「好的輸入帶來好的輸出」。選項C正是這種對應關係；模糊問題得到武斷答案或答非所問，反而顯示提示設計不良。","concept":"提示工程價值","aiExplained":true},{"id":"web-j2-57","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"下列敘述何者最能反映生成式 AI 在圖像生成領域的發展趨勢？","options":{"A":"生成式 AI 目前僅能生成基於簡單算法的低解析度圖像，且無法應用於高解析度或細節豐富的圖像創建","B":"隨著生成式 AI 技術的進步，圖像不僅風格多樣，且逼真度顯著提升，並可處理更複雜的圖像生成任務","C":"生成式 AI 技術目的為加快生成速度，可生成靜態圖像，無法生成動態圖像","D":"生成式 AI 在圖像生成方面的發展主要集中於圖像風格轉換，無涉及其他類型的視覺內容生成"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"隨著擴散模型等技術進步，生成式 AI 產出的圖像不僅風格多樣，逼真度也顯著提升，並能處理高解析度、複雜構圖甚至動態影像等任務，選項B最能反映此發展趨勢。其他選項將能力侷限於低解析度、僅靜態圖像或僅風格轉換，均與實際發展不符。","concept":"圖像生成趨勢","aiExplained":true},{"id":"web-j2-58","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"關於生成式 AI，下列 A~E 敘述哪些正確？ A. 生成的內容不會帶有偏見 B. 具有高度準確性，不會有虛假信息 C. 生成內容的準確性，建議需要經過人類審核 D. 每次生成的內容都可能不同 E. 生成式 AI 具有高度安全性，不會導致數據外流","options":{"A":"C、D","B":"A、C、D","C":"A、B、D、E","D":"A、C、D、E"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"生成式 AI 的輸出具有隨機性，每次生成的內容都可能不同（D正確）；其內容可能出錯或虛構，因此準確性需要經過人類審核（C正確）。至於不會有偏見（A）、不會有虛假資訊（B）、不會導致資料外流（E）皆與生成式 AI 的實際風險相悖，故正確組合為 C、D。","concept":"生成式AI特性","aiExplained":true},{"id":"web-j2-59","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"一家跨國企業計劃在財務部門導入生成式 AI，並結合自動化系統進行報告產出。導入此系統後，最有可能實現的效益為何？","options":{"A":"增加財務收益","B":"顯著提升報告準確性並減少人工錯誤","C":"加速市場推廣活動並提高銷售業績","D":"提高品牌曝光度並增強客戶關係管理"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"在財務部門導入生成式 AI 並結合自動化系統產出報告，最直接的效益是由系統自動彙整資料與生成內容，顯著提升報告準確性並減少人工作業造成的錯誤。增加財務收益、行銷推廣或品牌曝光屬於其他部門的目標，並非此導入情境最可能實現的效益。","concept":"財務AI效益","aiExplained":true},{"id":"web-j2-60","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某製造業團隊建立瑕疵偵測模型時，使用單張約 20MB 的高解析度工業影像作為訓練資料，並將所有影像儲存於 NAS（Network Attached Storage）中。訓練時透過 PyTorch 搭配 CNN 模型於 GPU 上進行，工程師觀察到 GPU 使用率僅約 20%至 30%，整體訓練時間耗費數日。根據上述情境，造成 GPU 利用率偏低的最可能原因為何？","options":{"A":"模型架構過於複雜，導致反向傳播時間過長","B":"訓練資料品質不穩定，造成模型難以收斂","C":"高解析影像從 NAS 載入產生 I/O（Input/Output）瓶頸，導致 GPU 等待","D":"批次大小（Batch Size）設定不當，導致 GPU 長時間閒置"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"單張影像高達約 20MB 且全部存放在 NAS，訓練時每批資料都要透過網路從 NAS 載入，資料讀取速度跟不上 GPU 運算速度，形成 I/O 瓶頸，GPU 大部分時間都在等待資料，使用率因而僅有兩三成。若是模型過於複雜，GPU 使用率反而會偏高，故最可能原因是選項C。","concept":"GPU I/O瓶頸","aiExplained":true},{"id":"web-j2-61","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在生成式 AI 導入過程中，資料安全與隱私保護的哪一方面是最重要的考量？","options":{"A":"權限控管與合規要求","B":"增強客服回饋（反饋）能力","C":"資料視覺化能力","D":"設定目標優先級"},"answer":"A","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"生成式 AI 導入過程中，資料安全與隱私保護的核心是權限控管與合規要求：透過存取權限管理確保只有授權人員能接觸敏感資料，並符合個資法等法規要求。客服回饋、資料視覺化與目標優先級屬於功能或管理面向，與資料安全隱私的直接關聯較低。","concept":"資料安全考量","aiExplained":true},{"id":"web-j2-62","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"若企業將資料安全管理外包給第三方服務供應商，屬於哪種風險應對策略？","options":{"A":"風險緩解","B":"風險轉移","C":"風險接受","D":"風險規避"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"風險應對策略中，「風險轉移」是指將風險的責任或損失轉由第三方承擔，例如購買保險或將業務外包。企業將資料安全管理外包給第三方服務供應商，即是把該風險的管理責任移轉給供應商，屬於典型的風險轉移策略。","concept":"風險轉移","aiExplained":true},{"id":"web-j2-63","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在生成式 AI 的風險管理中，下列哪一項屬於倫理風險？","options":{"A":"AI 生成的內容可能帶有偏見或歧視","B":"系統運行中斷可能導致企業業務受到影響","C":"因資料需求增加而引起的存儲成本上升","D":"員工培訓成本增加"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"倫理風險關注 AI 對公平、尊嚴與社會價值的影響，AI 生成內容可能帶有偏見或歧視，正是最典型的倫理風險。系統中斷屬於營運風險，儲存成本與培訓成本上升則屬於成本管理議題，皆不屬於倫理層面的風險。","concept":"AI倫理風險","aiExplained":true},{"id":"web-j2-64","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在企業導入 AI 的實施/營運階段，為持續發揮導入 AI 的價值，下列步驟的正確排序應為何？ A. AI 價值擴散 B.上線部署 C.模型監控與優化","options":{"A":"ACB","B":"ABC","C":"BAC","D":"BCA"},"answer":"D","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"在實施與營運階段，應先完成模型的上線部署（B），接著持續進行模型監控與優化（C），確保系統穩定且效能不退化，最後將成功經驗推廣至其他業務場景，實現 AI 價值擴散（A）。因此正確順序為 B→C→A。","concept":"AI營運階段排序","aiExplained":true},{"id":"web-j2-65","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"使用生成式 AI 協助撰寫一份有關產業碳排政策的分析報告，AI 提供的內容看起來語句通順且用詞專業，但經查證發現其中提到的法規條文與企業名稱並不存在。請問造成此現象最可能的原因為下列何者？","options":{"A":"模型語料涵蓋不足，導致資料無法完整反映現實","B":"提示語過度簡略，導致生成內容缺乏真實依據","C":"模型缺乏檢索能力，無法即時查詢正確資訊","D":"模型產生幻覺內容，虛構與真實資訊混雜出現"},"answer":"D","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"AI 生成的內容語句通順、用詞專業，但引用的法規條文與企業名稱經查證並不存在，這是典型的「幻覺」（Hallucination）現象：模型依據語言統計規律生成看似合理卻虛構的資訊，將真實與捏造內容混雜呈現。語料不足或提示簡略可能影響品質，但憑空捏造具體條文與名稱最直接的成因是模型幻覺。","concept":"AI幻覺","aiExplained":true},{"id":"web-j2-66","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在管理生成式 AI 系統的隱私風險時，下列哪一種技術最能確保數據使用的安全性？","options":{"A":"強化學習（Reinforcement Learning）","B":"深度學習（Deep Learning）","C":"零信任架構（Zero Trust Architecture）","D":"注意力機制（Attention Mechanism）"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"零信任架構（Zero Trust Architecture）以「永不信任、持續驗證」為原則，對每一次資料存取都進行身分驗證與最小權限控管，能有效降低生成式 AI 系統中資料被未授權存取的隱私風險。強化學習、深度學習與注意力機制都是模型技術，並非資料安全防護機制。","concept":"零信任架構","aiExplained":true},{"id":"web-j2-67","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在驗證生成式 AI 應用的概念驗證（Proof of Concept, POC）時，若企業希望確保模型生成的公平性，最適合採用哪種評估策略？","options":{"A":"壓力測試（Stress Testing）","B":"對抗性測試（Adversarial Testing）","C":"偏差檢測（Bias Detection）","D":"延遲測試（Latency Testing）"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"要在 POC 階段確保模型生成的公平性，應採用偏差檢測（Bias Detection），檢視模型輸出是否對特定族群、性別等產生系統性偏差。壓力測試與延遲測試針對效能，對抗性測試針對安全與穩健性，皆非直接評估公平性的策略。","concept":"偏差檢測","aiExplained":true},{"id":"web-j2-68","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"使用生成式 AI 產出需要邏輯清晰、高度準確性與一致性的文本時，下列哪一種溫度（Temperature）設定最能有助於降低回答的不確定性並提升一致性？","options":{"A":"將溫度設定在 0.1 至 0.3，使輸出結果趨於穩定可預測","B":"將溫度設定在 0.5 至 0.7，以取得適度創意與合理性平衡","C":"將溫度設定在 1.0 至 1.2，提高語句的多樣性與發散性","D":"維持預設溫度不變，讓模型依照原始設定自由生成"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"溫度（Temperature）參數控制生成內容的隨機程度：溫度越低，模型越傾向選擇機率最高的詞彙，輸出越穩定、可預測。需要邏輯清晰、高準確性與一致性的文本時，將溫度設在 0.1 至 0.3 的低區間最能降低不確定性；溫度調高則會增加多樣性與發散性，不利於一致性要求。","concept":"溫度參數","aiExplained":true},{"id":"web-j2-69","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"下列何者為專門用於評估大型語言模型（LLM）在「台灣本土特有知識」方面表現的基準測試資料集？","options":{"A":"HumanEval","B":"Table Understanding","C":"MBPP","D":"TTQA"},"answer":"D","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"TTQA（Taiwan Trivia Question Answering）是專門評估大型語言模型對台灣本土特有知識掌握程度的基準測試資料集，涵蓋台灣文化、地理與社會等在地知識。HumanEval 與 MBPP 用於評估程式碼生成能力，Table Understanding 則評估表格理解，皆與台灣本土知識無關。","concept":"TTQA基準測試","aiExplained":true},{"id":"web-j2-70","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某中型零售企業打算導入 AI 客服系統來提升顧客諮詢效率。根據 AI 導入的一般流程規劃，下列哪一個步驟最適合作為接下來的第一階段任務？","options":{"A":"設計符合品牌風格的 AI 回應邏輯與對話範本，強化用戶體驗","B":"選擇合適的 AI 技術供應商或開源方案，確定技術方向與架構","C":"蒐集過往客服對話記錄，進行資料清洗與前處理","D":"明確定義導入目標與關鍵績效指標，作為後續設計依據"},"answer":"D","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68cfb4f0fd89780001298b53","explanation":"AI 導入的一般流程以「明確定義導入目標與關鍵績效指標（KPI）」為第一階段，先確立要解決的問題與衡量成效的標準，後續的資料蒐集、技術選型與對話設計才有依據。若目標未定就先選供應商或設計回應邏輯，容易導致方向偏離與資源浪費。","concept":"AI導入目標定義","aiExplained":true},{"id":"web-j1-113","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"人工智慧（AI）的技術目標，是要讓電腦與機器模擬人類的哪些核心能力？","options":{"A":"僅進行高速資料運算與儲存","B":"僅複製既有知識與規則","C":"模擬人類的學習、理解、問題解決、決策制定與自主性","D":"僅用於圖像或語音的辨識"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"人工智慧的技術目標是讓電腦與機器模擬人類的核心認知能力，包括學習、理解、問題解決、決策制定與自主性，而非僅限於單一功能。高速運算與儲存、複製既有規則或單純的影像語音辨識，都只是局部能力，無法涵蓋 AI 追求的整體智慧表現。","concept":"AI核心能力","aiExplained":true},{"id":"web-j1-114","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"目前商業應用中，如語音辨識、影像辨識、或 Netflix 推薦系統等，其智慧被限制在狹窄領域內的 AI 類型是下列何者？","options":{"A":"通用人工智慧 (AGI)","B":"超級人工智慧 (ASI)","C":"狹義人工智慧 (ANI)","D":"聯邦代理 (Federated Agent)"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"語音辨識、影像辨識與 Netflix 推薦系統等商業應用，都只在特定任務的狹窄領域內展現智慧，無法跨領域泛化，屬於狹義人工智慧（ANI）。AGI 指具備人類水準的通用智慧，ASI 則指超越人類的超級智慧，目前皆尚未實現。","concept":"狹義人工智慧","aiExplained":true},{"id":"web-j1-115","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在 AI 發展的第一波浪潮（約 1950s-1980s），其核心思想是將智慧分解為一套明確的符號與邏輯規則。這波浪潮被稱為「規則的時代」或下列何者？","options":{"A":"統計學習","B":"深度學習","C":"符號主義","D":"模型的創造力"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"AI 發展的第一波浪潮以「將智慧分解為明確的符號與邏輯規則」為核心思想，由人類專家把知識寫成規則讓機器推理，這種取徑稱為符號主義（Symbolism），也被稱為規則的時代。統計學習與深度學習則分別對應後續以資料驅動的第二、三波浪潮。","concept":"符號主義","aiExplained":true},{"id":"web-j1-116","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"負責任的人工智慧（RAI）是 AI 治理的指導哲學。其根本目的是為了建立人類對 AI 系統的信任。此框架中的「穩健責任」主要關注的面向是？","options":{"A":"確保 AI 決策的無偏見性","B":"確保 AI 尊重個⼈權利與隱私","C":"確保 AI 系統本⾝安全可靠並能抵抗攻擊","D":"確保當 AI 造成損害時，各方責任明確"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"負責任 AI 框架中的「穩健責任」（Robustness）關注 AI 系統本身的安全性與可靠性，要求系統在各種情境下穩定運作，並能抵抗惡意攻擊與異常輸入。無偏見性屬於公平性原則、尊重個人權利屬於隱私原則、損害責任歸屬則屬於問責性原則。","concept":"穩健責任","aiExplained":true},{"id":"web-j1-117","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在機器學習中，訓練電腦下圍棋或自動駕駛車輛，系統透過與環境互動並不斷「試錯」來學習最佳策略，以最大化長期獎勵。這種學習方式屬於下列何者？","options":{"A":"監督式學習","B":"非監督式學習","C":"強化學習","D":"半監督式學習"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"系統透過與環境互動、不斷試錯，並以最大化長期獎勵為目標學習最佳策略，這正是強化學習（Reinforcement Learning）的定義，AlphaGo 下圍棋與自動駕駛都是代表性應用。監督式學習需要標註資料，非監督式學習找資料內在結構，皆不涉及獎勵驅動的試錯機制。","concept":"強化學習","aiExplained":true},{"id":"web-j1-118","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"一家智慧工廠為其核心生產設備建立了一個即時、動態的虛擬複製品，用於在不影響實體運作的情況下進行新流程的模擬和壓力測試。此技術最符合下列哪一種新興 AI 應用典範？","options":{"A":"AI 代理人 (AI Agent)","B":"數位孿生 (Digital Twin)","C":"聯邦代理 (Federated Agent)","D":"可解釋 AI (XAI)"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"為實體設備建立即時、動態同步的虛擬複製品，在不影響實體運作的情況下進行模擬與壓力測試，正是數位孿生（Digital Twin）的典型應用。AI 代理人強調自主執行任務，XAI 著重決策可解釋性，皆與「虛擬複製品」的概念不符。","concept":"數位孿生","aiExplained":true},{"id":"web-j1-119","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某金融機構使用 AI 進行信貸審批，需要確保其決策過程可被客戶和監管者理解和追溯。為實現負責任 AI 中的「透明性與問責性」原則，應導入下列哪種技術？","options":{"A":"零信任架構 (ZTA)","B":"差分隱私 (DP)","C":"可解釋 AI (XAI)","D":"數據增強 (Data Augmentation)"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"要讓信貸審批的 AI 決策過程可被客戶與監管者理解和追溯，應導入可解釋 AI（XAI），透過解釋模型判斷依據來落實透明性與問責性原則。零信任架構與差分隱私屬於資安與隱私保護技術，數據增強則用於擴充訓練資料，皆無法提供決策解釋能力。","concept":"可解釋AI","aiExplained":true},{"id":"web-j1-120","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"一家電商平台希望建立一個模型來預測某位客戶在未來 30 天內「是否會流失」（是/否）。此預測目標是一個離散的二元類別判斷，最適合採用下列哪種傳統監督式學習模型？","options":{"A":"線性迴歸","B":"邏輯迴歸","C":"K-均值聚類","D":"強化學習"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"預測客戶「是否會流失」是離散的二元分類問題，邏輯迴歸透過 Sigmoid 函數將輸出轉換為 0 到 1 之間的機率，正是處理二元分類的經典監督式學習模型。線性迴歸適用於連續數值預測，K-均值聚類屬於非監督式學習，強化學習則是獎勵驅動的決策學習，皆不適用此情境。","concept":"邏輯迴歸分類","aiExplained":true},{"id":"web-j1-121","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"一家人資公司利用 AI 系統篩選履歷。由於訓練數據反映了現實中長期存在的「科技業多為男性、護理業多為女性」的刻板印象，導致 AI 模型在篩選時複製了這種錯誤連結。此現象屬於演算法偏見來源的哪一種類型？","options":{"A":"數據不具代表性","B":"潛在的社會偏見","C":"互動中產生偏見","D":"模型訓練錯誤"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"訓練數據忠實反映了現實社會中長期存在的職業性別刻板印象，模型學習後複製了這種錯誤連結，屬於「潛在的社會偏見」：偏見源自社會既有的結構性不平等，而非資料抽樣不足或模型訓練錯誤。資料不具代表性指樣本涵蓋偏差，與此處「數據如實反映偏見現實」的情境不同。","concept":"社會偏見","aiExplained":true},{"id":"web-j1-122","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某醫療 AI 系統被設計用於初步判讀 X 光片，標示出可疑病灶區域，並將結果提供給醫生參考，但最終的診斷結論和治療方案完全由醫生決定。這種人與 AI 的互動模式屬於下列哪種人類監督層級？","options":{"A":"人在指揮 (Human-in-Command)","B":"人在迴圈內 (Human-in-the-Loop, HITL)","C":"人在迴圈上 (Human-on-the-Loop, HOTL)","D":"完全自動化"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"AI 僅負責初步判讀並標示可疑病灶，每一個案例的最終診斷與治療方案都由醫生審核決定，人類直接參與每一次決策迴圈，屬於人在迴圈內（Human-in-the-Loop）的監督層級。人在迴圈上是人類僅監督系統運作、必要時才介入，與此處逐案把關的模式不同。","concept":"人在迴圈內","aiExplained":true},{"id":"web-j1-123","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某公司導入 AI 系統，用於分析應聘者在面試語音中的情緒波動，作為是否錄取的主要依據。根據歐盟《人工智慧法案》(EU AI Act)，此應用屬於哪種風險等級？","options":{"A":"最小風險 (Minimal Risk)","B":"有限風險 (Limited Risk)","C":"高風險 (High-Risk)","D":"不可接受風險 (Unacceptable Risk)"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"依《歐盟人工智慧法案》附件三，用於招募甄選、評估求職者的AI系統屬於就業領域的高風險應用，因其直接影響個人的工作機會與生計。此類系統雖可上市使用，但必須符合資料治理、透明度與人工監督等嚴格要求。","concept":"AI法案風險分級","aiExplained":true},{"id":"web-j1-124","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"為防範內部員工無意疏失或惡意行為導致公司敏感資料外洩（例如將機密文件輸入公開 LLM），企業應導入何種資安架構，假設任何人在任何時候都可能是潛在威脅，並確保每次存取都經過明確驗證？","options":{"A":"傳統防火牆模型","B":"隔離沙箱機制","C":"零信任架構 (ZTA)","D":"數據加密儲存"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"零信任架構的核心原則是「永不信任、持續驗證」，不論存取來自內部或外部，每次都必須經過身分驗證與授權。相較於傳統防火牆只防外不防內，零信任能有效降低內部人員有意或無意造成的資料外洩風險。","concept":"零信任架構","aiExplained":true},{"id":"web-j1-125","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在機器學習中，下列關於「演算法」與「模型」的核⼼定義與關係敘述，何者最為正確？","options":{"A":"演算法是訓練完成後可以直接用於預測的成品","B":"模型是「食譜」，演算法是「依照食譜做出的料理」","C":"演算法是「食譜」，模型是「依照食譜做出的料理」","D":"兩者實務上完全相同，可互相替換稱呼"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"演算法是訓練模型的方法與步驟，如同食譜；模型則是演算法在資料上訓練完成後的產物，如同依食譜做出的料理。訓練好的模型才是實際用來預測的成品，兩者角色不同，不可混為一談。","concept":"演算法與模型","aiExplained":true},{"id":"web-j1-126","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"一家銀行希望建立即時信用卡盜刷偵測模型。由於漏掉的盜刷（偽陰性）會直接導致公司鉅額損失，因此在評估模型效能時，應最優先關注哪個指標以衡量模型「找出所有真正盜刷交易」的能力？","options":{"A":"精確率 (Precision)","B":"準確率 (Accuracy)","C":"召回率 (Recall)","D":"R 平方值 (R²)"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"召回率衡量的是所有真正的盜刷交易中被模型成功找出的比例，直接對應「不漏抓」的能力。當偽陰性的代價極高時，應優先提升召回率，寧可多查核一些可疑交易，也不能放過真正的盜刷。","concept":"召回率","aiExplained":true},{"id":"web-j1-127","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"聯邦代理 (Federated Agents) 是一種結合了「多代理系統」與「聯邦學習」的先進 AI 架構。此架構最適合應用於哪一類情境？","options":{"A":"需要將所有原始數據集中到一個中央伺服器進行訓練","B":"數據分散、隱私要求高，且需要多個智能體協同決策的場景","C":"需要生成高度逼真且全新的圖像或文本內容","D":"僅用於單一裝置上的數據預處理任務"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"聯邦學習讓資料留在本地、只交換模型參數，滿足資料分散與隱私要求；多代理系統則讓多個智能體協同決策。聯邦代理結合兩者，最適合資料分散、隱私敏感且需要協同運作的場景，例如跨機構的醫療或金融應用。","concept":"聯邦代理","aiExplained":true},{"id":"web-j2-128","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"檢索增強生成 (RAG) 技術將大型語言模型 (LLM) 比喻為「開書考試」，強調其能大幅減少 AI 產生錯誤資訊（幻覺），提升結果的準確性與可信度。請問 RAG 的核心機制是結合了哪兩種技術？","options":{"A":"圖像識別與語音生成","B":"資訊檢索與文本生成","C":"監督式學習與非監督式學習","D":"模型微調與模型蒸餾"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"RAG的運作方式是先透過資訊檢索從外部知識庫找出相關文件，再交由語言模型依據檢索結果進行文本生成。這種「先查資料再作答」的開書考試模式，讓回答有憑有據，大幅降低幻覺發生的機率。","concept":"檢索增強生成","aiExplained":true},{"id":"web-j2-129","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"當生成式 AI 模型產出看似流暢，但內容卻是與事實不符或憑空捏造的虛假資訊。此現象在生成式 AI 風險管理中被稱為下列何者？","options":{"A":"過度擬合 (Overfitting)","B":"數據漂移 (Data Drift)","C":"AI 幻覺 (AI Hallucination)","D":"提示工程 (Prompt Engineering)"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"幻覺指模型輸出語句流暢、看似合理，內容卻與事實不符或憑空捏造。這是生成式AI風險管理的核心議題，因為使用者容易被流暢的表述誤導而相信錯誤資訊。","concept":"AI幻覺","aiExplained":true},{"id":"web-j2-130","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在跨產業應用概覽中，生成式 AI 可透過分析醫學數據預測分子結構，以協助開發新藥。此應用情境屬於下列哪個產業領域？","options":{"A":"金融","B":"零售消費","C":"醫療保健","D":"軟體開發"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"分析醫學數據、預測分子結構以加速新藥開發，是生成式AI在醫療保健領域的代表性應用。此類應用能大幅縮短藥物研發週期並降低成本，屬於醫療產業的範疇。","concept":"醫療AI應用","aiExplained":true},{"id":"web-j2-131","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"為了引導生成式 AI 輸出安全、合規且可控的內容，同時防⽌產出不當或有害資訊，開發者會設置一組預先定義的規則與過濾機制。這套機制被稱為下列何者？","options":{"A":"模型監控 (Model Monitoring)","B":"AI 護欄 (Guardrails)","C":"差分隱私 (Differential Privacy)","D":"泛化能力 (Generalization Ability)"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"護欄是開發者預先定義的規則與過濾機制，用來約束模型的輸入與輸出，確保內容安全、合規且可控。它像道路護欄一樣，讓模型在允許的範圍內運作，防止產出有害或不當資訊。","concept":"AI護欄","aiExplained":true},{"id":"web-j2-132","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"Low-Code 平台與 No-Code 平台相比，其最大的技術特點差異在於 Low-Code 平台具備哪項特性？","options":{"A":"完全不需要撰寫任何程式碼","B":"容許少量的程式碼進行客製化擴充","C":"只能用於生成文本內容","D":"專門用於底層演算法開發"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"Low-Code平台以視覺化開發為主，但保留撰寫少量程式碼的空間，讓開發者能進行客製化擴充；No-Code則完全不需寫程式。容許程式碼擴充正是兩者最大的技術差異。","concept":"低程式碼平台","aiExplained":true},{"id":"web-j2-133","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在生成式 AI 導入評估的基礎核心步驟「掌握企業課題」中，第一個活動是將高層的願景轉化為可衡量的具體指標，這個步驟被稱為下列何者？","options":{"A":"選定應用範圍","B":"提取改善項目","C":"界定經營目標","D":"討論 AI 必要性"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"掌握企業課題的第一步是「界定經營目標」，將高層抽象的願景轉化為可衡量的具體指標，例如營收成長率或成本降低幅度。有了明確目標，後續提取改善項目與討論AI必要性才有依據。","concept":"界定經營目標","aiExplained":true},{"id":"web-j2-134","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某客服中心導入生成式 AI 助理後，報告顯示「平均郵件處理時間縮短了 25%」。同時，員工普遍反映「工作壓力顯著下降」。請問「平均郵件處理時間縮短 25%」屬於哪種效益類型？","options":{"A":"質化效益","B":"技術效益","C":"量化效益","D":"專案難易度"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"「處理時間縮短25%」是能以數字明確衡量的改善成果，屬於量化效益；員工壓力下降這類難以直接量化的感受，則屬質化效益。評估AI導入成效時，兩者應並陳但須分清類別。","concept":"量化效益","aiExplained":true},{"id":"web-j2-135","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"一家零售企業評估了兩個 AI 專案：專案 A (導入 AI 撰寫行銷文案，難度低/好處高)；專案 B (開發企業專屬的供應鏈優化模型，難度高/好處高)。根據 AI 導入的優先順序評估框架，該企業理想的決策是什麼？","options":{"A":"應優先執行專案 A，以快速驗證 AI 價值並建立團隊信心","B":"應優先執行專案 B，因為其潛在的收益遠大於專案 A","C":"兩個專案應同時啟動，以分散風險","D":"應先進行資源評估，再決定是否導入"},"answer":"A","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"依難易度與效益的優先順序評估框架，難度低、好處高的專案是理想的起步點。優先執行專案A能快速展現AI價值、累積經驗並建立團隊信心，為日後挑戰高難度專案奠定基礎。","concept":"導入優先順序","aiExplained":true},{"id":"web-j2-136","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在生成式 AI 導入成本結構分析中，專案所有參與人員，包括專案經理、AI 工程師、以及行銷人員學習操作 AI 工具所投入的工時成本，應主要歸類在哪一成本類別？","options":{"A":"開發費用","B":"軟硬體費用","C":"⼈事費⽤","D":"維運費用"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"人事費用涵蓋專案所有參與人員投入的工時成本，包括專案經理與工程師的作業時間，以及行銷人員學習AI工具的時間。這些以人力工時計算的成本，均應歸入人事費用而非開發或維運費用。","concept":"導入成本結構","aiExplained":true},{"id":"web-j2-137","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業欲建立 AI 客服系統，需要處理大量客戶來信、聊天紀錄與語音檔案。在導入規劃的「檢視數據可用性」步驟中，應優先關注哪種資料類型的轉換與特徵提取，因為其內容龐雜且沒有預定義結構？","options":{"A":"結構化數據","B":"半結構化數據","C":"非結構化數據","D":"數值型數據"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"客戶來信、聊天紀錄與語音檔案內容龐雜、沒有預定義格式，屬於非結構化數據。此類資料無法直接分析，必須優先進行轉換與特徵提取，才能供AI模型使用。","concept":"非結構化數據","aiExplained":true},{"id":"web-j2-138","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某公司希望 AI 客服能根據最新的產品技術手冊即時回答客戶的規格問題，但他們不想花費大量時間對整個基礎模型進行重新訓練。應優先選擇哪種技術架構？","options":{"A":"強化學習 (RL)","B":"模型微調 (Fine-tuning)","C":"檢索增強生成 (RAG)","D":"監督式學習 (SL)"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"RAG讓模型在回答前先從外部知識庫檢索最新的技術手冊內容，再據以生成答案，不必重新訓練基礎模型。知識更新只需更新資料庫，兼顧即時性與成本，最符合題目的需求。","concept":"RAG技術選型","aiExplained":true},{"id":"web-j2-139","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"一家金融科技公司在評估 AI 專案風險時，發現訓練數據中包含大量敏感的客戶 PII。為避免內部洩露風險，公司決定將敏感數據的儲存與管理外包給一家具有專業資安認證的雲端服務商，並簽訂責任協議。此風險應對策略屬於下列何者？","options":{"A":"風險緩解 (Mitigation)","B":"風險轉移 (Transfer)","C":"風險迴避 (Avoidance)","D":"風險接受 (Acceptance)"},"answer":"B","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"將敏感數據的儲存管理外包給具資安認證的雲端服務商，並以責任協議分攤後果，是把風險移轉給第三方承擔的做法，屬於風險轉移。緩解是降低風險影響，迴避是放棄該活動，接受則是不採取行動。","concept":"風險轉移","aiExplained":true},{"id":"web-j2-140","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在大型語言模型訓練流程中，當模型已透過指令微調具備基本遵循指令的能力後，若希望模型的輸出風格更自然、更有同理心，且符合人類的偏好和價值觀，需要進行哪一階段的優化？","options":{"A":"預訓練 (Pre-training)","B":"指令微調 (Instruction Fine-tuning)","C":"人類回饋強化學習 (RLHF)","D":"差分隱私處理"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"RLHF透過人類對模型輸出的偏好回饋訓練獎勵模型，再以強化學習調整模型行為，使輸出更自然、更符合人類價值觀。它是在指令微調之後，進一步對齊人類偏好的關鍵階段。","concept":"RLHF","aiExplained":true},{"id":"web-j2-141","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"生成式 AI 導入風險管理中，若企業的 AI 系統訓練資料來源或 AI 生成的內容可能觸犯他⼈的著作權或專利權。此風險主要被歸類在哪一類型？","options":{"A":"資料隱私與安全","B":"倫理與偏見","C":"法律合規問題","D":"治理與問責"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"訓練資料或生成內容可能侵害他人著作權、專利權，涉及的是智慧財產權法規的違反，屬於法律合規問題。倫理與偏見關注歧視與公平，資料隱私關注個資保護，性質各不相同。","concept":"法律合規風險","aiExplained":true},{"id":"web-j2-142","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司開發了一個線上聊天機器人，用以提供一般產品資訊查詢。根據歐盟《人工智慧法案》(EU AI Act)，這類屬於「有限風險」（Limited Risk）的 AI 系統，必須履行哪一項最重要的義務？","options":{"A":"必須將模型的原始程式碼公開","B":"必須確保機器人的回覆 100% 正確","C":"必須在互動中明確告知使用者，他們正在與 AI 系統對話","D":"必須對所有訓練數據進行差分隱私處理"},"answer":"C","needsContext":false,"source":"官方樣題／網路整理 · vocus","srcUrl":"https://vocus.cc/article/68dc87ecfd897800018bcdf1","explanation":"歐盟AI法案對有限風險系統課以透明度義務，聊天機器人必須明確告知使用者正在與AI互動，讓使用者保有知情與選擇的權利。公開原始碼或保證回覆完全正確，都不是法案的要求。","concept":"透明度義務","aiExplained":true},{"id":"web-j1-188","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在深度學習中，處理長序列數據最有效的方法是：","options":{"A":"注意力機制","B":"最大池化","C":"批次正規化","D":"丟棄法"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"注意力機制能讓模型直接計算序列中任意兩個位置的關聯，不受距離限制，有效解決長序列的長期依賴問題，也是Transformer架構的核心。池化、批次正規化與丟棄法都不是針對序列建模設計的技術。","concept":"注意力機制","aiExplained":true},{"id":"web-j1-189","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在AI系統的可靠性研究中，最具挑戰性的是：","options":{"A":"不確定性量化","B":"錯誤檢測","C":"性能監控","D":"故障恢復"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"不確定性量化要求模型不只給出預測，還要正確評估自己「有多確定」，涉及認知與偶然兩類不確定性的建模，是可靠性研究中最困難的課題。錯誤檢測、性能監控與故障恢復相對已有較成熟的工程手段。","concept":"不確定性量化","aiExplained":true},{"id":"web-j1-190","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"自然語言處理在金融領域的主要應用是：","options":{"A":"設備維護","B":"人員管理","C":"市場分析","D":"辦公室清潔"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"自然語言處理能自動分析新聞、財報與社群輿情等大量文本，從中萃取市場情緒與趨勢訊號，因此在金融領域的主要應用是市場分析。其餘選項與語言處理能力無關。","concept":"金融NLP應用","aiExplained":true},{"id":"web-j1-191","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"自動駕駛系統中，最具挑戰性的技術難點是：","options":{"A":"車道線識別","B":"速度控制","C":"路標辨識","D":"極端情況處理"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"車道線識別、路標辨識與速度控制已有成熟的技術方案，真正困難的是極端情況：罕見、訓練資料中少見的突發場景，模型難以事先窮舉與學習，因此是自動駕駛最具挑戰性的技術難點。","concept":"極端情況處理","aiExplained":true},{"id":"web-j1-192","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"醫療影像AI診斷系統的主要挑戰不包括：","options":{"A":"硬體成本","B":"標註資料取得","C":"假陽性控制","D":"模型可解釋性"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"醫療影像AI的核心挑戰在於標註資料取得困難、假陽性必須嚴格控制、模型須具可解釋性以取得醫師信任，這些都直接影響臨床可用性。硬體成本相對而言並非主要瓶頸，故為正確選項。","concept":"醫療影像AI","aiExplained":true},{"id":"web-j1-193","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"零售業使用電腦視覺進行客流分析的主要目的是：","options":{"A":"優化商品陳列和銷售策略","B":"節省人事成本","C":"降低店面租金","D":"增加商品種類"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"客流分析透過電腦視覺掌握顧客動線、停留熱區與尖峰時段，目的在於優化商品陳列與銷售策略，提升轉換率與營收。它是支援行銷決策的工具，而非單純節省成本的手段。","concept":"零售客流分析","aiExplained":true},{"id":"web-j1-194","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"電腦視覺技術在製造業最主要的應用是：","options":{"A":"人臉識別","B":"產品品質檢測","C":"影像特效製作","D":"自動駕駛系統"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"電腦視覺在製造業最主要的應用是產品品質檢測，以影像自動辨識刮痕、瑕疵與尺寸偏差，速度與一致性都優於人工目檢。人臉識別與自動駕駛則屬於其他領域的應用。","concept":"瑕疵檢測","aiExplained":true},{"id":"web-j1-195","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在大數據分析流程中，第一步驟應該是：","options":{"A":"資料收集","B":"資料分析","C":"資料解釋","D":"決策應用"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"大數據分析流程始於資料收集，必須先取得足量且相關的原始資料，後續的分析、解釋與決策應用才有基礎。沒有資料，一切分析都無從談起。","concept":"大數據分析流程","aiExplained":true},{"id":"web-j1-196","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"自動駕駛系統中的電腦視覺主要功能是：","options":{"A":"控制車速","B":"調節空調","C":"識別道路標誌和障礙物","D":"播放音樂"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"電腦視覺是自動駕駛的「眼睛」，主要功能是識別道路標誌、車輛、行人與障礙物，提供環境感知資訊供決策系統使用。車速控制屬於控制系統的職責，不是視覺系統的工作。","concept":"自駕環境感知","aiExplained":true},{"id":"web-j1-197","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統在處理對抗樣本時，最關鍵的問題是：","options":{"A":"檢測效率","B":"防禦策略","C":"樣本生成","D":"模型重訓練"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"對抗樣本是刻意加入微小擾動、使模型誤判的輸入，攻擊手法層出不窮，因此最關鍵的問題在於建立有效的防禦策略，例如對抗訓練與輸入淨化，以確保模型的穩健性。","concept":"對抗樣本防禦","aiExplained":true},{"id":"web-j1-198","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統在即時視訊分析中的主要瓶頸是：","options":{"A":"儲存空間","B":"即時性要求","C":"影像品質","D":"網路連接"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"即時視訊分析必須在極低延遲內完成偵測與辨識，對運算速度與處理管線提出極高要求，即時性要求正是主要瓶頸。儲存空間與影像品質雖有影響，但不如延遲限制來得關鍵。","concept":"即時視訊分析","aiExplained":true},{"id":"web-j1-199","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"自然語言處理的核心技術包括：","options":{"A":"語義分析","B":"圖像辨識","C":"溫度感測","D":"動作捕捉"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"語義分析是自然語言處理的核心技術之一，目的在理解文字的意義與上下文關係。圖像辨識屬於電腦視覺，溫度感測與動作捕捉則是感測器技術，皆不屬於NLP的範疇。","concept":"NLP核心技術","aiExplained":true},{"id":"web-j1-200","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"自然語言處理在醫療領域的應用包括：","options":{"A":"電子病歷分析","B":"手術器械控制","C":"醫院空調調節","D":"醫療設備維修"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"電子病歷是大量的醫療文本資料，自然語言處理可從中萃取診斷、用藥與病程資訊，支援臨床決策與研究，是NLP在醫療領域的典型應用。其餘選項屬於硬體控制或維護，與語言處理無關。","concept":"醫療NLP應用","aiExplained":true},{"id":"web-j1-201","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"自然語言處理在新聞媒體中的應用不包括：","options":{"A":"內容推薦","B":"攝影製作","C":"新聞生成","D":"輿情分析"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"NLP在新聞媒體的應用包括自動新聞生成、內容推薦與輿情分析，都是以文本為核心的任務。攝影製作屬於影像拍攝的專業工作，與語言處理技術無關。","concept":"媒體NLP應用","aiExplained":true},{"id":"web-j1-202","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪項不是電腦視覺在製造業的應用？","options":{"A":"產品檢測","B":"設備監控","C":"生產線優化","D":"員工培訓"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"電腦視覺在製造業可用於產品檢測、設備監控與生產線優化，皆以影像分析為基礎。員工培訓屬於人力資源管理範疇，並非電腦視覺的應用場景。","concept":"製造業電腦視覺","aiExplained":true},{"id":"web-j1-203","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"機器學習中的監督式學習主要用於：","options":{"A":"分類和預測任務","B":"數據壓縮","C":"異常檢測","D":"群組分析"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"監督式學習使用帶有標籤的資料訓練模型，讓模型學會從輸入對應到正確輸出，主要用於分類與預測任務。異常檢測與群組分析通常屬於非監督式學習的範疇。","concept":"監督式學習","aiExplained":true},{"id":"web-j1-204","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪項不是AI在內容創作中的應用？","options":{"A":"文案生成","B":"新聞撰稿","C":"劇本創作","D":"設備維修"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"AI在內容創作的應用涵蓋文案生成、新聞撰稿與劇本創作，都是以生成文本為核心的任務。設備維修屬於工程維護工作，不屬於內容創作領域。","concept":"AI內容創作","aiExplained":true},{"id":"web-j1-205","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪項不是電腦視覺在安全防護領域的應用？","options":{"A":"人臉識別","B":"行為分析","C":"入侵檢測","D":"天氣預報"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"電腦視覺在安全防護的應用包括人臉識別、行為分析與入侵檢測，皆以影像辨識為基礎。天氣預報依賴氣象數據與數值模型，並非電腦視覺的應用。","concept":"安防電腦視覺","aiExplained":true},{"id":"web-j1-206","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪項不是AI在零售業的主要應用？","options":{"A":"智慧結帳","B":"商品管理","C":"客流分析","D":"商品製造"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"AI在零售業的主要應用包括智慧結帳、商品管理與客流分析，聚焦於營運效率與顧客體驗。商品製造屬於製造業的生產環節，不是零售業的AI應用範疇。","concept":"零售AI應用","aiExplained":true},{"id":"web-j1-207","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"電腦視覺的核心技術不包括：","options":{"A":"圖像處理","B":"語音識別","C":"特徵提取","D":"物件檢測"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%881%ef%bc%89/","explanation":"電腦視覺的核心技術包括圖像處理、特徵提取與物件檢測，處理的對象是影像。語音識別處理的是聲音訊號，屬於語音技術領域，不在電腦視覺的範疇內。","concept":"電腦視覺技術","aiExplained":true},{"id":"web-j1-208","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"在虛擬現實環境中，生成式AI如何優化用戶體驗？","options":{"A":"根據用戶行為動態調整環境細節","B":"使用預設場景","C":"固定環境參數","D":"隨機生成元素"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"生成式AI的核心優勢在於能即時生成與調整內容。在虛擬現實環境中，系統可根據使用者的行為與互動回饋，動態調整環境細節，讓體驗更貼近個人需求。相較之下，預設場景、固定參數或隨機生成都無法針對使用者做出個人化回應。","concept":"生成式AI於VR應用","aiExplained":true},{"id":"web-j1-209","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"法律事務中的智慧文件處理主要用於：","options":{"A":"合約生成與證據檢索","B":"辦公室管理","C":"人事安排","D":"設備維護"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"法律工作的核心是大量文件的產出與檢索。智慧文件處理能自動生成合約草稿，並從龐大卷宗中快速檢索相關證據，直接對應法律事務的專業需求。其餘選項如辦公室管理、人事安排屬一般行政事務，並非智慧文件處理的主要用途。","concept":"法律智慧文件處理","aiExplained":true},{"id":"web-j1-210","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在醫療領域中，知識挖掘主要應用於以下哪個方面？","options":{"A":"病房管理","B":"醫院建築設計","C":"基因研究與分析","D":"醫療器材維修"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"知識挖掘是從大量資料中發掘隱含規律與關聯的技術。醫療領域的基因研究涉及海量基因序列與臨床資料，正需要知識挖掘找出基因與疾病間的關聯。病房管理、建築設計與器材維修都不是以資料規律探勘為核心的工作。","concept":"醫療知識挖掘","aiExplained":true},{"id":"web-j1-211","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"智慧醫療系統的進階功能是？","options":{"A":"多源醫療數據整合診斷","B":"基本病歷管理","C":"簡單預約系統","D":"固定處方開立"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"「進階功能」的關鍵在於超越單一資料來源的處理能力。整合病歷、影像、檢驗數據等多源醫療資料進行綜合診斷，展現了智慧醫療的高階價值。基本病歷管理、簡單預約與固定處方都屬於基礎或未智慧化的功能。","concept":"智慧醫療進階應用","aiExplained":true},{"id":"web-j1-212","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"在文學創作中，生成式AI主要應用於：","options":{"A":"印刷設備維護","B":"小說與歌詞創作","C":"紙張選擇","D":"裝訂作業"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"生成式AI擅長生成文字內容，在文學創作中自然是應用於小說、歌詞等作品的生成與構思輔助。印刷設備、紙張選擇與裝訂作業屬於出版流程的實體工作，與內容生成無關。","concept":"生成式AI文學創作","aiExplained":true},{"id":"web-j1-213","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"知識挖掘在風險控制中的深度應用？","options":{"A":"基本風險評估","B":"簡單監控預警","C":"固定審核流程","D":"多維度風險預測模型"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"題目強調「深度應用」，意指超越基礎作法的進階能力。整合多維度資料建立風險預測模型，能事前預測並量化風險，正是知識挖掘的深度價值所在。基本評估、簡單預警與固定流程都屬於淺層或傳統作法。","concept":"風控知識挖掘","aiExplained":true},{"id":"web-j1-214","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"智慧文件處理如何優化多語言合約審查？","options":{"A":"跨語言語義理解與合規性檢查","B":"逐字翻譯","C":"使用標準模板","D":"人工翻譯審核"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"多語言合約審查的難點在於不同語言間的語義落差與法規差異。智慧文件處理透過跨語言語義理解，能在不同語言版本間比對條款並自動檢查合規性。逐字翻譯與標準模板無法處理語義層次的問題，人工翻譯審核則非「智慧化」的作法。","concept":"多語言合約審查","aiExplained":true},{"id":"web-j1-215","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"市場研究中的競爭分析系統如何預測市場變化？","options":{"A":"僅分析歷史數據","B":"整合多源數據建立預測模型","C":"依賴專家意見","D":"追蹤單一指標"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"預測市場變化需要整合銷售、輿情、競品動態等多來源資料，建立預測模型才能掌握趨勢。僅分析歷史數據或追蹤單一指標會遺漏市場的動態訊號，依賴專家意見則缺乏資料驅動的客觀性。","concept":"競爭分析預測","aiExplained":true},{"id":"web-j1-216","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"金融領域中的智慧文件處理主要用於：","options":{"A":"辦公室清潔管理","B":"員工休假安排","C":"財務報告生成與合規檢查","D":"公司形象設計"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"金融業的文件工作以財務報告產出與法規遵循為核心。智慧文件處理能自動生成財務報告，並比對法規要求進行合規檢查，大幅降低人工作業與疏漏風險。清潔管理、休假安排與形象設計皆與文件處理無關。","concept":"金融文件處理","aiExplained":true},{"id":"web-j1-217","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"醫療保險中的風險評估主要用於：","options":{"A":"管理保險文件","B":"優化保險定價策略","C":"維護資訊系統","D":"規劃辦公空間"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"保險業的風險評估目的在於準確衡量投保人的風險水準，據以訂定合理保費，也就是優化保險定價策略。文件管理、系統維護與空間規劃都不是風險評估的功能範疇。","concept":"保險風險評估","aiExplained":true},{"id":"web-j1-218","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"智慧文件處理在跨部門協作中的高級應用是？","options":{"A":"簡單的文件共享","B":"智慧工作流程與自動化審批","C":"基本的文件儲存","D":"人工分發文件"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"題目問的是「高級應用」，重點在超越基本文件存取的層次。智慧工作流程能自動辨識文件內容、路由至相關部門並完成自動化審批，真正提升跨部門協作效率。簡單共享、基本儲存與人工分發都屬於初階作法。","concept":"智慧工作流程","aiExplained":true},{"id":"web-j1-219","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"知識挖掘在人才管理中的深度應用？","options":{"A":"基本履歷篩選","B":"簡單績效評估","C":"固定晉升標準","D":"多維度人才發展預測"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"「深度應用」指的是從資料中挖掘出前瞻性的洞察。整合績效、技能、學習歷程等多維度資料，預測人才的發展潛力與方向，才是知識挖掘在人才管理的進階價值。基本篩選、簡單評估與固定標準都屬於傳統人資作法。","concept":"人才知識挖掘","aiExplained":true},{"id":"web-j1-220","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"個人助理中的資訊查詢功能主要提供：","options":{"A":"設備維修服務","B":"清潔管理","C":"即時精確的查詢結果","D":"人事管理"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"個人助理的資訊查詢功能，價值在於即時回應並提供精確的查詢結果，例如天氣、行程或知識問答。設備維修、清潔管理與人事管理都不屬於資訊查詢的範疇。","concept":"個人助理功能","aiExplained":true},{"id":"web-j1-221","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"音樂創作中，生成式AI可以：","options":{"A":"自動生成音樂曲譜","B":"調整樂器音量","C":"安排練習場地","D":"管理樂器庫存"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"生成式AI能學習音樂的結構與風格，自動生成旋律與曲譜，成為創作者的輔助工具。調整音量、安排場地與管理庫存屬於執行面或行政作業，並非生成式AI的創作能力。","concept":"AI音樂生成","aiExplained":true},{"id":"web-j1-222","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"智慧文件處理在財務報告生成中主要用於：","options":{"A":"管理財務設備","B":"維護會計系統","C":"自動生成準確的財務報表","D":"規劃財務部門"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"智慧文件處理在財務領域的核心價值，是自動彙整數據並生成準確的財務報表，減少人工編製的錯誤與時間成本。管理設備、維護系統與部門規劃都不屬於文件處理的範疇。","concept":"財務報表自動化","aiExplained":true},{"id":"web-j1-223","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"金融領域中的欺詐檢測主要目的是：","options":{"A":"管理辦公環境","B":"維護資訊系統","C":"規劃人力資源","D":"及早發現可疑交易行為"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"欺詐檢測的目的在於從大量交易中即時辨識異常模式，及早發現可疑交易行為，以降低金融損失。辦公環境管理、資訊系統維護與人力規劃皆與欺詐檢測的目標無關。","concept":"金融欺詐檢測","aiExplained":true},{"id":"web-j1-224","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"生成式AI在教育領域的高級應用是？","options":{"A":"固定課程內容","B":"標準化測試","C":"基本練習題","D":"適應性學習路徑生成"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"教育領域的「高級應用」在於個人化。生成式AI能依據學習者的程度與弱點，動態生成適應性學習路徑，讓每位學生獲得客製化的學習歷程。固定課程、標準化測試與基本練習題都是傳統或初階作法。","concept":"適應性學習","aiExplained":true},{"id":"web-j1-225","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"生成式AI在音樂創作中的主要應用是：","options":{"A":"管理音樂設備","B":"自動生成音樂作品","C":"維護錄音室","D":"規劃練習空間"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"生成式AI的本質是「生成內容」，在音樂領域即為自動創作旋律、編曲等音樂作品。設備管理、錄音室維護與空間規劃屬於行政庶務，並非生成式AI的應用。","concept":"AI音樂創作","aiExplained":true},{"id":"web-j1-226","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"智慧化客服中的生成式AI功能不包括：","options":{"A":"自動回答","B":"情感分析","C":"實體櫃台設計","D":"智慧聊天機器人"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"智慧客服中的生成式AI提供自動回答、情感分析與智慧聊天機器人等軟體層面的功能。實體櫃台設計屬於實體空間規劃，與AI客服系統無關，因此是不包括的項目。","concept":"智慧客服功能","aiExplained":true},{"id":"web-j1-227","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"娛樂行業中，知識挖掘技術主要用於：","options":{"A":"場地清潔管理","B":"票務人員管理","C":"餐飲服務規劃","D":"內容推薦與觀眾分析"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-1-1-%e6%8e%a2%e7%b4%a2%e7%94%a2%e6%a5%ad%e5%b8%b8%e8%a6%8bai%e6%87%89%e7%94%a8%ef%bc%882%ef%bc%89/","explanation":"娛樂產業擁有大量的觀看行為與偏好資料，知識挖掘可從中分析觀眾輪廓並進行內容推薦，提升黏著度與營收。場地清潔、票務人員管理與餐飲規劃皆屬營運庶務，非知識挖掘的應用。","concept":"娛樂內容推薦","aiExplained":true},{"id":"web-j1-228","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統的透明度實現中，最具挑戰性的環節是？","options":{"A":"複雜模型的可解釋性","B":"效能優化","C":"資源配置","D":"介面設計"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"現代AI多採用深度神經網路等複雜模型，內部運作如同黑箱，要向人類清楚解釋其決策依據，是實現透明度最困難的環節。效能優化、資源配置與介面設計屬於工程面問題，技術上相對成熟。","concept":"模型可解釋性","aiExplained":true},{"id":"web-j1-229","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在處理AI系統的服務品質損害時，最根本的技術問題是？","options":{"A":"系統維護頻率","B":"硬體配置","C":"網路頻寬","D":"特徵工程的完整性"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"服務品質損害指AI系統對特定群體的服務效果較差，其根本原因常在於特徵工程不完整，未能充分涵蓋各群體的特性，導致模型對某些族群表現不佳。維護頻率、硬體配置與網路頻寬只影響系統運行，並非品質差異的根源。","concept":"服務品質損害","aiExplained":true},{"id":"web-j1-230","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在實施AI系統的包容性原則時，最大的技術挑戰是？","options":{"A":"系統維護成本","B":"多樣化特徵的整合","C":"資料儲存容量","D":"運算速度優化"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"包容性要求AI系統能公平服務不同背景的族群，技術上必須將語言、文化、行為等多樣化特徵整合進模型，這正是最大的挑戰。維護成本、儲存容量與運算速度屬於資源問題，並非包容性的核心難點。","concept":"AI包容性","aiExplained":true},{"id":"web-j1-231","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在貸款審批AI系統中，以下哪種情況最可能導致配置損害？","options":{"A":"歷史數據中存在性別薪資差異","B":"系統處理速度過慢","C":"用戶介面不友善","D":"資料儲存容量不足"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"配置損害指AI系統在資源或機會分配上對特定群體不公。若貸款審批模型以含有性別薪資差異的歷史資料訓練，會學到並複製這種偏見，造成核貸機會分配不公。處理速度、介面與儲存容量的問題都不涉及分配公平。","concept":"配置損害","aiExplained":true},{"id":"web-j1-232","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統在安全性評估中，最具挑戰性的環節是？","options":{"A":"效能測試","B":"對抗樣本防禦","C":"資源監控","D":"介面設計"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"對抗樣本是刻意設計的微小擾動輸入，能誘使AI模型做出錯誤判斷且人眼難以察覺，其防禦至今仍是未完全解決的難題，因此是安全性評估中最具挑戰性的環節。效能測試、資源監控與介面設計都有相對成熟的方法。","concept":"對抗樣本防禦","aiExplained":true},{"id":"web-j1-233","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在處理AI系統的錯誤率差異時，最關鍵的技術環節是？","options":{"A":"系統維護","B":"資源配置","C":"誤差傳播控制","D":"介面優化"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"處理不同群體間的錯誤率差異時，關鍵在於控制誤差在系統中的傳播，避免上游的偏誤被逐層放大，使特定群體的錯誤率持續惡化。系統維護、資源配置與介面優化都與錯誤率差異沒有直接關聯。","concept":"誤差傳播控制","aiExplained":true},{"id":"web-j1-234","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在評估平均絕對誤差差異時，以下哪種情況最能反映AI系統的實質問題？","options":{"A":"不同時段的系統反應速度","B":"使用者介面的操作難度","C":"預測值與實際值的偏離程度","D":"系統資源的使用效率"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"平均絕對誤差（MAE）衡量的正是預測值與實際值的平均偏離程度，因此評估MAE差異時，實質反映的是模型預測準確性的問題。反應速度、操作難度與資源使用效率屬於系統面向，與MAE指標無關。","concept":"平均絕對誤差","aiExplained":true},{"id":"web-j1-235","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在處理AI系統的精確率差異時，最關鍵的技術問題是？","options":{"A":"運算效率","B":"存儲容量","C":"特徵分布差異","D":"系統維護"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"精確率在不同群體間出現差異，根本原因多在於各群體的特徵分布不同，模型在訓練資料較少或分布偏移的群體上表現較差。運算效率、存儲容量與系統維護皆非造成精確率差異的因素。","concept":"精確率差異","aiExplained":true},{"id":"web-j1-236","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"AI系統的公平性評估中，最難處理的技術問題是？","options":{"A":"多重保護屬性的交互作用","B":"系統效能優化","C":"資料收集效率","D":"硬體資源分配"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"公平性評估的難點在於性別、年齡、種族等多重保護屬性往往同時存在且彼此交互作用，對單一屬性看似公平的模型，在屬性組合而成的子群體上仍可能存在偏誤。效能優化、收集效率與硬體分配皆非公平性的核心問題。","concept":"交叉公平性","aiExplained":true},{"id":"web-j1-237","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統的群組公平性評估中，最難處理的挑戰是？","options":{"A":"數據收集","B":"模型訓練","C":"系統部署","D":"偏見的隱含傳遞"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"群組公平性最難處理的是偏見的隱含傳遞：即使移除敏感屬性，偏見仍可能透過相關聯的代理變數（如居住地區、消費紀錄）隱性地進入模型。數據收集、模型訓練與系統部署是一般開發流程，並非此處的核心挑戰。","concept":"隱含偏見傳遞","aiExplained":true},{"id":"web-j1-238","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統在隱私保護方面，最關鍵的技術挑戰是？","options":{"A":"系統效能","B":"去識別化與效用平衡","C":"資源使用","D":"介面設計"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"隱私保護的核心兩難在於：去識別化程度越高，資料的分析效用往往越低。如何在保護個人隱私與保留資料價值之間取得平衡，正是最關鍵的技術挑戰。系統效能、資源使用與介面設計皆非隱私議題的重點。","concept":"去識別化與效用","aiExplained":true},{"id":"web-j1-239","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統在服務提供時應注意？","options":{"A":"降低成本","B":"避免群體歧視","C":"提高效率","D":"擴大規模"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"AI系統提供服務時，倫理上最需注意的是避免對特定群體造成歧視，確保不同族群獲得同等品質的服務。降低成本、提高效率與擴大規模屬於商業目標，不是負責任AI在服務提供上的首要考量。","concept":"避免群體歧視","aiExplained":true},{"id":"web-j1-240","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在確保AI系統可靠性時，最需要注意的問題是？","options":{"A":"運行速度","B":"介面設計","C":"極端情況的處理能力","D":"資源使用效率"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"可靠性關注系統在各種情境下都能穩定正確地運作，其中最需注意的是極端或罕見情況的處理能力，因為系統在常態下正常，不代表在邊界條件下也安全可靠。運行速度、介面設計與資源效率並非可靠性的核心。","concept":"AI系統可靠性","aiExplained":true},{"id":"web-j1-241","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的透明度原則，正確的是？","options":{"A":"完全開源","B":"決策可解釋","C":"技術公開","D":"數據共享"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"透明度原則的核心是決策可解釋，也就是能向利害關係人說明AI為何做出某項決策。完全開源、技術公開或數據共享並非透明度的必要條件，且可能牽涉智慧財產與隱私的問題。","concept":"透明度原則","aiExplained":true},{"id":"web-j1-242","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統在風險控制中，最容易被忽視的因素是？","options":{"A":"硬體故障","B":"長期演化效應","C":"系統負載","D":"資源消耗"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"風險控制通常聚焦於當下可見的硬體故障與系統負載，但AI系統會隨資料與環境變化而逐漸演化，長期累積的偏移效應最容易被忽視，需要持續監控。硬體故障、負載與資源消耗都是顯而易見的常規監控項目。","concept":"長期演化風險","aiExplained":true},{"id":"web-j1-243","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"負責任AI在開發過程中應優先考慮？","options":{"A":"技術創新","B":"經濟效益","C":"人類福祉","D":"市場競爭"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"負責任AI的核心精神是以人為本，開發過程應將人類福祉置於首位，確保技術服務於人而非造成傷害。技術創新、經濟效益與市場競爭都應在不損害人類福祉的前提下追求。","concept":"負責任AI","aiExplained":true},{"id":"web-j1-244","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統造成的損害類型主要包括？","options":{"A":"配置損害和服務品質損害","B":"硬體損害和軟體損害","C":"直接損害和間接損害","D":"實質損害和精神損害"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"在負責任AI的損害分類中，主要類型為配置損害（資源與機會分配不公）與服務品質損害（對特定群體服務效果較差）。其餘選項的分類方式並非AI倫理領域慣用的損害類型架構。","concept":"AI損害類型","aiExplained":true},{"id":"web-j1-245","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列哪項不是評估AI系統效能的關鍵指標？","options":{"A":"開發預算","B":"預測準確度","C":"服務公平性","D":"系統穩定性"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"評估AI系統效能著眼於系統本身的表現，如預測準確度、服務公平性與系統穩定性。開發預算屬於專案管理的成本面向，並非衡量系統效能的指標。","concept":"AI效能指標","aiExplained":true},{"id":"web-j1-246","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在確保AI系統包容性時，最難解決的技術問題是？","options":{"A":"效能優化","B":"資源配置","C":"系統維護","D":"特徵表達多樣性"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"包容性要求模型能理解並公平對待不同族群，技術上最難的是讓特徵表達具備足夠的多樣性，充分涵蓋各群體的語言、文化與行為差異。效能優化、資源配置與系統維護屬於一般工程議題，並非包容性的核心難點。","concept":"特徵表達多樣性","aiExplained":true},{"id":"web-j1-247","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在製造業中，AI檢測系統的選取率差異可能導致？","options":{"A":"成本增加","B":"效率提高","C":"品質控制不均","D":"產能提升"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e/","explanation":"選取率差異指檢測系統對不同批次或類型產品的判定比例不一致，這會使某些產品受到較嚴或較鬆的檢驗，導致品質控制不均。此差異本身不會提高效率或產能，成本增加也不是最直接的後果。","concept":"選取率差異","aiExplained":true},{"id":"web-j1-248","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"要評估AI系統的包容性，最適當的方法是：","options":{"A":"統計使用者數量","B":"分析系統效能","C":"進行多維度的使用者體驗研究","D":"檢測技術參數"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"包容性關注不同背景、能力與需求的使用者是否都能有效使用系統，因此必須透過多維度的使用者體驗研究，涵蓋不同族群的實際使用情境。單看使用者數量、系統效能或技術參數，都無法反映弱勢或特殊需求族群的真實體驗。","concept":"AI包容性評估","aiExplained":true},{"id":"web-j1-249","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於模型可解釋性，何者正確？","options":{"A":"只需向開發者解釋","B":"技術細節可以保密","C":"提供人類可理解的描述","D":"僅說明主要功能"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"可解釋性的核心是讓人類能理解模型的決策依據，因此應提供人類可理解的描述，而非僅限技術人員或只交代主要功能。若只向開發者解釋或將細節保密，利害關係人便無從判斷系統是否可信。","concept":"模型可解釋性","aiExplained":true},{"id":"web-j1-250","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在確保AI系統隱私保護時，最關鍵的考量是：","options":{"A":"資料加密的強度","B":"資料最小化與用途限制的平衡","C":"存取控制的嚴格度","D":"備份機制的完整性"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"隱私保護的關鍵在於資料最小化與用途限制之間取得平衡：只蒐集必要資料，且僅用於聲明的目的。加密強度、存取控制與備份屬於資安技術手段，若源頭蒐集過多或濫用資料，再強的加密也無法彌補隱私風險。","concept":"資料最小化原則","aiExplained":true},{"id":"web-j1-251","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的包容性技術，何者正確？","options":{"A":"只需基本功能","B":"效率為唯一考量","C":"忽略特殊需求","D":"應提供多元輔助功能"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"包容性技術強調系統應照顧不同能力與需求的使用者，因此需提供多元輔助功能，例如語音輸入、字幕或無障礙介面。只做基本功能、僅追求效率或忽略特殊需求，都違背包容性設計的精神。","concept":"包容性設計","aiExplained":true},{"id":"web-j1-252","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的錯誤分析，最關鍵的是：","options":{"A":"錯誤的檢測速度","B":"錯誤的修復時間","C":"錯誤的影響範圍評估","D":"錯誤的記錄完整性"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"錯誤分析最關鍵的是評估錯誤的影響範圍，因為同樣的錯誤率在不同族群或情境下造成的傷害差異極大。掌握影響範圍才能排定修復的優先順序；檢測速度、修復時間與記錄完整性都只是輔助面向。","concept":"錯誤影響評估","aiExplained":true},{"id":"web-j1-253","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"關於AI系統的錯誤分析，何者最能提升系統可靠性？","options":{"A":"建立錯誤模式與系統架構的關聯性分析","B":"統計錯誤發生頻率","C":"記錄錯誤類型","D":"分析個別錯誤案例"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"將錯誤模式與系統架構建立關聯性分析，才能找出錯誤的根本原因並從設計層面改善，真正提升可靠性。單純統計頻率、記錄類型或逐案分析，只停留在現象層面，難以系統性地消除錯誤來源。","concept":"錯誤根因分析","aiExplained":true},{"id":"web-j1-254","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統的透明度原則要求：","options":{"A":"隱藏系統細節","B":"清楚說明系統限制","C":"只告知成功案例","D":"選擇性提供資訊"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"透明度原則要求誠實揭露系統的能力與限制，讓使用者能正確評估何時可以信賴、何時需要謹慎。隱藏細節、只報成功案例或選擇性提供資訊，都會誤導利害關係人，違反透明度精神。","concept":"透明度原則","aiExplained":true},{"id":"web-j1-255","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的可靠性分析，最重要的是：","options":{"A":"分析的頻率","B":"分析的範圍","C":"分析的方法","D":"分析結果的實際應用價值"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"可靠性分析的價值最終體現在分析結果能否實際應用於改善系統；若分析報告束之高閣，再頻繁、再全面的分析也無濟於事。頻率、範圍與方法都是手段，實際應用價值才是目的。","concept":"可靠性分析應用","aiExplained":true},{"id":"web-j1-256","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統的透明度對利害關係人的重要性在於：","options":{"A":"提高運算效率","B":"建立對系統的信任","C":"降低維護成本","D":"簡化操作流程"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"透明度讓利害關係人了解系統如何運作、有哪些限制，進而建立對系統的信任，這是願意採用AI的基礎。透明度本身並不會提高運算效率、降低維護成本或簡化操作，它解決的是信任問題。","concept":"透明度與信任","aiExplained":true},{"id":"web-j1-257","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"評估AI系統透明度的最佳方法是：","options":{"A":"檢查技術文檔","B":"測試系統效能","C":"分析用戶反饋","D":"評估決策鏈的可追蹤性"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"透明度的核心在於決策過程能否被追蹤與還原，因此評估決策鏈的可追蹤性最能直接檢驗透明度。技術文檔、效能測試與用戶反饋只能間接反映，無法證明每個決策都有跡可循。","concept":"決策可追蹤性","aiExplained":true},{"id":"web-j1-258","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"提升AI模型可解釋性的最有效方法是：","options":{"A":"增加解釋的數量","B":"提供技術細節","C":"優化視覺化效果","D":"建立多層次的解釋框架"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"不同利害關係人需要不同深度的解釋：一般使用者需要白話說明，稽核人員需要技術細節，因此建立多層次的解釋框架最為有效。單純增加解釋數量、堆疊技術細節或美化視覺效果，都無法對症下藥。","concept":"多層次解釋框架","aiExplained":true},{"id":"web-j1-259","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI模型的反事實分析，最重要的是：","options":{"A":"假設情境的合理性","B":"分析的數量","C":"計算效率","D":"視覺呈現"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"反事實分析是探討「若輸入改變，結果會如何不同」，其價值完全建立在假設情境的合理性上；不合理的假設得出的結論沒有參考價值。分析數量、計算效率與視覺呈現都是次要考量。","concept":"反事實分析","aiExplained":true},{"id":"web-j1-260","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在評估AI系統的可靠性時，以下哪個指標最能反映系統的實際表現？","options":{"A":"所有測試數據的平均準確率","B":"最佳測試場景的準確率","C":"最弱勢數據子集的表現水平","D":"系統處理速度的穩定性"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"可靠的系統應在所有資料子集上都有穩定表現，因此最弱勢數據子集的表現最能揭露系統的實際短板。平均準確率會被多數群體拉高而掩蓋弱勢族群的低表現，最佳場景的準確率更是報喜不報憂。","concept":"弱勢子集表現","aiExplained":true},{"id":"web-j1-261","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"關於機器學習模型的錯誤影響，何者正確？","options":{"A":"錯誤率高低與可靠性無關","B":"單一類型的錯誤不會影響整體信任度","C":"錯誤可能導致完全失去對機器學習的信任","D":"錯誤只影響系統效能"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"機器學習的錯誤若發生在關鍵決策上，可能讓使用者對整個系統甚至整項技術完全失去信任，這正是錯誤管理的嚴重性所在。錯誤率與可靠性高度相關，且錯誤的影響絕不僅止於系統效能層面。","concept":"錯誤與信任","aiExplained":true},{"id":"web-j1-262","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"提升AI透明度的最有效方法是：","options":{"A":"公開技術細節","B":"建立分級解釋機制","C":"優化用戶界面","D":"提供技術支持"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"分級解釋機制能針對不同對象（一般用戶、管理者、稽核者）提供適當深度的說明，讓每個利害關係人都能獲得可理解的資訊，是提升透明度最有效的做法。單純公開技術細節，多數人反而看不懂。","concept":"分級解釋機制","aiExplained":true},{"id":"web-j1-263","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"機器學習模型的透明度包括：","options":{"A":"隱藏技術細節","B":"提供決策過程的說明","C":"只告知最終結果","D":"僅向專業人員說明"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"透明度要求模型能對外提供決策過程的說明，讓使用者理解結果是如何產生的。隱藏技術細節、只告知最終結果或僅向專業人員說明，都限縮了利害關係人的知情權，不符合透明度要求。","concept":"決策過程透明","aiExplained":true},{"id":"web-j1-264","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的利害關係人包括：","options":{"A":"只有開發人員","B":"僅限於直接使用者","C":"開發人員、使用者、管理者等多方人員","D":"只要考慮資金投資者"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"AI系統的利害關係人涵蓋開發人員、使用者、管理者，乃至受決策影響的第三方等多方人員。若只考慮開發者、直接使用者或投資者，會忽略系統對其他群體的影響，形成治理上的盲點。","concept":"利害關係人","aiExplained":true},{"id":"web-j1-265","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的隱私保護措施，何者正確？","options":{"A":"選擇性保護資料","B":"效能優先於保密","C":"需要完整的安全設定","D":"只保護核心數據"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"隱私保護必須建立完整的安全設定，涵蓋所有資料與各個存取環節，不能只挑部分資料或核心數據保護。若讓效能優先於保密或採取選擇性保護，任何一個缺口都可能造成整體隱私外洩。","concept":"隱私安全設定","aiExplained":true},{"id":"web-j1-266","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於模型的局部說明，何者正確？","options":{"A":"只分析整體表現","B":"不需要詳細說明","C":"針對特定預測提供分析","D":"僅評估系統效能"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"局部說明針對單一特定預測，分析哪些特徵促成了該次結果，例如以LIME或SHAP解釋個別案例。它與分析整體表現的全域說明相對，因此「針對特定預測提供分析」是正確描述。","concept":"局部可解釋性","aiExplained":true},{"id":"web-j1-267","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於隱私權法律要求，下列何者正確？","options":{"A":"只需要保護部分用戶資料","B":"資料使用不需經過用戶同意","C":"系統效能比隱私更重要","D":"使用者應具有選擇資料使用方式的控制權"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-2/","explanation":"隱私權法規強調當事人對個資的自主控制，使用者應能選擇、同意並掌控資料的使用方式。資料使用必須經過用戶同意，所有用戶資料都應受保護，隱私也不應讓位給系統效能。","concept":"個資自主控制","aiExplained":true},{"id":"web-j1-268","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的數據治理，最關鍵的是：","options":{"A":"處理速度","B":"存儲效率","C":"成本控制","D":"數據質量管理"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"數據治理的核心是數據質量管理，因為模型的表現與決策的可信度都建立在高品質資料之上，即所謂「垃圾進、垃圾出」。處理速度、存儲效率與成本控制屬於營運考量，並非治理的關鍵。","concept":"數據質量管理","aiExplained":true},{"id":"web-j1-269","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"原因推斷的主要作用是：","options":{"A":"預測未來趨勢","B":"優化模型參數","C":"分析特徵對結果的影響","D":"自動調整模型"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"原因推斷旨在分析特徵對結果的因果影響，回答「改變某特徵是否會改變結果」，而不只是觀察相關性。它不是用來預測未來趨勢、優化參數或自動調整模型的工具。","concept":"因果推斷","aiExplained":true},{"id":"web-j1-270","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"負責任AI系統的核心價值在於：","options":{"A":"追求最高效能","B":"維護人類主導地位","C":"最小化成本","D":"最大化自動化"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"負責任AI強調AI應輔助而非取代人類，維護人類在關鍵決策中的主導地位是其核心價值。若一味追求效能、成本最小化或自動化極大化，反而可能犧牲人類監督與問責，背離負責任AI的初衷。","concept":"人類主導原則","aiExplained":true},{"id":"web-j1-271","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在進行AI系統的反事實分析時，最關鍵的是：","options":{"A":"分析速度的優化","B":"資源使用的效率","C":"自動化程度的提升","D":"假設情境的合理性"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"反事實分析建立在「若某條件改變」的假設之上，假設情境必須合理且貼近現實，分析結論才有意義。分析速度、資源效率與自動化程度，都無法彌補不合理假設所造成的誤導。","concept":"反事實假設合理性","aiExplained":true},{"id":"web-j1-272","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的治理數據捕獲，最關鍵的要素是：","options":{"A":"建立完整的決策鏈追蹤機制","B":"最大化數據收集範圍","C":"提高數據處理速度","D":"降低存儲成本"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"治理數據捕獲的關鍵是建立完整的決策鏈追蹤機制，記錄每個決策由誰、依據什麼、在何時做出，才能支撐稽核與問責。盲目擴大蒐集範圍、追求處理速度或壓低存儲成本，都偏離治理的目的。","concept":"決策鏈追蹤","aiExplained":true},{"id":"web-j1-273","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的風險控制，最關鍵的是：","options":{"A":"控制速度","B":"資源效率","C":"預防機制","D":"成本管理"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"風險控制最關鍵的是預防機制，在風險發生前就加以辨識與防範，成本遠低於事後補救，也能避免不可回復的傷害。控制速度、資源效率與成本管理都只是操作層面的考量。","concept":"風險預防機制","aiExplained":true},{"id":"web-j1-274","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"機器學習中的權責管理主要目的是：","options":{"A":"提高運算效率","B":"確保系統透明可追溯","C":"降低運營成本","D":"加快開發速度"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"權責管理的目的在確保系統透明可追溯，一旦出問題能釐清責任歸屬、還原決策過程。它不是為了提升運算效率、降低成本或加快開發速度，而是治理與問責的基礎。","concept":"權責管理","aiExplained":true},{"id":"web-j1-275","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"模型監控的主要目的是：","options":{"A":"提高運算效率","B":"降低資源消耗","C":"確保系統穩定運行","D":"自動優化參數"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"模型監控的主要目的是確保系統穩定運行，持續追蹤模型在生產環境的表現，及早發現資料漂移或效能衰退。它本身並不負責提升運算效率、降低資源消耗或自動優化參數。","concept":"模型監控","aiExplained":true},{"id":"web-j1-276","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"負責任AI儀表板的核心功能包含：","options":{"A":"自動模型訓練","B":"模型效能與公平性評量","C":"數據自動清理","D":"硬體資源優化"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"負責任AI儀表板的核心功能是整合模型效能與公平性評量，協助團隊檢視錯誤分布、群體間差異與模型可解釋性。自動模型訓練、數據清理與硬體資源優化都不是它的定位。","concept":"負責任AI儀表板","aiExplained":true},{"id":"web-j1-277","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在評估AI系統的社會責任時，最需要考慮：","options":{"A":"技術創新性","B":"社會公平性","C":"效能優越性","D":"成本效益性"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"評估AI系統的社會責任時，最需要考慮社會公平性，也就是系統是否對不同群體造成差別待遇或加深既有的不平等。技術創新性、效能與成本效益屬於商業與工程考量，並不等於社會責任。","concept":"社會公平性","aiExplained":true},{"id":"web-j1-278","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪種情況最可能危及AI系統的責任性：","options":{"A":"決策過程中的人為干預被最小化","B":"系統響應時間略有延遲","C":"數據處理效率不夠理想","D":"模型準確率未達最優"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"責任性要求人類對AI決策保有監督與介入的能力，若決策過程中的人為干預被最小化，出錯時將無人能及時把關，也難以究責。回應延遲、處理效率不足或準確率未達最優，屬於效能問題而非責任性危機。","concept":"人為監督與問責","aiExplained":true},{"id":"web-j1-279","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"錯誤群體識別的方法不包括：","options":{"A":"決策樹","B":"錯誤熱圖","C":"整體預測","D":"數據清理"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"錯誤群體識別旨在找出模型在哪些資料子集上表現特別差，常用方法包括決策樹切分、錯誤熱圖與整體預測分布的比對。數據清理屬於資料前處理步驟，並不是識別錯誤群體的方法。","concept":"錯誤群體識別","aiExplained":true},{"id":"web-j1-280","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列哪項不是反事實分析的主要功能？","options":{"A":"自動修正預測結果","B":"觀察特徵變化影響","C":"提供不同預測結果","D":"分析模型敏感度"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"反事實分析的功能在於觀察特徵改變對預測的影響、提供不同情境下的預測結果，以及分析模型敏感度，屬於診斷性質的工具。它不會自動修正預測結果，修正仍需人為介入或重新訓練模型。","concept":"反事實分析功能","aiExplained":true},{"id":"web-j1-281","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在設計AI決策支援系統時，最需要注意：","options":{"A":"運算效率","B":"資源使用","C":"決策透明度","D":"響應速度"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"AI決策支援系統的建議會影響人類的重大決策，因此決策透明度最為關鍵，使用者必須能理解建議的依據，才能判斷是否採納。運算效率、資源使用與響應速度是工程指標，無法取代透明度。","concept":"決策透明度","aiExplained":true},{"id":"web-j1-282","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在評估AI系統的社會影響時，最需要關注：","options":{"A":"技術創新程度","B":"長期社會效應","C":"市場接受度","D":"運營效率"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"評估AI的社會影響時，最需關注長期社會效應，例如就業結構改變、偏見固化或資訊環境的長遠變化。技術創新程度、市場接受度與運營效率都偏向短期商業指標，無法反映深遠的社會後果。","concept":"長期社會效應","aiExplained":true},{"id":"web-j1-283","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪種情況最不利於維護AI系統的負責任性：","options":{"A":"過度依賴自動化決策","B":"系統響應較慢","C":"資源消耗較高","D":"維護成本增加"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"過度依賴自動化決策會削弱人類的監督與介入能力，一旦系統出錯便缺乏把關機制，最不利於維護負責任性。回應較慢、資源消耗較高或維護成本增加，只是效能與成本問題，不直接衝擊問責。","concept":"自動化依賴風險","aiExplained":true},{"id":"web-j1-284","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在設計AI決策支持系統時，最需要避免：","options":{"A":"系統響應延遲","B":"資源使用過多","C":"替代人類判斷","D":"操作流程複雜"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"設計AI決策支持系統時，最需避免讓系統替代人類判斷；AI應提供資訊與建議，最終決策權必須保留在人類手中。回應延遲、資源用量與流程複雜屬於可優化的工程問題，遠不如喪失人類判斷嚴重。","concept":"人類最終決策權","aiExplained":true},{"id":"web-j1-285","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於錯誤分析，不正確的是：","options":{"A":"識別錯誤分布","B":"分析錯誤原因","C":"提供改善建議","D":"自動修正錯誤"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"錯誤分析的功能包括識別錯誤在資料中的分布、分析錯誤原因並據以提出改善建議，本質上是診斷工具。它不會自動修正錯誤，修正必須由團隊評估後透過調整資料或模型來完成。","concept":"錯誤分析範疇","aiExplained":true},{"id":"web-j1-286","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"事件通知和提醒系統的主要目的是：","options":{"A":"減少系統負載","B":"優化資源配置","C":"確保及時反應和處理","D":"提高運算效率"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"事件通知和提醒系統的目的，是在系統發生異常或指標超出門檻時即時通知相關人員，確保及時反應和處理，把損害控制在最小範圍。它並非用來減少負載、優化資源配置或提高運算效率。","concept":"事件通知機制","aiExplained":true},{"id":"web-j1-287","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在機器學習操作中，以下哪種情況最可能導致權責問題？","options":{"A":"模型訓練時間過長","B":"系統資源使用率過高","C":"數據處理效率不足","D":"決策過程缺乏可解釋性"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab_1-2%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e-3/","explanation":"機器學習操作中，若決策過程缺乏可解釋性，出錯時便無法還原決策依據、釐清責任歸屬，最容易引發權責問題。訓練時間、資源使用率與處理效率只是效能議題，與問責沒有直接關聯。","concept":"可解釋性與問責","aiExplained":true},{"id":"web-j1-288","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在進行因果推斷時,最關鍵的前提條件是:","options":{"A":"確保處理組和對照組的隨機分配","B":"收集足夠大的樣本量","C":"使用先進的統計工具","D":"建立完整的數據庫"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"因果推斷要成立，最關鍵的前提是處理組與對照組經過隨機分配，如此兩組在其他條件上才具可比性，結果差異方能歸因於處理本身。樣本量、統計工具與資料庫只是輔助條件，無法消除選擇偏誤。","concept":"因果推斷隨機分配","aiExplained":true},{"id":"web-j1-289","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"對於多目標優化問題,最適合的特徵選擇策略是:","options":{"A":"單一指標選擇","B":"順序篩選","C":"帕累托最優化","D":"隨機搜索"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"多目標優化中各目標往往互相衝突，帕累托最優化能找出「無法在不犧牲某一目標下改善另一目標」的解集合，最適合系統性地權衡多個指標。單一指標選擇或隨機搜索都無法妥善處理目標間的取捨。","concept":"帕累托最優化","aiExplained":true},{"id":"web-j1-290","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列何者不是分佈分析的目的?","options":{"A":"了解數據特性","B":"檢測異常值","C":"評估離散程度","D":"優化系統架構"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"分佈分析的目的在於了解數據特性、檢測異常值與評估離散程度，屬於資料層面的探索工作。優化系統架構是系統工程議題，與資料分佈分析無關。","concept":"分佈分析目的","aiExplained":true},{"id":"web-j1-291","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"InterpretML工具包的主要功能是什麼?","options":{"A":"加速數據處理","B":"優化系統架構","C":"解釋機器學習模型","D":"提升網絡安全"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"InterpretML 是微軟開源的可解釋機器學習工具包，提供玻璃盒模型與事後解釋等方法，協助使用者理解模型的預測依據。它並非用於加速資料處理、優化架構或網路安全。","concept":"可解釋AI工具","aiExplained":true},{"id":"web-j1-292","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在高維特徵空間中,最有效的數據可視化方法是:","options":{"A":"散點圖矩陣","B":"t-SNE降維","C":"主成分投影","D":"平行座標圖"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"t-SNE 是專為高維資料視覺化設計的非線性降維方法，能將高維空間中的鄰近關係保留到二維或三維圖上呈現。散點圖矩陣與平行座標圖在維度很高時會過於擁擠而難以判讀。","concept":"t-SNE降維視覺化","aiExplained":true},{"id":"web-j1-293","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"公平性評量的核心目標是:","options":{"A":"確保模型無差別對待","B":"提升處理速度","C":"降低運營成本","D":"優化系統架構"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"公平性評量關注模型是否對不同族群產生系統性的差別待遇，核心目標就是確保模型無差別對待。處理速度、成本與系統架構屬於效能與工程面向，並非公平性議題。","concept":"AI公平性","aiExplained":true},{"id":"web-j1-294","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"下列何者是正確的數據分佈統計特徵?","options":{"A":"集中趨勢","B":"系統效能","C":"處理速度","D":"存儲容量"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"集中趨勢（如平均數、中位數、眾數）是描述資料分佈的基本統計特徵，其他還包括離散程度與偏態等。系統效能、處理速度與存儲容量都是系統指標，並非分佈統計量。","concept":"分佈統計特徵","aiExplained":true},{"id":"web-j1-295","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪種情況不適合使用微擾分析?","options":{"A":"配方優化","B":"參數調整","C":"穩定性測試","D":"分類預測"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"微擾分析是對輸入施加小幅變動以觀察輸出的反應，適合配方優化、參數調整與穩定性測試等需要觀察連續變動影響的情境。分類預測是模型任務本身，並非微擾分析的應用場景。","concept":"微擾分析應用","aiExplained":true},{"id":"web-j1-296","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列何者是特徵選擇的正確目的?","options":{"A":"提升預測準確性","B":"加快處理速度","C":"降低系統成本","D":"優化介面設計"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"特徵選擇透過保留有資訊量的特徵、剔除冗餘與雜訊，主要目的在於提升模型的預測準確性並降低過擬合風險。加快處理速度只是附帶效益，系統成本與介面設計則與其無關。","concept":"特徵選擇目的","aiExplained":true},{"id":"web-j1-297","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪種情況不適合使用因果推斷?","options":{"A":"政策評估","B":"醫療干預","C":"教育效果","D":"隨機現象"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"因果推斷用於評估介入措施與結果之間的因果關係，政策評估、醫療干預與教育效果都是典型應用。純粹的隨機現象沒有可辨識的因果機制，自然不適合進行因果推斷。","concept":"因果推斷適用場景","aiExplained":true},{"id":"web-j1-298","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"下列何者不是了解分佈和特徵對開發者的重要性?","options":{"A":"能夠識別數據中的異常值和偏差","B":"能夠直接提升系統運算速度","C":"有助於進行特徵工程和數據清理","D":"可以針對特徵調整模型參數"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"了解資料分佈與特徵，開發者才能識別異常值與偏差、進行特徵工程與資料清理，並據以調整模型參數。系統運算速度取決於硬體與演算法實作，不會因了解分佈而直接提升。","concept":"資料分佈重要性","aiExplained":true},{"id":"web-j1-299","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"評估動態系統穩定性最有效的方法是:","options":{"A":"靜態測試","B":"擾動響應分析","C":"單點檢查","D":"平均性能測量"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"動態系統的穩定性必須觀察系統受到擾動後能否回復或維持正常運作，因此擾動響應分析最能有效評估。靜態測試、單點檢查與平均性能測量都無法反映系統的動態行為。","concept":"系統穩定性評估","aiExplained":true},{"id":"web-j1-300","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在評估特徵重要性時,最關鍵的考量是:","options":{"A":"計算效率","B":"特徵獨立性","C":"實施成本","D":"存儲需求"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"特徵之間若高度相關，重要性分數會互相分攤而失真，因此評估特徵重要性時最關鍵的是留意特徵獨立性。計算效率、實施成本與存儲需求屬於工程考量，不影響重要性判讀的正確性。","concept":"特徵重要性評估","aiExplained":true},{"id":"web-j1-301","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"微擾技術的主要目的是什麼?","options":{"A":"提升系統效能","B":"降低運營成本","C":"優化用戶界面","D":"觀察小幅度變動的影響"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"微擾技術是在輸入或參數上施加小幅度變動，觀察其對輸出結果的影響，常用於敏感度分析與模型行為的解釋。提升效能、降低成本或優化界面都不是它的目的。","concept":"微擾技術","aiExplained":true},{"id":"web-j1-302","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"反事實分析的主要功能是什麼?","options":{"A":"預測未來趨勢","B":"加速數據處理","C":"探索改變結果的特徵","D":"優化系統架構"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"反事實分析回答「若輸入特徵改變，結果是否會不同」的問題，用來探索哪些特徵改變後能夠翻轉模型的結果，是可解釋AI的重要方法。它並非用於預測趨勢或加速處理。","concept":"反事實分析","aiExplained":true},{"id":"web-j1-303","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"微擾分析的核心目標是:","options":{"A":"觀察細微變化影響","B":"提升系統效能","C":"降低運營成本","D":"優化工作流程"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"微擾分析的核心是在輸入上施加細微變化，觀察輸出的相應變動，藉此了解系統的敏感度與穩定性。提升效能、降低成本與優化流程都不是它的目標。","concept":"微擾分析目標","aiExplained":true},{"id":"web-j1-304","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"在處理多模態數據時,最具挑戰性的問題是:","options":{"A":"數據清理","B":"特徵對齊","C":"模型選擇","D":"效能優化"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"多模態數據來自文字、影像、聲音等不同來源，各模態的表示方式與語意粒度差異很大，如何將不同模態的特徵對齊到共同的表示空間是最具挑戰性的問題。資料清理與模型選擇在單一模態下同樣存在，並非多模態特有的核心難題。","concept":"多模態特徵對齊","aiExplained":true},{"id":"web-j1-305","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在進行微擾分析時,最重要的步驟是:","options":{"A":"擾動範圍確定","B":"數據收集","C":"結果驗證","D":"報告生成"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"微擾分析中擾動範圍的確定最為關鍵：範圍過大會破壞局部性、使分析失去意義，過小則觀察不到有效變化。資料收集、結果驗證與報告生成屬於一般分析流程的通用步驟。","concept":"微擾範圍設定","aiExplained":true},{"id":"web-j1-306","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在評估培訓效果時,最關鍵的步驟是:","options":{"A":"控制成本","B":"安排時間","C":"設定對照組","D":"選擇場地"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"評估培訓效果本質上是因果效應的推估，必須設定對照組才能排除其他因素的干擾，確認成效確實來自培訓本身。成本、時間與場地都只是行政層面的安排。","concept":"對照組設計","aiExplained":true},{"id":"web-j1-307","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在處理時間序列數據時,最適合的分佈分析方法是:","options":{"A":"簡單直方圖","B":"標準差分析","C":"自相關函數","D":"百分位數統計"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-4/","explanation":"時間序列資料的觀測值之間存在時間相依性，自相關函數能刻畫不同時間差下的相關結構，是最適合的分佈分析方法。直方圖、標準差與百分位數統計都忽略了時間順序所攜帶的資訊。","concept":"時間序列自相關","aiExplained":true},{"id":"web-j1-308","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"企業運用AI進行品質控制時，適合採用：","options":{"A":"社交媒體分析","B":"情感辨識","C":"機器視覺技術","D":"自然語言處理"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"品質控制主要在檢測產品的外觀瑕疵、尺寸偏差等視覺特徵，機器視覺技術能自動辨識影像中的缺陷，最適合此類應用。社交媒體分析、情感辨識與自然語言處理針對的是文字或情緒資料。","concept":"機器視覺品檢","aiExplained":true},{"id":"web-j1-309","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統的數據安全策略最應該重視：","options":{"A":"存儲容量","B":"處理速度","C":"多維度防護體系","D":"使用便利性"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"資料安全面臨外洩、竄改、未授權存取等多種威脅，單一措施難以涵蓋，因此最應重視建立涵蓋存取控制、加密、備份與監控的多維度防護體系。存儲容量與處理速度屬於效能議題。","concept":"資料安全防護","aiExplained":true},{"id":"web-j1-310","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的安全管理，何者正確？","options":{"A":"無需特別管理","B":"需建立完整的安全管理機制","C":"出問題才管理","D":"隨機管理"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"AI系統涉及資料、模型與應用等多層面風險，必須建立涵蓋事前預防、事中監控與事後應變的完整安全管理機制。等出問題才處理或隨機管理都是被動且高風險的做法。","concept":"AI安全管理","aiExplained":true},{"id":"web-j1-311","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的合規評估，何者正確？","options":{"A":"只需在導入時評估","B":"需定期進行評估","C":"只需在出問題時評估","D":"無需進行評估"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"法規要求與AI系統本身都會隨時間演變，合規評估必須定期執行，才能持續確認系統符合最新規範。只在導入時或出問題時才評估，會讓合規缺口長期存在。","concept":"AI合規評估","aiExplained":true},{"id":"web-j1-312","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在AI系統的風險分級中，若某系統同時具備多個風險等級的特徵，應：","options":{"A":"採用最低風險等級的管理要求","B":"採用最高風險等級的管理要求","C":"取其平均風險等級","D":"另創建新的風險等級"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"風險分級採取「就高原則」：當系統同時具備多個風險等級的特徵時，應以最高風險等級的管理要求辦理，確保風險控管不會出現缺口。取平均或另創等級都會弱化對高風險面向的管控。","concept":"風險分級就高原則","aiExplained":true},{"id":"web-j1-313","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的數據管理，下列何者不正確？","options":{"A":"可任意刪除數據","B":"需備份重要數據","C":"需保護數據安全","D":"需維護數據品質"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"資料管理必須確保資料的安全、品質與可用性，重要資料應備份留存；任意刪除資料會破壞資料完整性，也可能違反法規的保存義務，因此是不正確的做法。","concept":"AI資料管理","aiExplained":true},{"id":"web-j1-314","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統在自動化決策中產生爭議時，最適當的處理方式是：","options":{"A":"完全接受系統決策","B":"完全否定系統決策","C":"暫停所有相關決策","D":"建立人機協作的審核機制"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"自動化決策發生爭議時，最適當的做法是建立人機協作的審核機制，由人類介入複核關鍵決策。完全接受或完全否定系統決策都過於極端，暫停所有相關決策則會嚴重影響營運。","concept":"人機協作審核","aiExplained":true},{"id":"web-j1-315","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的數據管理，何者錯誤？","options":{"A":"可以忽略數據隱私保護","B":"需要確保數據質量","C":"需要進行數據清洗","D":"需要數據整合分析"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"AI系統的資料管理須兼顧資料品質、清洗與整合分析，而資料隱私保護更是法規與倫理的基本要求，絕不可忽略，因此選項A是錯誤的敘述。","concept":"資料隱私保護","aiExplained":true},{"id":"web-j1-316","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"企業導入AI技術的最佳時機是：","options":{"A":"現有流程已優化但仍有明確改進空間","B":"競爭對手開始使用AI","C":"技術成本降低時","D":"員工要求改革時"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"導入AI的最佳時機是現有流程已經優化、問題定義清楚且仍有明確改進空間時，AI才能對準真正的痛點創造價值。若只是跟風競爭對手或因成本降低而導入，容易淪為目標不明的失敗專案。","concept":"AI導入時機","aiExplained":true},{"id":"web-j1-317","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的問責機制，下列何者不正確？","options":{"A":"可完全依賴AI決策","B":"需明確責任歸屬","C":"需建立監督機制","D":"需保留決策紀錄"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"問責機制要求明確責任歸屬、建立監督機制並保留決策紀錄，人類仍須對最終決策負責。若完全依賴AI決策，會造成責任真空，正好違反問責原則，因此是不正確的敘述。","concept":"AI問責機制","aiExplained":true},{"id":"web-j1-318","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"企業建立AI風險管理架構時，最容易忽視的是：","options":{"A":"新興風險的識別機制","B":"常見風險的控制","C":"風險評估流程","D":"風險報告制度"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"常見風險的控制、風險評估流程與報告制度通常已有既定做法，企業最容易忽視的是新興風險的識別機制。AI技術演進快速，若缺乏主動偵測新型風險的機制，往往等到損害發生才察覺。","concept":"新興風險識別","aiExplained":true},{"id":"web-j1-319","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"企業制定AI使用規範時，最需要考慮：","options":{"A":"實操可行性和靈活性","B":"規範的嚴格程度","C":"規範的數量","D":"規範的形式"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"使用規範若過於僵硬或脫離實務，員工難以遵循反而形同虛設，因此制定時最需要考慮實操可行性與靈活性，讓規範能真正落地並因應技術變化調整。嚴格程度、數量與形式都是次要問題。","concept":"AI使用規範","aiExplained":true},{"id":"web-j1-320","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的使用權限，下列何者不正確？","options":{"A":"可任意授權","B":"需嚴格管控","C":"需定期審查","D":"需分級管理"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"AI系統的使用權限應依角色分級管理、嚴格管控並定期審查。若可任意授權，將造成未授權存取與濫用的風險，因此是不正確的做法。","concept":"權限管理","aiExplained":true},{"id":"web-j1-321","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"企業使用AI改善客戶服務時，不適合採用：","options":{"A":"聊天機器人","B":"情感分析","C":"客戶數據分析","D":"社會信用評分"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"聊天機器人、情感分析與客戶數據分析都是改善客戶服務的常見AI應用。社會信用評分是對個人進行全面性評等，嚴重侵害基本權利，屬於高度爭議甚至被法規禁止的用途，不適合用於客服。","concept":"AI應用倫理界線","aiExplained":true},{"id":"web-j1-322","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統在金融風險評估中，最需要避免的是：","options":{"A":"評估過程複雜","B":"評估時間過長","C":"評估成本過高","D":"評估標準單一化"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"金融風險評估若標準單一化，容易忽略借款人與市場的多元面向，造成系統性誤判與對特定族群的不公平，是最需要避免的問題。評估過程的複雜度、時間與成本則屬於可管理的工程議題。","concept":"風險評估多元化","aiExplained":true},{"id":"web-j1-323","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統的透明度設計最應該注重：","options":{"A":"技術細節的公開","B":"使用方法的說明","C":"決策邏輯的可理解性","D":"系統結構的展示"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"透明度的目的在於讓使用者與受影響者理解AI為何做出該項決策，因此設計上最應注重決策邏輯的可理解性。單純公開技術細節或展示系統結構，一般人未必能理解，無法達成透明度的實質意義。","concept":"AI透明度","aiExplained":true},{"id":"web-j1-324","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列哪一類AI系統不需要特別義務？","options":{"A":"垃圾郵件過濾器","B":"AI醫療軟體","C":"招聘系統","D":"社會評分系統"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"依風險分級架構（如歐盟AI法案），垃圾郵件過濾器屬於低度或最小風險的應用，無須承擔特別義務。AI醫療軟體與招聘系統屬於高風險須嚴格管理，社會評分系統則屬於被禁止的用途。","concept":"AI風險分級","aiExplained":true},{"id":"web-j1-325","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪項不是評估企業AI需求的重要指標？","options":{"A":"目前面臨的挑戰","B":"期望達成的目標","C":"現有流程的效率","D":"競爭對手的數量"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"評估企業AI需求應從自身條件出發，包括目前面臨的挑戰、期望達成的目標與現有流程的效率。競爭對手的數量與企業自身的實際需求沒有直接關聯，不是重要指標。","concept":"AI需求評估","aiExplained":true},{"id":"web-j1-326","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於AI系統的效能評估，最關鍵的是：","options":{"A":"評估頻率","B":"評估指標的科學性","C":"評估成本","D":"評估範圍"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"效能評估的價值取決於指標是否科學合理：若指標無法真實反映系統表現，再高的評估頻率或再廣的評估範圍都失去意義。因此評估指標的科學性是最關鍵的因素。","concept":"效能評估指標","aiExplained":true},{"id":"web-j1-327","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"企業使用AI進行員工績效評估時，最重要的原則是：","options":{"A":"評估流程的自動化程度","B":"評估標準的透明度和公平性","C":"評估結果的即時性","D":"評估系統的使用便利性"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-2-%e6%8e%a2%e8%a8%8e%e8%b2%a0%e8%b2%ac%e4%bb%bbai%e5%9c%a8%e7%94%a2%e6%a5%ad%e6%87%89%e7%94%a8%e5%ae%9c%e6%9c%89%e7%9a%84%e6%8c%87%e5%b0%8e%e6%ba%96%e5%89%87-5/","explanation":"以AI評估員工績效直接影響個人權益，最重要的原則是評估標準的透明度和公平性，讓員工了解評估依據並確保不產生歧視或偏誤。自動化程度、即時性與便利性都是次要考量。","concept":"績效評估公平性","aiExplained":true},{"id":"web-j1-328","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"下列哪種技術組合最不適合用於情緒分析？","options":{"A":"自然語言處理+深度學習","B":"機器學習+文本分析","C":"神經網絡+詞向量","D":"決策樹+線性回歸"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"情緒分析屬於文本分類任務，仰賴自然語言處理、文本分析與詞向量等語意表示技術，搭配深度學習或神經網絡效果最佳。線性回歸用於預測連續數值，決策樹雖可分類但缺乏語意理解能力，兩者的組合最難捕捉文字中的情感訊息。","concept":"情緒分析技術","aiExplained":true},{"id":"web-j1-329","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI系統在安全監控中最不需要的功能是：","options":{"A":"物體追踪","B":"行為識別","C":"語音辨識","D":"異常檢測"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"安全監控的核心是從影像中掌握動態與風險，因此物體追踪、行為識別與異常檢測都是必要功能。語音辨識處理的是聲音轉文字，與影像監控的主要目標關聯最低。","concept":"AI安全監控應用","aiExplained":true},{"id":"web-j1-330","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"機器學習模型的評估標準不包括：","options":{"A":"準確率","B":"效能","C":"創意性","D":"穩定性"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"機器學習模型的評估著重於準確率、運算效能與穩定性等可量化的客觀指標。創意性屬於主觀特質，無法量化衡量，因此不是模型的評估標準。","concept":"模型評估指標","aiExplained":true},{"id":"web-j1-331","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"機器學習的訓練資料主要用於：","options":{"A":"展示結果","B":"儲存資訊","C":"測試系統","D":"建立模型"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"機器學習透過訓練資料讓演算法從中學習特徵與規律，進而建立可用於預測的模型。展示結果或測試系統是後續階段的工作，並非訓練資料的主要用途。","concept":"訓練資料用途","aiExplained":true},{"id":"web-j1-332","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"非監督式學習最適合用於：","options":{"A":"詐騙偵測","B":"人臉辨識","C":"客戶分群","D":"語音辨識"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"非監督式學習不需要標記資料，擅長從資料中自行找出隱藏的結構與相似性，客戶分群正是典型的聚類應用。詐騙偵測、人臉辨識與語音辨識通常依賴有標記答案的監督式學習。","concept":"非監督式學習應用","aiExplained":true},{"id":"web-j1-333","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"機器學習中的過擬合現象指的是：","options":{"A":"模型過度符合訓練資料","B":"模型完全無法學習","C":"資料量過少","D":"運算速度過慢"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"過擬合指模型過度貼合訓練資料，連雜訊與細節都一併學進去，導致面對新資料時表現大幅下降。它反映的是泛化能力不足，而非學習失敗、資料量或運算速度的問題。","concept":"過擬合","aiExplained":true},{"id":"web-j1-334","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在開發語音助理時，最不需要考慮：","options":{"A":"語音識別","B":"自然語言處理","C":"圖像生成","D":"對話管理"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"語音助理的核心流程是聽懂使用者說話並給予適當回應，因此需要語音識別、自然語言處理與對話管理。圖像生成屬於視覺內容創作技術，與語音互動的核心功能無關。","concept":"語音助理技術","aiExplained":true},{"id":"web-j1-335","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"人工智慧具備的特性不包括下列何者？","options":{"A":"學習能力","B":"創造能力","C":"判斷能力","D":"記憶能力"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"傳統上人工智慧被定義為具備學習、判斷與記憶等能力，能模擬人類的認知處理過程。真正源於自主意圖的原創創造能力，目前仍被視為人類獨有的特質，不屬於AI的基本特性。","concept":"AI基本特性","aiExplained":true},{"id":"web-j1-336","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於強人工智慧的描述，下列何者正確？","options":{"A":"已經完全實現並廣泛應用","B":"AlphaGo是最完整的強人工智慧範例","C":"目前尚未真正出現完整的強人工智慧","D":"只能處理特定領域的問題"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"強人工智慧指具備與人類相當的通用智慧，能跨領域自主思考與學習，目前尚未真正實現。AlphaGo只能下圍棋，屬於專精單一領域的弱人工智慧，因此其餘選項的描述皆不正確。","concept":"強弱AI區別","aiExplained":true},{"id":"web-j1-337","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"機器學習在網絡安全中最不需要的功能是：","options":{"A":"異常檢測","B":"威脅識別","C":"行為分析","D":"圖像處理"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"網絡安全防護以偵測入侵與威脅為核心，異常檢測、威脅識別與行為分析都是機器學習的關鍵應用。圖像處理針對視覺資料，與網路流量或使用者行為資料的分析需求關聯最低。","concept":"AI資安應用","aiExplained":true},{"id":"web-j1-338","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"機器學習在風險評估中最不需要的技術是：","options":{"A":"預測模型","B":"模式識別","C":"語音識別","D":"異常檢測"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"風險評估仰賴預測模型推估未來風險，並以模式識別和異常檢測找出可疑訊號。語音識別處理的是聲音輸入，與風險量化分析沒有直接關係。","concept":"AI風險評估","aiExplained":true},{"id":"web-j1-339","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"關於迴歸分析，下列何者錯誤？","options":{"A":"屬於監督式學習","B":"用於尋找資料間關係","C":"只能處理線性關係","D":"可繪製最佳擬合線"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"迴歸分析屬於監督式學習，用於找出變數之間的關係並可繪製最佳擬合線。除了線性迴歸外，還有多項式迴歸等非線性方法，因此「只能處理線性關係」的敘述錯誤。","concept":"迴歸分析","aiExplained":true},{"id":"web-j1-340","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"非監督式學習適合用於：","options":{"A":"市場區隔分析","B":"人臉辨識系統","C":"語音辨識","D":"垃圾郵件過濾"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"市場區隔分析需要在沒有預先標記的情況下，依顧客特徵自動分群，正是非監督式學習聚類的典型應用。人臉辨識、語音辨識與垃圾郵件過濾則多以標記資料訓練，屬於監督式學習的範疇。","concept":"非監督式應用","aiExplained":true},{"id":"web-j1-341","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"下列何者不是機器學習的應用領域？","options":{"A":"金融預測","B":"醫療診斷","C":"影像辨識","D":"人類情感創造"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"機器學習已廣泛應用於金融預測、醫療診斷與影像辨識等領域。人類情感是主觀的內在經驗，機器可以辨識情緒訊號，卻無法真正創造人類情感，因此不屬於其應用領域。","concept":"機器學習應用","aiExplained":true},{"id":"web-j1-342","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"增強式學習的特色為：","options":{"A":"需要大量標記資料","B":"透過環境回饋學習","C":"完全不需要輸入資料","D":"必須有正確答案"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"增強式學習讓代理人透過與環境互動，依據獎勵或懲罰的回饋逐步調整策略。它不需要事先標記的大量資料，也沒有標準答案可供比對，與監督式學習明顯不同。","concept":"增強式學習","aiExplained":true},{"id":"web-j1-343","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"深度學習中的注意力機制最不適用於：","options":{"A":"簡單分類任務","B":"機器翻譯","C":"語音識別","D":"圖像描述"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"注意力機制的價值在於處理序列資料時動態聚焦於重要部分，因此在機器翻譯、語音識別與圖像描述等任務中效果顯著。簡單分類任務的輸入輸出結構單純，通常不需要注意力機制即可完成。","concept":"注意力機制","aiExplained":true},{"id":"web-j1-344","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI在智慧建築中最不需要的功能是：","options":{"A":"能源管理","B":"安全監控","C":"環境控制","D":"語音合成"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"智慧建築的重點在於自動化管理能源、監控安全與調節室內環境。語音合成是把文字轉成語音的輸出技術，並非建築智慧化管理的必要功能。","concept":"智慧建築應用","aiExplained":true},{"id":"web-j1-345","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI在新聞分析中最不需要的技術是：","options":{"A":"文本分類","B":"情感分析","C":"圖像生成","D":"主題建模"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"新聞分析屬於文本處理任務，需要文本分類整理內容、情感分析判斷立場、主題建模挖掘議題。圖像生成是創造視覺內容的技術，與文字新聞的分析工作無關。","concept":"文本分析應用","aiExplained":true},{"id":"web-j1-346","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在處理自然語言處理任務時，以下哪項技術最不適合？","options":{"A":"遞歸神經網絡","B":"K均值聚類","C":"轉換器模型","D":"LSTM網絡"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"遞歸神經網絡、LSTM與轉換器模型都是為處理序列文字而設計的架構，是自然語言處理的主力技術。K均值聚類是通用的分群演算法，並非針對語言序列設計，最不適合直接處理NLP任務。","concept":"NLP模型","aiExplained":true},{"id":"web-j1-347","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"深度學習是機器學習的：","options":{"A":"替代技術","B":"競爭技術","C":"子集合","D":"獨立領域"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-1/","explanation":"深度學習是機器學習底下的一個子集合，特點是使用多層神經網絡自動學習特徵表示。兩者並非競爭或替代關係，機器學習又隸屬於更廣義的人工智慧範疇。","concept":"AI層級關係","aiExplained":true},{"id":"web-j1-348","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"ResNet中的殘差連接(Residual Connection)主要解決什麼問題？","options":{"A":"過擬合","B":"梯度爆炸","C":"記憶體不足","D":"梯度消失"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"深層網絡在反向傳播時梯度會逐層衰減，造成梯度消失而難以訓練。ResNet的殘差連接讓梯度可以直接跳層回傳，有效緩解此問題，使上百層的深層網絡得以成功訓練。","concept":"殘差連接","aiExplained":true},{"id":"web-j1-349","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"深度學習中的curriculum learning的主要思想是？","options":{"A":"隨機學習","B":"並行學習","C":"反向學習","D":"由易到難學習"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"Curriculum learning仿效人類的學習歷程，先讓模型學習簡單樣本，再逐步加入困難樣本。這種由易到難的訓練安排能讓學習過程更穩定、收斂更快。","concept":"課程學習","aiExplained":true},{"id":"web-j1-350","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"針對不平衡數據集，以下哪種方法最不適合？","options":{"A":"直接刪除多數類樣本","B":"使用加權損失函數","C":"過採樣少數類","D":"使用SMOTE算法"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"處理不平衡資料常用加權損失函數、過採樣少數類或以SMOTE合成樣本，這些方法都能保留原有資訊。直接刪除多數類樣本會丟失大量有價值的資料，是最不建議的粗糙做法。","concept":"不平衡資料處理","aiExplained":true},{"id":"web-j1-351","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"深度學習模型的損失函數(Loss Function)的作用是？","options":{"A":"加速模型訓練","B":"評估模型表現","C":"簡化模型結構","D":"儲存模型參數"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"損失函數量化模型預測值與實際值之間的差距，是評估模型表現好壞的依據。訓練過程正是以最小化損失為目標來更新參數，因此它扮演指引學習方向的角色。","concept":"損失函數","aiExplained":true},{"id":"web-j1-352","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在深度學習中，L1正則化相比L2正則化的主要特點是？","options":{"A":"計算更簡單","B":"傾向於產生稀疏解","C":"對異常值更敏感","D":"訓練更穩定"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"L1正則化以權重的絕對值作為懲罰項，會將不重要的權重壓縮到零，因此傾向產生稀疏解，兼具特徵選擇的效果。L2則是讓權重整體變小但不歸零，兩者特性不同。","concept":"L1正則化","aiExplained":true},{"id":"web-j1-353","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"以下哪個不是深度學習模型的常見層類型？","options":{"A":"卷積層","B":"池化層","C":"全連接層","D":"排序層"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"卷積層、池化層與全連接層都是深度學習網絡的標準組成，分別負責特徵擷取、降維與整合輸出。「排序層」並不是神經網絡的常見層類型。","concept":"神經網絡層","aiExplained":true},{"id":"web-j1-354","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"深度學習中的蒸餾(Distillation)技術主要用於？","options":{"A":"將大模型知識轉移到小模型","B":"提高模型準確率","C":"加快訓練速度","D":"減少數據需求"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"知識蒸餾讓小模型（學生）學習大模型（教師）的輸出分布，把大模型的知識轉移到小模型。如此可在大幅縮減模型規模的同時，盡量保留原有的預測能力，有利於實際部署。","concept":"知識蒸餾","aiExplained":true},{"id":"web-j1-355","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"深度學習中的權重剪枝(Weight Pruning)的主要目的是？","options":{"A":"提高訓練速度","B":"增加模型準確率","C":"改善模型泛化","D":"減少模型參數量"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"權重剪枝將網絡中貢獻度低的權重移除，主要目的是減少模型參數量與運算負擔。修剪後的模型更輕量，適合部署在資源受限的裝置上。","concept":"權重剪枝","aiExplained":true},{"id":"web-j1-356","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"深度學習中的批次標準化(Batch Normalization)的作用是？","options":{"A":"穩定訓練過程","B":"加快運算速度","C":"減少記憶體使用","D":"簡化模型結構"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"批次標準化將每層的輸入分布標準化，減緩內部協變量偏移，使訓練過程更穩定。它同時允許使用較大的學習率並降低對參數初始化的敏感度，核心作用就是穩定訓練。","concept":"批次標準化","aiExplained":true},{"id":"web-j1-357","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"TensorFlow服務(TensorFlow Serving)的主要用途是？","options":{"A":"訓練模型","B":"部署模型","C":"測試模型","D":"設計模型"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"TensorFlow Serving是專為生產環境設計的模型服務系統，負責將訓練好的模型部署上線並提供推論服務。它支援版本管理與高效能請求處理，並非用來訓練或設計模型。","concept":"模型部署","aiExplained":true},{"id":"web-j1-358","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"CNN主要應用在哪個領域？","options":{"A":"圖像處理","B":"語音辨識","C":"自然語言處理","D":"時間序列分析"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"CNN以卷積層擷取局部特徵，特別擅長處理具有空間結構的影像資料，因此主要應用於圖像處理領域。語音與自然語言等序列資料傳統上多由RNN類模型處理。","concept":"CNN應用領域","aiExplained":true},{"id":"web-j1-359","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"以下哪個不是深度學習常見的模型評估方法？","options":{"A":"交叉驗證","B":"留一驗證","C":"隨機分割","D":"連續測試"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"交叉驗證、留一驗證與隨機分割都是常見的模型評估方法，用於檢驗模型在未見資料上的表現。「連續測試」並不是深度學習的標準評估方法。","concept":"模型評估方法","aiExplained":true},{"id":"web-j1-361","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"TensorFlow 2.0的主要改進不包含？","options":{"A":"簡化的API","B":"降低運算效能","C":"動態圖支援","D":"Keras整合"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"TensorFlow 2.0的改進包括簡化的API、預設動態圖執行與深度整合Keras，讓開發更直覺。降低運算效能是缺點而非改進，自然不在其改進項目之列。","concept":"TensorFlow 2.0","aiExplained":true},{"id":"web-j1-362","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"TensorFlow中的張量(Tensor)是指？","options":{"A":"只能是二維矩陣","B":"多維數據陣列","C":"只能是向量","D":"只能是純量"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"張量是TensorFlow的基本資料結構，指多維數據陣列。純量、向量、矩陣分別是零維、一維、二維張量，張量可以推廣到任意維度，並不侷限於特定維度。","concept":"張量","aiExplained":true},{"id":"web-j1-363","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"深度學習中的分組標準化(Group Normalization)相比批次標準化的優勢是？","options":{"A":"計算更簡單","B":"效果更好","C":"不依賴批次大小","D":"訓練更快"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"批次標準化的統計量依賴批次大小，批次過小時估計不準、效果變差。分組標準化改為在通道分組內計算統計量，不依賴批次大小，因此在小批次訓練時表現更穩定。","concept":"分組標準化","aiExplained":true},{"id":"web-j1-364","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"深度學習中的對抗訓練(Adversarial Training)的主要目的是？","options":{"A":"提高訓練速度","B":"增強模型魯棒性","C":"減少參數數量","D":"改善模型解釋性"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"對抗訓練在訓練過程中加入對抗樣本，讓模型學會抵抗刻意設計的微小擾動。其主要目的是增強模型的魯棒性，降低被對抗攻擊誤導的風險。","concept":"對抗訓練","aiExplained":true},{"id":"web-j1-365","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"以下哪個不是深度學習常見的資料預處理步驟？","options":{"A":"隨機改變數據","B":"標準化","C":"正規化","D":"特徵縮放"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"標準化、正規化與特徵縮放都是常見的資料預處理步驟，目的是讓特徵尺度一致、有利於模型收斂。隨機改變數據會破壞資料的真實性，不屬於正規的預處理程序。","concept":"資料預處理","aiExplained":true},{"id":"web-j1-366","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"以下哪個不是深度學習模型常見的優化器(Optimizer)？","options":{"A":"Adam","B":"SGD","C":"RMSprop","D":"Quick Sort"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"Adam、SGD與RMSprop都是深度學習常用的優化器，負責依梯度更新模型參數。Quick Sort是排序演算法，與模型參數優化完全無關。","concept":"優化器","aiExplained":true},{"id":"web-j1-367","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"深度學習模型在訓練過程中主要是透過什麼來改進？","options":{"A":"人工調整","B":"隨機猜測","C":"誤差反饋","D":"資料重組"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-3-%e8%a7%a3%e6%9e%90%e5%b8%b8%e8%a6%8b%e7%9a%84%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%8a%80%e8%a1%93-2/","explanation":"深度學習訓練時先計算預測值與實際值之間的誤差，再透過反向傳播將誤差回饋至各層，據以調整權重。這種誤差反饋機制是模型持續改進的核心，而非人工調整或隨機猜測。","concept":"誤差反向傳播","aiExplained":true},{"id":"web-j1-368","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"特徵工程中，保持簡單性原則的主要目的是：","options":{"A":"節省運算資源","B":"減少儲存空間","C":"加快處理速度","D":"提高模型可解釋性"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"特徵工程強調保持簡單，是因為簡單的特徵讓模型的決策邏輯更容易被理解與追蹤，有助於除錯以及向利害關係人說明模型行為。節省運算資源或加快處理速度只是附帶效果，並非此原則的主要目的。","concept":"特徵工程簡單性","aiExplained":true},{"id":"web-j1-369","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在處理網路日誌資料時，最不適合的特徵工程方式是：","options":{"A":"會話特徵","B":"直接使用原始日誌","C":"行為序列特徵","D":"統計聚合特徵"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"原始網路日誌通常是非結構化且充滿雜訊的文字紀錄，直接餵入模型難以萃取有效資訊。實務上會先轉換成會話特徵、行為序列或統計聚合等結構化特徵，模型才能有效學習使用者行為模式。","concept":"日誌特徵工程","aiExplained":true},{"id":"web-j1-370","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在進行特徵重要性排序時，最不可靠的方法是：","options":{"A":"梯度提升樹","B":"線性模型係數","C":"互信息","D":"特徵出現順序"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"梯度提升樹的重要性分數、線性模型係數與互信息，都是依據資料與模型之間的統計關係所計算的評估方法；特徵在資料集中出現的先後順序與其預測能力毫無關聯，因此是最不可靠的排序依據。","concept":"特徵重要性評估","aiExplained":true},{"id":"web-j1-371","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在資料預處理中，最不重要的考量是：","options":{"A":"資料品質","B":"資料完整性","C":"資料一致性","D":"資料存儲格式"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"資料品質、完整性與一致性直接決定模型能否學到正確的模式，是預處理階段的核心考量；資料存儲格式屬於技術實作細節，可透過格式轉換輕易處理，相對而言重要性最低。","concept":"資料預處理考量","aiExplained":true},{"id":"web-j1-372","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列何者是收集資料時的重要考量：","options":{"A":"資料的法律和道德問題","B":"運算速度","C":"硬體配置","D":"程式語言選擇"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"收集資料時必須確認來源合法、取得適當授權並顧及隱私與道德議題，否則後續應用可能違法或侵害當事人權益。運算速度、硬體配置與程式語言都是後端實作的選擇，並非收集階段的關鍵考量。","concept":"資料收集倫理","aiExplained":true},{"id":"web-j1-373","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在建立異常檢測模型時，最不適合的特徵工程方式是：","options":{"A":"僅保留異常樣本的特徵","B":"建立統計特徵","C":"計算距離特徵","D":"密度估計特徵"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"異常檢測的關鍵在於先刻畫「正常」的樣態，才能辨識偏離正常的個體；若只保留異常樣本的特徵，模型將失去正常行為的參照基準。統計特徵、距離特徵與密度估計則都是異常檢測常用的有效做法。","concept":"異常檢測特徵","aiExplained":true},{"id":"web-j1-374","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"以下哪個不是特徵工程的重要技術：","options":{"A":"特徵縮放","B":"特徵編碼","C":"特徵複製","D":"特徵組合"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"特徵縮放、特徵編碼與特徵組合都是特徵工程的核心技術，分別處理數值尺度、類別轉換與特徵間的交互作用；單純複製特徵不會帶來任何新資訊，反而造成冗餘與共線性，不屬於重要技術。","concept":"特徵工程技術","aiExplained":true},{"id":"web-j1-375","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在實時預測系統中，最不適合的特徵工程策略是：","options":{"A":"增量更新","B":"快取機制","C":"複雜特徵組合","D":"特徵預計算"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"即時預測系統對延遲極為敏感，增量更新、快取機制與特徵預計算都是為了縮短線上運算時間的策略；複雜的特徵組合需要大量即時運算，容易拖慢回應速度，最不適合即時場景。","concept":"即時特徵工程","aiExplained":true},{"id":"web-j1-376","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在進行模型驗證時，最不適合的交叉驗證方式是：","options":{"A":"隨機抽樣驗證","B":"K折交叉驗證","C":"留一交叉驗證","D":"分層交叉驗證"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"K折、留一與分層交叉驗證都會系統性地輪流使用所有資料進行訓練與驗證，估計結果較穩定；單純隨機抽樣切分僅依賴少數次隨機劃分，結果受切分運氣影響大，也無法保證類別比例一致，可靠度最低。","concept":"交叉驗證方法","aiExplained":true},{"id":"web-j1-377","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在信用卡詐欺偵測的應用中，資料集呈現嚴重不平衡，下列處理方式何者最不適當？","options":{"A":"直接刪除多數類別的資料至平衡","B":"使用SMOTE技術生成少數類別的合成樣本","C":"調整類別權重","D":"使用集成學習方法"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"詐欺樣本本來就極少，若直接刪除多數類別資料到與少數類別平衡，會丟棄絕大多數有價值的正常交易資訊，嚴重削弱模型的學習能力。SMOTE合成樣本、調整類別權重與集成學習才是處理不平衡的常見做法。","concept":"類別不平衡處理","aiExplained":true},{"id":"web-j1-378","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在進行深度學習特徵提取時，最不需要考慮的因素是：","options":{"A":"模型架構","B":"層次化特徵","C":"特徵表示學習","D":"特徵命名規範"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"深度學習的特徵提取關注模型架構設計、層次化特徵與表示學習，因為特徵是由網路自動學習出來的；特徵命名規範屬於工程管理層面的慣例，對特徵提取的效果本身沒有影響。","concept":"深度特徵提取","aiExplained":true},{"id":"web-j1-379","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"資料清理的主要目的是：","options":{"A":"減少資料量","B":"加快處理速度","C":"確保資料質量","D":"簡化資料結構"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"資料清理是要處理缺失值、錯誤值、重複與不一致等問題，確保進入模型的資料正確可信，也就是保障資料品質。減少資料量或加快處理速度只是可能的副作用，並非清理的主要目的。","concept":"資料清理目的","aiExplained":true},{"id":"web-j1-380","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在進行特徵重要性評估時，最不可靠的方法是：","options":{"A":"隨機森林特徵重要性","B":"排列重要性","C":"SHAP值","D":"特徵名稱分析"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"隨機森林特徵重要性、排列重要性與SHAP值都是基於模型行為與資料計算出的量化指標，有明確的統計依據；僅憑特徵名稱推測其重要性完全沒有客觀根據，因此最不可靠。","concept":"特徵重要性評估","aiExplained":true},{"id":"web-j1-381","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在進行特徵選擇時，採用包裝法（Wrapper Method）的主要缺點是：","options":{"A":"無法處理特徵間的相互關係","B":"計算成本過高","C":"容易選擇無關特徵","D":"特徵重要性不穩定"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"包裝法需要針對每一組候選特徵子集實際訓練並評估模型，當特徵數量增加時，子集組合呈指數成長，運算成本非常高，這是它相對於過濾法最主要的缺點。","concept":"包裝法特徵選擇","aiExplained":true},{"id":"web-j1-382","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"若某預測模型在訓練集表現極佳但在驗證集表現不佳，最可能的原因是：","options":{"A":"特徵數量不足","B":"模型過度擬合","C":"資料集過小","D":"特徵尺度不一致"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"訓練集表現極佳但驗證集明顯變差，代表模型把訓練資料的雜訊與細節也背了下來，缺乏對新資料的泛化能力，這正是過度擬合的典型徵兆。常見對策包括正則化、增加資料量或簡化模型。","concept":"過度擬合","aiExplained":true},{"id":"web-j1-383","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在即時預測系統中，特徵工程的主要挑戰不包括：","options":{"A":"特徵名稱的命名規範","B":"計算時間的限制","C":"特徵更新的即時性","D":"系統資源的消耗"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"即時預測系統的特徵工程挑戰集中在延遲與資源層面：特徵必須即時更新、計算要在時限內完成、系統資源消耗必須可控。特徵名稱如何命名只是開發慣例，不構成即時系統的技術挑戰。","concept":"即時特徵挑戰","aiExplained":true},{"id":"web-j1-384","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在處理圖結構資料時，最不適合的特徵工程方式是：","options":{"A":"節點特徵","B":"隨機路徑採樣","C":"圖嵌入","D":"拓撲特徵"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"節點特徵、圖嵌入與拓撲特徵都能系統性地保留圖的結構與屬性資訊，是圖資料常用的特徵表示方式；單純隨機抽取路徑缺乏對整體結構的一致刻畫，直接作為特徵最不穩定可靠。","concept":"圖資料特徵","aiExplained":true},{"id":"web-j1-385","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在處理序列資料時，最不適合的特徵工程方式是：","options":{"A":"滑動窗口特徵","B":"序列模式特徵","C":"隨機排序特徵","D":"狀態轉換特徵"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"序列資料的價值在於元素間的先後順序與時間相依性，滑動窗口、序列模式與狀態轉換特徵都是為了保留這種順序資訊而設計；隨機排序反而徹底破壞序列結構，使資料失去意義。","concept":"序列資料特徵","aiExplained":true},{"id":"web-j1-386","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在監督式學習中，標籤的主要功能是：","options":{"A":"用於資料分類","B":"作為模型輸入","C":"降低運算複雜度","D":"作為模型訓練的目標輸出"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"監督式學習是以「輸入特徵對應正確答案」的成對資料進行訓練，標籤就是模型要學著預測的目標輸出，用來計算誤差並更新參數。標籤不是模型的輸入特徵，也與降低運算複雜度無關。","concept":"監督式學習標籤","aiExplained":true},{"id":"web-j1-387","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在製作圖像識別模型時，最不適合的特徵工程方式是：","options":{"A":"顏色直方圖特徵","B":"將像素值加總平均","C":"邊緣檢測特徵","D":"紋理特徵提取"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/1-4-%e8%a7%a3%e6%9e%90%e6%a9%9f%e5%99%a8%e5%ad%b8%e7%bf%92%e6%a0%b8%e5%bf%83%e6%a6%82%e5%bf%b5/","explanation":"把整張影像的像素值加總平均，會完全抹去空間結構與局部紋理資訊，只剩下一個平均亮度值，無法支撐辨識任務。顏色直方圖、邊緣檢測與紋理特徵提取則都是經典且有效的影像特徵方法。","concept":"影像特徵工程","aiExplained":true},{"id":"web-j1-388","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"RLHF（人類反饋強化學習）的正確順序步驟是什麼？","options":{"A":"獎勵模型、提示示範、部署","B":"提示示範、獎勵模型、部署","C":"部署、提示示範、獎勵模型","D":"獎勵模型、部署、提示示範"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"RLHF的標準流程是先以人類撰寫的提示示範資料進行監督式微調，再蒐集人類對模型輸出的偏好排序來訓練獎勵模型，最後以強化學習優化並部署模型，因此「提示示範、獎勵模型、部署」的順序正確。","concept":"RLHF流程","aiExplained":true},{"id":"web-j1-389","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"一家醫院正在評估病患健康狀況，使用從50個異常案例和150個正常案例收集的數據，包括年齡、血型、體重和心率。哪種機器學習方法最合適？","options":{"A":"非監督式學習（聚類）","B":"監督式學習（分類）","C":"強化學習","D":"半監督式學習"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"題目中每筆病患資料都已標註為異常或正常，屬於有標籤資料，而任務是將病患歸入這兩個類別，正是監督式學習的分類問題。聚類適用於無標籤資料，強化學習則用於序列決策情境。","concept":"監督式分類","aiExplained":true},{"id":"web-j1-390","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"如果模型的計算時間變短而GPU使用率降低，最可能的情況是什麼？","options":{"A":"模型已成功優化","B":"模型在數據處理中遇到瓶頸","C":"模型已簡化並失去精度","D":"GPU出現故障"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"GPU使用率降低代表GPU經常處於閒置等待狀態，每批運算很快完成卻沒有持續被餵入資料，典型原因是資料前處理或載入速度跟不上，形成資料處理瓶頸；若是模型真的優化成功，GPU通常仍會維持高使用率。","concept":"GPU效能瓶頸","aiExplained":true},{"id":"web-j1-391","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"以下哪項技術通常不用於生成式AI模型？","options":{"A":"支持向量機","B":"擴散模型","C":"變分自編碼器","D":"生成對抗網絡"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"擴散模型、變分自編碼器與生成對抗網絡都是主流的生成式模型，能學習資料分布並產生新樣本；支持向量機是判別式的分類與迴歸方法，不具備生成資料的能力，因此不用於生成式AI。","concept":"生成式模型類型","aiExplained":true},{"id":"web-j1-392","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"當類別高度不平衡時，哪種指標最適合評估模型性能？","options":{"A":"準確率","B":"F1分數","C":"ROC AUC","D":"均方誤差"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"類別高度不平衡時，準確率會被多數類別灌水而失真；ROC AUC衡量模型在所有決策閾值下區分正負類的整體能力，不依賴單一閾值，能較客觀反映不平衡資料上的效能。均方誤差則是迴歸指標，不適用於分類評估。","concept":"不平衡評估指標","aiExplained":true},{"id":"web-j1-393","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"Transformer模型的核心技術是什麼？","options":{"A":"卷積層","B":"循環連接","C":"注意力機制","D":"池化運算符"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"Transformer的核心是自注意力機制，讓序列中每個位置都能直接關注其他所有位置的資訊，有效捕捉長距離依賴並支援平行運算，取代了傳統的卷積與循環結構。","concept":"注意力機制","aiExplained":true},{"id":"web-j1-394","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"存儲「姓名、學生證號、地址、生日和性別」應使用哪種資料類型組合？","options":{"A":"字串、整數、字串、日期、布林","B":"字串、字串、字串、整數、字串","C":"字串、整數、整數、日期、字串","D":"整數、整數、字串、日期、布林"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"姓名與地址是文字，適合字串型別；生日應使用日期型別以便計算年齡與排序；性別僅有兩種取值時可用布林表示；學生證號在此選項中以整數處理。選項A是四個組合中唯一各欄位型別皆合理的配置。","concept":"資料類型選擇","aiExplained":true},{"id":"web-j1-395","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在混淆矩陣中，真陽性與假陰性的總和代表：","options":{"A":"所有實際為正的案例","B":"所有預測為正的案例","C":"所有正確的預測","D":"所有錯誤的預測"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"真陽性是實際為正且被正確預測為正的案例，假陰性是實際為正卻被誤判為負的案例，兩者相加正好涵蓋所有實際為正的樣本，也就是計算召回率時使用的分母。","concept":"混淆矩陣","aiExplained":true},{"id":"web-j1-396","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"以下哪種正則化技術不用於防止過擬合？","options":{"A":"L1正則化","B":"L2正則化","C":"梯度下降","D":"Dropout"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"L1與L2正則化透過懲罰項限制權重大小，Dropout以隨機關閉神經元避免共同適應，三者皆屬防止過擬合的正則化技術；梯度下降只是最小化損失函數的優化演算法，本身不具正則化功能。","concept":"正則化技術","aiExplained":true},{"id":"web-j1-397","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪種AI應用根據歐盟AI Act會被分類為「高風險」？","options":{"A":"AI驅動的電子遊戲角色","B":"AI天氣預測系統","C":"用於就業決策的AI系統","D":"AI音樂推薦系統"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"歐盟AI Act將用於就業、招募與人員管理決策的AI系統列為高風險，因為它直接影響個人的工作權益，須符合嚴格的透明度與風險管理要求；遊戲角色、天氣預測與音樂推薦則屬於低風險應用。","concept":"歐盟AI法風險分級","aiExplained":true},{"id":"web-j1-398","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"歐盟AI Act要求高風險AI系統必須進行哪種評估？","options":{"A":"用戶滿意度評估","B":"合規性評估","C":"市場競爭力評估","D":"成本效益評估"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"歐盟AI Act要求高風險AI系統在上市前必須通過合規性評估，證明其符合資料治理、透明度、人為監督與穩健性等法規要求，並持續接受監管。用戶滿意度、市場競爭力與成本效益屬商業考量，並非法規義務。","concept":"高風險AI合規","aiExplained":true},{"id":"web-j1-399","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"根據金融業AI指引，以下哪項是金融服務AI系統的關鍵要求？","options":{"A":"最大投資回報率","B":"決策的可解釋性","C":"完全自動化決策","D":"最小化計算資源"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"金融業涉及信用評估與授信等重大決策，主管機關的AI指引特別強調決策過程必須可解釋，讓客戶與監理單位能了解結果的依據，以確保公平與問責。追求報酬率或完全自動化都不是指引的核心要求。","concept":"金融AI可解釋性","aiExplained":true},{"id":"web-j1-400","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在一個超市中，當物品放入購物車時會自動檢測並在結帳時自動收費，這主要使用了哪種AI技術？","options":{"A":"自然語言處理","B":"電腦視覺","C":"強化學習","D":"生成對抗網絡"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"自動偵測放入購物車的商品需要即時辨識影像中的物品種類與顧客動作，這是電腦視覺的典型應用，例如無人商店即是結合攝影機與影像辨識技術完成自動結帳。","concept":"電腦視覺應用","aiExplained":true},{"id":"web-j1-401","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"卷積神經網絡(CNN)最常用於處理哪種類型的數據？","options":{"A":"時間序列數據","B":"圖像數據","C":"文本數據","D":"聲音數據"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"CNN透過卷積核在影像上滑動萃取局部特徵，並利用權重共享與空間層次結構逐層組合出高階特徵，特別適合處理具有空間結構的圖像數據，是影像辨識的主力架構。","concept":"CNN應用領域","aiExplained":true},{"id":"web-j1-402","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"以下哪項正確定義了機器學習？","options":{"A":"AI的一個子集，系統可以自動從數據中學習，而無需明確編程","B":"使用演算法比人類更快地執行計算","C":"一個可以在所有方面完美模仿人類智能的系統","D":"為每種情況編程計算機遵循預定規則"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"機器學習是人工智慧的子領域，核心在於讓系統從資料中自動學習規律並改善表現，而不需要針對每種情況撰寫明確規則。其他選項分別誤解為單純加速計算、完美模仿人類或預先編寫規則，皆不正確。","concept":"機器學習定義","aiExplained":true},{"id":"web-j1-403","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"哪種視覺化方法無法判斷資料集的中心趨勢？","options":{"A":"直方圖","B":"雷達圖","C":"散點圖","D":"箱型圖"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"直方圖與箱型圖能呈現資料分布與中位數等中心位置，散點圖也能觀察資料點聚集的中心區域；雷達圖是以多軸比較多個變數的量值輪廓，無法呈現單一資料集的分布與中心趨勢。","concept":"資料視覺化","aiExplained":true},{"id":"web-j1-404","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪項不是負責任AI的關鍵原則？","options":{"A":"透明度","B":"公平性","C":"不計代價最大化預測準確度","D":"隱私保護"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"負責任AI的核心原則包括透明度、公平性與隱私保護，強調在模型效能與社會影響之間取得平衡；不計代價追求預測準確度可能犧牲公平性與隱私，正好違背負責任AI的精神。","concept":"負責任AI原則","aiExplained":true},{"id":"web-j1-405","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"混淆矩陣中，精確率(Precision)的計算方式是：","options":{"A":"TP / (TP + FN)","B":"TP / (TP + FP)","C":"TN / (TN + FP)","D":"(TP + TN) / (TP + TN + FP + FN)"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"精確率衡量的是被模型預測為正的案例中實際為正的比例，因此分子是TP，分母是所有預測為正的數量TP加FP。它回答的問題是「模型判定為正的案例裡，有多少真的是正」。","concept":"精確率計算","aiExplained":true},{"id":"web-j1-406","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在負責任AI的開發過程中，「偏見緩解」主要指什麼？","options":{"A":"降低模型運算成本","B":"減少對特定硬體的依賴","C":"確保AI不對特定群體產生不公平結果","D":"限制AI做出決策的速度"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"偏見緩解是指在資料收集、模型訓練與結果評估各階段採取措施，避免AI系統對特定性別、種族或群體產生系統性的不公平結果，是落實公平性原則的具體作法，與運算成本或硬體依賴無關。","concept":"偏見緩解","aiExplained":true},{"id":"web-j1-407","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"開發用於預測人類行為、隱私偏好、信用評分或種族的AI系統屬於歐盟AI Act的哪種風險類別？","options":{"A":"不可接受風險","B":"高風險","C":"有限風險","D":"最小風險"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%911-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%88%e5%85%b150%e9%a1%8c%ef%bc%89/","explanation":"用於信用評分、行為預測等會實質影響個人權益的AI系統，在歐盟AI Act中被歸類為高風險，必須遵守風險管理、資料治理與人為監督等義務，但尚未達到社會評分那類被完全禁止的程度。","concept":"AI風險分類","aiExplained":true},{"id":"web-j2-408","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"AI模型的\"可解釋性\"（Explainability）指的是什麼？","options":{"A":"理解模型如何做出決策的能力","B":"模型處理複雜數據的速度","C":"模型的預測準確度","D":"模型的市場競爭力"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"可解釋性指的是人類能夠理解模型如何從輸入推導出特定決策的程度。它讓開發者與使用者得以檢視判斷依據、除錯並建立信任，尤其在金融、醫療等高風險領域至關重要。處理速度、預測準確度與市場競爭力都不是這個概念所指的內涵。","concept":"模型可解釋性","aiExplained":true},{"id":"web-j2-409","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"什麼是\"對抗樣本\"（Adversarial Examples）？","options":{"A":"用於模型訓練的高難度數據","B":"模型無法正確分類的數據","C":"經特意設計使AI模型產生錯誤輸出的輸入","D":"來自競爭對手系統的測試數據"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"對抗樣本是在原始輸入上刻意加入人眼難以察覺的微小擾動，使模型產生錯誤輸出的特製輸入。它揭露了模型決策邊界的脆弱性，是AI安全與強健性研究的核心議題。這與訓練難度高的資料或競爭對手的測試資料是完全不同的概念。","concept":"對抗樣本","aiExplained":true},{"id":"web-j2-410","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在AI系統中實現\"公平性\"（Fairness）的主要挑戰是什麼？","options":{"A":"計算資源限制","B":"數據存儲容量","C":"模型訓練時間","D":"不同公平標準間的權衡與定義"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"公平性存在多種數學定義，例如群體公平與個體公平，這些標準彼此之間往往無法同時滿足。因此實務上必須先釐清採用哪種公平定義，並在不同標準與模型效能之間做權衡，這正是實現公平性的最大挑戰。計算資源、儲存容量與訓練時間只是工程層面的問題。","concept":"AI公平性","aiExplained":true},{"id":"web-j2-411","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"哪種技術最適合處理圖像數據？","options":{"A":"卷積神經網絡（CNN）","B":"循環神經網絡（RNN）","C":"決策樹","D":"朴素貝葉斯"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"卷積神經網絡以卷積核在影像上滑動，能有效擷取局部空間特徵，並透過權重共享大幅減少參數量。這種設計與影像的二維網格結構高度契合，因此成為影像處理的主流架構。RNN擅長序列資料，決策樹與朴素貝葉斯屬傳統機器學習方法，皆非影像任務的首選。","concept":"CNN影像應用","aiExplained":true},{"id":"web-j2-413","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"以下哪種不是常見的AI模型部署方式？","options":{"A":"雲端部署","B":"紙本部署","C":"邊緣設備部署","D":"混合部署"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"模型部署是把訓練好的模型放到實際運行環境提供服務，常見方式包括雲端部署、邊緣設備部署，以及兩者並用的混合部署。紙本無法執行程式與模型運算，自然不是一種部署方式。","concept":"模型部署方式","aiExplained":true},{"id":"web-j2-414","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"以下哪項不是生成式對抗網絡（GAN）的應用？","options":{"A":"網絡流量異常檢測","B":"圖像生成","C":"風格轉換","D":"超分辨率重建"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"GAN由生成器與判別器對抗訓練而成，強項在於生成逼真的內容，典型應用包括圖像生成、風格轉換與超分辨率重建。網絡流量異常檢測屬於資安監控任務，主流做法是統計分析或異常偵測模型，並非GAN的代表性應用。","concept":"GAN應用","aiExplained":true},{"id":"web-j2-415","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"OpenAI的API最適合應用於哪種場景？","options":{"A":"大規模數據處理與分析","B":"自然語言理解與生成","C":"影像識別與處理","D":"物聯網設備管理"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"OpenAI的API以GPT系列大型語言模型為核心，專長是自然語言的理解與生成，適用於對話、摘要、翻譯與文案撰寫等場景。大規模數據分析、影像處理與物聯網設備管理各有更合適的專門工具。","concept":"OpenAI API應用","aiExplained":true},{"id":"web-j2-416","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"下列哪種不是No-code/Low-code平台的典型特點？","options":{"A":"需要深入了解底層程式架構","B":"拖拽式界面設計","C":"預配置的模板與連接器","D":"視覺化的工作流程設計"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"No-code/Low-code平台的核心價值在於降低開發門檻，讓非工程背景者也能透過拖拽式界面、預配置模板與視覺化流程快速建置應用。若使用時仍需要深入了解底層程式架構，就違背了這類平台的設計初衷。","concept":"低程式碼平台","aiExplained":true},{"id":"web-j2-417","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"哪種深度學習架構最適合處理序列數據？","options":{"A":"循環神經網絡（RNN）","B":"卷積神經網絡（CNN）","C":"多層感知器（MLP）","D":"自編碼器（Autoencoder）"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"循環神經網絡具有循環連接，能將前一時間步的隱藏狀態傳遞到下一步，因此能捕捉序列資料中的時間依賴關係。CNN擅長空間特徵、MLP處理固定長度向量、自編碼器用於壓縮與重建，都不是專為序列設計的架構。","concept":"序列資料模型","aiExplained":true},{"id":"web-j2-418","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"下列哪項不是常見的AI倫理問題？","options":{"A":"隱私保護","B":"算法公平性","C":"自主性與控制","D":"硬體兼容性"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"AI倫理關注的是技術對人與社會的影響，例如隱私保護、算法公平性，以及人類對系統的自主性與控制權。硬體兼容性屬於工程與技術整合問題，不在倫理討論的範疇。","concept":"AI倫理議題","aiExplained":true},{"id":"web-j2-419","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"哪種技術最適合進行即時自然語言翻譯？","options":{"A":"監督式學習","B":"神經機器翻譯（Neural Machine Translation）","C":"關聯規則學習","D":"支持向量機"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"神經機器翻譯以編碼器－解碼器架構（如Transformer）直接學習語言之間的對應關係，能生成流暢且語意連貫的譯文，是目前即時翻譯服務的主流技術。監督式學習只是廣義的學習範式，關聯規則學習與支持向量機則不適合生成式的翻譯任務。","concept":"神經機器翻譯","aiExplained":true},{"id":"web-j2-420","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"AI系統的\"可擴展性\"（Scalability）主要關注什麼？","options":{"A":"模型適應新任務的能力","B":"系統用戶界面的設計","C":"系統處理增長數據量與用戶數的能力","D":"系統的市場擴張潛力"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"可擴展性衡量的是系統在資料量與使用者數量成長時，能否透過擴充資源維持穩定效能。這關係到架構設計，例如水平擴展與負載平衡，而非模型適應新任務的能力、界面設計或市場擴張。","concept":"系統可擴展性","aiExplained":true},{"id":"web-j2-421","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在企業AI應用中，\"數據湖\"（Data Lake）的主要優勢是什麼？","options":{"A":"提供高度結構化的數據存儲","B":"允許存儲大量原始格式的數據","C":"減少數據存儲成本","D":"簡化數據加密過程"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"數據湖允許以原始格式集中存放結構化、半結構化與非結構化資料，不必事先定義結構，保留了後續多元分析的彈性。高度結構化的存儲是數據倉儲的特性，而降低成本與簡化加密並非數據湖的核心賣點。","concept":"資料湖","aiExplained":true},{"id":"web-j2-422","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"AI系統中的\"偏見\"（Bias）主要來源是什麼？","options":{"A":"系統硬體限制","B":"使用者操作錯誤","C":"網絡連接問題","D":"訓練數據中的不公平表示"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"AI系統的偏見主要來自訓練數據：若資料對特定族群的代表性不足，或本身帶有歷史累積的不公平，模型就會學到並放大這些偏差。硬體限制、操作錯誤或網絡問題都不會系統性地造成這種歧視性結果。","concept":"訓練資料偏見","aiExplained":true},{"id":"web-j2-423","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"AI模型訓練中的過擬合（Overfitting）問題主要表現為什麼？","options":{"A":"模型訓練速度過慢","B":"模型無法收斂","C":"模型對所有數據的預測均不準確","D":"模型在訓練數據上表現良好但在新數據上表現差"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"過擬合是模型過度記憶訓練資料中的細節與雜訊，導致在訓練集上表現優異、卻無法泛化到未見過的新資料。常見解法包括正則化、增加資料量與提早停止訓練。訓練速度過慢或無法收斂則屬於另外的優化問題。","concept":"過擬合","aiExplained":true},{"id":"web-j2-424","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"聯邦學習（Federated Learning）的主要優勢是什麼？","options":{"A":"提高模型訓練速度","B":"保護用戶隱私同時允許模型學習","C":"減少計算資源需求","D":"簡化模型部署流程"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"聯邦學習讓資料保留在各參與方的本地設備，只上傳模型參數或梯度到中央伺服器彙整，因此能在不集中原始資料的前提下共同訓練模型。這種設計的最大價值，就是同時兼顧模型學習成效與用戶隱私保護。","concept":"聯邦學習","aiExplained":true},{"id":"web-j2-425","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"什麼是\"知識圖譜\"（Knowledge Graph）？","options":{"A":"視覺化顯示AI學習進度的工具","B":"描述神經網絡結構的圖表","C":"展示數據分布的統計圖","D":"表示實體與關係的結構化知識庫"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"知識圖譜是以節點表示實體、以邊表示實體間關係的結構化知識庫，例如「台北—位於—台灣」這樣的三元組。它常用於搜尋引擎、推薦系統與問答系統，協助機器理解語意層面的關聯。","concept":"知識圖譜","aiExplained":true},{"id":"web-j2-426","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在生成式AI中，什麼是\"幻覺\"（Hallucination）問題？","options":{"A":"模型無法生成任何輸出","B":"模型生成的內容過於抽象","C":"模型過度依賴特定輸入模式","D":"模型生成看似合理但實際上不準確或虛構的內容"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"幻覺指模型生成的內容語句流暢、看似合理，實際上卻與事實不符或純屬虛構，例如捏造不存在的文獻或數據。這源於語言模型依機率生成文字而非查證事實，因此在關鍵應用中必須搭配事實查核或檢索增強等機制。","concept":"AI幻覺","aiExplained":true},{"id":"web-j2-427","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"機器學習中的\"特徵工程\"（Feature Engineering）指的是什麼？","options":{"A":"設計新型神經網絡架構","B":"優化模型訓練參數","C":"從原始數據中提取有用特徵的過程","D":"模型部署後的性能監控"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/3-22-ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e8%80%83%e7%a7%912-%e6%a8%a1%e6%93%ac%e8%80%83%e9%a1%8c%ef%bc%8850%e9%a1%8c%ef%bc%89/","explanation":"特徵工程是運用領域知識，從原始資料中萃取、轉換與建構出有助於模型學習的特徵，例如從日期欄位衍生出星期幾。在傳統機器學習中，特徵品質往往比演算法的選擇更能左右最終成效。","concept":"特徵工程","aiExplained":true},{"id":"web-j1-428","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在深度學習中，\"權重標準化\"(Weight Normalization)與批次標準化(Batch Normalization)的主要區別是：","options":{"A":"權重標準化需要更多計算","B":"權重標準化直接重參數化權重而非標準化激活","C":"權重標準化僅用於全連接層","D":"它們完全相同"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"權重標準化是將權重向量重參數化為方向與長度兩部分直接處理，不依賴mini-batch的統計量。批次標準化則是對每層的激活值依批次的均值與變異數進行標準化，兩者作用的對象根本不同。","concept":"權重標準化","aiExplained":true},{"id":"web-j1-429","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"Azure AI視覺的「色彩分析」功能如何幫助視覺設計？","options":{"A":"僅通過提高圖像解析度","B":"提供色彩分布和主色彩信息以指導設計決策","C":"僅通過壓縮圖像","D":"只通過調整圖像大小"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"色彩分析功能會回傳影像的主色調、前景與背景色，以及整體色彩分布等資訊。設計師可據此挑選協調的配色、維持品牌視覺一致性，讓設計決策有數據依據，而非僅憑主觀感覺。","concept":"Azure色彩分析","aiExplained":true},{"id":"web-j2-430","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在深度學習中，\"注意力門控\"(Attention Gating)機制的主要目的是：","options":{"A":"增加模型深度","B":"減少訓練時間","C":"選擇性地聚焦於重要特徵","D":"降低模型複雜度"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"注意力門控透過學習到的權重對特徵進行篩選，放大與任務相關的重要特徵、抑制無關訊息，讓模型把運算資源聚焦在關鍵區域。它的目的在於提升表現與可解釋性，而非單純增加深度或降低複雜度。","concept":"注意力門控","aiExplained":true},{"id":"web-j1-431","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"高斯誤差線性單元(GELU)激活函數與ReLU的主要區別是：","options":{"A":"GELU總是提供更好的結果","B":"GELU需要更少的計算資源","C":"GELU在輸入附近是平滑的，並結合了門控機制","D":"GELU僅用於特定類型的網絡"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"ReLU在零點有折角且負區間輸出恆為零，GELU則以高斯累積分布函數對輸入做平滑加權，處處平滑可微。這相當於依輸入值大小進行機率式的門控，實務上被GPT、BERT等Transformer模型廣泛採用。","concept":"GELU激活函數","aiExplained":true},{"id":"web-j1-432","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"像素對比學習(Pixel-level Contrastive Learning)與標準對比學習的主要區別是：","options":{"A":"需要更少的計算資源","B":"總是產生更好的結果","C":"不需要負樣本","D":"在像素級別而非全局級別應用對比損失"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"標準對比學習是在整張影像的全局表徵上計算對比損失，學到的是圖像層級的表示。像素級對比學習則把對比損失下放到像素層級，讓空間中每個位置都學到具判別性的特徵，特別有利於語意分割等密集預測任務。","concept":"像素對比學習","aiExplained":true},{"id":"web-j1-433","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在影像處理中，邊緣檢測的主要應用是什麼？","options":{"A":"只是為了美化圖像","B":"僅用於圖像壓縮","C":"識別物體邊界和形狀特徵","D":"僅用於調整圖像亮度"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"邊緣是影像中亮度發生急遽變化的位置，通常對應物體的輪廓。邊緣檢測因此被用來識別物體邊界與形狀特徵，是物件辨識、影像分割等後續處理的重要基礎步驟，而不只是美化或壓縮影像。","concept":"邊緣檢測","aiExplained":true},{"id":"web-j1-434","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在深度學習中，\"漸進式標籤精煉\"(Progressive Label Refinement)的核心思想是：","options":{"A":"逐步調整和優化訓練過程中的標籤","B":"使用更多的標籤分類","C":"完全避免使用硬標籤","D":"僅在特定域中應用標籤"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"漸進式標籤精煉的核心是在訓練過程中逐步修正與優化標籤：讓模型先從較粗糙或帶雜訊的標籤學起，再迭代產生更精確的標籤繼續訓練。這種做法常見於半監督與弱監督學習，用來對抗標註品質不佳的問題。","concept":"標籤精煉","aiExplained":true},{"id":"web-j1-435","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在影像處理中，RGB色彩模式中的色彩數量有多少？","options":{"A":"約16.7百萬","B":"約1千","C":"約65千","D":"無限多"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"標準RGB採24位元色彩深度，紅、綠、藍三個通道各以8位元表示256階。三通道組合共有256的三次方、約1,677萬種顏色，也就是俗稱的1600萬色或全彩。","concept":"RGB色彩深度","aiExplained":true},{"id":"web-j1-436","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在影像處理中，什麼是「形態學操作」？","options":{"A":"只是改變圖像尺寸","B":"基於形狀處理圖像的操作，如膨脹和侵蝕","C":"僅用於彩色調整","D":"只是圖像旋轉的另一種說法"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"形態學操作是基於形狀、以結構元素對影像進行處理的一類運算，最基本的是膨脹與侵蝕，並可組合成開運算與閉運算。它常用於去除雜訊、填補孔洞與強化物體結構，多應用於二值影像。","concept":"形態學操作","aiExplained":true},{"id":"web-j1-437","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"Azure AI視覺中的「自訂模型」訓練需要什麼條件？","options":{"A":"只需一張圖像","B":"足夠的已標記訓練數據","C":"不需要任何數據","D":"只能用現有模型"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"自訂模型是在預訓練模型的基礎上，用使用者自己的資料進行訓練，以辨識特定領域的物件或場景。這個過程必須提供足夠數量且已正確標記的訓練影像，標註的品質與數量直接決定模型成效。","concept":"自訂視覺模型","aiExplained":true},{"id":"web-j1-438","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"Azure AI視覺中的敏感內容審核功能主要用於什麼？","options":{"A":"識別和過濾不適當的圖像內容","B":"僅檢測圖像質量","C":"僅識別圖像中的人物","D":"僅用於識別版權材料"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"敏感內容審核功能會偵測影像中的成人、暴力等不適當內容，並回傳各類別的信心分數。平台可據此自動過濾或標記違規圖像，維護使用環境並降低人工審核的負擔。","concept":"內容審核","aiExplained":true},{"id":"web-j1-439","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"Azure AI視覺的「智慧裁剪」功能如何決定關注區域？","options":{"A":"隨機選擇區域","B":"分析視覺內容以識別重要區域","C":"總是從中心裁剪","D":"僅基於圖像亮度裁剪"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"智慧裁剪會分析影像內容的顯著性，自動找出人臉、主體等視覺上重要的區域，再以該區域為中心裁出指定比例的縮圖。這比單純從中心裁切或隨機裁切更能保留影像的重點資訊。","concept":"智慧裁剪","aiExplained":true},{"id":"web-j1-440","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"主動轉移學習(Active Transfer Learning)結合了哪兩種學習範式？","options":{"A":"監督學習和無監督學習","B":"強化學習和監督學習","C":"主動學習和轉移學習","D":"半監督學習和自監督學習"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"主動學習讓模型主動挑選最具資訊價值的樣本請人標註，以最少的標註成本獲得最佳效果；轉移學習則是把既有任務學到的知識遷移到新任務。主動轉移學習結合兩者，在遷移知識的同時聰明地選樣標註。","concept":"主動轉移學習","aiExplained":true},{"id":"web-j1-441","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在深度學習中，\"Sharpness-Aware Minimization\"(SAM)的核心創新是：","options":{"A":"尋找既有低損失值又對權重擾動敏感度低的解","B":"增加模型複雜度","C":"減少神經網絡層數","D":"僅用於計算機視覺任務"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"SAM的創新在於它不只最小化損失值，還同時懲罰損失曲面的尖銳程度，尋找位於平坦區域的解。權重受到小幅擾動時損失仍然穩定的平坦極小值，通常能帶來更好的泛化能力。","concept":"SAM優化","aiExplained":true},{"id":"web-j1-442","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在物件偵測中，「邊界框」是指什麼？","options":{"A":"圖像的外部邊界","B":"標示物體位置的矩形框","C":"圖像的色彩範圍","D":"圖像的分辨率限制"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"邊界框是用一個矩形框標示物體在影像中的位置與範圍，通常以左上角座標加寬高、或對角兩點座標來表示。它是物件偵測任務的標準輸出格式，讓系統同時給出物體的類別與所在位置。","concept":"邊界框","aiExplained":true},{"id":"web-j1-443","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"Azure AI視覺中的「背景移除」功能主要用於哪些應用場景？","options":{"A":"電子商務產品展示和照片編輯","B":"只用於醫學影像","C":"僅用於衛星圖像","D":"只用於文件掃描"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"背景移除功能可自動將前景主體與背景分離，產生去背影像或前景遮罩。最典型的應用是電子商務的產品圖去背與一般照片編輯，能大幅節省人工修圖的時間成本。","concept":"背景移除","aiExplained":true},{"id":"web-j1-444","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"Azure AI視覺中的「物體偵測」功能相比「圖像分類」提供哪些額外信息？","options":{"A":"物體的位置和類別，以及多個物體的識別","B":"它們提供完全相同的信息","C":"物體偵測只能處理人物","D":"圖像分類總是更準確"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"圖像分類只為整張影像輸出一個類別標籤；物體偵測則進一步以邊界框標出每個物體的位置，並能在同一張影像中同時辨識多個不同物體。因此偵測提供的是「有什麼、在哪裡、有幾個」的完整資訊。","concept":"物體偵測","aiExplained":true},{"id":"web-j1-445","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在深度學習中，\"去卷積\"(Deconvolution)和\"轉置卷積\"(Transposed Convolution)的關係是：","options":{"A":"它們是完全不同的操作","B":"轉置卷積是一種更準確的術語，描述了所謂的\"去卷積\"操作","C":"去卷積需要更多計算","D":"轉置卷積只用於特定領域"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"深度學習中所謂的「去卷積」實際執行的是卷積矩陣的轉置運算，用於將特徵圖上採樣放大，並非數學上真正的反卷積。因此「轉置卷積」被視為更準確的術語，常見於影像分割與生成模型的解碼端。","concept":"轉置卷積","aiExplained":true},{"id":"web-j1-446","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在遷移學習中，\"域適應\"(Domain Adaptation)技術主要用於：","options":{"A":"減少源域和目標域之間的分布差異","B":"完全重新訓練模型","C":"僅適應特定類別","D":"增加模型參數"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"域適應處理的是訓練資料（源域）與實際應用資料（目標域）分布不一致的問題，透過對齊兩者的特徵分布，讓在源域訓練的模型於目標域仍能維持效能。它不需要完全重新訓練模型，是遷移學習的重要分支。","concept":"域適應","aiExplained":true},{"id":"web-j1-447","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在電腦視覺中，\"Siamese Network\"主要用於解決什麼問題？","options":{"A":"圖像分割","B":"目標檢測","C":"相似性比較和一次性學習","D":"圖像超解析"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-1/","explanation":"Siamese網路由兩個共享權重的分支組成，將成對輸入映射到同一嵌入空間，再以距離度量判斷兩者的相似程度。這種設計特別適合相似性比較與一次性學習，典型應用如人臉驗證與簽名比對。","concept":"孿生網路","aiExplained":true},{"id":"web-j1-448","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"提高圖像偵測準確性的關鍵因素不包括","options":{"A":"圖片格式","B":"圖片檔案大小","C":"人臉大小範圍","D":"圖片拍攝時間"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"圖片格式、檔案大小與人臉在畫面中的大小範圍，都會直接影響偵測演算法能否正確解析影像內容，屬於影響偵測準確性的關鍵因素。至於圖片的拍攝時間只是附屬的中繼資料，與影像本身的品質或可辨識度無關，因此不屬於關鍵因素。","concept":"影像偵測影響因素","aiExplained":true},{"id":"web-j1-449","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"影片分析系統理解創意內容的技術挑戰是：","options":{"A":"僅分析標準內容","B":"增加處理資源","C":"跨模態隱喻理解與符號解析","D":"限制分析內容類型"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"創意內容常運用隱喻、象徵等非字面的表達方式，單一模態的分析難以捕捉其真正含義。系統必須整合影像、聲音與文字等多模態訊息，進行跨模態的隱喻理解與符號解析，才能正確詮釋創意內容，這正是主要的技術挑戰。其餘選項只是迴避或限縮問題，並非面對挑戰的方向。","concept":"跨模態理解","aiExplained":true},{"id":"web-j1-450","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"影片分析系統理解文化特定行為的方法是：","options":{"A":"僅使用通用模型","B":"文化知識整合與語境解釋框架","C":"限制支援文化範圍","D":"簡化行為識別任務"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"同一行為在不同文化中可能有截然不同的意義，僅靠通用模型無法正確判讀。將文化知識整合進系統，並建立語境解釋框架，才能依據文化背景正確詮釋特定行為。限制支援的文化範圍或簡化識別任務都是迴避問題，而非解決方法。","concept":"文化語境理解","aiExplained":true},{"id":"web-j2-451","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"臉部偵測演算法在複雜背景中準確定位人臉的關鍵技術是：","options":{"A":"僅增加模型大小","B":"多尺度特徵金字塔與注意力機制","C":"限制偵測角度","D":"僅在高解析度影像中應用"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"複雜背景中的人臉常出現大小不一、局部遮擋等情況，多尺度特徵金字塔能同時擷取不同尺寸的人臉特徵，注意力機制則引導模型聚焦於人臉區域、抑制背景干擾。兩者結合正是複雜場景下準確定位人臉的關鍵技術，單純加大模型或限制偵測條件都無法根本解決問題。","concept":"臉部偵測技術","aiExplained":true},{"id":"web-j1-452","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"文件辨識的功能不包括：","options":{"A":"文件分析","B":"鍵值對提取","C":"修改文件內容","D":"文件佈局識別"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"文件辨識服務的核心是「讀取與理解」文件，功能涵蓋文件分析、鍵值對提取與版面佈局識別等。它只負責從文件中萃取資訊，並不會修改原始文件的內容，因此修改文件內容不屬於其功能範圍。","concept":"文件辨識功能","aiExplained":true},{"id":"web-j1-453","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"視覺干擾識別技術能夠","options":{"A":"識別影像中的干擾","B":"只識別特定類型的干擾","C":"增加影像清晰度","D":"減少影像檔案大小"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"視覺干擾識別技術的目的在於辨識影像中存在的各種干擾，例如模糊、雜訊或遮蔽，以評估影像品質或輔助後續處理。它並非僅限特定類型的干擾，也不負責提升清晰度或縮小檔案，因此「識別影像中的干擾」才是正確描述。","concept":"視覺干擾識別","aiExplained":true},{"id":"web-j1-455","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"臉部特徵標記的位置將會回傳","options":{"A":"像素單位","B":"厘米單位","C":"英寸單位","D":"毫米單位"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"臉部特徵標記（landmarks)是指眼角、鼻尖、嘴角等關鍵點在影像中的座標，系統會以像素為單位回傳這些位置。數位影像的座標系統本來就建立在像素之上，厘米、英寸、毫米等實體長度單位無法直接對應到影像中的點位。","concept":"臉部特徵標記","aiExplained":true},{"id":"web-j1-456","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"文件辨識通過機器學習可以：","options":{"A":"只處理特定類型的文件","B":"自動化地從文件中提取關鍵資訊","C":"只能識別手寫文件","D":"A和C都正確"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"文件辨識藉由機器學習模型學習各類文件的結構與內容特徵，能自動化地從文件中提取欄位、表格與鍵值對等關鍵資訊。它並不限於特定文件類型，也不是只能處理手寫文件，因此「自動化提取關鍵資訊」才是正確描述。","concept":"文件智慧擷取","aiExplained":true},{"id":"web-j1-457","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"使用 Azure AI 視覺訓練自訂模型，主要可用於：","options":{"A":"僅限於文字辨識","B":"只能進行人臉偵測","C":"圖像分類或物件偵測","D":"僅用於影片剪輯"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"Azure AI 視覺允許使用者以自己的影像資料訓練自訂模型，主要用途是圖像分類（判斷整張影像的類別）與物件偵測（找出影像中特定物件的位置）。它並非僅限文字辨識或人臉偵測，更與影片剪輯無關。","concept":"自訂視覺模型","aiExplained":true},{"id":"web-j2-458","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"Azure AI文件辨識服務分為哪三大類","options":{"A":"手寫識別、印刷體識別、數字識別","B":"影像分析、文字識別、語音識別","C":"文字翻譯、文字理解、文字生成","D":"預生成模型、自訂模型、文件分析"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"Azure AI 文件辨識服務的模型分為三大類：文件分析模型負責萃取文字與版面結構，預生成（預建）模型可直接處理發票、收據等常見文件，自訂模型則讓使用者以自有文件訓練專屬模型。只有選項D完整涵蓋這三大類。","concept":"文件辨識模型分類","aiExplained":true},{"id":"web-j1-459","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"OCR模型能夠識別：","options":{"A":"印刷體和手寫體文字","B":"僅能識別印刷體文字","C":"僅能識別手寫體文字","D":"僅能識別數字和特殊符號"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"OCR 模型經過大量不同字體與書寫風格資料的訓練，能同時識別印刷體與手寫體文字。它並非僅限單一文字型態，也不是只能處理數字或特殊符號，因此涵蓋印刷與手寫兩者的選項才正確。","concept":"OCR辨識範圍","aiExplained":true},{"id":"web-j1-460","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"智慧縮圖的運作方式不包括以下哪一項？","options":{"A":"移除影像中的雜亂元素","B":"識別主要物體所在區域","C":"增加影像的檔案大小","D":"調整影像比例以符合目標尺寸"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"智慧縮圖會先識別影像中主要物體所在的區域，移除周圍的雜亂元素，再調整比例裁切出符合目標尺寸的縮圖，讓重點主體保留在畫面中。整個過程是縮小與裁切影像，不會也不需要增加影像的檔案大小。","concept":"智慧縮圖","aiExplained":true},{"id":"web-j1-461","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"影片索引器的協助工具功能如何幫助用戶","options":{"A":"提供多種語言轉譯和翻譯功能","B":"只協助特定語言的用戶","C":"修改影片內容","D":"增加影片解析度"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"影片索引器的協助工具功能透過語音轉譯與多語言翻譯，將影片內容轉成文字並以不同語言呈現，讓聽障者或不同語言背景的使用者都能理解影片內容。它不會修改影片本身，也與提升解析度無關。","concept":"影片索引器","aiExplained":true},{"id":"web-j1-462","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"影片分析系統理解極長時間序列的技術是：","options":{"A":"僅分析片段內容","B":"降低分析頻率","C":"簡化分析任務","D":"階層時間抽象與記憶壓縮機制"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"極長時間序列的影片無法把所有細節都平坦地留在記憶中，系統需要以階層式的時間抽象將內容分層摘要，並透過記憶壓縮機制保留關鍵資訊、捨棄冗餘細節，才能理解跨越長時間的事件脈絡。僅分析片段或降低分析頻率都會遺漏長程關聯。","concept":"長時序影片理解","aiExplained":true},{"id":"web-j1-463","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"臉部辨識數據結構概述主要是說明","options":{"A":"只能用於特定種族的人","B":"只能在特定光線下進行","C":"只能用於特定年齡段的人","D":"臉部辨識系統中的一對一比對功能"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"臉部辨識資料結構概述說明的是系統如何組織臉部資料以支援比對作業，其中一對一比對即「驗證」功能——確認眼前的人臉是否與特定已註冊者相符。其餘選項把系統限縮於特定種族、光線或年齡，都是錯誤的敘述。","concept":"臉部驗證比對","aiExplained":true},{"id":"web-j1-464","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"OCR技術識別後的文字通常會被組織成","options":{"A":"只有單個字元","B":"字組、文字行和段落或文字區塊","C":"只能識別完整段落","D":"只能識別特定格式的文字"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"OCR 辨識後不會只輸出零散字元，而是依照版面結構將結果組織成字組、文字行，再彙整為段落或文字區塊，方便後續依層級取用內容。這種階層式輸出是 OCR 服務的標準結果格式，其他選項都錯誤地限縮了輸出形式。","concept":"OCR輸出結構","aiExplained":true},{"id":"web-j1-465","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在自適應文件分析系統中，最重要的技術突破是：","options":{"A":"動態欄位關係學習與未見格式泛化能力","B":"更快的處理速度","C":"更大的模型容量","D":"多種輸出格式支援"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"自適應文件分析系統的價值在於面對從未見過的文件格式仍能正確運作，其關鍵突破是動態學習欄位之間的關係，並具備對未見格式的泛化能力。處理速度、模型容量或輸出格式支援都只是工程層面的改進，並非核心技術突破。","concept":"文件分析泛化","aiExplained":true},{"id":"web-j1-466","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"臉部辨識系統實現跨設備一致性的技術方法是：","options":{"A":"限制使用特定設備","B":"設備不變特徵與標準化管道","C":"降低跨設備標準","D":"要求使用相同設備"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"要讓臉部辨識在不同鏡頭、解析度與感光元件的設備上維持一致表現，關鍵是萃取不受設備差異影響的設備不變特徵，並建立標準化的影像處理管道統一輸入品質。限制或要求使用相同設備只是迴避問題，並未真正達成跨設備一致性。","concept":"跨設備一致性","aiExplained":true},{"id":"web-j1-467","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"OCR技術能夠識別","options":{"A":"只能識別印刷體文字","B":"印刷或手寫的文字","C":"只能識別英文字符","D":"只能識別數字和特殊符號"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-2/","explanation":"現代 OCR 模型透過多樣化的訓練資料，已能同時辨識印刷與手寫文字，並支援多種語言與書寫風格。宣稱僅能辨識印刷體、英文字符或數字符號的選項，都過度限縮了 OCR 的實際能力。","concept":"OCR辨識能力","aiExplained":true},{"id":"web-j2-468","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"下列哪項不是解決語言模型長文本生成\"重複循環\"問題的有效方法？","options":{"A":"引入懲罰機制降低已生成詞的概率","B":"增加模型層數","C":"使用束搜索（Beam Search）","D":"採用注意力約束機制"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"針對長文本生成的重複循環問題，常見對策包括對已生成詞施加懲罰以降低其再次出現的機率、調整束搜索等解碼策略，以及利用注意力約束避免模型反覆聚焦相同內容。單純增加模型層數只是擴大規模，並非針對重複問題的解法。","concept":"重複生成問題","aiExplained":true},{"id":"web-j2-469","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"Transformer模型中的解碼器負責：","options":{"A":"分析輸入數據的結構","B":"根據編碼器生成的隱含表示來生成輸出序列","C":"預處理輸入數據","D":"壓縮數據以節省存儲空間"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"在 Transformer 的編碼器—解碼器架構中，編碼器先將輸入序列轉換為隱含表示，解碼器再根據這些隱含表示逐步生成輸出序列，例如翻譯後的句子。解碼器並不負責分析輸入結構、預處理資料或壓縮儲存空間。","concept":"Transformer解碼器","aiExplained":true},{"id":"web-j2-470","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"生成式AI中的\"能力湧現\"（Emergent Abilities）現象指的是：","options":{"A":"模型在特定領域的突出表現","B":"模型規模增大後出現的新能力","C":"通過微調獲得的特定技能","D":"模型在不同任務間的知識遷移"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"能力湧現指模型參數規模與訓練資料量跨過某個門檻後，突然展現出小模型不具備的新能力，例如多步推理或程式撰寫。這種能力並非靠微調刻意訓練而來，也不是單指特定領域表現或知識遷移，而是隨規模增大自然浮現的現象。","concept":"能力湧現","aiExplained":true},{"id":"web-j1-471","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"PHI在醫療領域代表：","options":{"A":"個人歷史信息","B":"病患健康指數","C":"預防健康介入","D":"受保護的健康訊息"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"PHI 是 Protected Health Information 的縮寫，即「受保護的健康訊息」，指可識別個人身分的醫療與健康相關資料。在醫療 AI 應用中處理 PHI，必須遵循如美國 HIPAA 等嚴格的隱私法規，確保病患資料安全。","concept":"PHI隱私保護","aiExplained":true},{"id":"web-j2-472","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"現代語言模型中的\"上下文窗口限制\"主要影響：","options":{"A":"模型處理長文本的能力","B":"生成文本的創造性","C":"多語言處理能力","D":"對專業領域文本的理解"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"上下文窗口決定模型一次能納入注意力計算的 token 數量，超出窗口的內容便無法被模型「看見」，因此其限制主要影響處理長文本的能力。文本過長時模型會遺失前文資訊，導致理解與生成品質下降。","concept":"上下文窗口","aiExplained":true},{"id":"web-j1-473","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪種NLP任務通常不需要使用序列到序列（Seq2Seq）模型？","options":{"A":"機器翻譯","B":"文本摘要","C":"對話生成","D":"實體識別"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"機器翻譯、文本摘要與對話生成都是輸入一段序列、輸出另一段新序列的任務，屬於典型的 Seq2Seq 應用。實體識別則是對輸入序列中的每個詞進行標註分類，屬於序列標註問題，不需要生成新序列，因此通常不使用 Seq2Seq 模型。","concept":"Seq2Seq適用任務","aiExplained":true},{"id":"web-j1-474","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"遷移學習的主要優勢是：","options":{"A":"可以利用在一個任務上學到的知識來改進另一個相關任務","B":"可以完全取代傳統學習方法","C":"不需要任何訓練數據","D":"總是比從頭訓練更快"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"遷移學習的核心優勢在於將模型於某一任務上學到的知識，遷移到另一個相關任務，減少新任務所需的標註資料與訓練成本。它不能完全取代傳統學習方法，仍需要一定的訓練資料，訓練速度也視任務相關性而定，並非總是更快。","concept":"遷移學習","aiExplained":true},{"id":"web-j1-475","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"文本摘要技術應用於公司管理的主要優勢是：","options":{"A":"減少公司會議次數","B":"減少員工人數","C":"幫助公司高管快速掌握市場發展情況、公司內部狀況及會議要點","D":"自動生成演示文稿"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"文本摘要能將大量報告、會議紀錄與市場資訊濃縮成精簡重點，讓公司高階主管快速掌握市場發展、公司內部狀況與會議要點，提升決策效率。其價值在於資訊濃縮與快速吸收，而非減少會議次數或員工人數。","concept":"文本摘要應用","aiExplained":true},{"id":"web-j1-476","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"命名實體識別(NER)的主要目的是：","options":{"A":"識別和分類文本中的命名實體(如人名、地名)","B":"創建新的實體名稱","C":"翻譯實體名稱","D":"統計實體出現頻率"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"命名實體識別的目標是從文本中找出人名、地名、組織名等命名實體，並將其歸類到對應的類別，是資訊擷取的基礎步驟。它並非用來創造新名稱、翻譯實體名稱，統計出現頻率也只是後續可能的應用而非其目的。","concept":"命名實體識別","aiExplained":true},{"id":"web-j2-477","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"Transformer模型相比於RNN的主要優勢是：","options":{"A":"更容易訓練但準確性較低","B":"使用更少的計算資源","C":"只能處理短文本","D":"可以高效並行處理長序列數據"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"Transformer 以自注意力機制取代 RNN 的循環結構，序列中所有位置可同時計算，因此能高效並行處理長序列資料，大幅縮短訓練時間並更好地捕捉長距離依賴。RNN 必須逐步處理序列而難以並行化，這正是兩者的關鍵差異。","concept":"Transformer優勢","aiExplained":true},{"id":"web-j2-478","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"生成對抗網絡(GANs)的核心組件包括：","options":{"A":"編碼器和解碼器","B":"分類器和回歸器","C":"預處理器和後處理器","D":"生成器和判別器"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"生成對抗網絡由生成器與判別器兩個核心組件構成：生成器負責產生以假亂真的樣本，判別器負責分辨樣本是真實資料還是生成的。兩者在對抗訓練中相互提升，最終使生成品質不斷提高。","concept":"GAN架構","aiExplained":true},{"id":"web-j2-479","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"語言模型中的\"知識編輯\"（Knowledge Editing）技術主要解決的問題是：","options":{"A":"提高模型訓練效率","B":"增強模型的多語言能力","C":"優化模型的記憶使用","D":"更新模型中特定的事實性知識"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"知識編輯技術用於直接修改模型內部儲存的特定事實性知識，例如更正過時或錯誤的資訊，而不需重新訓練整個模型。它針對的是「模型知道什麼」，而非訓練效率、多語言能力或記憶體使用的最佳化。","concept":"知識編輯","aiExplained":true},{"id":"web-j1-480","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在實體連結（Entity Linking）中，最困難的挑戰是：","options":{"A":"識別命名實體的邊界","B":"對實體進行分類","C":"解決實體指代的歧義性","D":"建立完整的知識庫"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"實體連結要把文本中的提及對應到知識庫中的正確實體，最大的困難在於同一名稱可能指涉多個實體，例如「蘋果」可能是水果也可能是公司。解決這種指代歧義必須充分利用上下文語境，是實體連結中最具挑戰性的環節。","concept":"實體歧義消解","aiExplained":true},{"id":"web-j1-481","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在機器學習中，過擬合(Overfitting)意味著：","options":{"A":"模型太簡單，無法捕捉數據中的模式","B":"數據太少，無法訓練模型","C":"模型在訓練數據上表現良好，但在新數據上表現差","D":"模型太大，無法在標準計算機上運行"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"過擬合指模型過度記憶訓練資料中的細節與雜訊，導致在訓練資料上表現優異，但面對新資料時泛化能力差、表現明顯下滑。模型太簡單而無法捕捉資料模式屬於欠擬合，與過擬合正好相反。","concept":"過擬合","aiExplained":true},{"id":"web-j1-482","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在設計問答系統時，以下哪項技術最適合處理需要推理的複雜問題？","options":{"A":"基於檢索的方法","B":"模式匹配","C":"神經符號整合方法","D":"關鍵詞提取"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"需要推理的複雜問題往往得結合多個事實進行邏輯推導，單靠檢索、模式匹配或關鍵詞提取只能找到表面相關的內容。神經符號整合方法結合神經網路的語意理解與符號系統的邏輯推理能力，最適合處理這類問題。","concept":"神經符號整合","aiExplained":true},{"id":"web-j2-483","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"零樣本學習（Zero-shot Learning）在NLP中的應用優勢是：","options":{"A":"可處理未見過的類別或任務","B":"訓練速度比有監督學習更快","C":"只需少量計算資源","D":"模型大小比標準模型小"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"零樣本學習讓模型無需針對特定類別或任務的標註資料，即可直接處理未見過的類別或任務，主要仰賴預訓練階段學到的通用知識與語意關聯。其優勢在於對新任務的泛化能力，而非訓練速度、計算資源或模型大小。","concept":"零樣本學習","aiExplained":true},{"id":"web-j1-484","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在自然語言處理中，文本數據增強(Text Data Augmentation)技術的主要目的是：","options":{"A":"減少訓練時間","B":"減少模型參數","C":"增加訓練數據的多樣性，提高模型泛化能力","D":"簡化模型架構"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"文本數據增強透過同義詞替換、回譯、隨機刪改等方式產生多樣化的訓練樣本，目的在於增加訓練資料的多樣性，讓模型見過更多變化，進而提高泛化能力並降低過擬合風險。它並非為了縮短訓練時間、減少參數或簡化架構。","concept":"文本資料增強","aiExplained":true},{"id":"web-j2-485","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在大型語言模型中，\"模型崩潰\"（Model Collapse）現象指的是：","options":{"A":"訓練過程中損失突然增大","B":"生成過程中記憶耗盡","C":"處理長文本時的性能下降","D":"微調後模型輸出多樣性大幅降低"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"模型崩潰指模型輸出趨於單一、喪失多樣性的退化現象，對應到題目即微調後模型輸出多樣性大幅降低，反覆生成相似內容而失去原有的表達廣度。損失暴增、記憶耗盡或長文本效能下降都是其他類型的問題，並非模型崩潰的定義。","concept":"模型崩潰","aiExplained":true},{"id":"web-j2-486","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"語言模型的\"溫度參數\"（Temperature Parameter）主要影響：","options":{"A":"訓練速度","B":"生成文本的多樣性與隨機性","C":"模型對不同語言的處理能力","D":"記憶長文本的能力"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"溫度參數控制取樣時機率分布的平滑程度：溫度越高，分布越平坦，生成結果越多樣、越具隨機性；溫度越低，模型越傾向選擇高機率詞，輸出越保守穩定。因此它主要影響生成文本的多樣性與隨機性，與訓練速度或語言能力無關。","concept":"溫度參數","aiExplained":true},{"id":"web-j1-487","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在文字分類任務中，以下哪項是評估模型性能的常用指標？","options":{"A":"文本長度","B":"處理時間","C":"文件大小","D":"準確率和F1分數"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-3/","explanation":"文字分類任務常以準確率衡量整體預測正確的比例，並以 F1 分數兼顧精確率與召回率，特別適合類別不平衡的情況。文本長度、處理時間與檔案大小都與模型的分類品質無關，不能作為性能評估指標。","concept":"分類評估指標","aiExplained":true},{"id":"web-j2-488","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"稀疏注意力(Sparse Attention)機制的主要目的是：","options":{"A":"增加模型複雜性","B":"處理更長的序列並降低計算成本","C":"僅用於特定語言處理","D":"純粹為提高模型準確性"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"標準自注意力的計算量會隨序列長度呈平方成長，稀疏注意力讓每個標記只關注部分關鍵位置，大幅降低計算與記憶體成本，因此能處理更長的序列。增加模型複雜性、僅限特定語言或單純提高準確性，都不是稀疏注意力的設計目的。","concept":"稀疏注意力機制","aiExplained":true},{"id":"web-j1-489","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於自訂翻譯工具，下列敘述何者錯誤？","options":{"A":"可順暢整合到現有應用程式中","B":"只能用於翻譯特定領域的文本","C":"可透過平行處理的文件來自訂翻譯系統","D":"支持使用字典資料來訓練模型"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"自訂翻譯工具可利用平行處理的文件與字典資料來訓練專屬模型，並能順暢整合到現有應用程式中，這些都是正確特性。選項B的「只能」過於絕對，自訂翻譯系統並非僅限於特定領域的文本，因此是錯誤敘述。","concept":"自訂翻譯工具","aiExplained":true},{"id":"web-j1-490","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"關於說話者辨識技術，下列敘述何者錯誤？","options":{"A":"通過分析語音特性來驗證身份","B":"可用於安全驗證","C":"只能識別預先錄製的聲音","D":"能夠根據說話者的獨特聲紋進行身份識別"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"說話者辨識是透過分析語音特性與獨特聲紋來驗證或識別身份，常用於安全驗證情境，且能處理即時的語音輸入。選項C宣稱只能識別預先錄製的聲音，與此技術可即時辨識說話者的特性不符，故為錯誤敘述。","concept":"說話者辨識","aiExplained":true},{"id":"web-j1-491","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在深度學習模型中，權重(weight)和偏置(bias)的作用是？","options":{"A":"決定模型處理方式","B":"確定模型的訓練速度","C":"限制模型的輸出範圍","D":"控制模型的記憶容量"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"權重決定各輸入特徵對輸出的影響程度，偏置則調整神經元的啟動門檻，兩者是模型的可學習參數，共同決定模型如何處理與轉換輸入資料。訓練速度、輸出範圍限制或記憶容量都不是權重與偏置的直接作用。","concept":"權重與偏置","aiExplained":true},{"id":"web-j1-492","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在預先設定的功能中，\"可評估並傳回\"指的是？","options":{"A":"檢查系統穩定性","B":"記錄系統運行日誌","C":"預測系統性能","D":"系統能夠分析輸入的數據並生成相應的輸出"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"「可評估並傳回」描述的是功能接收輸入後進行運算評估，再將結果回傳的行為，也就是系統能分析輸入的數據並生成相應的輸出。檢查系統穩定性、記錄運行日誌或預測系統性能，都不符合這個描述。","concept":"函式評估與回傳","aiExplained":true},{"id":"web-j2-493","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"關於大型語言模型的訓練數據來源，下列敘述何者錯誤？","options":{"A":"包括書籍、文章和網頁","B":"數據量越大，模型學習能力越強","C":"數據多樣性有助於模型理解不同領域的知識","D":"訓練數據僅來自專業學術文獻"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"大型語言模型的訓練語料涵蓋書籍、文章與網頁等多元來源，資料量越大、多樣性越高，越有助於模型學習與理解不同領域的知識。選項D將訓練數據限定為僅來自專業學術文獻，與實際情況不符，故為錯誤敘述。","concept":"LLM訓練數據","aiExplained":true},{"id":"web-j1-494","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"命名實體識別(Named Entity Recognition)的主要功能是：","options":{"A":"僅識別文本中的人名","B":"只用於分類文檔類型","C":"在非結構化文本中識別並分類實體如人名、地點、組織等","D":"純粹用於改進搜索引擎"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"命名實體識別的核心任務是在非結構化文本中找出並分類人名、地點、組織等實體。它不是只識別人名，也不是用來分類文檔類型，改進搜索引擎只是其眾多下游應用之一，而非主要功能本身。","concept":"命名實體識別","aiExplained":true},{"id":"web-j1-495","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"自然語言理解和生成模型（如Gemini 1.5、Claude 3.5、Llama）的主要特點是：","options":{"A":"僅能處理特定主題","B":"只支援英文","C":"能處理多模態輸入並生成相應輸出","D":"僅用於學術研究"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"Gemini 1.5、Claude 3.5、Llama 這類新一代模型的主要特點，是能處理文字、影像等多模態輸入並生成相應輸出，應用範圍廣泛。它們不限於特定主題、不只支援英文，也絕非僅供學術研究使用。","concept":"多模態模型","aiExplained":true},{"id":"web-j2-496","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"令牌化（Tokenization）過程中，常見詞和不常見詞的處理方式有何不同？","options":{"A":"不常見詞會被完全忽略","B":"常見詞需要更多計算資源","C":"不常見詞只能以英文表示","D":"常見詞通常使用單一標記，不常見詞使用多個標記"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"現代分詞器多採用子詞策略：高頻的常見詞通常對應單一標記，不常見詞則被拆解成多個子詞標記的組合來表示，如此能在有限詞彙表下涵蓋各種詞形。不常見詞不會被忽略，也不是只能以英文表示。","concept":"子詞令牌化","aiExplained":true},{"id":"web-j2-497","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"可擴展性(Scalability)在大型語言模型中面臨的主要挑戰是：","options":{"A":"僅限於硬體限制","B":"只涉及數據存儲","C":"隨模型規模增長帶來的計算複雜度、能耗和推理延遲問題","D":"純粹是理論上的限制"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"模型規模持續擴大時，計算複雜度、訓練與推理的能耗，以及推理延遲都會急遽上升，這正是大型語言模型可擴展性面臨的核心挑戰。它不只是硬體或數據存儲的問題，更不是純粹理論上的限制。","concept":"模型可擴展性","aiExplained":true},{"id":"web-j2-498","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"生成式AI模型的訓練數據主要來源是：","options":{"A":"僅限於專業撰寫的教科書","B":"網際網路和其他公開文字來源","C":"只使用特定領域的技術文檔","D":"僅來自於受控實驗環境"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"生成式AI需要大量且多樣的語料才能學到廣泛的語言模式，主要來源是網際網路與其他公開文字來源，如網頁、書籍與文章。僅靠教科書、特定領域技術文檔或受控實驗環境，都無法提供足夠規模與多樣性的資料。","concept":"訓練數據來源","aiExplained":true},{"id":"web-j2-499","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"以下何者不是生成式AI的基礎模型？","options":{"A":"GPT-3","B":"GPT-4","C":"Claude","D":"SQL"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"GPT-3、GPT-4與Claude都是大型語言模型，屬於生成式AI的基礎模型。SQL是用來查詢與管理關聯式資料庫的結構化查詢語言，並不是AI模型，故選D。","concept":"基礎模型辨識","aiExplained":true},{"id":"web-j2-500","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"語言模型對齊(Alignment)研究的主要目標是：","options":{"A":"僅確保多語言一致性","B":"使AI系統行為符合人類意圖和價值觀","C":"純粹針對技術效能優化","D":"只關注模型大小縮減"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"對齊研究的核心目標是使AI系統的行為符合人類的意圖與價值觀，例如透過人類回饋強化學習讓模型輸出更有幫助且無害。它並非針對多語言一致性、技術效能優化或模型大小縮減的研究。","concept":"AI對齊","aiExplained":true},{"id":"web-j1-501","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"語言識別技術的主要應用是：","options":{"A":"僅用於安全驗證","B":"只能用於法律文件","C":"自動偵測文本或音訊的語言","D":"僅適用於偵測文本抄襲"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"語言識別技術的功能是自動偵測一段文本或音訊所使用的語言，常作為翻譯、語音辨識等流程的前置步驟。它並非僅限於安全驗證、法律文件或抄襲偵測等特定用途。","concept":"語言識別","aiExplained":true},{"id":"web-j2-502","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"關於Transformer模型中的前饋神經網絡(Feed-Forward Network)，下列敘述何者正確？","options":{"A":"只在編碼器中使用，不在解碼器中使用","B":"在每個子層中獨立應用於每個位置","C":"是模型的主要瓶頸，限制了整體性能","D":"主要用於處理序列間的依賴關係"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"Transformer的前饋神經網路以逐位置方式獨立作用於序列中的每個位置，且編碼器與解碼器的每一層都包含此子層，故B正確。負責處理序列間依賴關係的是注意力機制，而非前饋網路，它也不是限制整體性能的主要瓶頸。","concept":"前饋神經網路","aiExplained":true},{"id":"web-j1-503","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"文本嵌入(Text Embedding)的主要功能是？","options":{"A":"壓縮文本以節省存儲空間","B":"加密文本以保護隱私","C":"將文本轉換為向量空間的表示","D":"確保文本生成的一致性"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"文本嵌入將字詞或句子映射為向量空間中的數值表示，使語義相近的文本在向量空間中距離較近，方便模型進行計算、比較與檢索。它不是壓縮或加密技術，也與生成一致性無關。","concept":"文本嵌入","aiExplained":true},{"id":"web-j1-504","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在自然語言處理中，詞幹提取(Stemming)和詞形還原(Lemmatization)的主要區別是？","options":{"A":"詞幹提取只用於名詞，詞形還原用於所有詞類","B":"詞形還原考慮詞的語義，而詞幹提取僅基於規則","C":"詞幹提取更準確，詞形還原更快速","D":"詞形還原只用於英文，詞幹提取適用於所有語言"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"詞形還原會利用詞典與詞性等語言知識，將詞還原成有意義的原形；詞幹提取則僅依規則裁切詞尾，可能產生不成詞的結果。因此兩者的主要區別在於詞形還原考慮語義，而詞幹提取僅基於規則。","concept":"詞幹提取與還原","aiExplained":true},{"id":"web-j2-505","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"注意力機制(Attention Mechanism)在NLP中的主要作用是：","options":{"A":"幫助模型專注於輸入序列中的相關部分","B":"減少模型所需的記憶體","C":"提高模型訓練速度","D":"限制模型輸出的長度"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"注意力機制讓模型在處理每個標記時，能動態聚焦於輸入序列中與當前任務最相關的部分，有效捕捉長距離的依賴關係。它的目的不是減少記憶體、提高訓練速度或限制輸出長度。","concept":"注意力機制","aiExplained":true},{"id":"web-j2-506","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"生成式AI的主要特點是什麼？","options":{"A":"能夠創造獨特的文字、圖像或程式碼，而不需要明確的指令","B":"只能處理結構化的數據","C":"無法處理複雜的語言任務","D":"只能執行監督式學習"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"生成式AI的核心特點是能根據訓練中學到的模式，創造出新的文字、圖像或程式碼等內容，而不需要針對每項產出撰寫明確的指令。它能處理非結構化資料與複雜語言任務，訓練方式也不限於監督式學習。","concept":"生成式AI特性","aiExplained":true},{"id":"web-j1-507","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"聯邦學習(Federated Learning)的主要優勢是：","options":{"A":"保護隱私的同時允許多方共同訓練AI模型","B":"僅適用於醫療數據","C":"只能用於小型模型","D":"純粹提高計算效率"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-4/","explanation":"聯邦學習讓各參與方在本地訓練模型、只交換模型參數而不上傳原始資料，因此能在保護數據隱私的同時完成多方協同訓練，這是其主要優勢。它不限於醫療數據或小型模型，重點在隱私保護而非計算效率。","concept":"聯邦學習","aiExplained":true},{"id":"web-j2-508","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在負責任使用生成式AI的首階段，識別潛在危害的方法包括？","options":{"A":"系統性地評估可能產生的有害內容種類","B":"僅評估過去發生過的問題","C":"僅關注技術限制","D":"依賴用戶反饋報告"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"負責任使用生成式AI的第一階段是識別潛在危害，做法是系統性地評估模型可能產生的各類有害內容，事先盤點風險。只看過去發生的問題、只關注技術限制或被動依賴用戶反饋，都無法完整涵蓋潛在危害。","concept":"負責任AI流程","aiExplained":true},{"id":"web-j2-509","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"Transformer模型的核心組成包括哪兩個主要部分？","options":{"A":"輸入層和輸出層","B":"詞彙切分器和注意力機制","C":"向量空間和梯度下降","D":"編碼器和解碼器"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"Transformer架構由編碼器與解碼器兩大部分組成：編碼器將輸入序列轉換為語義表示，解碼器再據此生成輸出序列。詞彙切分器與注意力機制是其中的技術元件，並非架構的兩大主體。","concept":"編碼器與解碼器","aiExplained":true},{"id":"web-j1-510","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在設計階段，確認AI應用情境的目的是？","options":{"A":"確定AI模型的結構","B":"估算項目的成本","C":"按業務需求設計AI分析項目","D":"選擇合適的供應商"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"設計階段確認AI應用情境的目的，是根據實際業務需求來設計AI分析項目，確保技術方案對準真正要解決的問題。決定模型結構、估算成本與選擇供應商，都是其他環節處理的事項。","concept":"AI應用情境設計","aiExplained":true},{"id":"web-j1-511","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"Azure模型目錄中包含哪些合作夥伴的開源模型？","options":{"A":"僅有微軟自己的模型","B":"OpenAI、HuggingFace、Mistral和Meta等","C":"僅有Google和IBM的模型","D":"僅有中國開發的模型"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"Azure模型目錄除了微軟自家與OpenAI的模型外，也收錄HuggingFace、Mistral、Meta等合作夥伴的開源模型，讓開發者依需求挑選合適的模型。因此正確答案是涵蓋多家合作夥伴的選項B。","concept":"Azure模型目錄","aiExplained":true},{"id":"web-j2-512","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"解碼器處理階段中，預測過程主要依賴於什麼？","options":{"A":"僅依賴於輸入的原始文本","B":"編碼器的最終輸出值","C":"標記的數值向量形式和關鍵標記的選擇","D":"僅依賴於訓練數據中的高頻詞組"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"解碼器預測下一個標記時，依賴的是各標記的數值向量形式，並透過注意力機制挑選出最相關的關鍵標記作為預測依據。它並非只看輸入的原始文本或高頻詞組，也不是僅依賴編碼器的最終輸出值。","concept":"解碼器預測","aiExplained":true},{"id":"web-j1-513","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"模型卡(Model Cards)在負責任AI實踐中的主要作用是？","options":{"A":"僅記錄模型版本號","B":"僅作為市場營銷工具","C":"僅詳述硬體需求","D":"透明披露模型能力、局限性和潛在偏見"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"模型卡的作用是透明地披露模型的能力、適用範圍、局限性與潛在偏見，協助使用者判斷模型是否適合其應用情境，是負責任AI的重要實踐。它不只是版本紀錄、市場營銷工具或硬體需求說明。","concept":"模型卡","aiExplained":true},{"id":"web-j1-514","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"什麼是AI系統的「領域適應」(domain adaptation)？","options":{"A":"系統適應不同的計算環境","B":"訓練模型適應與訓練數據分佈不同的新領域","C":"調整用戶界面以適應不同的使用場景","D":"模型適應不同的編程語言"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"領域適應是指讓在某一資料分佈上訓練的模型，能遷移並適用於分佈不同的新領域，例如把以一般新聞語料訓練的模型調整到醫療文本上。它與計算環境、使用者介面或程式語言的適配無關。","concept":"領域適應","aiExplained":true},{"id":"web-j2-515","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"大型語言模型在多步驟推理任務中的主要局限是？","options":{"A":"僅受詞彙量限制","B":"僅受記憶體容量限制","C":"缺乏持續的工作記憶和自我糾錯能力","D":"僅受計算速度限制"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"大型語言模型在多步驟推理任務中，缺乏持續的工作記憶來追蹤中間狀態，也難以自我察覺並修正先前步驟的錯誤，因此長鏈推理容易出錯。這是能力層面的核心局限，而非單純的詞彙量、記憶體容量或計算速度問題。","concept":"LLM推理局限","aiExplained":true},{"id":"web-j2-516","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在開發醫療診斷輔助AI系統時，最關鍵的倫理考量是？","options":{"A":"僅關注計算速度","B":"僅考慮用戶界面設計","C":"透明度、可解釋性和公平性的平衡","D":"僅優化模型大小"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"醫療診斷輔助AI直接影響病患安全，最關鍵的倫理考量是在透明度、可解釋性與公平性之間取得平衡：醫師需能理解系統建議的依據，且系統不能對特定族群產生偏差。計算速度、介面設計或模型大小屬於技術面，並非倫理核心。","concept":"醫療AI倫理","aiExplained":true},{"id":"web-j1-517","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"對於內容過濾系統，保守錯誤(False Positive)和自由錯誤(False Negative)之間的權衡主要考慮什麼？","options":{"A":"過度審查與有害內容泄露的平衡","B":"只考慮計算效率","C":"僅考慮用戶滿意度","D":"僅考慮法規遵從"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"內容過濾若偏向保守，誤攔正常內容（False Positive）會造成過度審查；若偏向寬鬆，漏放有害內容（False Negative）則使其外洩。因此兩類錯誤的權衡，本質上就是在過度審查與有害內容泄露之間取得平衡。","concept":"過濾誤判權衡","aiExplained":true},{"id":"web-j1-518","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在AI系統中，「漏檢」(false negative)指的是什麼？","options":{"A":"系統識別出不存在的目標","B":"系統無法運行的狀態","C":"系統未能識別出實際存在的目標","D":"系統誤判目標類別"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"漏檢（false negative）指目標實際存在，系統卻未能將其識別出來，例如過濾器放行了真正的垃圾郵件。識別出不存在的目標則屬於誤報（false positive），兩者方向正好相反。","concept":"偽陰性漏檢","aiExplained":true},{"id":"web-j2-519","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"Azure OpenAI提供的模型不包括？","options":{"A":"GPT-4","B":"BERT","C":"DALL-E","D":"GPT-3.5-turbo"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"Azure OpenAI服務提供GPT-4、GPT-3.5-turbo等語言模型，以及DALL-E影像生成模型。BERT是Google提出的預訓練語言模型，不屬於Azure OpenAI提供的模型範圍，故選B。","concept":"Azure OpenAI","aiExplained":true},{"id":"web-j2-520","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"批量歸一化(Batch Normalization)在Transformer中的主要作用是？","options":{"A":"降低計算複雜度","B":"增加模型表達能力","C":"穩定訓練過程並加速收斂","D":"專門處理稀有詞彙"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"歸一化層的主要功能是將各層輸入的分佈調整得更穩定，減緩訓練過程中分佈飄移的問題，使訓練更穩定並加速收斂。它並非為了降低計算複雜度、增加表達能力或處理稀有詞彙而設計。","concept":"歸一化作用","aiExplained":true},{"id":"web-j1-521","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在AI導入中，數據的品質主要影響？","options":{"A":"模型的運行速度","B":"AI模型的學習效果和效能","C":"系統的成本","D":"用戶介面的設計"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"資料是AI模型學習的基礎，品質不佳（如缺漏、雜訊、偏差）會直接損害模型的學習效果與最終效能，即所謂「垃圾進、垃圾出」。運行速度、系統成本與使用者介面設計受資料品質的影響相對間接。","concept":"數據品質影響","aiExplained":true},{"id":"web-j1-522","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪項不是企業導入AI的發展階段？","options":{"A":"構想","B":"設計","C":"驗證POC","D":"批量生產"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"企業導入AI通常歷經構想、設計、POC驗證等發展階段，逐步確認可行性後再擴大部署。「批量生產」是製造業量產的概念，不屬於企業導入AI的發展階段，故選D。","concept":"AI導入階段","aiExplained":true},{"id":"web-j2-523","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在通過提示工程改進生成式AI回應時，\"落地數據\"指的是什麼？","options":{"A":"從地理位置資料庫獲取的資訊","B":"在提示中加入具體上下文資訊實現模型微調","C":"模型部署到實體伺服器上的過程","D":"用於評估模型性能的基準測試數據"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"在提示工程中，「落地數據」（grounding data）指在提示中加入具體的上下文資訊，讓模型的回應建立在所提供的事實基礎上，藉此提升回應的準確性與相關性。它與地理位置資料、實體伺服器部署或基準測試數據無關。","concept":"落地數據","aiExplained":true},{"id":"web-j2-524","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"以下哪一項不是Azure OpenAI的主要功能？","options":{"A":"提供多種AI模型供選擇","B":"整合安全和合規機制","C":"提供API接口供開發使用","D":"提供免費無限制的訓練資源"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"Azure OpenAI的主要功能包括提供多種AI模型供選擇、整合安全與合規機制，以及提供API接口供開發使用。雲端運算與訓練資源皆按用量計費，並不存在免費且無限制的訓練資源，故D不是其功能。","concept":"Azure服務功能","aiExplained":true},{"id":"web-j1-525","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在設備預測性維護AI系統中，短期和長期預測的區別主要在於？","options":{"A":"使用的模型類型","B":"數據的來源","C":"預測的時間範圍和應對措施","D":"系統的成本"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"設備預測性維護中，短期預測著重即將發生的故障並觸發即時應對，長期預測則支援備料與保養排程等規劃決策。兩者的區別主要在於預測的時間範圍與對應的應對措施，而非模型類型、數據來源或成本。","concept":"預測性維護","aiExplained":true},{"id":"web-j1-526","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"計算AI項目ROI時，除了量化效益外，還應考慮哪些因素？","options":{"A":"僅考慮硬體成本","B":"僅考慮軟體授權費用","C":"僅考慮人員培訓成本","D":"質化效益如安全提升、客戶滿意度及知識留存"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"計算AI項目ROI時，除了可量化的成本節省與效率提升外，還應納入質化效益，例如安全提升、客戶滿意度改善與組織知識留存，才能完整呈現項目價值。僅考慮硬體、軟體授權或培訓成本都過於片面。","concept":"AI項目ROI","aiExplained":true},{"id":"web-j1-527","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"預測序列\"The boy kicked\"中的下一標記時，模型會特別重視哪些詞？","options":{"A":"The, the","B":"The, is","C":"boy, the","D":"boy, kicked"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-5/","explanation":"注意力機制會對語義上最相關的詞賦予較高權重。預測「The boy kicked」的下一個標記時，主詞「boy」與動詞「kicked」最能決定後續內容（例如踢了什麼），因此模型會特別重視這兩個詞，而冠詞「The」的資訊量很低。","concept":"注意力權重","aiExplained":true},{"id":"web-j1-528","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"智慧交通系統使用AI技術的主要效益是什麼？","options":{"A":"僅提高汽車速度","B":"減少交通擁堵，提高行車效率","C":"僅增加停車位","D":"僅降低路面溫度"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"智慧交通系統透過AI即時分析車流資料、動態調控號誌與規劃路線，核心效益在於減少交通擁堵並提升整體行車效率。其他選項如提高汽車速度、增加停車位或降低路面溫度，都不是AI導入交通管理的主要目的。","concept":"智慧交通應用","aiExplained":true},{"id":"web-j1-529","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"NER技術在新聞文章分析中的主要功能是什麼？","options":{"A":"檢查新聞真實性","B":"自動生成新聞標題","C":"識別人名、地名、組織名等實體","D":"翻譯新聞內容"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"命名實體識別（NER）是自然語言處理的基礎技術，功能是從文本中自動辨識出人名、地名、組織名等具特定意義的實體。在新聞文章分析中，它能快速標註報導中的關鍵對象，作為後續資訊擷取與知識建構的基礎；查證真實性、生成標題或翻譯都不屬於NER的職責。","concept":"命名實體識別","aiExplained":true},{"id":"web-j2-530","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在AI系統的公平性評估中，最複雜的技術挑戰是？","options":{"A":"確定相關的人口統計變量","B":"收集足夠的代表性數據","C":"選擇適當的公平性度量","D":"解決多種公平性定義之間的固有衝突和權衡"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"公平性研究已證明，多種公平性定義（如群體公平、個體公平、校準與均等錯誤率）在數學上往往無法同時滿足，必須進行取捨，這是最深層的技術挑戰。相較之下，確定變量、收集代表性數據與選擇單一度量都是可操作的步驟，難度低於處理定義之間的固有衝突。","concept":"AI公平性權衡","aiExplained":true},{"id":"web-j1-531","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"無人機物流配送系統的AI決策模組面臨的最大挑戰是？","options":{"A":"電池續航問題","B":"導航精確度","C":"包裹取放機制","D":"在複雜城市環境中處理不可預測因素和緊急情況的即時決策"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"無人機在城市中配送時，必須面對行人、車輛、天候與突發障礙等高度不可預測的因素，AI決策模組要在極短時間內做出安全可靠的即時判斷，這是最核心的挑戰。電池續航、導航精度與取放機制屬於工程問題，相對已有成熟解法。","concept":"即時決策挑戰","aiExplained":true},{"id":"web-j1-532","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在自動化新聞撰寫系統中，AI面臨的最大困難是？","options":{"A":"識別真正重要的新聞要素並進行合理的因果分析","B":"產生語法正確的句子","C":"保持寫作風格的一致性","D":"整合多種信息來源"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"自動化新聞撰寫的瓶頸不在語言生成本身，而在於判斷哪些事實才是真正具新聞價值的要素，並對事件做出合理的因果分析，這需要接近人類的理解與推理能力。語法正確、風格一致與多來源整合，現有模型已能相當程度地處理。","concept":"新聞價值判斷","aiExplained":true},{"id":"web-j1-533","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"金融市場預測模型的最根本限制是？","options":{"A":"計算複雜度過高","B":"市場的隨機性和受非量化因素影響的程度","C":"歷史數據的品質問題","D":"特徵工程的難度"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"金融市場受政策、情緒、突發事件等大量無法量化的因素影響，且本質上具高度隨機性，因此任何預測模型都存在根本性的上限。計算複雜度、資料品質與特徵工程只是技術層面的困難，可以逐步改善，不構成最根本的限制。","concept":"市場隨機性","aiExplained":true},{"id":"web-j1-534","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"製造業中電腦視覺技術的缺陷檢測主要優勢是什麼？","options":{"A":"僅能降低生產成本","B":"僅能加快生產速度","C":"提高檢測精確度和速度，減少人為錯誤","D":"僅能檢測大型缺陷"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"電腦視覺可對產線影像進行高速且一致的自動判讀，同時提升缺陷檢測的精確度與速度，並避免人工目檢的疲勞與疏漏。其餘選項以「僅能」限縮單一效果，皆未能涵蓋此技術的核心價值。","concept":"視覺瑕疵檢測","aiExplained":true},{"id":"web-j2-535","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在生成式AI音樂創作中，最難實現的特性是？","options":{"A":"生成具有長期主題發展和情感敘事的原創複雜曲目","B":"模仿特定作曲家風格","C":"多樂器編曲","D":"遵循音樂理論規則"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"生成式AI擅長模仿特定風格、多樂器編曲與遵循樂理等模式性任務，但要創作具有長期主題發展與情感敘事弧線的原創複雜曲目，必須維持跨越長時間結構的一致性與音樂性表達，這是目前最難實現的特性。","concept":"音樂長程結構","aiExplained":true},{"id":"web-j1-536","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在疫情預測模型中，AI面臨的最大技術難題是？","options":{"A":"收集足夠的歷史數據","B":"計算資源的限制","C":"模型的部署和擴展","D":"整合人類行為變化和政策干預對傳播動態的複雜影響"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"疫情傳播動態會隨民眾行為改變與政策干預而劇烈變化，這些人為因素與病毒傳播互相回饋，難以用固定參數建模，因此整合這些複雜影響是AI疫情預測最大的技術難題。歷史數據、計算資源與部署擴展屬於一般工程議題。","concept":"疫情建模難點","aiExplained":true},{"id":"web-j1-537","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"數位資產管理(DAM)在廣告業中的主要用途是什麼？","options":{"A":"組織和管理大量影像、影片和音頻文件","B":"僅用於創建新廣告","C":"僅用於測量廣告效果","D":"僅用於分析競爭對手廣告"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"廣告業每天產出大量影像、影片與音頻素材，DAM系統的主要用途就是集中組織、標註與管理這些數位資產，方便團隊檢索與重複利用。其他選項都以「僅用於」描述單一狹隘功能，並非DAM的定位。","concept":"數位資產管理","aiExplained":true},{"id":"web-j1-538","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"數位資產管理(DAM)在製造業的主要應用是什麼？","options":{"A":"管理員工資料","B":"管理產品照片和設計圖等數位資源","C":"管理財務記錄","D":"管理生產排程"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"在製造業中，DAM主要用來集中管理產品照片、設計圖、3D模型等數位資源，確保設計與行銷部門能取得正確版本的素材。員工資料、財務記錄與生產排程分別屬於人資、財務與ERP／MES系統的範疇。","concept":"DAM製造應用","aiExplained":true},{"id":"web-j1-539","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在使用AI進行網絡安全防護時，最大的技術障礙是？","options":{"A":"處理大量網絡流量數據","B":"即時反應速度要求","C":"適應不斷演變且前所未見的攻擊模式","D":"與現有安全系統的整合"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"網路攻擊手法不斷演變，零時差攻擊等前所未見的模式沒有歷史樣本可供學習，AI防護系統必須具備偵測未知威脅的泛化能力，這是最大的技術障礙。處理大流量、即時反應與系統整合皆有較成熟的工程解法。","concept":"未知攻擊偵測","aiExplained":true},{"id":"web-j1-540","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在自動化農業AI系統中，作物疾病早期檢測的最大挑戰是？","options":{"A":"部署足夠的感應器","B":"在有限且不平衡的數據條件下識別症狀微弱的早期疾病跡象","C":"處理變化的光照條件","D":"系統的能源管理"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"作物疾病初期症狀微弱且樣本稀少，資料集往往高度不平衡，模型必須在這種有限且偏斜的數據條件下辨識早期病徵，是最大的挑戰。感應器部署、光照變化與能源管理屬於可克服的工程問題。","concept":"不平衡資料辨識","aiExplained":true},{"id":"web-j1-541","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在AI輔助的風險管理系統中，最難建模的風險類型是？","options":{"A":"市場風險","B":"信用風險","C":"系統性風險和黑天鵝事件","D":"操作風險"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"系統性風險與黑天鵝事件發生頻率極低、缺乏歷史樣本，且往往由前所未有的因素引發，超出模型從過去資料學到的分布，因此最難建模。市場、信用與操作風險都有較充足的數據與成熟的量化方法。","concept":"黑天鵝風險","aiExplained":true},{"id":"web-j1-542","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在金融市場AI預測系統中，最大的技術盲點是？","options":{"A":"處理高頻交易數據","B":"模型參數優化","C":"預測由新聞事件、政策變化或市場情緒引起的突發性波動","D":"系統的延遲問題"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"AI預測系統主要從歷史價格與量化數據學習規律，對於新聞事件、政策變化或市場情緒引發的突發性波動，因缺乏可學習的先兆訊號而難以預測，構成最大的技術盲點。高頻資料處理、參數優化與延遲皆屬工程上可解的問題。","concept":"突發波動預測","aiExplained":true},{"id":"web-j1-543","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在製造業的AI質量管理系統中，最具挑戰性的問題是？","options":{"A":"在高度多變的生產環境中識別罕見且微妙的品質偏差","B":"系統的部署成本","C":"員工的使用培訓","D":"資料儲存空間的需求"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"現代產線產品多樣且環境高度多變，罕見而微妙的品質偏差樣本極少，模型必須在變動條件下仍能精準辨識，是AI品質管理最具挑戰性之處。部署成本、使用培訓與儲存需求屬於管理與資源層面的問題。","concept":"罕見瑕疵辨識","aiExplained":true},{"id":"web-j1-544","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"多模態AI系統的核心技術挑戰是？","options":{"A":"處理多種數據類型的計算負擔","B":"不同模態數據之間深層語義關係的建模與融合","C":"數據存儲需求","D":"系統部署的複雜性"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"多模態AI的核心在於讓文字、影像、聲音等不同型態的資料在語義層面互相對齊與融合，因此不同模態間深層語義關係的建模與融合是最關鍵的技術挑戰。計算負擔、儲存需求與部署複雜性雖然存在，但屬於一般性工程議題。","concept":"多模態融合","aiExplained":true},{"id":"web-j1-545","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在AI輔助重症監護決策系統中，最大的技術挑戰是？","options":{"A":"處理多種醫療設備的數據","B":"系統反應速度","C":"用戶界面設計","D":"在高噪聲、不完整數據條件下做出可靠的時間關鍵型決策"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"重症監護資料常有雜訊、缺漏且病況瞬息萬變，AI必須在不完整資訊下即時做出攸關生命的可靠決策，時間關鍵性與資料品質的雙重壓力構成最大技術挑戰。設備資料整合、反應速度與介面設計相對容易處理。","concept":"時間關鍵決策","aiExplained":true},{"id":"web-j1-546","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在醫療AI的臨床實施中，最難克服的非技術障礙是？","options":{"A":"硬體資源限制","B":"數據標準化問題","C":"系統整合複雜性","D":"建立醫護人員的信任和克服對\"黑箱\"決策的抗拒"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"醫療AI落地最難的往往不是技術，而是醫護人員對「黑箱」決策的不信任：臨床人員需要理解模型依據，才敢採納建議並承擔醫療責任。建立信任與克服抗拒因此成為最難克服的非技術障礙，其餘選項皆屬技術層面問題。","concept":"醫療AI信任","aiExplained":true},{"id":"web-j1-547","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"氣象預測中的知識挖掘應用案例GraphCast模型的主要特點是什麼？","options":{"A":"僅預測特定區域天氣","B":"在1分鐘內提供未來10天全球天氣預測","C":"僅預測溫度變化","D":"僅預測短期天氣"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-6/","explanation":"GraphCast是DeepMind開發的氣象預測模型，能在約1分鐘內產出未來10天的全球天氣預測，速度遠快於傳統數值天氣預報，精度亦可與之匹敵。它並非僅限特定區域、單一變數或短期預測。","concept":"GraphCast模型","aiExplained":true},{"id":"web-j1-548","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在優化具有多個目標函數的機器學習模型時，下列哪種方法最為有效？","options":{"A":"僅優化主要目標","B":"簡單加權求和","C":"隨機優化單一目標","D":"帕累托前沿探索與多目標優化算法"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"當模型存在多個彼此衝突的目標函數時，帕累托前沿探索能找出「無法再改善某一目標而不犧牲其他目標」的解集合，讓決策者在明確的權衡中挑選，是多目標優化最有效的方法。僅優化單一目標或簡單加權求和都會遺漏重要的權衡資訊。","concept":"多目標優化","aiExplained":true},{"id":"web-j1-549","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在處理多來源融合資料集時，下列哪種策略最能改善特徵質量？","options":{"A":"簡單拼接所有特徵","B":"隨機選擇特徵子集","C":"領域知識引導的特徵交互設計","D":"忽略特徵來源差異"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"融合多來源資料時，由領域知識引導特徵之間的交互設計，能建立有意義的組合特徵並化解來源間的語義差異，最能改善特徵質量。簡單拼接或隨機挑選特徵子集忽略了資料間的關聯結構，效果有限。","concept":"特徵工程策略","aiExplained":true},{"id":"web-j1-550","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在多模型系統中，下列哪種集成策略通常能提供最穩健的預測結果？","options":{"A":"總是選擇最複雜的模型","B":"基於不確定性估計的自適應集成","C":"隨機選擇預測結果","D":"僅使用最新訓練的模型"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"基於不確定性估計的自適應集成，會依各模型對當前輸入的信心程度動態調整權重，讓可靠的模型主導預測，因此通常最為穩健。一味選最複雜或最新的模型、甚至隨機挑選結果，都無法保證泛化表現。","concept":"模型集成策略","aiExplained":true},{"id":"web-j1-551","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"Azure Machine Learning工作區的主要功能是什麼？","options":{"A":"提供一個集中位置處理所有機器學習成品","B":"處理大量資料的運算","C":"提供預訓練的模型","D":"分配運算資源"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"Azure Machine Learning工作區是機器學習專案的最上層資源，提供一個集中位置管理資料集、實驗、模型與端點等所有機器學習成品。運算處理、預訓練模型與資源分配是工作區內個別元件的職能，而非工作區本身的定位。","concept":"AzureML工作區","aiExplained":true},{"id":"web-j1-552","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在建立雲端AI服務時，下列哪項安全措施最能有效防止未授權使用？","options":{"A":"定期備份訓練資料","B":"實作金鑰輪替與最小權限原則","C":"增加模型複雜度","D":"使用冗餘儲存系統"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"防止雲端AI服務被未授權使用，關鍵在存取控制：定期輪替API金鑰可降低金鑰外洩後被濫用的風險，最小權限原則則確保每個身分只能存取必要資源。備份、模型複雜度與冗餘儲存屬於可靠性議題，與授權管控無關。","concept":"雲端存取安全","aiExplained":true},{"id":"web-j1-553","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在設計機器學習CI/CD流程時，下列哪個環節最能有效保障模型質量？","options":{"A":"最大化部署頻率","B":"整合自動化測試與驗證閾值","C":"簡化審批流程","D":"避免使用版本控制"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"在機器學習的CI/CD流程中，整合自動化測試並設定驗證閾值，能確保每次模型更新都通過效能與品質檢核才進入部署，是保障模型質量最有效的環節。一味追求部署頻率、簡化審批或捨棄版本控制反而會增加風險。","concept":"MLOps品質關卡","aiExplained":true},{"id":"web-j2-554","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在評估機器學習模型的公平性時，下列哪種方法最為全面？","options":{"A":"僅考慮整體准確率","B":"多標準公平性評估與對抗性測試","C":"避免分析群體差異","D":"使用單一公平性指標"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"單一指標無法涵蓋公平性的多重面向，採用多標準公平性評估並輔以對抗性測試，能同時檢視不同群體、不同定義下的表現與潛在漏洞，是最全面的做法。僅看整體準確率或迴避群體差異分析，都會掩蓋模型的偏誤。","concept":"公平性評估","aiExplained":true},{"id":"web-j1-555","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列哪項不是Azure AI服務功能測試的必要步驟？","options":{"A":"確認API連接與身份驗證","B":"確認輸入資料格式符合要求","C":"檢驗回應時間與模型輸出","D":"重新設計服務架構藍圖"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"功能測試的目的是驗證既有服務是否正常運作，因此包含確認API連接與身份驗證、檢查輸入資料格式，以及檢驗回應時間與模型輸出。重新設計服務架構藍圖屬於設計階段的工作，並非功能測試的必要步驟。","concept":"AI服務測試","aiExplained":true},{"id":"web-j1-556","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在Azure中，若要使用AI相關服務，首先需要建立什麼資源？","options":{"A":"Azure AI 中樞","B":"Azure 虛擬機器","C":"Azure 儲存體帳戶","D":"Azure SQL 資料庫"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"在Azure的AI開發流程中，須先建立Azure AI中樞作為統籌資源，才能在其下建立專案並取用各項AI服務。虛擬機器、儲存體帳戶與SQL資料庫是一般基礎架構資源，並非使用AI服務的先決條件。","concept":"Azure AI資源","aiExplained":true},{"id":"web-j2-557","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"El在設計企業級AI策略時，下列哪種方法最能確保長期成功？","options":{"A":"價值導向路線圖與技術債管理","B":"追求最新技術趨勢","C":"避免建立AI治理框架","D":"集中式技術決策"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"企業級AI策略要能長期成功，必須以商業價值為導向規劃路線圖，並同步管理技術債，確保投資聚焦且系統可持續演進。盲目追逐最新技術趨勢、缺乏治理框架或過度集中技術決策，都會讓AI布局失去方向與韌性。","concept":"企業AI策略","aiExplained":true},{"id":"web-j1-558","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在Azure機器學習中，虛擬機器的設定不包括考慮？","options":{"A":"CPU數量","B":"顏色主題","C":"記憶體大小","D":"運算能力"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"在Azure機器學習中設定虛擬機器時，考量的是CPU數量、記憶體大小與整體運算能力等效能規格，以符合訓練工作負載的需求。顏色主題屬於介面外觀設定，與虛擬機器的運算資源配置完全無關。","concept":"運算資源配置","aiExplained":true},{"id":"web-j1-559","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在處理高度稀疏的大規模數據時，下列哪種表示方法最為高效？","options":{"A":"密集矩陣存儲","B":"避免使用壓縮技術","C":"隨機特徵哈希","D":"優化的稀疏表示與高效索引結構"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"高度稀疏的大規模數據若以密集矩陣儲存，會浪費大量空間存放零值；採用優化的稀疏表示搭配高效索引結構，只儲存並運算非零元素，最能兼顧空間與計算效率。忽略壓縮或隨機哈希都無法達到同樣效果。","concept":"稀疏資料表示","aiExplained":true},{"id":"web-j1-560","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在設計企業AI系統連接架構時，下列哪種模式最能確保可擴展性？","options":{"A":"點對點直接集成","B":"集中式單體應用","C":"事件驅動微服務與API網關","D":"避免使用標準化接口"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"事件驅動的微服務架構搭配API網關，能讓各AI服務鬆耦合地獨立擴展，並由網關統一管理路由、認證與流量，是確保可擴展性的最佳模式。點對點直接集成與集中式單體都會隨系統成長而愈來愈難維護。","concept":"可擴展架構","aiExplained":true},{"id":"web-j1-561","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在Azure機器學習工作區中，什麼是Compute資源的主要功能？","options":{"A":"提供運算能力執行機器學習工作","B":"儲存訓練資料","C":"分析模型表現","D":"視覺化結果"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"在Azure Machine Learning工作區中，Compute資源的角色就是提供運算能力，用來執行模型訓練、管線與推論等機器學習工作。資料儲存、模型表現分析與結果視覺化分別由資料存放區、實驗記錄與其他工具負責。","concept":"AzureML運算","aiExplained":true},{"id":"web-j1-562","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在使用Azure Machine Learning時，什麼是設計工具(Designer)的主要優勢？","options":{"A":"提供更高的模型準確度","B":"提供視覺化介面建立機器學習流程","C":"減少資料處理時間","D":"自動調整模型參數"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"Azure Machine Learning的設計工具（Designer）提供拖放式的視覺化介面，讓使用者不必撰寫程式即可串接資料處理、訓練與評估模組，快速建立機器學習流程。它本身不保證更高準確度，也不是以自動調參為主要賣點。","concept":"視覺化ML流程","aiExplained":true},{"id":"web-j1-563","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在Azure Machine Learning中，以下哪項不是評估模型效能的指標？","options":{"A":"均方誤差(MSE)","B":"平均絕對誤差(MAE)","C":"計算時間","D":"決定係數(R²)"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"均方誤差（MSE）、平均絕對誤差（MAE）與決定係數R²都是評估迴歸模型預測效能的標準指標，衡量預測值與實際值的差距或解釋力。計算時間反映的是效率與成本，並非模型效能的評估指標。","concept":"迴歸評估指標","aiExplained":true},{"id":"web-j1-564","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在Azure Machine Learning中，確保模型品質的最佳實踐不包括？","options":{"A":"資料預處理","B":"交叉驗證","C":"參數調整","D":"增加模型複雜度"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"資料預處理、交叉驗證與參數調整都是提升模型品質的公認實務。單純增加模型複雜度不僅無法保證表現更好，反而容易造成過度擬合、降低泛化能力，因此不屬於確保模型品質的最佳實踐。","concept":"模型品質實務","aiExplained":true},{"id":"web-j1-565","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在機器學習中，將資料分成訓練集和測試集的比例通常為何？","options":{"A":"50:50","B":"70:30","C":"40:60","D":"90:10"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"機器學習實務上常以70:30的比例切分訓練集與測試集，讓模型有足夠資料學習，同時保留具代表性的樣本評估泛化能力。50:50會犧牲過多訓練資料，90:10則可能使測試結果不夠穩定。","concept":"資料切分比例","aiExplained":true},{"id":"web-j1-566","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI雲端服務的優勢之一是什麼？","options":{"A":"降低資料安全性風險","B":"減少硬體投資成本","C":"增加本地運算速度","D":"減少資料量需求"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"採用AI雲端服務時，企業不需自行採購與維護昂貴的GPU等硬體設備，按用量付費即可取得所需運算能力，因此能顯著減少硬體投資成本。雲端並不會提升本地運算速度，也不會降低資料量需求或消除安全風險。","concept":"雲端服務效益","aiExplained":true},{"id":"web-j1-567","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在優化AI服務的響應時間時，下列哪種策略通常最為有效？","options":{"A":"多級快取與計算預取","B":"增加模型複雜度","C":"集中處理所有請求","D":"避免使用並行處理"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-7/","explanation":"多級快取可讓重複性請求直接取用先前的結果，計算預取則預先準備可能用到的運算，兩者結合能大幅縮短AI服務的響應時間。增加模型複雜度或集中處理所有請求反而會拖慢回應，並行處理更是不可或缺的手段。","concept":"服務效能優化","aiExplained":true},{"id":"web-j2-568","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在健康醫療應用中使用AutoML的最關鍵挑戰是什麼？","options":{"A":"數據隱私、可解釋性和高準確性要求","B":"僅需考慮訓練速度","C":"醫療數據總是結構完整","D":"醫療模型不需要監管審批"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"醫療領域涉及病患個資，受法規嚴格保護，模型決策又直接影響診斷與治療，因此除了高準確性外，還必須兼顧數據隱私與可解釋性。訓練速度只是工程層面的考量，醫療數據實務上常有缺漏，模型上線前也多需通過監管審批，其餘選項的敘述皆與實務相反。","concept":"醫療AI關鍵挑戰","aiExplained":true},{"id":"web-j1-569","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在AutoML系統設計多層處理管道時，最重要的考量是什麼？","options":{"A":"確保所有步驟使用相同的算法","B":"防止數據洩漏和確保驗證的有效性","C":"最大化處理步驟的數量","D":"確保所有步驟有相同的運行時間"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"多層管道中若前處理步驟（如標準化、特徵選取）在切分資料前就接觸到驗證集或測試集的資訊，就會造成數據洩漏，使評估結果過度樂觀。因此設計管道時最重要的是確保每個步驟只以訓練資料擬合，維持驗證的有效性。步驟數量多寡、演算法是否一致或運行時間相同都不是核心考量。","concept":"數據洩漏防範","aiExplained":true},{"id":"web-j1-570","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在處理回歸問題時，AutoML系統可能使用哪些評估指標？","options":{"A":"僅使用準確率","B":"僅使用混淆矩陣","C":"僅使用F1分數","D":"均方誤差、平均絕對誤差或R平方"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"迴歸任務的預測目標是連續數值，因此採用均方誤差、平均絕對誤差與R平方等指標，衡量預測值與實際值之間的差距與解釋力。準確率、混淆矩陣與F1分數都是分類任務的評估工具，不適用於迴歸問題。","concept":"迴歸評估指標","aiExplained":true},{"id":"web-j1-571","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"機器學習中的「過擬合」問題是指：","options":{"A":"模型太簡單，無法捕捉數據特徵","B":"訓練時間過長","C":"模型對訓練數據擬合過度，無法很好地泛化到新數據","D":"計算資源不足"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"過擬合是指模型過度記住訓練資料的細節與雜訊，在訓練集上表現很好，但面對新資料時泛化能力差。模型太簡單而無法捕捉特徵屬於欠擬合，訓練時間過長與計算資源不足則與擬合程度沒有直接關係。","concept":"過擬合","aiExplained":true},{"id":"web-j1-572","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"自動化機器學習使用何種方式評估不同模型的表現？","options":{"A":"僅通過訓練集的損失函數","B":"主觀評估各模型的結果","C":"通過預先定義的評估指標來比較模型","D":"只考慮模型訓練時間"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"AutoML會依任務類型預先定義評估指標，例如分類用AUC、迴歸用均方誤差，並在驗證資料上以同一標準比較多個候選模型，客觀挑選表現最佳者。僅看訓練集損失容易被過擬合誤導，主觀評估與訓練時間都不是可靠的比較依據。","concept":"模型評估指標","aiExplained":true},{"id":"web-j1-573","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在AutoML中，為何選擇遠端計算而不是本機計算？","options":{"A":"遠端計算總是便宜的","B":"本機計算不支援神經網路","C":"遠端計算可以手動調整參數","D":"遠端計算可以平行處理提高效率"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"AutoML需要同時嘗試大量演算法與超參數組合，遠端計算叢集可將這些實驗平行分派到多個節點執行，大幅縮短整體搜尋時間、提高效率。遠端計算未必較便宜，本機同樣能訓練神經網路，手動調參更與遠端或本機無關。","concept":"平行運算效率","aiExplained":true},{"id":"web-j1-574","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"對於小型資料集或類別不平衡的資料，哪種計量可能是比較好的主要計量選擇？","options":{"A":"accuracy","B":"AUC_weighted","C":"precision_score_weighted","D":"norm_macro_recall"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"準確率在類別不平衡時會被多數類撐高而失真，在小型資料集上也不穩定。AUC_weighted依各類別的樣本數加權計算AUC，衡量模型整體的區辨能力，較不受類別比例影響，因此是小型或不平衡資料較合適的主要計量。","concept":"不平衡資料指標","aiExplained":true},{"id":"web-j1-575","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AutoML在網絡安全領域主要用於：","options":{"A":"密碼生成","B":"網絡設計","C":"用戶界面優化","D":"異常檢測和威脅識別"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"網路安全的核心需求是從大量流量與行為紀錄中找出偏離正常模式的訊號，AutoML可自動建立異常檢測與威脅識別模型，及早發現入侵或惡意行為。密碼生成、網路設計與使用者介面優化都不是它在資安領域的主要用途。","concept":"異常檢測應用","aiExplained":true},{"id":"web-j1-576","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在AutoML模型部署後，最重要的維護活動是什麼？","options":{"A":"定期重新訓練模型界面","B":"更新模型的視覺化效果","C":"定期更改模型名稱","D":"監控模型性能並處理模型漂移問題"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"模型上線後，輸入資料的分布會隨時間改變而產生模型漂移，若不持續監控性能並適時重新訓練，預測品質會逐漸下降。因此部署後最重要的維護工作是性能監控與漂移處理，而非更改名稱或更新視覺化等表面調整。","concept":"模型監控與漂移","aiExplained":true},{"id":"web-j1-577","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在Azure AutoML中，部署模型為Web服務的主要好處是什麼？","options":{"A":"減少模型的維護成本","B":"使模型能夠接收新數據並提供即時預測","C":"增加模型的精確度","D":"減少模型的大小"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"將模型部署為Web服務後，外部系統即可透過API即時傳入新數據並取得預測結果，讓模型真正投入營運使用。部署本身不會提升模型精確度，也不會縮小模型體積或必然降低維護成本。","concept":"模型部署服務","aiExplained":true},{"id":"web-j1-578","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在AutoML中，哪種類型的任務適合使用深度學習模型？","options":{"A":"簡單的二元分類","B":"基本回歸問題","C":"複雜的電腦視覺和自然語言處理任務","D":"小型資料集分析"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"深度學習擅長從高維、非結構化資料中自動學習階層式特徵，因此複雜的電腦視覺與自然語言處理任務最能發揮其優勢。簡單的二元分類、基本迴歸或小型資料集，使用傳統機器學習通常更有效率，也較不易過擬合。","concept":"深度學習適用任務","aiExplained":true},{"id":"web-j1-579","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在使用AutoML處理視頻數據時，最常見的挑戰是什麼？","options":{"A":"計算資源需求和時空特徵提取","B":"視頻數據總是結構化的","C":"視頻分類比圖像分類簡單","D":"視頻特徵提取不需要特殊處理"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"視頻由連續影格構成，除了每格影像的空間特徵，還要擷取跨影格的時間動態，資料量與運算量都極為龐大，因此計算資源需求與時空特徵提取是最常見的挑戰。其餘選項對視頻資料性質的描述都不正確。","concept":"視頻資料挑戰","aiExplained":true},{"id":"web-j1-580","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在設置計算目標時，虛擬機器大小是根據什麼提供建議的？","options":{"A":"只基於可用預算","B":"只根據預期的使用時間","C":"根據資料和實驗類型","D":"只基於數據大小"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"設置計算目標時，系統會依據資料的規模特性與實驗類型（如分類、迴歸或深度學習）推薦合適的虛擬機器大小，確保運算資源與工作負載相匹配。僅憑預算、預期使用時間或單看數據大小，都不足以做出合適的建議。","concept":"計算目標設定","aiExplained":true},{"id":"web-j1-581","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AutoML系統如何處理特徵間的非線性互動？","options":{"A":"總是忽略非線性關係","B":"僅使用線性模型","C":"通過特殊的特徵交叉或使用能夠捕捉非線性關係的模型","D":"刪除所有可能有非線性關係的特徵"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"特徵之間常存在非線性互動，AutoML可透過特徵交叉產生組合特徵，或直接選用樹模型、神經網路等能捕捉非線性關係的演算法來處理。忽略非線性、僅用線性模型或刪除相關特徵，都會犧牲模型的表達能力。","concept":"非線性特徵處理","aiExplained":true},{"id":"web-j1-582","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"使用AutoML處理文本數據時，常用的預處理技術是：","options":{"A":"影像縮放","B":"標記化和詞袋模型","C":"傅立葉變換","D":"主成分分析"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"文本必須先轉換成模型可運算的數值形式，常見做法是先做標記化將句子切成詞元，再以詞袋模型統計詞頻建立特徵向量。影像縮放與傅立葉變換屬於影像或訊號處理，主成分分析則是降維技術，皆非文本專屬的預處理。","concept":"文本預處理","aiExplained":true},{"id":"web-j1-583","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在自動化機器學習中，如何有效處理高度偏斜(Highly Skewed)的數值特徵？","options":{"A":"使用適當的變換來調整分布","B":"刪除所有偏斜特徵","C":"將所有值設為中位數","D":"忽略特徵分布形狀"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"高度偏斜的數值特徵會讓許多模型的分布假設失效，常用做法是套用對數、平方根或Box-Cox等變換，使分布更接近常態並降低極端值的影響。直接刪除特徵或一律改成中位數會損失資訊，忽略分布形狀則會拖累模型表現。","concept":"偏斜特徵變換","aiExplained":true},{"id":"web-j1-584","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"規模調整在特徵工程中的主要作用是：","options":{"A":"減少特徵數量","B":"增加特徵複雜度","C":"確保資料各個特徵在相似範圍內","D":"降低特徵的相關性"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"不同特徵的數值範圍可能相差極大，規模調整（如標準化、正規化）能把各特徵拉到相似的量級，避免大數值特徵主宰距離計算或梯度更新。它不會減少特徵數量，也不是為了增加複雜度或降低特徵間的相關性。","concept":"特徵縮放","aiExplained":true},{"id":"web-j1-585","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"自動化機器學習在處理大型資料集時的優勢是什麼？","options":{"A":"可在叢集節點上平行處理定型","B":"不需要資料預處理","C":"不需要特徵工程","D":"可以在沒有標記數據的情況下工作"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"面對大型資料集，自動化機器學習可將定型工作分散到叢集的多個節點平行執行，同時嘗試多組模型與參數，大幅縮短訓練時間。資料預處理、特徵工程與標記數據仍是必要環節，自動化並不代表可以省略。","concept":"分散式訓練","aiExplained":true},{"id":"web-j1-586","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在AutoML中，\"早期停止\"技術的主要目的是什麼？","options":{"A":"避免過度訓練而浪費計算資源","B":"防止模型參數過多","C":"增加模型的泛化能力","D":"減少記憶體的使用"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"早期停止會在模型表現不再改善時提前結束訓練，或淘汰表現不佳的迭代，避免把計算資源浪費在無效的過度訓練上。在AutoML需要大量嘗試模型與參數組合的情境下，這項技術能顯著節省時間與成本。","concept":"早期停止","aiExplained":true},{"id":"web-j1-587","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在AutoML系統中，什麼是\"特徵漂移\"(Feature Drift)，為何重要？","options":{"A":"輸入數據分布隨時間變化，影響模型性能","B":"特徵名稱的變更","C":"特徵重要性的定期波動","D":"特徵存儲位置的變更"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-8/","explanation":"特徵漂移指模型輸入數據的分布隨時間改變，例如客群結構或感測器特性變化，導致模型在新資料上的表現逐漸退化。因此模型上線後必須持續監控輸入分布，必要時重新訓練，這正是特徵漂移重要的原因。","concept":"特徵漂移","aiExplained":true},{"id":"web-j1-588","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"機器學習模型評估中的\"混淆矩陣\"(Confusion Matrix)主要用於？","options":{"A":"計算訓練時間","B":"測量計算困難度","C":"評估模型性能穩定性","D":"詳細分析分類錯誤類型"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"混淆矩陣把預測結果分成真陽性、偽陽性、真陰性與偽陰性，能清楚呈現模型把哪些類別誤判成哪些類別。透過它還可進一步計算精確率、召回率等指標，是詳細分析分類錯誤類型的核心工具。","concept":"混淆矩陣","aiExplained":true},{"id":"web-j1-589","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在貨車輪胎安全評估中，影像分類技術面臨的最大挑戰是：","options":{"A":"環境光線變化對模型判斷的影響","B":"輪胎品牌差異導致的誤判","C":"模型無法處理高解析度影像","D":"訓練資料不足的問題"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"輪胎檢測多在戶外或廠區等光線多變的環境進行，亮度、陰影與反光的變化會改變影像外觀，直接影響分類模型判斷的穩定性，是這類應用最大的挑戰。品牌差異、解析度或資料量問題，相對可以透過蒐集與標註策略緩解。","concept":"光線變化挑戰","aiExplained":true},{"id":"web-j1-590","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在視覺服務中，訓練時的\"疊代\"(Iteration)指的是？","options":{"A":"連續添加相同圖片","B":"模型訓練的版本或周期","C":"重複相同視角拍攝","D":"影像處理層數"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"在視覺服務（如Custom Vision）中，每次以現有資料完成一次訓練就產生一個「疊代」，代表模型的一個版本或訓練週期，可用來比較不同版本的成效並選擇要發布的模型。它與重複加入相同圖片或拍攝視角無關。","concept":"訓練疊代版本","aiExplained":true},{"id":"web-j1-591","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"Azure AI文件辨識服務在法律領域的主要價值是?","options":{"A":"替代法律專業人員","B":"降低法律成本","C":"快速搜尋和檢索關鍵條款","D":"生成法律文件"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"法律文件量大且條文繁複，Azure AI文件辨識能自動擷取文件中的關鍵欄位與條款，讓人員快速搜尋、檢索所需內容，大幅節省人工翻閱時間。它是輔助工具，並非取代法律專業人員，也不是用來生成法律文件。","concept":"文件辨識應用","aiExplained":true},{"id":"web-j1-592","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在自動機器學習中，VotingEnsemble 演算法的 AUC 數值為 0.94827，代表：","options":{"A":"模型僅能正確分類 94.827% 的資料","B":"模型區分正負類別的能力達到 94.827% 的準確度","C":"模型的誤報率為 5.173%","D":"模型已達到 94.827% 的最大訓練精確度"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"AUC衡量模型將正類樣本排在負類樣本之前的機率，0.94827代表模型區分正負類別的能力相當高，接近完美的1。它不等於分類正確率，也不能直接解讀為誤報率或訓練精確度。","concept":"AUC指標解讀","aiExplained":true},{"id":"web-j1-593","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"Focal Loss在目標檢測中的主要貢獻是：","options":{"A":"解決小目標被忽略的問題","B":"提高邊界框定位精度","C":"解決前景-背景類別嚴重不平衡問題","D":"減少訓練時所需的計算資源"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"目標檢測中背景樣本數量遠多於前景目標，一般交叉熵損失會被大量容易分類的背景樣本主導。Focal Loss透過調節因子降低易分類樣本的權重，讓訓練聚焦於困難樣本，有效解決前景與背景類別嚴重不平衡的問題。","concept":"Focal Loss","aiExplained":true},{"id":"web-j1-594","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"視覺問答（Visual Question Answering）技術結合了哪些AI領域？","options":{"A":"計算機視覺與強化學習","B":"計算機視覺與自然語言處理","C":"計算機視覺與語音識別","D":"計算機視覺與推薦系統"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"視覺問答要求系統看懂影像內容，同時理解並回答自然語言提出的問題，因此結合了計算機視覺與自然語言處理兩大領域的技術。強化學習、語音識別與推薦系統都不是視覺問答的核心組成。","concept":"視覺問答技術","aiExplained":true},{"id":"web-j1-595","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在長期運行的AI視覺系統中，概念漂移（Concept Drift）指的是：","options":{"A":"模型參數隨時間緩慢變化","B":"用戶對系統功能的需求變化","C":"模型理解能力隨規模增長","D":"數據分佈特性隨時間發生變化"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"概念漂移指資料的統計特性隨時間發生變化，使模型當初學到的規律不再適用；長期運行的視覺系統會因場景、物件外觀或使用情境改變而性能下降。因此需要持續監控模型表現，並定期以新資料重新訓練。","concept":"概念漂移","aiExplained":true},{"id":"web-j1-596","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在Custom Vision的訓練過程中，若資料量有限，應優先選擇哪種訓練方式?","options":{"A":"Advanced Training","B":"Quick Training","C":"Transfer Learning","D":"Reinforcement Learning"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"Custom Vision的快速訓練能在短時間內完成建模，適合資料量有限或需要快速驗證迭代的情境；進階訓練需投入更多運算時間與成本，通常在資料較多、任務較困難時才採用。遷移學習與強化學習並非Custom Vision提供的訓練方式選項。","concept":"快速訓練","aiExplained":true},{"id":"web-j1-597","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在機器學習部署環境中，容器(Container)的主要優勢是？","options":{"A":"無需網絡連接","B":"完全免費使用","C":"環境一致性和隔離性","D":"無需維護更新"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"容器將模型、程式碼與相依環境打包成一致的執行單元，確保開發、測試與生產環境行為一致，且彼此隔離互不干擾，因此成為機器學習部署的主流做法。容器仍需要網路連線與持續維護更新，也未必完全免費。","concept":"容器化部署","aiExplained":true},{"id":"web-j1-598","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在不平衡分類問題中，下列哪種評估指標最適合用來評估模型性能？","options":{"A":"準確率（Accuracy）","B":"錯誤率（Error Rate）","C":"均方誤差（Mean Squared Error）","D":"F1分數（F1 Score）"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"類別不平衡時，準確率與錯誤率都會被多數類撐高而失真；F1分數是精確率與召回率的調和平均，能同時反映誤報與漏報，更適合評估少數類的辨識能力。均方誤差則是迴歸任務的指標，不適用於分類問題。","concept":"F1分數","aiExplained":true},{"id":"web-j1-599","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在機器學習工作流程中，模型訓練完成後的下一個關鍵步驟是什麼？","options":{"A":"刪除訓練數據","B":"重新標記數據","C":"評估模型表現","D":"變更算法參數"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"模型訓練完成後，必須先在驗證或測試資料上評估表現，確認泛化能力達標，才能決定要調整模型還是進入部署。刪除訓練數據、重新標記或直接變更參數，都不是訓練完成後的標準下一步。","concept":"模型評估流程","aiExplained":true},{"id":"web-j1-600","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在Azure機器學習自動化實驗中，表現最好的模型通常是?","options":{"A":"訓練時間最長的","B":"最簡單的模型","C":"集成模型(Ensemble)","D":"最早訓練的模型"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"Azure自動化機器學習通常會在實驗最後訓練VotingEnsemble與StackEnsemble等集成模型，結合多個表現較佳的個別模型的預測，因此排行榜上表現最好的通常是集成模型。訓練時間長短或訓練順序與最終表現沒有必然關係。","concept":"集成模型","aiExplained":true},{"id":"web-j1-601","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"卷積神經網路中殘差連接（Residual Connections）的主要作用是：","options":{"A":"解決深層網路中的梯度消失問題","B":"減少模型參數總量","C":"提高卷積操作的計算效率","D":"增強模型對旋轉不變性的能力"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"殘差連接讓輸入可以跳過若干層直接與輸出相加，梯度得以沿著捷徑回傳，緩解深層網路的梯度消失問題，使數十甚至上百層的網路能有效訓練。它並不會減少參數總量、提升卷積效率或帶來旋轉不變性。","concept":"殘差連接","aiExplained":true},{"id":"web-j1-602","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在文件智能化處理中，OCR技術之後通常需要進行什麼處理？","options":{"A":"影像壓縮","B":"文本語義分析","C":"文件加密","D":"水印添加"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"OCR只負責把影像中的文字轉成機器可讀的字元，若要理解內容、擷取關鍵資訊或進行文件分類，還需要後續的文本語義分析。影像壓縮、文件加密與添加水印都與理解文字內容無關。","concept":"OCR後續處理","aiExplained":true},{"id":"web-j1-603","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在 Azure AI 服務中，建立自訂電腦視覺模型時，下列哪種資源最適合用於高效能推論？","options":{"A":"免費試用版資源","B":"標準 S0 定價層級","C":"Azure Container Instances","D":"Azure Kubernetes Service"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"建立自訂電腦視覺資源時，標準S0定價層級提供比免費層更高的交易速率與配額，能支撐正式環境的高效能推論需求。免費試用層有嚴格的速率限制，Azure Container Instances與Kubernetes Service則屬於部署運算選項，不是此處的資源定價層級。","concept":"定價層級選擇","aiExplained":true},{"id":"web-j1-604","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"對 OCR 技術自動擷取和辨識合約內容的系統而言，最大的限制是：","options":{"A":"處理非標準格式或手寫文件的能力有限","B":"無法處理大型文件","C":"僅支援英文文件","D":"處理速度過慢"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"OCR對印刷體、版面固定的文件辨識效果最好，但合約常出現非標準格式、掃描品質不一或手寫簽註，系統處理這類內容的能力有限，是最大的限制。現代OCR多已支援多語言與大型文件，處理速度也相當快。","concept":"OCR技術限制","aiExplained":true},{"id":"web-j1-605","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在電腦視覺應用中，為確保模型的泛化能力，訓練數據應該?","options":{"A":"僅包含高品質圖像","B":"包含多樣化的場景和條件","C":"只使用專業相機拍攝的圖像","D":"限制在特定光線條件下"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"訓練資料若涵蓋多樣化的場景、光線、角度與拍攝條件，模型才能學到具普遍性的特徵，在真實環境的各種狀況下維持穩定表現。只使用高品質、專業相機或單一光線條件的影像，反而會讓模型在條件改變時失準。","concept":"資料多樣性","aiExplained":true},{"id":"web-j1-606","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在電腦視覺應用中，物件偵測技術最適合用來解決什麼問題?","options":{"A":"臉部情緒辨識","B":"文字翻譯","C":"語音辨識","D":"檢測焊接點的合規性"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"物件偵測不僅辨識影像中有哪些目標，還能框出每個目標的位置，適合在影像中逐一找出焊接點並檢查其合規性。臉部情緒辨識偏向影像分類，文字翻譯與語音辨識則分屬自然語言處理與語音領域。","concept":"物件偵測應用","aiExplained":true},{"id":"web-j1-607","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在Azure AI服務中，「視覺 + 文件」功能主要用於何種應用?","options":{"A":"語音轉文字","B":"使用OCR技術擷取文件內容","C":"產生圖像描述","D":"創建語音助手"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-9/","explanation":"Azure AI服務的「視覺＋文件」功能結合OCR技術，能從掃描檔或影像中擷取印刷與手寫文字等文件內容，支援後續的資料處理與分析。語音轉文字、產生圖像描述與建立語音助手分屬其他服務的功能範圍。","concept":"文件OCR擷取","aiExplained":true},{"id":"web-j2-608","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在語言模型的推理過程中，\"貪婪解碼\"(Greedy Decoding)策略的特點是：","options":{"A":"總是選擇最不可能的下一個標記","B":"隨機選擇下一個標記","C":"遍歷所有可能的解碼路徑","D":"總是選擇最可能的下一個標記"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"貪婪解碼在每一步都直接挑選機率最高的下一個標記，不做任何隨機取樣或路徑回溯。這種策略計算簡單、速度快，但容易陷入局部最佳而錯過整體更好的生成結果。相較之下，遍歷所有路徑屬於窮舉搜索，隨機挑選則是取樣式解碼的做法。","concept":"貪婪解碼","aiExplained":true},{"id":"web-j2-609","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在大型語言模型中，\"符號接地問題\"(Symbol Grounding Problem)主要關注：","options":{"A":"模型如何將符號與實際概念連接","B":"如何選擇最佳的分詞器","C":"數學符號的處理方法","D":"編程語言的解析能力"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"符號接地問題探討的是符號（如文字）如何與真實世界的概念和經驗建立連結，而不只是符號之間的相互指涉。對大型語言模型而言，這關係到模型是否真正理解語意，還是只在操弄統計關聯，與分詞器選擇或程式解析能力無關。","concept":"符號接地問題","aiExplained":true},{"id":"web-j2-610","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"零樣本學習(Zero-shot Learning)的核心思想是：","options":{"A":"使用零個樣本進行訓練","B":"模型能處理訓練中未見過的類別或任務","C":"不需要任何參數即可學習","D":"只處理簡單且明確定義的任務"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"零樣本學習指模型不需要針對特定任務的標註範例，就能處理訓練階段未見過的類別或任務。它依靠預訓練階段學到的廣泛知識與語意關聯來泛化，而非「用零個樣本訓練」這種字面解讀，也不表示不需要任何參數。","concept":"零樣本學習","aiExplained":true},{"id":"web-j2-611","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"Microsoft Power Automate中，「觸發程序」的主要功能是：","options":{"A":"結束工作流程","B":"啟動工作流程","C":"修改工作流程","D":"儲存工作流程"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"在 Power Automate 中，觸發程序（Trigger）是整個流程的起點，當特定事件發生（如收到郵件、表單送出）時便自動啟動後續的動作序列。沒有觸發程序，工作流程就不會被執行；結束、修改與儲存都不是它的職責。","concept":"自動化觸發程序","aiExplained":true},{"id":"web-j1-612","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"下列哪項不是評估AI情緒分析結果的有效指標？","options":{"A":"準確率","B":"召回率","C":"處理時間長短","D":"F1分數"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"情緒分析屬於分類任務，評估其結果品質時常用準確率、召回率與F1分數等指標。處理時間長短反映的是系統效能而非分析結果的正確性，因此不是評估情緒分析「結果」的有效指標。","concept":"分類評估指標","aiExplained":true},{"id":"web-j1-613","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在Azure Portal中，若要建立新的資源，應該點選：","options":{"A":"所有服務","B":"建立資源","C":"儀表板","D":"我的資源"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"Azure Portal 的功能表提供「建立資源」選項，點選後即可從市集挑選並部署新的服務或資源。「所有服務」用於瀏覽既有服務類別，儀表板則是個人化的監控頁面，皆非建立新資源的入口。","concept":"Azure資源建立","aiExplained":true},{"id":"web-j1-614","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪項不是解決AI模型中出現災難性遺忘(Catastrophic Forgetting)的有效策略？","options":{"A":"彈性權重合併","B":"知識蒸餾","C":"增加批量大小","D":"漸進式學習"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"災難性遺忘指模型學習新任務時覆蓋掉舊任務知識的現象，常見因應策略包括彈性權重合併（EWC）、知識蒸餾與漸進式學習。單純增加批量大小只影響訓練效率與穩定性，無法幫助模型保留舊知識。","concept":"災難性遺忘","aiExplained":true},{"id":"web-j2-615","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在評估生成式AI的創意內容時，最具挑戰性的方面是：","options":{"A":"創造力評估的主觀性","B":"計算效率的量化","C":"模型大小的影響","D":"硬體加速的可用性"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"創意內容的好壞高度依賴個人審美與文化背景，缺乏統一客觀的量化標準，因此主觀性是評估生成式AI創意作品時最大的挑戰。計算效率或模型大小都可以客觀量測，評估難度相對低得多。","concept":"生成內容評估","aiExplained":true},{"id":"web-j2-616","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"以下哪一項不是評估大型語言模型性能的標準基準測試？","options":{"A":"MNISTBench","B":"MMLU","C":"HumanEval","D":"TruthfulQA"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"MMLU 測多領域知識、HumanEval 測程式生成、TruthfulQA 測回答真實性，三者都是常見的大型語言模型基準測試。MNISTBench 並不存在；MNIST 是手寫數字影像資料集，與語言模型評測無關。","concept":"LLM基準測試","aiExplained":true},{"id":"web-j2-617","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"以下哪種不是大型語言模型常用的解碼策略？","options":{"A":"貪婪解碼","B":"集束搜索","C":"核採樣","D":"隨機梯度冷卻"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"貪婪解碼、集束搜索（Beam Search）與核採樣（Nucleus Sampling）都是語言模型生成文字時常用的解碼策略。「隨機梯度冷卻」是杜撰的名詞；梯度相關方法屬於訓練階段的優化技術，與解碼無關。","concept":"解碼策略","aiExplained":true},{"id":"web-j2-618","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在生成式AI的基礎模型訓練過程中，\"token\"最適當的定義是什麼？","options":{"A":"一個完整的句子","B":"一個段落","C":"文本的基本單位，可能是單詞、字元或其組合","D":"僅限於單一字母"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"Token 是模型處理文本的基本單位，經分詞器切分後可能對應完整單詞、子詞、字元或其組合。它既不限於單一字母，也不等同於句子或段落這類較大的文本結構。","concept":"Token定義","aiExplained":true},{"id":"web-j2-619","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"參數高效微調(PEFT)方法的主要優勢是：","options":{"A":"顯著減少訓練資源需求","B":"完全避免災難性遺忘","C":"確保100%的領域適應","D":"消除對原始預訓練模型的依賴"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"參數高效微調（如 LoRA、Adapter）只更新少量新增或選定的參數，凍結大部分預訓練權重，因此能大幅降低運算與記憶體需求。它能緩解但無法完全避免災難性遺忘，也不保證百分之百的領域適應，更仍然依賴原始預訓練模型。","concept":"參數高效微調","aiExplained":true},{"id":"web-j1-620","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"AI內容生成在行銷領域中最常用於？","options":{"A":"確定產品定價策略","B":"創建吸引人的文案和視覺內容","C":"選擇目標受眾群體","D":"決定行銷預算分配"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"生成式AI在行銷上最普遍的應用是快速產出廣告文案、社群貼文與視覺素材，協助創意內容的大量產製與個人化。定價策略、受眾選擇與預算分配屬於策略決策，多半仍以數據分析與人為判斷為主。","concept":"AI行銷應用","aiExplained":true},{"id":"web-j2-621","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在生成式AI行程規劃中，為確保生成內容的準確性，應該：","options":{"A":"提供明確的限制條件","B":"使用專業術語","C":"避免設定特定地點","D":"僅提供籠統的需求"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"在提示中明確給出日期、預算、地點、人數等限制條件，能縮小模型的生成空間，使行程內容更貼近實際需求並減少憑空編造。需求越籠統，模型越容易產生不準確或不可行的安排。","concept":"提示限制條件","aiExplained":true},{"id":"web-j1-622","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列哪項是設計高效自動化流程的關鍵元素？","options":{"A":"複雜的分支結構","B":"清晰的錯誤處理機制","C":"最少的人工監督","D":"最快的執行速度"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"自動化流程通常在無人值守下運行，一旦某步驟失敗，若缺乏清晰的錯誤處理機制，錯誤會沿流程擴散甚至造成資料損毀。因此妥善的例外偵測、通知與重試設計是高效自動化的關鍵；複雜分支或一味追求速度反而增加維護風險。","concept":"自動化錯誤處理","aiExplained":true},{"id":"web-j2-623","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在生成式AI評估中，\"困惑度\"(Perplexity)測量的是：","options":{"A":"模型處理複雜任務的能力","B":"模型對下一個標記的預測準確程度","C":"模型生成多樣性文本的能力","D":"模型訓練的複雜程度"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"困惑度衡量模型對測試文本中下一個標記的預測有多不確定，數值越低代表模型預測越準確、對語言分布的掌握越好。它並不直接反映生成多樣性、任務複雜度或訓練的複雜程度。","concept":"困惑度","aiExplained":true},{"id":"web-j1-624","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列關於模型蒸餾(Model Distillation)的說法，哪一項是錯誤的？","options":{"A":"學生模型通常比教師模型有更多參數","B":"可以提高模型的部署效率","C":"學生模型學習教師模型的\"暗知識\"","D":"軟標籤通常比硬標籤包含更多信息"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"模型蒸餾是讓小的學生模型模仿大的教師模型，因此學生模型參數通常「少於」教師模型，選項A的敘述剛好相反。蒸餾透過教師輸出的軟標籤傳遞暗知識，能在縮小模型的同時保留多數效能，提升部署效率。","concept":"模型蒸餾","aiExplained":true},{"id":"web-j1-625","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"使用雲端AI服務時，哪項操作可能違反服務條款？","options":{"A":"處理大量公開數據","B":"創建自動回覆系統","C":"處理未經授權的個人資料","D":"自動化報告生成"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"各大雲端AI服務的條款都要求用戶合法取得並處理資料，未經授權處理他人個人資料會違反服務條款，也可能觸犯個資保護法規。處理公開數據、建立自動回覆系統或自動化報告生成則屬正常使用範圍。","concept":"雲端服務合規","aiExplained":true},{"id":"web-j2-626","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"Transformer架構中的\"自注意力機制\"(Self-Attention)的核心優勢是什麼？","options":{"A":"比RNN結構需要更多的計算資源","B":"可以並行處理序列中的所有元素","C":"只關注序列中的關鍵詞","D":"無法處理長序列"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"自注意力機制讓序列中每個位置同時與所有其他位置計算關聯，不必像RNN那樣逐步依序處理，因此可以充分並行化、大幅加速訓練。這種設計也讓模型更容易捕捉長距離的依賴關係。","concept":"自注意力機制","aiExplained":true},{"id":"web-j1-627","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"使用Excel Online儲存AI分析結果的好處是：","options":{"A":"易於分享與後續分析","B":"無需網絡連接","C":"支援大規模資料處理","D":"提供內置的機器學習演算法"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a-10/","explanation":"Excel Online 是雲端試算表，檔案存放於雲端後可直接以連結分享、多人共同編輯，便於團隊後續整理與分析AI產出的結果。它需要網路連線，不內建機器學習演算法，也不適合超大規模資料處理。","concept":"雲端協作工具","aiExplained":true},{"id":"web-j2-628","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"Low Code 開發中的「資料視覺化」(Data Visualization) 元件主要用於：","options":{"A":"創建動態圖表和儀表板顯示業務數據","B":"僅生成靜態報告","C":"取代所有商業智能工具","D":"只用於特定類型的圖表"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"資料視覺化元件讓開發者以拖拉方式建立動態圖表與儀表板，即時呈現業務數據並支援互動式操作。它並非只能輸出靜態報告，也不是要全面取代專業商業智能工具，更不限於特定圖表類型。","concept":"資料視覺化元件","aiExplained":true},{"id":"web-j2-629","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"在 Low Code 開發中實施「微前端架構」(Micro-Frontend Architecture) 的核心挑戰是：","options":{"A":"無法在 Low Code 環境中實現","B":"僅適用於大型企業","C":"在視覺化開發環境中管理獨立開發、測試和部署的 UI 組件，確保一致的用戶體驗","D":"只能通過大量自定義代碼實現"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"微前端把使用者介面拆成可獨立開發、測試與部署的組件，搬到 Low Code 的視覺化環境時，難點在於如何管理這些獨立UI組件並維持一致的用戶體驗。這並非做不到，也不是只有大型企業或依賴大量自定義代碼才能實現。","concept":"微前端架構","aiExplained":true},{"id":"web-j2-630","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"關於 No Code/Low Code 平台在「法規嚴格行業」(Highly Regulated Industries) 中的 GxP 驗證，以下哪項描述最準確？","options":{"A":"需要建立平台驗證策略，包括供應商評估、風險分析和功能測試的文檔證據鏈","B":"無法在受監管環境中使用 No Code/Low Code 平台","C":"GxP 驗證僅適用於傳統開發方法","D":"只需驗證最終應用，無需關注平台本身"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"在製藥等 GxP 受監管環境導入 No Code/Low Code 平台，必須建立完整的平台驗證策略，涵蓋供應商評估、風險分析與功能測試的文檔證據鏈，證明系統適用於預期用途。監管要求同樣及於平台本身，不能只驗證最終應用。","concept":"GxP平台驗證","aiExplained":true},{"id":"web-j2-631","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"在環境監測應用中，No Code 平台主要用於：","options":{"A":"控制關鍵環境系統","B":"取代所有環境管理軟體","C":"開發傳感器數據收集和可視化應用","D":"僅用於合規報告"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"環境監測情境中，No Code 平台常用來快速開發蒐集傳感器數據並加以視覺化的應用，例如即時儀表板與警示通知。控制關鍵環境系統涉及高安全性要求，通常不會交由 No Code 工具處理，平台也非只用於合規報告。","concept":"NoCode應用場景","aiExplained":true},{"id":"web-j2-632","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"Low Code 平台的「業務規則引擎」(Business Rules Engine) 主要功能是：","options":{"A":"允許非技術用戶定義和管理複雜的業務邏輯","B":"僅處理數據驗證","C":"只能由程式設計師配置","D":"主要用於用戶界面設計"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"業務規則引擎讓非技術背景的業務人員能以視覺化方式定義、修改與管理複雜的商業邏輯，例如審批條件或計價規則。這正是 Low Code 降低開發門檻的核心價值，其功能不限於資料驗證，也非程式設計師專用。","concept":"業務規則引擎","aiExplained":true},{"id":"web-j2-633","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在實施企業級 Low Code 安全策略時，「多層次風險建模」(Multi-dimensional Risk Modeling) 的最佳方法是：","options":{"A":"僅關注數據安全","B":"僅評估平台供應商風險","C":"同時考慮技術風險、業務影響、合規要求和公民開發者能力水平的綜合評估框架","D":"僅處理訪問控制問題"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"多層次風險建模強調同時納入技術風險、業務影響、合規要求與公民開發者能力等維度，建立綜合評估框架，才能完整掌握企業級 Low Code 的風險樣貌。只聚焦單一面向如數據安全或供應商風險，都會留下評估盲點。","concept":"多層次風險建模","aiExplained":true},{"id":"web-j2-634","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"在公共安全領域，No Code/Low Code 平台主要應用於：","options":{"A":"控制關鍵緊急響應系統","B":"取代所有公共安全管理軟體","C":"完全自動化決策過程","D":"開發事件報告和資源管理應用"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"公共安全領域採用 No Code/Low Code 平台，多用於開發事件報告、資源調度與管理等行政支援應用，快速回應業務需求。關鍵緊急響應系統與完全自動化決策攸關人命，仍需嚴謹的傳統開發流程與人為監督。","concept":"NoCode應用場景","aiExplained":true},{"id":"web-j2-635","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"Low Code 開發中的「事件驅動架構」(Event-Driven Architecture) 與「命令查詢職責分離」(CQRS) 模式結合的主要複雜性在於：","options":{"A":"兩者無法在 Low Code 環境中結合","B":"在視覺化設計環境中表達事件源、命令處理和查詢模型間的複雜關係","C":"僅適用於特定行業應用","D":"只能通過大量自定義代碼實現"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"事件驅動架構搭配 CQRS 涉及事件源、命令處理與查詢模型之間的複雜互動，要在以視覺化為主的 Low Code 設計環境中清楚表達這些關係，正是兩者結合的主要複雜性所在。它們並非無法結合，也不必然依賴大量自定義代碼。","concept":"事件驅動與CQRS","aiExplained":true},{"id":"web-j2-636","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"關於 No Code 解決方案在「預測性維護」(Predictive Maintenance) 應用中的主要局限性，最準確的描述是：","options":{"A":"完全無法實現預測性維護","B":"僅能處理歷史數據","C":"不適用於工業環境","D":"實現高級分析模型與設備診斷的深度整合，同時處理異構數據源和實時監控的複雜性"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"預測性維護需要將高級分析模型與設備診斷深度整合，同時處理感測器等異構數據源與實時監控，這種整合複雜性正是 No Code 方案的主要局限。它並非完全無法實現預測性維護，也不是只能處理歷史數據。","concept":"預測性維護局限","aiExplained":true},{"id":"web-j2-637","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"Low Code 開發中的「微服務支持」(Microservices Support) 主要優勢是：","options":{"A":"僅適用於大型企業應用","B":"允許開發模塊化、可獨立部署的服務","C":"要求所有應用使用相同架構","D":"只關注前端開發"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"微服務支持讓 Low Code 平台能夠開發模塊化、可獨立部署與擴展的服務，各服務可以分別更新而不影響整體系統。這種彈性不限於大型企業應用，也不代表所有應用必須採用相同架構，更不是只關注前端。","concept":"微服務架構","aiExplained":true},{"id":"web-j2-638","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"在食品和餐飲業，No Code 應用的典型例子包括：","options":{"A":"取代所有銷售點系統","B":"完全自動化食品製備","C":"庫存管理和在線訂餐應用","D":"僅用於員工排班"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"餐飲業常用 No Code 平台快速搭建庫存管理、在線訂餐與預約等營運應用，貼合門市日常需求。它並不是要取代所有銷售點系統，更不可能自動化實體的食品製備流程，應用範圍也不限於員工排班。","concept":"NoCode應用場景","aiExplained":true},{"id":"web-j2-639","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"評估企業級 Low Code 平台的「數據主權框架」(Data Sovereignty Framework) 時，最關鍵的考量是：","options":{"A":"僅關注數據存儲位置","B":"平台確保數據在不同司法管轄區合規儲存、處理和傳輸的能力，包括本地化和隔離機制","C":"只評估數據加密標準","D":"主要考慮備份策略"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"數據主權關注數據受所在司法管轄區法律約束的問題，因此評估重點是平台能否確保數據在不同轄區內合規地儲存、處理與傳輸，並提供數據本地化與隔離機制。僅看存儲位置、加密標準或備份策略都過於片面。","concept":"數據主權","aiExplained":true},{"id":"web-j2-640","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"評估企業級 Low Code 平台的「認知負荷平衡」(Cognitive Load Balancing) 時，最關鍵的因素是：","options":{"A":"僅評估界面設計","B":"平台在功能豐富性和易用性之間的平衡，以及不同抽象層次間的無縫轉換機制","C":"只關注學習曲線","D":"主要考慮用戶數量"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"認知負荷平衡衡量平台能否在功能豐富性與易用性之間取得平衡，並讓使用者在不同抽象層次（如視覺化設計與程式碼擴充）之間無縫轉換。只看介面設計、學習曲線或用戶數量，都不足以涵蓋這個概念的核心。","concept":"認知負荷平衡","aiExplained":true},{"id":"web-j2-641","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"No Code/Low Code 平台中的「情境感知安全控制」(Context-Aware Security Controls) 最準確的定義是：","options":{"A":"根據用戶身份、位置、設備特性和行為模式動態調整安全策略的機制","B":"僅基於用戶角色的安全控制","C":"只關注數據加密","D":"主要用於外部訪問控制"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"情境感知安全控制會依據用戶身份、位置、設備特性與行為模式等即時情境，動態調整安全策略與存取權限。相較於僅依角色的靜態控制，它能更精準地因應風險變化，適用範圍也不限於外部訪問或數據加密。","concept":"情境感知安全","aiExplained":true},{"id":"web-j2-642","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"評估企業級 Low Code 平台的「持續演進策略」(Continuous Evolution Strategy) 時，最關鍵的高級指標是：","options":{"A":"僅評估版本更新頻率","B":"平台在保持向後兼容性的同時，不斷整合新技術和最佳實踐的能力和路線圖","C":"只關注功能添加速度","D":"主要考慮供應商財務穩定性"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"持續演進策略的核心是平台能否在維持向後兼容性的前提下，持續整合新技術與最佳實踐，並提出清晰的發展路線圖。單看版本更新頻率、功能添加速度或供應商財務狀況，都無法判斷演進的品質與永續性。","concept":"平台演進策略","aiExplained":true},{"id":"web-j2-643","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在實施跨組織 Low Code 策略時，「技術資產貨幣化」(Technical Asset Monetization) 的最佳實踐是：","options":{"A":"僅通過降低許可成本實現投資回報","B":"將所有應用作為商業產品銷售","C":"建立內部市場和評估框架，將可重用元件、模板和解決方案轉化為有形業務價值","D":"僅專注於成本節約"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"技術資產貨幣化的最佳實踐是建立內部市場與評估框架，把可重用元件、模板與解決方案轉化為有形的業務價值，讓跨組織的 Low Code 投資持續累積效益。它不只是降低許可成本或節約開支，也不等於把所有應用當商品外售。","concept":"技術資產貨幣化","aiExplained":true},{"id":"web-j2-644","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"評估企業級 Low Code 平台的「彈性架構」(Resilient Architecture) 時，最關鍵的高級指標是：","options":{"A":"僅考慮系統正常運行時間","B":"平台處理組件失敗、網絡延遲和資源限制的能力，以及自我修復和優雅降級機制","C":"只評估災難恢復計劃","D":"主要考慮數據備份策略"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"彈性架構的評估重點在平台面對組件失敗、網絡延遲與資源限制時的承受能力，以及是否具備自我修復與優雅降級機制。僅看系統正常運行時間、災難恢復計劃或備份策略，無法反映系統在異常狀況下的整體韌性。","concept":"彈性架構","aiExplained":true},{"id":"web-j2-645","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"No Code 平台在建築和房地產行業的主要應用是：","options":{"A":"取代所有建築設計軟體","B":"完全自動化建築過程","C":"僅用於財務管理","D":"開發物業管理應用和客戶關係管理系統"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"建築與房地產業多利用 No Code 平台開發物業管理應用與客戶關係管理系統，加速業務流程數位化。專業建築設計軟體與實體建築過程並非 No Code 的替代對象，其應用也不限於財務管理。","concept":"NoCode應用場景","aiExplained":true},{"id":"web-j2-646","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"No Code/Low Code 平台的 API 集成能力主要用於：","options":{"A":"僅連接內部系統","B":"與企業現有系統和第三方服務建立連接","C":"只用於資料庫集成","D":"替代所有傳統集成方法"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"API 集成能力讓 No Code/Low Code 應用能與企業既有系統及第三方服務（如支付、CRM、通訊工具）建立連接，實現數據互通與流程串接。它不限於內部系統或資料庫集成，也不是要取代所有傳統集成方法。","concept":"API集成","aiExplained":true},{"id":"web-j2-647","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"No Code/Low Code 平台的「版本控制」(Version Control) 功能主要目的是：","options":{"A":"僅追踪用戶活動","B":"管理應用變更並支持團隊協作","C":"只記錄數據庫變更","D":"限制特定版本的用戶數"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%84%aa%e5%8b%a2%e8%88%87%e9%99%90%e5%88%b6/","explanation":"版本控制功能記錄應用的每次變更，支援回溯、比較與多人協作開發，避免修改互相覆蓋。其目的在管理應用的變更歷程與生命週期，而非追蹤用戶活動、記錄數據庫變更或限制用戶數量。","concept":"版本控制","aiExplained":true},{"id":"web-j2-648","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"No Code/Low Code 平台中的「認知摩擦係數」(Cognitive Friction Coefficient) 是指：","options":{"A":"僅關注平台的學習曲線","B":"量化用戶在實現業務目標過程中遇到的心智阻力和複雜性","C":"只評估平台的技術實現","D":"主要用於市場分析"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"認知摩擦源自互動設計領域，指使用者在操作系統時感受到的心智阻力。將其量化為係數，即是衡量用戶在 No Code/Low Code 平台上達成業務目標過程中遇到的心智阻力與複雜性。其餘選項僅侷限於學習曲線、技術實現或市場分析，均未涵蓋此概念的核心意涵。","concept":"認知摩擦","aiExplained":true},{"id":"web-j2-649","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"評估企業級 Low Code 平台的「認知擴展邊界」(Cognitive Extension Boundary) 時，最關鍵的因素是：","options":{"A":"僅評估平台的技術限制","B":"只關注用戶數量限制","C":"主要評估資料庫容量","D":"平台在保持核心易用性的同時支持高級擴展和定制的能力邊界"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"認知擴展邊界關注的是平台能否在維持核心易用性的前提下，支援進階擴展與客製化，這是評估企業級 Low Code 平台能否同時服務公民開發者與專業開發者的關鍵。僅看技術限制、用戶數量或資料庫容量都過於狹隘。","concept":"平台擴展能力","aiExplained":true},{"id":"web-j2-650","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"No Code/Low Code 平台的「離線功能」(Offline Capabilities) 是指：","options":{"A":"僅用於開發過程","B":"只支援靜態內容","C":"應用程式在無網絡連接時的運作能力","D":"與雲平台不兼容"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"離線功能指應用程式在沒有網路連線時仍能持續運作的能力，例如本地資料暫存與恢復連線後的同步。這對行動場域或網路不穩定環境中的企業應用尤其重要。其餘選項將其誤解為僅限開發階段、只支援靜態內容或與雲端不相容，皆不正確。","concept":"離線功能","aiExplained":true},{"id":"web-j2-651","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"在評估 No Code/Low Code 平台的「認知負荷閾值」(Cognitive Load Threshold) 時，最關鍵的指標是：","options":{"A":"僅評估平台的功能數量","B":"只關注用戶界面元素數量","C":"主要評估文檔頁數","D":"平台在不同技能水平的用戶中保持易用性的複雜度臨界點"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"認知負荷閾值的核心在於找出平台複雜度的臨界點，也就是平台在面對不同技能水平的使用者時，仍能維持易用性的複雜度上限。單純計算功能數量、介面元素或文件頁數，都無法反映使用者實際承受的認知負擔。","concept":"認知負荷","aiExplained":true},{"id":"web-j2-652","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"企業級 Low Code 開發中的「複合安全模型」(Composite Security Model) 主要解決的問題是：","options":{"A":"僅關注數據加密","B":"在應用程式碼、數據、API 和基礎設施各層實現一致的安全控制和治理","C":"只用於用戶認證","D":"主要用於滿足特定行業法規"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"複合安全模型強調安全不能只落在單一環節，而是要在應用程式碼、資料、API 與基礎設施等各層實現一致的安全控制與治理。僅做資料加密或用戶認證都只是其中一環，無法構成完整的多層防護。","concept":"多層安全治理","aiExplained":true},{"id":"web-j2-653","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"「公民開發者」(Citizen Developer) 指的是：","options":{"A":"具有電腦科學學位的程式設計師","B":"國家認證的軟體開發人員","C":"使用 No Code/Low Code 工具建立應用程式的非 IT 專業人員","D":"專門從事政府專案的開發人員"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"公民開發者指不具 IT 專業背景、但能運用 No Code/Low Code 工具自行建立應用程式的業務人員。這個概念強調的是開發能力的民主化，與學歷、官方認證或服務對象無關。","concept":"公民開發者","aiExplained":true},{"id":"web-j2-654","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"在企業環境中實施 No Code/Low Code 策略的最佳做法是：","options":{"A":"完全替換所有傳統開發","B":"建立治理框架和安全標準","C":"允許任何部門自由選擇任何工具","D":"限制只有 IT 部門可以使用這些工具"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"企業導入 No Code/Low Code 的關鍵是建立治理框架與安全標準，讓公民開發在受控環境中進行，兼顧創新速度與風險管理。完全取代傳統開發或放任各部門自由選工具都會造成失控，僅限 IT 部門使用則失去賦能業務人員的意義。","concept":"低程式碼治理","aiExplained":true},{"id":"web-j2-655","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"評估企業級 Low Code 平台的「認知一致性」(Cognitive Consistency) 時，最關鍵的因素是：","options":{"A":"平台的設計語言、交互模式和功能組織方式保持一致的心智模型","B":"所有用戶界面元素使用相同的配色方案","C":"僅提供單一類型的開發視圖","D":"限制可用元件的數量"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"認知一致性指平台的設計語言、互動模式與功能組織方式維持一致的心智模型，使用者學會一處後即可類推到其他部分，降低學習成本。單純統一配色、只提供單一開發視圖或限制元件數量，都不等於心智模型層次的一致性。","concept":"認知一致性","aiExplained":true},{"id":"web-j2-656","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"關於 Low Code 平台中的「非功能性需求契約」(Non-functional Requirements Contract)，下列哪項陳述最準確？","options":{"A":"它只關注應用程序的基本功能","B":"它僅適用於大型企業部署","C":"它主要用於降低許可成本","D":"它定義平台在安全性、性能、可用性和合規性方面的可測量保證"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"非功能性需求契約定義平台在安全性、效能、可用性與合規性等面向可測量的保證，例如服務水準協議中的正常運行時間承諾。它處理的是「系統做得多好」而非「系統做什麼」，因此與基本功能、企業規模或授權成本無直接關聯。","concept":"非功能性需求","aiExplained":true},{"id":"web-j2-657","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"No Code/Low Code 平台中的「認知分區設計」(Cognitive Zoning Design) 最準確的描述是：","options":{"A":"僅關注用戶界面佈局","B":"只評估顏色方案","C":"基於用戶認知模型和任務流程組織平台界面和功能的設計方法","D":"主要用於資料可視化"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"認知分區設計是依據使用者的認知模型與任務流程，來組織平台介面和功能的設計方法，讓功能分區符合使用者的思考脈絡。它不只是介面佈局或配色的表層問題，而是資訊架構層次的設計策略。","concept":"認知分區設計","aiExplained":true},{"id":"web-j2-658","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在評估 No Code/Low Code 平台時，「退出策略」(Exit Strategy) 是指：","options":{"A":"從平台提取資料的能力，與應用遷移無關","B":"取消訂閱的流程","C":"僅與財務成本相關","D":"在需要時將應用程式遷移到其他平台的可行性"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"評估退出策略的重點在於：當企業需要更換平台時，能否可行地將應用程式遷移到其他平台，這直接關係到供應商鎖定的風險。單純的資料匯出、退訂流程或財務成本，都只是退出策略的部分面向。","concept":"供應商鎖定","aiExplained":true},{"id":"web-j2-659","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"Low Code 開發中的「持續知識集成」(Continuous Knowledge Integration) 策略主要解決的問題是：","options":{"A":"將組織的業務規則、最佳實踐和領域知識編碼到平台和應用資產中，減少知識流失","B":"僅關注技術文檔管理","C":"只用於培訓新用戶","D":"主要用於代碼註釋"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"持續知識集成的目標是把組織的業務規則、最佳實務與領域知識編碼進平台與應用資產中，使知識沉澱為可重用的資產，降低人員異動造成的知識流失。它的範疇遠大於技術文件管理、新人培訓或程式碼註解。","concept":"知識資產化","aiExplained":true},{"id":"web-j2-660","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"「影子 IT」(Shadow IT) 與 No Code/Low Code 開發的關係是：","options":{"A":"No Code/Low Code 工具總是屬於影子 IT","B":"兩者完全無關","C":"No Code/Low Code 平台有助於減少影子 IT 風險","D":"No Code/Low Code 工具只能用於影子 IT 專案"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"影子 IT 指未經 IT 部門核准而私自使用的系統與工具。受治理的 No Code/Low Code 平台提供業務人員一個受控且被 IT 認可的開發管道，讓原本可能私下進行的開發需求浮上檯面，因此有助於降低影子 IT 風險。","concept":"影子IT治理","aiExplained":true},{"id":"web-j2-661","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"Low Code 架構中的「彈性部署拓撲」(Elastic Deployment Topology) 主要解決的問題是：","options":{"A":"僅適用於固定資源的環境","B":"只能部署到單一雲供應商","C":"主要用於開發環境","D":"根據工作負載和資源需求動態調整計算資源和服務分佈"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"彈性部署拓撲讓平台能根據工作負載與資源需求，動態調整運算資源與服務的分佈，例如自動擴縮容或跨環境調度。固定資源、綁定單一雲供應商或僅限開發環境的說法，都與「彈性」的本質相反。","concept":"彈性部署","aiExplained":true},{"id":"web-j2-662","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"Low Code 平台中的「自定義程式碼擴展」(Custom Code Extensions) 允許：","options":{"A":"完全繞過平台限制","B":"只能使用特定的程式語言","C":"在視覺化工具不足時添加自定義功能","D":"僅用於前端設計"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"自定義程式碼擴展是 Low Code 平台的重要補充機制：當視覺化工具不足以實現特定需求時，開發者可撰寫自訂程式碼補足功能。它是在平台框架內的受控擴展，並非完全繞過平台限制，也不侷限於特定語言或前端設計。","concept":"程式碼擴展","aiExplained":true},{"id":"web-j2-663","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"No Code/Low Code 開發的「DevOps 整合」指的是：","options":{"A":"與持續整合/持續部署流程的無縫連接","B":"僅適用於大型企業","C":"完全取代了 DevOps 流程","D":"僅限於測試環境"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"DevOps 整合指 No Code/Low Code 開發能與持續整合／持續部署流程無縫銜接，例如版本控制、自動化測試與部署管線。這讓低程式碼應用也能納入正規的軟體交付流程，而非取代 DevOps 或僅限於測試環境。","concept":"CI/CD整合","aiExplained":true},{"id":"web-j2-664","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"No Code 平台的視覺化流程設計通常基於：","options":{"A":"業務流程模型和符號 (BPMN)","B":"統一建模語言 (UML)","C":"實體關係圖 (ERD)","D":"網路拓撲圖"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"No Code 平台的視覺化流程設計多以業務流程模型和符號（BPMN）為基礎，因為 BPMN 專為描述業務流程而設計，業務人員也容易理解。UML 偏向軟體系統建模，ERD 描述資料結構，網路拓撲圖則與流程設計無關。","concept":"BPMN流程建模","aiExplained":true},{"id":"web-j2-665","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"Low Code 平台中的「多級緩存策略」(Multi-tier Caching Strategy) 對應用性能的影響主要體現在：","options":{"A":"僅影響資料庫操作","B":"只關注前端渲染速度","C":"僅適用於移動應用","D":"通過在客戶端、應用服務和數據層實現智能緩存，降低延遲並提高吞吐量"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"多級緩存策略在客戶端、應用服務與資料層分別實現智能快取，讓資料就近取用，降低延遲並提高吞吐量。它是貫穿整個架構的效能策略，並非只影響資料庫操作、前端渲染或行動應用單一層面。","concept":"多層快取","aiExplained":true},{"id":"web-j2-666","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在企業規模的 No Code/Low Code 實施中，「技術資產變現」(Technical Asset Monetization) 策略的核心是：","options":{"A":"僅關注降低許可成本","B":"將內部開發的組件、模板和解決方案轉化為可重用、可商品化的資產","C":"只通過減少開發人員來節省成本","D":"主要通過外包實現成本效益"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"技術資產變現的核心是把內部開發的組件、模板與解決方案轉化為可重用、可商品化的資產，讓一次性的開發投入產生持續價值。這是資產經營的思維，而非單純降低授權費、裁減人力或外包節費。","concept":"資產重用變現","aiExplained":true},{"id":"web-j2-667","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"在評估 No Code/Low Code 平台的「認知擴展性」(Cognitive Scalability) 時，最關鍵的指標是：","options":{"A":"隨著應用和團隊規模增長，平台在保持易用性的同時支持更複雜場景的能力","B":"僅關注用戶數量擴展","C":"只評估技術性能","D":"主要關注許可模式"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_no-code%ef%bc%8flow-code-%e7%9a%84%e5%9f%ba%e6%9c%ac%e6%a6%82%e5%bf%b5/","explanation":"認知擴展性衡量的是：隨著應用數量與團隊規模成長，平台能否在維持易用性的同時支撐更複雜的場景。它同時關照使用者的認知負擔與場景複雜度兩個維度，不能只看用戶數量、技術性能或許可模式。","concept":"認知擴展性","aiExplained":true},{"id":"web-j2-668","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"金融機構對AI系統進行「透明性與可解釋性」評估時，下列何者最重要？","options":{"A":"揭露所有技術細節","B":"確認可解釋性的程度與其AI系統應用之重要性相稱","C":"避免任何揭露","D":"忽略客戶反饋"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"依金管會「金融業運用人工智慧指引」，可解釋性的程度應與 AI 系統應用之重要性相稱：高風險應用需要較高的可解釋性，低風險應用則可適度簡化。揭露所有技術細節可能洩漏營業秘密並引來攻擊，完全不揭露或忽略客戶反饋則違反透明性原則。","concept":"可解釋性相稱","aiExplained":true},{"id":"web-j2-669","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"金融機構使用AI系統所蒐集的客戶資料時，下列何者不適當？","options":{"A":"無限制地分享客戶資料給第三方","B":"確認已取得客戶同意或符合相關法令","C":"評估是否須進一步對資料進行額外之隱私保護處理","D":"記錄資料蒐集之來源並確保透過合法管道取得"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"使用客戶資料必須取得同意或符合相關法令、確保來源合法並留存紀錄，必要時還須進行額外的隱私保護處理。無限制地將客戶資料分享給第三方，明顯違反個人資料保護的基本要求，是最不適當的做法。","concept":"客戶資料保護","aiExplained":true},{"id":"web-j2-670","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"關於金融業運用AI「落實透明性與可解釋性」原則，下列何者正確？","options":{"A":"所有AI系統都需要同等程度的透明度","B":"資訊揭露越詳細越好","C":"可解釋性的程度應與AI系統應用之重要性相稱","D":"與洗錢防制相關的AI系統應完全透明"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"落實透明性與可解釋性的正確原則是相稱性：可解釋性的程度應與 AI 系統應用的重要性相稱。並非所有系統都需要同等透明度，資訊揭露也非越詳細越好；洗錢防制相關系統若完全透明，反而可能被有心人士規避。","concept":"透明性原則","aiExplained":true},{"id":"web-j2-671","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"關於金融業AI「可解釋性報告」的關鍵要素，下列何者最不相關？","options":{"A":"輸入特徵的重要性排序","B":"模型決策邏輯說明","C":"模型訓練耗時","D":"主要影響決策的因素分析"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"可解釋性報告的重點在於說明模型「為何如此決策」，因此輸入特徵的重要性排序、決策邏輯說明與主要影響因素分析都是關鍵要素。模型訓練耗時屬於工程效率指標，與解釋決策依據無關，故最不相關。","concept":"可解釋性報告","aiExplained":true},{"id":"web-j2-672","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"金融機構委託第三方業者導入AI系統相關作業時，下列何者不正確？","options":{"A":"應與第三方業者簽訂書面契約","B":"明定導入事項範圍及第三方業者之責任範疇","C":"明確規定資料加密傳輸及存儲安全","D":"無須釐清責任分配議題"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"金融機構委託第三方導入 AI 時，應簽訂書面契約、明定導入範圍與第三方責任範疇，並明確規範資料加密傳輸及儲存安全。責任分配是委外管理的核心議題，「無須釐清責任分配」的說法明顯違反第三方風險管理原則。","concept":"委外風險管理","aiExplained":true},{"id":"web-j2-673","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"關於AI系統生命週期，下列何者不正確？","options":{"A":"包含6個階段","B":"系統規劃及設計是首要階段","C":"系統部署及監控為最後階段","D":"模型建立及驗證是其中一個階段"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"依金管會「金融業運用人工智慧指引」，AI 系統生命週期分為四個階段：系統規劃及設計、資料蒐集及輸入、模型建立及驗證、系統部署及監控。因此「包含 6 個階段」的敘述不正確，其餘三個選項均符合此架構。","concept":"AI生命週期","aiExplained":true},{"id":"web-j2-674","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"下列哪項技術最能有效解決AI系統中的「冷啟動問題」(Cold Start Problem)？","options":{"A":"遷移學習 (Transfer Learning)","B":"降維技術 (Dimensionality Reduction)","C":"批次正規化 (Batch Normalization)","D":"梯度裁剪 (Gradient Clipping)"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"冷啟動問題指系統在缺乏歷史資料時難以做出準確預測。遷移學習可將已在其他領域或大量資料上學到的知識移轉到新任務，有效彌補初期資料不足的困境。降維、批次正規化與梯度裁剪都是訓練過程的技巧，無法解決資料匱乏的根本問題。","concept":"冷啟動問題","aiExplained":true},{"id":"web-j2-675","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"金融機構在對面對客戶的AI服務進行風險評估時，下列何者風險程度最低？","options":{"A":"信用評分系統","B":"機器人理財系統","C":"自動化貸款審核系統","D":"智能客服系統"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"智能客服系統主要提供資訊查詢與問題引導，通常不直接做出影響客戶權益的決策，風險程度相對最低。信用評分、機器人理財與自動化貸款審核都直接影響客戶的金融權益與資產配置，屬於較高風險的應用。","concept":"AI風險分級","aiExplained":true},{"id":"web-j2-676","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"金融業運用AI系統時，應優先考量何種原則？","options":{"A":"提高效率","B":"建立治理及問責機制","C":"降低成本","D":"增加獲利"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"金管會指引將「建立治理及問責機制」列為金融業運用 AI 的核心原則之首，要求機構對 AI 系統的決策與影響負最終責任。提高效率、降低成本與增加獲利是商業考量，必須建立在健全的治理基礎之上。","concept":"治理與問責","aiExplained":true},{"id":"web-j2-677","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"金融機構在運用「集成學習」(Ensemble Learning)方法時，其主要優勢是：","options":{"A":"結合多個模型可提高穩定性和準確性","B":"大幅降低計算資源需求","C":"消除對數據預處理的需求","D":"完全解決模型解釋性問題"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"集成學習透過結合多個模型的預測結果，降低單一模型的偏差與變異，因此能提高整體的穩定性和準確性。它通常需要更多而非更少的計算資源，也無法免除資料前處理，更不會自動解決模型解釋性問題。","concept":"集成學習","aiExplained":true},{"id":"web-j2-678","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"金融機構運用AI系統的風險評估時，下列哪一項因素不需要考量？","options":{"A":"是否直接提供客戶服務","B":"使用個人資料的程度","C":"AI自主決策程度","D":"系統研發的成本"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"AI 系統的風險評估應聚焦於對客戶與市場的潛在影響，例如是否直接提供客戶服務、使用個人資料的程度與 AI 自主決策程度。系統研發成本屬於預算管理範疇，與系統上線後的風險高低無關。","concept":"AI風險評估","aiExplained":true},{"id":"web-j2-679","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"金融機構推動AI系統時，下列哪一項不屬於「以風險為基礎落實核心原則」的措施？","options":{"A":"記錄","B":"監控機制","C":"審查及核准","D":"最大化效能"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"以風險為基礎落實核心原則，強調依風險高低採取記錄、監控機制、審查及核准等控管措施。「最大化效能」是追求業務績效的目標，並非風險控管措施，故不屬於此範疇。","concept":"風險基礎方法","aiExplained":true},{"id":"web-j2-680","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"關於AI系統的「模型解釋技術」，下列何者與其他三項屬於不同類別？","options":{"A":"LIME (Local Interpretable Model-agnostic Explanations)","B":"SHAP (SHapley Additive exPlanations)","C":"梯度增強樹 (Gradient Boosting Tree)","D":"部分依賴圖 (Partial Dependence Plot)"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"LIME、SHAP 與部分依賴圖都是用來解釋模型決策的「解釋技術」，梯度增強樹則是一種機器學習「模型」本身，屬於被解釋的對象而非解釋工具。因此梯度增強樹與其他三項分屬不同類別。","concept":"模型解釋技術","aiExplained":true},{"id":"web-j2-681","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"金融機構在評估AI模型中「特徵共線性」(Feature Collinearity)問題時，主要關注點應該是：","options":{"A":"提高模型訓練速度","B":"避免模型不穩定和解釋性降低","C":"增加特徵數量","D":"減少存儲空間需求"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"特徵共線性指多個輸入特徵高度相關，會使模型的係數估計不穩定，微小的資料變動就可能造成結果大幅波動，同時讓特徵重要性難以解讀。因此關注共線性的目的在於避免模型不穩定與解釋性降低。","concept":"特徵共線性","aiExplained":true},{"id":"web-j2-682","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"金融機構在面對AI模型「效度偏移」(Model Drift)問題時，最適合採取的措施是：","options":{"A":"完全重新開發新模型","B":"建立定期監控機制並及時校調模型","C":"增加模型參數數量","D":"降低模型更新頻率"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"模型效度偏移指模型上線後，因資料分布或市場環境變化導致預測效能逐漸衰退。最務實的因應方式是建立定期監控機制，持續追蹤模型表現並及時校調，而非每次都重新開發，更不應降低更新頻率。","concept":"模型漂移","aiExplained":true},{"id":"web-j2-683","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"金融機構運用AI系統進行數據分析時，應特別注意什麼？","options":{"A":"僅使用最新數據","B":"避免使用第三方數據","C":"資料來源的合宜性及數據資料之品質","D":"儘可能使用最大量的數據"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"AI 分析的品質取決於輸入資料，因此金融機構應特別注意資料來源的合宜性及數據品質，確保資料合法取得、正確且具代表性。只用最新資料或盲目追求最大資料量反而可能引入偏誤，第三方資料經妥善評估後仍可使用。","concept":"資料品質","aiExplained":true},{"id":"web-j2-684","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"金融機構運用AI系統時，下列哪一種監督機制最能平衡自動化效率與風險控制？","options":{"A":"完全自主決策無人類介入","B":"每個決策都需人工審核","C":"定期抽查少量案例","D":"風險分級監督：高風險決策需人工審核，低風險決策可自動執行"},"answer":"D","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"風險分級監督讓高風險決策保留人工審核、低風險決策自動執行，在自動化效率與風險控制之間取得最佳平衡。完全自主決策缺乏問責，每案人工審核喪失自動化價值，定期抽查則可能漏接高風險個案。","concept":"人類監督機制","aiExplained":true},{"id":"web-j2-685","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"關於AI系統「可解釋性」，以下哪種敘述最為精確？","options":{"A":"複雜度較高的黑箱模型可能需要額外的可解釋性工具來輔助理解","B":"所有AI模型均應有相同程度的可解釋性","C":"可解釋性和模型準確度呈正比關係","D":"僅內部使用的AI系統不需要考慮可解釋性"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"深度學習等複雜度較高的黑箱模型，內部決策邏輯難以直接理解，可能需要 LIME、SHAP 等額外的可解釋性工具來輔助。可解釋性應依應用重要性相稱配置，並非所有模型都要求相同程度；且可解釋性與準確度之間常存在權衡而非正比，內部系統同樣需要可解釋性以利稽核。","concept":"模型可解釋性","aiExplained":true},{"id":"web-j2-686","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"金融業運用AI系統時，最適合採用何種方式來落實核心原則？","options":{"A":"統一標準方式","B":"以成本為基礎","C":"以風險為基礎","D":"以效率為基礎"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"金管會指引明確採取「以風險為基礎」的方式落實核心原則，依 AI 系統的風險高低配置相應的控管強度。統一標準忽略不同應用的差異，以成本或效率為基礎則可能犧牲客戶權益與金融穩定。","concept":"風險基礎方法","aiExplained":true},{"id":"web-j2-687","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"金融機構在確保AI系統「穩健性與安全性」時，下列何者正確？","options":{"A":"使用最新但未經測試的技術","B":"避免任何安全控管措施","C":"選擇較具備韌性之模型","D":"忽略系統監控"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_ai%e6%b2%bb%e7%90%86%e6%a6%82%e5%bf%b5_%e3%80%8a%e9%87%91%e8%9e%8d%e6%a5%ad%e9%81%8b%e7%94%a8%e4%ba%ba%e5%b7%a5%e6%99%ba/","explanation":"確保穩健性與安全性的正確做法包括選擇較具韌性的模型，使系統在面對異常輸入或惡意攻擊時仍能穩定運作。使用未經測試的技術、迴避安全控管措施或忽略系統監控，都與穩健性原則背道而馳。","concept":"穩健性與安全","aiExplained":true},{"id":"web-j1-688","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"指示變量法在處理缺失值時的操作方式為何？","options":{"A":"直接移除該筆資料","B":"建立一個新欄位表示是否為缺失值","C":"將缺失值補為欄位最大值","D":"依據模型預測填補該欄位"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"指示變量法不直接填補缺失值，而是額外建立一個新欄位（例如0/1旗標）標示該筆資料是否缺失。如此一來，模型能把「缺失」本身當作一項資訊來學習，避免因直接刪除或任意填補而扭曲原始資料分布。","concept":"缺失值處理","aiExplained":true},{"id":"web-j1-689","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"下列哪一項最能正確描述GAN的訓練過程？","options":{"A":"生成器與判別器彼此合作以收斂模型","B":"判別器試圖模擬生成器並最終替代它","C":"兩個網路在對抗過程中相互推動彼此改進","D":"判別器提供資料標籤給生成器進行監督式學習"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"GAN由生成器與判別器組成，生成器努力產生以假亂真的樣本，判別器則努力分辨真偽。兩者在對抗過程中互相施壓、共同進步，最終使生成品質不斷提升。彼此合作收斂或由判別器提供標籤的說法，都誤解了其對抗式訓練的本質。","concept":"GAN對抗訓練","aiExplained":true},{"id":"web-j1-690","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"聯邦學習的哪一階段負責讓中央伺服器將初始模型提供給各客戶端？","options":{"A":"模型聚合階段","B":"本地訓練階段","C":"初始模型下發","D":"參數回傳階段"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"聯邦學習的流程始於中央伺服器將初始的全域模型下發給各客戶端，客戶端才能據此展開本地訓練。之後各端回傳參數，由伺服器聚合更新全域模型，再進入下一輪循環。","concept":"聯邦學習流程","aiExplained":true},{"id":"web-j1-691","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"下列哪一項屬於鑑別式人工智慧(Discriminative AI)的應用特徵？","options":{"A":"從資料中辨識出樣本所屬的分類","B":"根據輸入產生新的圖像或文字","C":"建立新知識並推論新規則","D":"產生無監督的自我回饋學習過程"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"鑑別式AI著重於學習輸入與類別之間的決策邊界，用來判斷樣本屬於哪一個分類，例如影像分類或垃圾郵件辨識。根據輸入產生新圖像或文字則屬於生成式AI的範疇，兩者的定位不同。","concept":"鑑別式AI","aiExplained":true},{"id":"web-j1-692","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"哪一種抽樣方法會先將資料依照母體結構群分好，再從每一群中抽取樣本？","options":{"A":"隨機抽樣","B":"分層抽樣(Stratified Sampling)","C":"系統抽樣","D":"兩階段式抽樣"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"分層抽樣先依母體的結構特徵（如性別、年齡層）將資料劃分成若干層，再從每一層中分別抽取樣本。這能確保各子群體都獲得適當代表，降低抽樣偏差。","concept":"分層抽樣","aiExplained":true},{"id":"web-j1-693","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"深度學習技術雖具高效能，但主要侷限為何？","options":{"A":"模型準確率過高導致誤判","B":"僅能處理數學相關任務","C":"對大量資料與計算資源需求極高，且缺乏可解釋性","D":"無法在自然語言任務上應用"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"深度學習依賴大量標註資料與龐大運算資源，訓練成本高昂；同時模型內部是多層非線性轉換，決策過程宛如黑箱、缺乏可解釋性。這正是它在高風險領域落地時的主要侷限。","concept":"深度學習侷限","aiExplained":true},{"id":"web-j1-694","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"聯邦學習中，模型聚合的目的是什麼？","options":{"A":"訓練資料集中處理與編碼壓縮","B":"將各客戶端回傳的參數整合，形成更新的全域模型","C":"刪除不相關資料特徵以節省記憶體","D":"利用 GAN 將結果視覺化呈現"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"在聯邦學習中，各客戶端只回傳模型參數或梯度，而非原始資料。伺服器將這些參數加以聚合（例如加權平均），形成更新後的全域模型，再下發給客戶端進行下一輪訓練。","concept":"模型聚合","aiExplained":true},{"id":"web-j1-695","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"將數值型離群值透過轉換為對數以壓縮其極端差異，這種方式稱為？","options":{"A":"分群合併法","B":"函數校正法(如 log 轉換)","C":"標準差平移法","D":"類別型映射"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"對數轉換屬於函數校正法，透過log等單調函數壓縮數值間的極端差異，使右偏分布較接近常態、降低離群值的影響。它不刪除任何資料，只是改變尺度，讓模型較不受極端值干擾。","concept":"對數轉換","aiExplained":true},{"id":"web-j1-696","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"強化學習(Reinforcement Learning)的核心學習原理為何？","options":{"A":"使用先驗知識建立邏輯規則","B":"最大化累積獎勵，透過試誤方式學習行為策略","C":"對資料進行無指導的群聚分類","D":"透過人工規則進行分類與預測"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"強化學習讓代理人在環境中不斷嘗試行動，依據環境回饋的獎勵或懲罰調整策略。其核心目標是最大化長期累積獎勵，屬於試誤式學習，而非依賴標註資料或人工規則。","concept":"強化學習","aiExplained":true},{"id":"web-j1-697","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"結構化資料最常見的格式為何？","options":{"A":"自然語言段落","B":"圖像像素矩陣","C":"表格型資料，如CSV或資料庫欄位","D":"聲音波形與頻譜資料"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"結構化資料指具有固定欄位與格式的資料，最典型的就是表格型資料，如CSV檔或關聯式資料庫的欄位。自然語言段落、圖像與聲音則屬於非結構化資料。","concept":"結構化資料","aiExplained":true},{"id":"web-j1-698","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"資料精簡後獲得的知識會如何？","options":{"A":"一定會失去所有準確性","B":"可能會有些微誤差，但能提升效率","C":"只能用於非監督式學習任務","D":"僅適用於圖像類資料"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"資料精簡（如取樣、降維）是以較小的資料量近似原始資訊，因此得到的知識可能帶有些微誤差。但換來的是儲存與運算效率大幅提升，在實務上是可接受的取捨。","concept":"資料精簡","aiExplained":true},{"id":"web-j1-699","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"使用「平均值法」偵測離群值的原則為何？","options":{"A":"平均值加減 1 個標準差","B":"平均值加減 2 個 IQR","C":"平均值加減 3 個標準差","D":"平均值除以中位數"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"平均值法假設資料近似常態分布，將落在平均值加減三個標準差以外的觀測值視為離群值。因為約99.7%的資料會落在此範圍內，超出者即可合理判定為異常。","concept":"離群值偵測","aiExplained":true},{"id":"web-j1-700","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"鑑別式人工智慧(Discriminative AI)主要的核心功能是什麼？","options":{"A":"自動產生圖像、影片與語音內容","B":"從資料中辨識模式進行分類與預測","C":"模仿人類情感與行為進行互動","D":"自行設計神經網路架構"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"鑑別式AI的核心是從資料中辨識模式，據以進行分類與預測，例如判斷一封郵件是否為垃圾郵件。它不負責產生新內容，這一點與生成式AI形成明確對比。","concept":"鑑別式AI","aiExplained":true},{"id":"web-j1-701","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列哪一項屬於將類別型轉為數值型的例子？","options":{"A":"將地址轉為區域類別(北部、中部)","B":"將「學歷」以入學年齡轉換為數值，如小學為 6 歲","C":"將收入欄位依範圍分為高、中、低","D":"將圖片標記轉為一組類別標籤"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"將「學歷」依入學年齡轉換為數值（如小學為6歲），是把類別型資料映射為有意義數值的典型作法。其餘選項不是維持類別型態，就是把數值轉成類別，轉換方向正好相反。","concept":"類別轉數值","aiExplained":true},{"id":"web-j1-702","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"MYCIN 系統的主要功能是什麼？","options":{"A":"模仿人類情感進行互動的聊天機器人","B":"醫學診斷系統，用於辨識細菌感染並建議抗生素","C":"預測天氣變化的模擬系統","D":"識別化學結構的圖像分析系統"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"MYCIN是1970年代史丹佛大學開發的醫療專家系統，透過規則推理協助辨識細菌感染，並建議適當的抗生素與劑量。它是符號式AI應用於醫學診斷的經典代表。","concept":"專家系統","aiExplained":true},{"id":"web-j1-703","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"「等寬裝箱法(Equal-Width-Interval)」的核心概念為？","options":{"A":"每一個區間包含相同筆數的資料","B":"每一區間的寬度相同","C":"每一區間轉換為獨熱編碼","D":"依照資料標準差自動分區"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"等寬裝箱法是把數值範圍切成寬度相等的區間，例如0到100分成10個各寬10的箱子。要讓每個區間包含相同筆數的，是等頻（等深）裝箱法，兩者不可混淆。","concept":"等寬裝箱","aiExplained":true},{"id":"web-j1-704","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"資料一般化(Data Generalization)的主要目的是？","options":{"A":"將數值欄位轉為文字敘述","B":"將詳細資料轉換為較高層次的概念資料","C":"將缺失值轉為 0","D":"增加欄位數以提升模型複雜度"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"資料一般化是將低層次的詳細資料以較高層次的概念取代，例如把「年齡23歲」概化為「青年」、把街道地址概化為城市。這有助於精簡資料，也常用於保護個人隱私。","concept":"資料一般化","aiExplained":true},{"id":"web-j1-705","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"下列何者並非統計學習AI的技術核心？","options":{"A":"特徵工程(Feature Engineering)","B":"機器學習(Machine Learning)","C":"邏輯推理(Logic Reasoning)","D":"數據挖掘(Data Mining)"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"統計學習取向的AI以資料為核心，倚重機器學習、特徵工程與數據挖掘從資料中歸納規律。邏輯推理則屬於符號式（規則式）AI的核心技術，不在統計學習的範疇內。","concept":"統計學習AI","aiExplained":true},{"id":"web-j1-706","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"下列哪一項最有可能出現在 CRISP-DM 的處理流程中？","options":{"A":"資料理解與前處理","B":"語音合成與增強","C":"卷積神經網路訓練","D":"感測器信號還原"},"answer":"A","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"CRISP-DM是資料探勘的標準流程，包含商業理解、資料理解、資料準備、建模、評估與部署六個階段。資料理解與前處理正是其中的核心步驟，其餘選項屬於特定技術而非流程階段。","concept":"CRISP-DM流程","aiExplained":true},{"id":"web-j1-707","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列哪一項不是AI治理的主要目標？","options":{"A":"促進AI系統的公平性與透明性","B":"提升AI模型的可控性與安全性","C":"強化AI系統的自我進化能力","D":"降低AI發展對社會可能產生的風險"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e4%ba%ba%e5%b7%a5%e6%99%ba%e6%85%a7%e6%a6%82%e8%ab%96%e6%a8%a1%e6%93%ac%e9%a1%8c150%e9%a1%8c/","explanation":"AI治理的目標在於確保AI系統公平、透明、安全、可控，並降低其對社會可能造成的風險。強化AI的自我進化能力屬於技術發展方向，並非治理追求的目標，甚至可能增加治理的難度。","concept":"AI治理","aiExplained":true},{"id":"web-j2-708","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"制定生成式 AI 導入策略時，釐清導入目標是為了「提升效率」、「降低成本」或「開創產品」，這屬於策略規劃三大核心中的哪一項？","options":{"A":"高階支持","B":"定位目標","C":"漸進式融合","D":"技術選型"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"釐清導入生成式AI是為了提升效率、降低成本還是開創新產品，屬於「定位目標」的工作，也就是先確立導入的方向與預期價值。目標明確之後，後續的技術選型與推動節奏才有依據。","concept":"導入策略規劃","aiExplained":true},{"id":"web-j2-709","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"NIST AI RMF (風險管理框架) 強調了治理 (Govern)、映射 (Map)、測量 (Measure) 和管理 (Manage) 四大功能，其核心目標是？","options":{"A":"評估 AI 模型的商業價值","B":"提供一個系統化管理 AI 風險的結構化方法","C":"加速 AI 模型的訓練過程","D":"制定 AI 技術的國際標準"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"NIST AI RMF透過治理、映射、測量、管理四大功能，提供一套系統化、結構化的AI風險管理方法。其重點在於辨識與控管AI風險，而非評估商業價值、加速訓練或制定國際標準。","concept":"AI風險管理框架","aiExplained":true},{"id":"web-j2-710","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"Google Gemini 支援「文字+圖片+音訊」混合輸入，這屬於哪種進階應用技巧？","options":{"A":"串接工具鏈","B":"融合多模態輸入提升創意質量","C":"客製化訓練模型","D":"動態調整生成參數"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"Gemini能同時接收文字、圖片與音訊，屬於融合多模態輸入的進階應用技巧。多模態輸入能提供更豐富的上下文，讓模型的生成結果更貼近需求、提升創意品質。","concept":"多模態輸入","aiExplained":true},{"id":"web-j2-711","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"根據 McKinsey 報告，明確定義業務需求可將 AI 導入成功率提升多少？","options":{"A":"10%","B":"20%","C":"30%","D":"50%"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"根據McKinsey的報告，導入AI前先明確定義業務需求，可將導入成功率提升約30%。這說明成功的關鍵不在技術本身，而在於先想清楚要解決什麼問題。","concept":"AI導入成功要素","aiExplained":true},{"id":"web-j2-713","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"DeepMind 的 AlphaFold 主要解決了哪個科學領域的重大問題？","options":{"A":"氣候變遷預測","B":"蛋白質結構摺疊預測","C":"宇宙暗物質探索","D":"量子計算機設計"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"AlphaFold成功預測蛋白質的三維摺疊結構，解決了困擾生物學界半世紀的重大難題。這項突破大幅加速藥物開發與疾病研究，是AI應用於基礎科學的里程碑。","concept":"AlphaFold","aiExplained":true},{"id":"web-j2-714","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"成功的企業通常將生成式 AI 定位為？","options":{"A":"完全取代人類員工的工具","B":"輔助人類工作的協作工具","C":"僅供 IT 部門使用的專業系統","D":"短期內可以快速獲利的噱頭"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"成功導入生成式AI的企業多將其定位為輔助人類工作的協作工具，由AI處理初稿與重複性任務，人類負責判斷與把關。視AI為完全取代人力的工具或短期獲利噱頭，都是常見的錯誤定位。","concept":"人機協作定位","aiExplained":true},{"id":"web-j2-715","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"對於醫療診斷等高風險領域，模型缺乏可解釋性（黑箱問題）是一個挑戰，文件建議導入什麼工具來提升透明度？","options":{"A":"GPU 加速卡","B":"可解釋性工具（如 LIME）","C":"數據標註平台","D":"項目管理軟體"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"針對醫療診斷等高風險應用，可導入LIME等可解釋性工具，說明模型做出判斷的依據。這能提升決策透明度與使用者信任，也有助於符合法規對問責的要求。","concept":"可解釋性AI","aiExplained":true},{"id":"web-j2-716","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"將用戶的修改記錄回傳用於訓練模型，如鹿班系統透過設計師修正數據進行迭代，屬於哪種品質提升方法？","options":{"A":"實施數據清洗","B":"導入混合評估體系","C":"設計持續學習機制 (即時反饋閉環)","D":"掌握提示工程技巧"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"將使用者的修改記錄回傳給模型持續訓練，形成即時反饋閉環，屬於持續學習機制的設計。鹿班系統正是透過設計師的修正數據不斷迭代，讓生成品質隨著使用而提升。","concept":"持續學習機制","aiExplained":true},{"id":"web-j2-717","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"如果需要進行藝術創作或概念藝術設計，文件推薦使用哪個圖像生成工具？","options":{"A":"魯班 AI (鹿班)","B":"ChatGPT","C":"Midjourney","D":"Synthesia"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"Midjourney以藝術風格與美感表現見長，特別適合藝術創作與概念藝術設計。鹿班主打電商圖像的量產，Synthesia專注於AI影片生成，ChatGPT則以文字生成為主。","concept":"圖像生成工具","aiExplained":true},{"id":"web-j2-719","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在商業或學術場景中，處理 AI 生成內容的正確態度是？","options":{"A":"完全信任並直接使用","B":"認為 AI 輸出完全不可靠而棄用","C":"將其視為初稿，進行必要的後期編輯和人工審查","D":"只使用 AI 生成的圖像，不使用文本"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"AI生成內容可能包含錯誤、偏見或幻覺，因此應將其視為初稿，再由人工進行查證、編輯與審查後才能使用。完全信任直接採用，或全盤棄用，都不是負責任的使用態度。","concept":"AI內容審查","aiExplained":true},{"id":"web-j2-720","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"在自動化流程範例中：ChatGPT 生成文案 -> Zapier 觸發 -> DALL-E 3 生成配圖 -> Canva 排版發布，體現了哪種進階技巧？","options":{"A":"客製化訓練企業專屬模型","B":"透過 API 串接不同工具實現端到端自動化","C":"融合多模態輸入","D":"動態調整生成參數"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"此流程透過API與Zapier把ChatGPT、DALL-E 3、Canva等不同工具串接起來，從文案、配圖到排版發布一氣呵成。這正是以API串接工具鏈、實現端到端自動化的典型範例。","concept":"API工具串接","aiExplained":true},{"id":"web-j2-721","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"如果 AI 模型因訓練數據偏差，在處理招聘申請時系統性地給予男性候選人更高的評分，這體現了哪種風險？","options":{"A":"數據隱私洩露","B":"偏見強化與歧視風險","C":"模型幻覺","D":"著作權侵權"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"訓練數據若隱含性別偏差，模型會學到並放大這種偏見，在招聘情境中系統性地給予特定群體較高或較低的評分。這屬於偏見強化與歧視風險，是AI倫理治理的核心議題。","concept":"AI偏見風險","aiExplained":true},{"id":"web-j2-722","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"進行生成式 AI 導入評估的首要基礎是？","options":{"A":"選擇最先進的 AI 模型","B":"評估 IT 部門的程式設計能力","C":"明確業務需求，識別 AI 能解決的具體問題","D":"計算公司伺服器的總數量"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"導入生成式AI的首要基礎是明確業務需求，找出AI能解決的具體問題與痛點。若跳過此步驟直接追逐最先進的模型，容易導致投資與實際需求脫節，專案失敗率大增。","concept":"需求評估","aiExplained":true},{"id":"web-j2-723","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"為了保護用戶上傳的語音數據中的生物特徵信息，可以採用哪種數據治理技術？","options":{"A":"數據複製與備份","B":"數據最小化與聲紋混淆/匿名化","C":"數據標籤化與分類","D":"數據壓縮與歸檔"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"語音資料含有聲紋等生物特徵，屬於高敏感個資。透過數據最小化只蒐集必要的資料，並以聲紋混淆或匿名化技術去識別化，能有效降低隱私外洩的風險。","concept":"數據治理","aiExplained":true},{"id":"web-j2-724","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"PwC 的研究顯示，投資於變革管理（如員工培訓、溝通）的企業，其 AI 導入成功率高出多少？","options":{"A":"15%","B":"25%","C":"35%","D":"50%"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"根據PwC的研究，投資於員工培訓、內部溝通等變革管理的企業，其AI導入成功率高出約35%。這顯示除了技術之外，組織與人的因素同樣是導入成敗的關鍵。","concept":"變革管理","aiExplained":true},{"id":"web-j2-725","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"建立數據治理框架，確保數據安全、可追溯並符合法規，是為了實現生成式 AI 的哪個目標？","options":{"A":"最高的運行速度","B":"最低的運營成本","C":"持續的價值、合規性與適應性","D":"最具創意的輸出結果"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"建立數據治理框架能確保資料安全、可追溯且符合法規，讓生成式AI的應用得以長期維持價值、保持合規並隨環境調整。它追求的是永續經營，而非單純的速度或成本極小化。","concept":"數據治理框架","aiExplained":true},{"id":"web-j2-726","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"根據 Google 報告，企業導入生成式 AI 的效益在短期（6-12個月）內通常聚焦於哪些應用？","options":{"A":"開發全新的智能客服系統","B":"進行複雜的供應鏈預測","C":"自動化文件生成、程式碼輔助開發等低風險、高回報應用","D":"推動全新的創新商業模式"},"answer":"C","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"Google報告指出，企業導入生成式AI的短期（6至12個月）效益多來自低風險、高回報的應用，例如自動化文件生成與程式碼輔助開發。這類應用見效快，適合作為導入初期的切入點。","concept":"短期導入效益","aiExplained":true},{"id":"web-j2-727","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"解決跨文化內容生成問題的有效方法是？","options":{"A":"僅使用英文進行 AI 生成","B":"訓練在地化模型或採用雙層校對機制（AI初翻+母語者潤飾）","C":"增加 Temperature 參數以產生多樣性","D":"使用更複雜的機器翻譯引擎"},"answer":"B","needsContext":false,"source":"網路題庫 · S測驗 sustainnovation","srcUrl":"https://sustainnovation.cc/ipas-ai%e6%87%89%e7%94%a8%e8%a6%8f%e5%8a%83%e5%b8%ab-%e5%88%9d%e7%b4%9a_%e7%94%9f%e6%88%90%e5%bc%8fai%e6%a8%a1%e6%93%ac%e8%a9%a6%e9%a1%8c150%e9%a1%8c/","explanation":"跨文化內容生成容易出現語感與文化脈絡的落差，有效解法是訓練在地化模型，或採用「AI初翻加母語者潤飾」的雙層校對機制。僅用英文生成或調高Temperature參數，都無法解決文化適應的問題。","concept":"在地化生成","aiExplained":true},{"id":"web-j1-1362","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某保險公司規劃推出一套 AI 核保輔助系統，針對線上投保申請進行初步風險評估並自動回覆審核結果。系統開發完成後，依據金融機構運用人工智慧技術作業規範，系統在正式與消費者互動前，必須確認相關揭露義務已落實。請問下列何者不屬於該規範要求金融機構必要揭露的事項？ 第一科：人工智慧基礎概論","options":{"A":"詳細公開本系統所採用的機器學習模型架構與完整訓練資料內容","B":"說明本服務的適用對象與用途範圍，使消費者了解系統的使用限制與服務邊界","C":"說明當消費者對 AI 核保結果有異議時，是否提供人工複核或申訴管道","D":"告知消費者本次核保審查結果係由 AI 系統自動完成，非人工逐案審核"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"依金融機構運用人工智慧技術的作業規範，金融機構須向消費者揭露服務的適用對象與範圍、審核結果是否由 AI 自動完成，以及有異議時是否提供人工複核或申訴管道，選項 B、C、D 皆屬必要揭露事項。至於機器學習模型架構與完整訓練資料內容涉及營業秘密與資訊安全，規範並未要求詳細公開，故 A 不屬必要揭露事項。","concept":"AI金融揭露義務","aiExplained":true},{"id":"web-j1-1363","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某製造業導入 AI 進行生產排程，需整合 ERP（企業資源規劃系統）訂單資料、 第一科：人工智慧基礎概論設備感測器產生的連續數值紀錄，以及維修技師手寫異常描述（掃描為 PDF）。 資料治理主管需判斷三類資料的型態。下列何者最能正確對應其資料型態？","options":{"A":"ERP 訂單資料為半結構化、感測器數值為結構化、維修文字描述為非結構化","B":"ERP 訂單資料為結構化、感測器數值為結構化、維修文字描述為非結構化","C":"ERP 訂單資料為結構化、感測器數值為非結構化、維修文字描述為半結構化","D":"三者皆屬結構化資料，因為都可以轉換為數值格式後進行分析"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"ERP 訂單資料具固定欄位與格式，屬結構化資料；設備感測器產生的連續數值紀錄同樣以固定格式的數值欄位儲存，亦屬結構化資料。維修技師手寫的異常描述掃描為 PDF，是無固定結構的自由文字影像，屬非結構化資料，因此 B 的對應最正確。","concept":"資料型態分類","aiExplained":true},{"id":"web-j1-1364","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某企業集團在多個領域導入 AI 技術，應用於不同業務場景。請問下列哪一項最第一科：人工智慧基礎概論符合異常檢測（Anomaly Detection）的主要應用目標？","options":{"A":"分析客戶的消費行為資料，將客群依偏好進行分群，以制定差異化行銷策略","B":"根據歷史交易與客戶資料，建立模型預測未來可能發生違約的客戶","C":"彙整企業各部門的營運數據，建立儀表板供管理層追蹤關鍵績效指標 （KPI）的變化","D":"從設備感測資料中，即時偵測出與正常運作模式顯著偏離的訊號，以預警可能發生的故障"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"異常檢測的目標是找出與正常模式顯著偏離的資料點。選項 D 從設備感測資料中即時偵測與正常運作模式明顯偏離的訊號並預警故障，正是異常檢測的典型應用。A 屬於分群應用、B 屬於分類預測、C 只是彙整數據的描述性儀表板，皆非異常檢測。","concept":"異常檢測","aiExplained":true},{"id":"web-j1-1365","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某跨國企業需透過網路將各國子公司之敏感資料傳輸至總部進行模型訓練。資訊安全主管要求在傳輸過程中防範中間人攻擊，避免資料遭竊取或竄改。在不第一科：人工智慧基礎概論影響系統跨國即時傳輸效率之前提下，下列哪一項措施最能有效降低此風險？","options":{"A":"在接收端加強存取權限與身分驗證，限制只有授權人員可讀取資料","B":"在資料傳輸過程中進行加密，並確認雙方身分以確保通訊安全","C":"將資料拆分為多個部分分批傳送，降低單次資料外洩風險","D":"改用離線備援方式進行跨國資料交換，以降低網路攻擊風險"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"中間人攻擊的風險在於資料傳輸途中被竊聽或竄改，最直接有效的防護是對傳輸通道加密並驗證通訊雙方身分，如同 TLS 的作法，既確保機密性與完整性，也不明顯影響即時傳輸效率。A 只強化接收端存取控制，C 拆分傳送與 D 離線交換都未真正解決傳輸過程的竊聽與竄改問題。","concept":"傳輸加密防護","aiExplained":true},{"id":"web-j1-1366","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某電商平台導入強化學習（Reinforcement Learning）技術優化商品推薦策略，AI 代理（AI Agent）會根據使用者的點擊與購買行為持續調整推薦內容。技術團隊在討論中發現，系統面臨一個核心挑戰：若 AI Agent 總是推薦過去表現良好的商品，可能會錯失發掘更高潛力商品的機會；但若頻繁嘗試未知商品，又可能影響短期的推薦成效與使用者體驗。請問上述情境敘述的是強化學習中哪一個第一科：人工智慧基礎概論核心問題？","options":{"A":"探索與利用的權衡（Exploration vs. Exploitation）","B":"偏差與變異的權衡（Bias vs. Variance）","C":"梯度爆炸與消失（Vanishing and Exploding Gradients）","D":"過擬合與欠擬合（Overfitting and Underfitting）"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"情境描述的是「持續推薦過去表現良好的商品」與「嘗試未知商品以發掘更高潛力」之間的兩難，這正是強化學習中探索（Exploration）與利用（Exploitation）的權衡問題。偏差與變異、梯度爆炸與消失、過擬合與欠擬合都是模型訓練層面的議題，與這種行動決策的取捨無關。","concept":"探索與利用權衡","aiExplained":true},{"id":"web-j1-1367","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某銀行使用 LIME（Local Interpretable Model-agnostic Explanations）來解釋其信第一科：人工智慧基礎概論貸審核模型的決策結果。分析師在閱讀解釋報告時，看到系統建立了一個簡化模型來近似原模型在該筆資料附近的行為。下列何者最能說明 LIME 中代理模型（Surrogate model）的意義？","options":{"A":"一個全局解釋所有預測的線性代理模型","B":"用於產生擾動資料的資料生成機制","C":"一種獨立訓練的生成式模型，用於輔助預測","D":"用於擬合原黑箱模型在目標實例附近的預測行為"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"LIME 的核心作法是在目標實例附近產生擾動資料，再用一個可解釋的簡單模型去擬合原黑箱模型在該局部區域的預測行為，這個簡單模型就是代理模型。它只負責局部近似而非全局解釋，也不是資料生成機制或獨立的生成式模型，故 D 最能說明其意義。","concept":"LIME代理模型","aiExplained":true},{"id":"web-j1-1368","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"小明剛加入一間電商公司擔任 AI 專案的業務窗口，在與技術團隊的交接會議中，工程師說明模型訓練時，會持續比對預測值與實際值之間的差距，並透過一套機制逐步調整模型內部參數，直到預測結果趨於穩定為止。請問工程師敘第一科：人工智慧基礎概論述的是深度學習中哪個元件的功能？","options":{"A":"優化器（Optimizer）","B":"資料前處理模組","C":"模型架構","D":"激活函數（Activation Function）"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"工程師描述的是比對預測值與實際值的差距，並透過機制逐步調整模型內部參數直到結果趨於穩定，這正是優化器的功能，例如以梯度下降法更新權重使損失逐步下降。資料前處理模組、模型架構與激活函數都不負責參數的迭代更新。","concept":"優化器功能","aiExplained":true},{"id":"web-j1-1369","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某音樂串流平台希望開發一套 AI 系統，能根據平台上累積的大量歌曲資料，自動生成具有不同風格變化的全新旋律，供創作者作為靈感參考。平台技術長在評估方案時強調，系統不能只是播放或拼接既有歌曲片段，也不能僅進行資料第一科：人工智慧基礎概論的重建，而是要真正學習音樂的結構與風格，並創作出從未出現過的新旋律。 請問下列哪一種模型技術最符合此需求？","options":{"A":"K-近鄰演算法（K-Nearest Neighbors, KNN）","B":"自編碼器（Autoencoder）","C":"生成對抗網路（GAN）","D":"隨機森林（Random Forest）"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"題目要求系統學習音樂的結構與風格並創作從未出現過的新旋律，而非拼接既有片段或僅做資料重建，這是生成式模型的任務。GAN 透過生成器與判別器的對抗訓練，能產生逼真且全新的樣本，最符合需求；KNN 與隨機森林屬判別式方法，自編碼器則以資料重建與壓縮為主。","concept":"生成對抗網路","aiExplained":true},{"id":"web-j1-1370","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某金融集團評估將大型語言模型導入客服與風控系統，團隊採用如 120B 參數等第一科：人工智慧基礎概論級的超大型語言模型以確保回應品質。請問下列何者最能說明企業在正式環境部署超大型語言模型時，最需要優先考量的因素？","options":{"A":"模型參數量龐大，導致每次輸出結果差異極大，難以符合金融業對回應一致性的要求","B":"超大型模型無法支援批次處理，在高併發的客服場景下將造成嚴重的服務瓶頸","C":"推理延遲較高且運算資源消耗龐大，每次請求成本遠高於小型模型，需在模型效能與營運成本之間審慎權衡","D":"模型會依任務複雜度自動調整運算資源配置，因此不需特別考量推理成本"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"120B 參數等級的超大型語言模型在推理時延遲較高，且運算資源消耗龐大，每次請求的成本遠高於小型模型，因此正式部署前必須在模型效能與營運成本之間審慎權衡，C 正確。大型模型並非輸出必然不一致、也非不能批次處理，更不會自動調整資源而免除成本考量。","concept":"LLM部署成本","aiExplained":true},{"id":"web-j1-1371","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某電商平台建置機器學習模型，用於預測用戶在瀏覽特定商品後的購買機率。 模型上線初期表現穩定，但維運團隊在定期審查中發現兩種不同情形： 情形甲：模型上線半年後恰逢消費趨勢轉變，過去高購買意願的用戶行為模式 （如長時間停留商品頁）不再是強烈的購買訊號，即便輸入特徵分布與訓練期相近，模型預測準確率仍明顯下降。 第一科：人工智慧基礎概論情形乙：平台新增了行動裝置端的入口，新用戶的年齡分布、裝置類型與使用時段特徵與原訓練資料差異顯著，導致模型對這批用戶的預測偏差增大。 下列哪一項最能正確對應兩種情形所屬的模型劣化類型？","options":{"A":"甲為資料漂移（Data Drift） 、乙為概念漂移（Concept Drift）","B":"甲為概念漂移（Concept Drift） 、乙為資料漂移（Data Drift）","C":"甲為模型過擬合（Overfitting） 、乙為資料漂移（Data Drift）","D":"甲與乙均屬概念漂移（Concept Drift） ，因為兩者都導致模型預測準確率下降"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"情形甲的輸入特徵分布與訓練期相近，但特徵與購買行為之間的對應關係因消費趨勢轉變而失效，屬於概念漂移；情形乙是新用戶的年齡、裝置等特徵分布與訓練資料顯著不同，屬於資料漂移。因此 B 的對應正確，兩者劣化機制並不相同。","concept":"模型漂移類型","aiExplained":true},{"id":"web-j1-1372","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「AI 核心能力」，下列何者最正確？","options":{"A":"AI 系統的價值在於感知資料、推論模式並輔助或自動化決策","B":"AI 僅能處理結構化表格","C":"AI 一定具有通用人類智慧","D":"AI 只能用於學術研究"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 系統的核心價值在於感知環境資料、從中推論模式，進而輔助甚至自動化決策，選項 A 正確描述了這項能力。AI 並非只能處理結構化表格，現今的 AI 也不具備通用人類智慧，應用範圍更遍及產業而不限於學術研究。","concept":"AI核心能力","aiExplained":true},{"id":"web-j1-1373","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「大數據 5V」，下列何者最正確？","options":{"A":"只要資料筆數多就不需要資料品質治理","B":"Volume、Velocity、Variety 等特性會影響資料蒐集、儲存與即時處理設計","C":"大數據一定不需要抽樣與統計","D":"Variety 指模型版本數量"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"大數據的 Volume（量）、Velocity（速度）、Variety（多樣性）等特性，會直接影響資料蒐集、儲存架構與即時處理的設計，故 B 正確。資料量大反而更需要品質治理，抽樣與統計仍是常用手段，而 Variety 指的是資料型態的多樣性，並非模型版本數量。","concept":"大數據5V特性","aiExplained":true},{"id":"web-j1-1374","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「分析類型」，下列何者最正確？","options":{"A":"診斷性分析主要預測未來","B":"處方性分析只整理歷史報表","C":"描述性、診斷性、預測性與處方性分析分別回答發生什麼、為何發生、將發生什麼、該怎麼做","D":"描述性分析會自動下決策指令"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"四種分析類型各有定位：描述性分析回答「發生了什麼」、診斷性分析回答「為何發生」、預測性分析回答「將發生什麼」、處方性分析回答「該怎麼做」，選項 C 的對應完整正確。診斷性分析並非預測未來，處方性分析也不只是整理歷史報表，描述性分析更不會自動下決策。","concept":"四種分析類型","aiExplained":true},{"id":"web-j1-1375","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「監督式學習」，下列何者最正確？","options":{"A":"完全不需要標註資料","B":"只用於資料視覺化","C":"只能找未知群集","D":"有標註答案的資料適合訓練分類或迴歸模型"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"監督式學習的前提是擁有帶標註答案的資料，模型從輸入特徵與標籤的對應關係中學習，適合訓練分類或迴歸模型，故 D 正確。它並非不需要標註資料，也不是用於資料視覺化，尋找未知群集則屬於非監督式學習的範疇。","concept":"監督式學習","aiExplained":true},{"id":"web-j1-1376","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「非監督式學習」，下列何者最正確？","options":{"A":"無標註資料可用分群、降維或異常偵測探索潛在結構","B":"能保證判定每筆資料的真實類別","C":"必須先提供正確答案","D":"只能做文字生成"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"非監督式學習處理無標註資料，透過分群、降維或異常偵測等方法探索資料的潛在結構，故 A 正確。由於沒有正確答案可供對照，它無法保證判定每筆資料的真實類別，也不需要事先提供標籤，應用更不限於文字生成。","concept":"非監督式學習","aiExplained":true},{"id":"web-j1-1377","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「強化學習」，下列何者最正確？","options":{"A":"只根據靜態標籤做分類","B":"代理人在環境中透過行動、回饋與獎勵學習策略","C":"不需要環境回饋","D":"等同資料庫查詢"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"強化學習的核心是代理人在環境中採取行動，依據環境回饋的獎勵訊號持續調整策略以極大化長期報酬，故 B 正確。它不是根據靜態標籤做分類，環境回饋更是學習不可或缺的要素，與資料庫查詢完全不同。","concept":"強化學習機制","aiExplained":true},{"id":"web-j1-1378","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「模型評估」，下列何者最正確？","options":{"A":"準確率永遠是唯一指標","B":"不平衡資料不影響評估","C":"準確率、精確率、召回率與 F1 要依問題成本選擇","D":"評估只需看訓練集表現"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"評估指標應依問題的錯誤成本選擇：準確率、精確率、召回率與 F1 各有適用情境，尤其在不平衡資料下準確率容易失真，必須搭配其他指標判讀，故 C 正確。模型評估也必須以測試集表現為準，不能只看訓練集。","concept":"模型評估指標","aiExplained":true},{"id":"web-j1-1379","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「深度學習」，下列何者最正確？","options":{"A":"完全不需要資料與算力","B":"只適用小型表格","C":"一定比所有傳統模型更可解釋","D":"多層神經網路適合從大量非結構化資料中自動學習特徵"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"深度學習以多層神經網路從大量非結構化資料（如影像、語音、文字）中自動學習特徵表示，故 D 正確。它需要大量資料與算力支撐，可解釋性通常低於傳統模型，適用場景也不限於小型表格資料。","concept":"深度學習特性","aiExplained":true},{"id":"web-j1-1380","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「自然語言處理」，下列何者最正確？","options":{"A":"NLP 用於理解、分類、摘要、翻譯與分析文字或語音內容","B":"NLP 主要處理邊界框定位","C":"NLP 只能做數值迴歸","D":"NLP 不處理語意脈絡"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"自然語言處理的任務涵蓋文字與語音內容的理解、分類、摘要、翻譯與分析，故 A 正確。邊界框定位屬於電腦視覺的物件偵測任務，而 NLP 的核心正是處理語意與上下文脈絡，並非只能做數值迴歸。","concept":"NLP應用範疇","aiExplained":true},{"id":"web-j1-1381","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「電腦視覺」，下列何者最正確？","options":{"A":"主要分析文字情緒","B":"電腦視覺處理影像中的分類、偵測、分割與瑕疵判讀","C":"只能處理財務表格","D":"與影像資料無關"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"電腦視覺專門處理影像資料，涵蓋影像分類、物件偵測、影像分割與工業瑕疵判讀等任務，故 B 正確。文字情緒分析屬於自然語言處理的範疇，財務表格則是結構化資料分析的對象，皆非電腦視覺的主要任務。","concept":"電腦視覺任務","aiExplained":true},{"id":"web-j1-1382","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「RAG 與微調」，下列何者最正確？","options":{"A":"RAG 必須重新訓練模型","B":"微調最適合即時更新每月內規","C":"RAG 適合查詢快速更新的外部知識，微調適合調整模型風格或任務能力","D":"兩者完全沒有差異"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"RAG 透過檢索外部知識庫再生成回答，不需重新訓練模型，適合處理更新頻繁的知識；微調則是調整模型參數，適合塑造回應風格或強化特定任務能力，故 C 正確。每月更新的內規若靠微調維護，成本高且緩不濟急，兩者的定位明顯不同。","concept":"RAG與微調","aiExplained":true},{"id":"web-j1-1383","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「AI 倫理」，下列何者最正確？","options":{"A":"只要準確率高即可忽略公平性","B":"黑箱模型不需要申訴機制","C":"個資使用不需要告知","D":"透明性、公平性、問責性、隱私性與安全性是高風險 AI 的核心要求"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"高風險 AI 應用的核心治理要求包括透明性、公平性、問責性、隱私性與安全性，故 D 正確。準確率高不能取代公平性檢視，黑箱模型更需要提供申訴機制，個資的蒐集與使用也必須履行告知義務。","concept":"AI倫理原則","aiExplained":true},{"id":"web-j1-1384","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「AI 安全」，下列何者最正確？","options":{"A":"AI 系統需防範對抗攻擊、資料污染與供應鏈風險","B":"模型部署後不會被攻擊","C":"安全只與硬體故障有關","D":"開源元件不需盤點"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 系統面臨的安全威脅不只硬體故障，還包括對抗樣本攻擊、訓練資料污染，以及開源元件等供應鏈風險，故 A 正確。模型部署上線後仍可能遭受攻擊，開源元件也必須盤點管理，安全防護是持續性的工作。","concept":"AI安全威脅","aiExplained":true},{"id":"web-j1-1385","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「隱私保護」，下列何者最正確？","options":{"A":"蒐集越多個資越一定合法","B":"最小化蒐集、去識別化與授權管理可降低個資風險","C":"匿名化永遠不可能再識別","D":"隱私只影響行銷部門"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"降低個資風險的關鍵作法包括僅蒐集必要資料的最小化原則、去識別化處理，以及嚴謹的授權與存取管理，故 B 正確。蒐集越多個資不代表合法，匿名化資料仍可能透過交叉比對被重新識別，隱私議題也影響全組織而非僅行銷部門。","concept":"隱私保護原則","aiExplained":true},{"id":"web-j1-1386","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「AI 導入治理」，下列何者最正確？","options":{"A":"上線後不用監控","B":"可完全省略利害關係人溝通","C":"AI 專案需建立資料、模型、風險、監控與人工覆核機制","D":"治理會讓 AI 專案不需要測試"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"完整的 AI 導入治理需建立資料治理、模型管理、風險評估、上線後持續監控與人工覆核機制，故 C 正確。模型上線後仍會劣化因此必須監控，利害關係人溝通與系統測試也都是不可省略的環節。","concept":"AI導入治理","aiExplained":true},{"id":"web-j1-1387","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「AI 核心能力」，下列何者最正確？","options":{"A":"AI 一定具有通用人類智慧","B":"AI 只能用於學術研究","C":"AI 僅能處理結構化表格","D":"AI 系統的價值在於感知資料、推論模式並輔助或自動化決策"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 系統的核心價值在於感知環境資料、推論其中的模式，進而輔助或自動化決策，選項 D 的敘述最正確。現今的 AI 不具備通用人類智慧，處理對象也不限於結構化表格，應用範圍更遍及各產業而非僅學術研究。","concept":"AI核心能力","aiExplained":true},{"id":"web-j1-1388","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「大數據 5V」，下列何者最正確？","options":{"A":"Volume、Velocity、Variety 等特性會影響資料蒐集、儲存與即時處理設計","B":"大數據一定不需要抽樣與統計","C":"Variety 指模型版本數量","D":"只要資料筆數多就不需要資料品質治理"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"大數據的 Volume（量）、Velocity（速度）、Variety（多樣性）等特性，會直接影響資料蒐集、儲存與即時處理架構的設計，故 A 正確。資料筆數多反而更需要品質治理，抽樣與統計仍不可或缺，Variety 指的是資料型態多樣而非模型版本數量。","concept":"大數據5V特性","aiExplained":true},{"id":"web-j1-1389","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「分析類型」，下列何者最正確？","options":{"A":"處方性分析只整理歷史報表","B":"描述性、診斷性、預測性與處方性分析分別回答發生什麼、為何發生、將發生什麼、該怎麼做","C":"描述性分析會自動下決策指令","D":"診斷性分析主要預測未來"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"描述性、診斷性、預測性與處方性分析分別回答「發生什麼」、「為何發生」、「將發生什麼」與「該怎麼做」，選項 B 的對應完整正確。診斷性分析著重解釋過去而非預測未來，處方性分析提供行動建議而非整理報表，描述性分析也不會自動下決策指令。","concept":"四種分析類型","aiExplained":true},{"id":"web-j1-1390","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「監督式學習」，下列何者最正確？","options":{"A":"只用於資料視覺化","B":"只能找未知群集","C":"有標註答案的資料適合訓練分類或迴歸模型","D":"完全不需要標註資料"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"監督式學習需要有標註答案的資料，模型從輸入與標籤的對應關係中學習，適合訓練分類或迴歸模型，故 C 正確。它並非不需要標註資料，也不是資料視覺化工具，尋找未知群集則是非監督式學習的任務。","concept":"監督式學習","aiExplained":true},{"id":"web-j1-1391","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「非監督式學習」，下列何者最正確？","options":{"A":"必須先提供正確答案","B":"只能做文字生成","C":"能保證判定每筆資料的真實類別","D":"無標註資料可用分群、降維或異常偵測探索潛在結構"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"非監督式學習針對無標註資料，以分群、降維或異常偵測等方法探索潛在結構，故 D 正確。它不需要事先提供正確答案，也因缺乏標籤而無法保證判定每筆資料的真實類別，應用範圍更不限於文字生成。","concept":"非監督式學習","aiExplained":true},{"id":"web-j1-1392","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「強化學習」，下列何者最正確？","options":{"A":"代理人在環境中透過行動、回饋與獎勵學習策略","B":"不需要環境回饋","C":"等同資料庫查詢","D":"只根據靜態標籤做分類"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"強化學習的核心是代理人在環境中透過行動、觀察回饋並累積獎勵來學習最佳策略，故 A 正確。環境回饋是強化學習不可或缺的要素，它不是根據靜態標籤做分類，更與資料庫查詢完全不同。","concept":"強化學習機制","aiExplained":true},{"id":"web-j1-1393","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「模型評估」，下列何者最正確？","options":{"A":"不平衡資料不影響評估","B":"準確率、精確率、召回率與 F1 要依問題成本選擇","C":"評估只需看訓練集表現","D":"準確率永遠是唯一指標"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"準確率、精確率、召回率與 F1 各有適用情境，應依問題中不同錯誤的成本來選擇，尤其在不平衡資料下準確率容易產生誤導，故 B 正確。模型評估必須以測試集表現為準，準確率也絕非唯一指標。","concept":"模型評估指標","aiExplained":true},{"id":"web-j1-1394","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「深度學習」，下列何者最正確？","options":{"A":"只適用小型表格","B":"一定比所有傳統模型更可解釋","C":"多層神經網路適合從大量非結構化資料中自動學習特徵","D":"完全不需要資料與算力"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"深度學習以多層神經網路從大量非結構化資料中自動學習特徵表示，適合處理影像、語音與文字等資料，故 C 正確。它需要充足的資料與算力，可解釋性通常低於傳統模型，並不限於小型表格的應用。","concept":"深度學習特性","aiExplained":true},{"id":"web-j1-1395","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「自然語言處理」，下列何者最正確？","options":{"A":"NLP 只能做數值迴歸","B":"NLP 不處理語意脈絡","C":"NLP 主要處理邊界框定位","D":"NLP 用於理解、分類、摘要、翻譯與分析文字或語音內容"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"自然語言處理用於理解、分類、摘要、翻譯與分析文字或語音內容，故 D 正確。邊界框定位是電腦視覺的物件偵測任務，NLP 的核心正是處理語意與上下文脈絡，也不是只能做數值迴歸。","concept":"NLP應用範疇","aiExplained":true},{"id":"web-j1-1396","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「電腦視覺」，下列何者最正確？","options":{"A":"電腦視覺處理影像中的分類、偵測、分割與瑕疵判讀","B":"只能處理財務表格","C":"與影像資料無關","D":"主要分析文字情緒"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"電腦視覺處理影像資料中的分類、偵測、分割與瑕疵判讀等任務，故 A 正確。分析文字情緒屬於自然語言處理的範疇，財務表格是結構化資料分析的對象，電腦視覺的核心正是與影像資料密切相關。","concept":"電腦視覺任務","aiExplained":true},{"id":"web-j1-1397","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「RAG 與微調」，下列何者最正確？","options":{"A":"微調最適合即時更新每月內規","B":"RAG 適合查詢快速更新的外部知識，微調適合調整模型風格或任務能力","C":"兩者完全沒有差異","D":"RAG 必須重新訓練模型"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"RAG 以檢索外部知識庫的方式補充最新資訊，不需重新訓練模型，適合查詢快速更新的知識；微調則透過調整參數改變模型的風格或任務能力，故 B 正確。若用微調來維護每月更新的內規，成本高且時效差，兩者定位明顯不同。","concept":"RAG與微調","aiExplained":true},{"id":"web-j1-1398","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「AI 倫理」，下列何者最正確？","options":{"A":"黑箱模型不需要申訴機制","B":"個資使用不需要告知","C":"透明性、公平性、問責性、隱私性與安全性是高風險 AI 的核心要求","D":"只要準確率高即可忽略公平性"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"透明性、公平性、問責性、隱私性與安全性是高風險 AI 應用的核心治理要求，故 C 正確。準確率高不能取代公平性檢視，黑箱模型更需要申訴機制以保障當事人權益，個資使用也必須履行告知義務。","concept":"AI倫理原則","aiExplained":true},{"id":"web-j1-1399","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「AI 安全」，下列何者最正確？","options":{"A":"安全只與硬體故障有關","B":"開源元件不需盤點","C":"模型部署後不會被攻擊","D":"AI 系統需防範對抗攻擊、資料污染與供應鏈風險"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 系統需防範的安全威脅包括對抗攻擊、訓練資料污染與開源元件等供應鏈風險，故 D 正確。模型部署後仍可能遭受攻擊，安全議題不只與硬體故障有關，開源元件也必須納入盤點管理。","concept":"AI安全威脅","aiExplained":true},{"id":"web-j1-1400","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「隱私保護」，下列何者最正確？","options":{"A":"最小化蒐集、去識別化與授權管理可降低個資風險","B":"匿名化永遠不可能再識別","C":"隱私只影響行銷部門","D":"蒐集越多個資越一定合法"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"最小化蒐集、去識別化與授權管理是降低個資風險的三項關鍵作法，故 A 正確。蒐集越多個資並不代表合法，匿名化後的資料仍可能被交叉比對再識別，隱私保護更是全組織的責任而非僅限行銷部門。","concept":"隱私保護原則","aiExplained":true},{"id":"web-j1-1401","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「AI 導入治理」，下列何者最正確？","options":{"A":"可完全省略利害關係人溝通","B":"AI 專案需建立資料、模型、風險、監控與人工覆核機制","C":"治理會讓 AI 專案不需要測試","D":"上線後不用監控"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 專案的導入治理需建立資料、模型、風險、監控與人工覆核等機制，涵蓋開發到營運的完整生命週期，故 B 正確。模型上線後仍須持續監控劣化情形，利害關係人溝通與測試也都是治理中不可省略的環節。","concept":"AI導入治理","aiExplained":true},{"id":"web-j1-1402","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「AI 核心能力」，下列何者最正確？","options":{"A":"AI 只能用於學術研究","B":"AI 僅能處理結構化表格","C":"AI 系統的價值在於感知資料、推論模式並輔助或自動化決策","D":"AI 一定具有通用人類智慧"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 的核心價值在於感知外部資料、從中推論模式，進而輔助甚至自動化決策，這正是選項所描述的能力範疇。其餘選項把 AI 限縮在學術研究或結構化表格，或誇大為必然具備通用人類智慧，都是常見的誤解。","concept":"AI核心能力","aiExplained":true},{"id":"web-j1-1403","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「大數據 5V」，下列何者最正確？","options":{"A":"Variety 指模型版本數量","B":"只要資料筆數多就不需要資料品質治理","C":"大數據一定不需要抽樣與統計","D":"Volume、Velocity、Variety 等特性會影響資料蒐集、儲存與即時處理設計"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"大數據的 Volume（量）、Velocity（速度）、Variety（多樣性）等特性，會直接影響資料蒐集、儲存架構與即時處理的設計決策。資料量大並不代表可以忽略品質治理，也不代表不需要抽樣與統計，而 Variety 指的是資料型態多樣，並非模型版本數量。","concept":"大數據5V特性","aiExplained":true},{"id":"web-j1-1404","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「分析類型」，下列何者最正確？","options":{"A":"描述性、診斷性、預測性與處方性分析分別回答發生什麼、為何發生、將發生什麼、該怎麼做","B":"描述性分析會自動下決策指令","C":"診斷性分析主要預測未來","D":"處方性分析只整理歷史報表"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"四種分析類型各有定位：描述性分析回答「發生什麼」，診斷性分析回答「為何發生」，預測性分析回答「將發生什麼」，處方性分析則建議「該怎麼做」。描述性分析不會自動下決策，診斷性分析聚焦過去的原因而非預測未來，處方性分析也不是只整理歷史報表。","concept":"資料分析四類型","aiExplained":true},{"id":"web-j1-1405","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「監督式學習」，下列何者最正確？","options":{"A":"只能找未知群集","B":"有標註答案的資料適合訓練分類或迴歸模型","C":"完全不需要標註資料","D":"只用於資料視覺化"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"監督式學習的特徵是使用有標註答案的資料進行訓練，適合建立分類或迴歸模型。找未知群集是非監督式學習的範疇，而監督式學習正需要標註資料，也不是資料視覺化的專用技術。","concept":"監督式學習","aiExplained":true},{"id":"web-j1-1406","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「非監督式學習」，下列何者最正確？","options":{"A":"只能做文字生成","B":"能保證判定每筆資料的真實類別","C":"無標註資料可用分群、降維或異常偵測探索潛在結構","D":"必須先提供正確答案"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"非監督式學習處理的是無標註資料，透過分群、降維或異常偵測來探索資料的潛在結構。它不需要事先提供正確答案，也無法保證判定每筆資料的真實類別，更不限於文字生成。","concept":"非監督式學習","aiExplained":true},{"id":"web-j1-1407","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「強化學習」，下列何者最正確？","options":{"A":"等同資料庫查詢","B":"只根據靜態標籤做分類","C":"不需要環境回饋","D":"代理人在環境中透過行動、回饋與獎勵學習策略"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"強化學習的核心是代理人在環境中採取行動，依據環境回饋與獎勵訊號逐步學習最佳策略。它與依靜態標籤做分類或資料庫查詢本質不同，且環境回饋正是學習的必要條件。","concept":"強化學習","aiExplained":true},{"id":"web-j1-1408","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「模型評估」，下列何者最正確？","options":{"A":"準確率、精確率、召回率與 F1 要依問題成本選擇","B":"評估只需看訓練集表現","C":"準確率永遠是唯一指標","D":"不平衡資料不影響評估"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"準確率、精確率、召回率與 F1 各有適用情境，應依據問題的錯誤成本來選擇，例如漏判代價高時要重視召回率。只看訓練集會忽略過擬合問題，準確率在不平衡資料下更會產生誤導，因此不能當作唯一指標。","concept":"模型評估指標","aiExplained":true},{"id":"web-j1-1409","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「深度學習」，下列何者最正確？","options":{"A":"一定比所有傳統模型更可解釋","B":"多層神經網路適合從大量非結構化資料中自動學習特徵","C":"完全不需要資料與算力","D":"只適用小型表格"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"深度學習以多層神經網路為架構，擅長從大量非結構化資料（如影像、文字、語音）中自動學習特徵表示。它通常需要大量資料與算力支撐，且可解釋性一般低於傳統模型，並非只適用小型表格。","concept":"深度學習","aiExplained":true},{"id":"web-j1-1410","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「自然語言處理」，下列何者最正確？","options":{"A":"NLP 不處理語意脈絡","B":"NLP 主要處理邊界框定位","C":"NLP 用於理解、分類、摘要、翻譯與分析文字或語音內容","D":"NLP 只能做數值迴歸"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"自然語言處理的任務範疇涵蓋文字與語音內容的理解、分類、摘要、翻譯與分析。邊界框定位屬於電腦視覺的物件偵測任務，而 NLP 正是以處理語意脈絡見長，也不限於數值迴歸。","concept":"自然語言處理","aiExplained":true},{"id":"web-j1-1411","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「電腦視覺」，下列何者最正確？","options":{"A":"與影像資料無關","B":"主要分析文字情緒","C":"只能處理財務表格","D":"電腦視覺處理影像中的分類、偵測、分割與瑕疵判讀"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"電腦視覺專門處理影像資料，典型任務包括影像分類、物件偵測、影像分割與工業瑕疵判讀。文字情緒分析屬於 NLP 範疇，財務表格則是結構化資料分析的對象，與電腦視覺的核心任務不同。","concept":"電腦視覺","aiExplained":true},{"id":"web-j1-1412","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「RAG 與微調」，下列何者最正確？","options":{"A":"RAG 適合查詢快速更新的外部知識，微調適合調整模型風格或任務能力","B":"兩者完全沒有差異","C":"RAG 必須重新訓練模型","D":"微調最適合即時更新每月內規"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"RAG 透過檢索外部知識庫來補充模型回答，適合資訊更新頻繁的場景，且不必重新訓練模型；微調則是調整模型參數，適合改變回答風格或強化特定任務能力。若內規每月更新，更新 RAG 知識庫比反覆微調更有效率。","concept":"RAG與微調","aiExplained":true},{"id":"web-j1-1413","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「AI 倫理」，下列何者最正確？","options":{"A":"個資使用不需要告知","B":"透明性、公平性、問責性、隱私性與安全性是高風險 AI 的核心要求","C":"只要準確率高即可忽略公平性","D":"黑箱模型不需要申訴機制"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"高風險 AI 系統的核心倫理要求包括透明性、公平性、問責性、隱私性與安全性，五者缺一不可。準確率高不能替代公平性檢驗，黑箱模型更需要申訴與救濟機制，個資使用也必須履行告知義務。","concept":"AI倫理原則","aiExplained":true},{"id":"web-j1-1414","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「AI 安全」，下列何者最正確？","options":{"A":"開源元件不需盤點","B":"模型部署後不會被攻擊","C":"AI 系統需防範對抗攻擊、資料污染與供應鏈風險","D":"安全只與硬體故障有關"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 系統面臨的威脅不只硬體故障，還包括對抗攻擊、訓練資料污染與開源元件帶來的供應鏈風險。模型部署後仍可能被攻擊，因此需要持續防護，開源元件也應納入盤點管理。","concept":"AI系統安全","aiExplained":true},{"id":"web-j1-1415","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「隱私保護」，下列何者最正確？","options":{"A":"隱私只影響行銷部門","B":"蒐集越多個資越一定合法","C":"匿名化永遠不可能再識別","D":"最小化蒐集、去識別化與授權管理可降低個資風險"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"降低個資風險的基本作法是最小化蒐集（只收必要資料）、去識別化處理，以及嚴謹的授權管理。蒐集越多不代表合法，匿名化資料仍可能透過交叉比對被再識別，隱私議題也影響整個組織而非僅行銷部門。","concept":"個資隱私保護","aiExplained":true},{"id":"web-j1-1416","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「AI 導入治理」，下列何者最正確？","options":{"A":"AI 專案需建立資料、模型、風險、監控與人工覆核機制","B":"治理會讓 AI 專案不需要測試","C":"上線後不用監控","D":"可完全省略利害關係人溝通"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"完整的 AI 導入治理涵蓋資料治理、模型管理、風險評估、上線後監控與人工覆核機制。治理是為了確保品質與課責，不會取代測試；上線後仍需持續監控模型表現，利害關係人溝通也是不可省略的一環。","concept":"AI導入治理","aiExplained":true},{"id":"web-j1-1417","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「AI 核心能力」，下列何者最正確？","options":{"A":"AI 僅能處理結構化表格","B":"AI 系統的價值在於感知資料、推論模式並輔助或自動化決策","C":"AI 一定具有通用人類智慧","D":"AI 只能用於學術研究"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 系統的價值來自三個環節：感知資料、推論模式，以及輔助或自動化決策，這是理解 AI 能力邊界的正確框架。AI 並非只限學術研究或結構化表格，而現今的 AI 仍屬弱 AI，不必然具備通用人類智慧。","concept":"AI核心能力","aiExplained":true},{"id":"web-j1-1418","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「大數據 5V」，下列何者最正確？","options":{"A":"只要資料筆數多就不需要資料品質治理","B":"大數據一定不需要抽樣與統計","C":"Volume、Velocity、Variety 等特性會影響資料蒐集、儲存與即時處理設計","D":"Variety 指模型版本數量"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Volume、Velocity、Variety 等大數據特性，決定了系統在資料蒐集、儲存與即時處理上的架構設計。即使資料筆數龐大，品質治理與抽樣統計仍然必要，而 Variety 描述的是資料型態的多樣性，與模型版本無關。","concept":"大數據5V特性","aiExplained":true},{"id":"web-j1-1419","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「分析類型」，下列何者最正確？","options":{"A":"診斷性分析主要預測未來","B":"處方性分析只整理歷史報表","C":"描述性分析會自動下決策指令","D":"描述性、診斷性、預測性與處方性分析分別回答發生什麼、為何發生、將發生什麼、該怎麼做"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"描述性、診斷性、預測性與處方性分析構成資料分析的成熟度階梯，分別回答發生什麼、為何發生、將發生什麼與該怎麼做。其他選項混淆了各類型的定位：描述性分析不下決策、診斷性分析不做預測、處方性分析重在行動建議而非歷史報表。","concept":"資料分析四類型","aiExplained":true},{"id":"web-j1-1420","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「監督式學習」，下列何者最正確？","options":{"A":"有標註答案的資料適合訓練分類或迴歸模型","B":"完全不需要標註資料","C":"只用於資料視覺化","D":"只能找未知群集"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"有標註答案的資料是監督式學習的前提，模型從輸入與正確標籤的對應關係中學習，用於分類或迴歸任務。若目標是探索未知群集，那屬於非監督式學習的範疇；監督式學習也不是用來做資料視覺化的技術。","concept":"監督式學習","aiExplained":true},{"id":"web-j1-1421","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「非監督式學習」，下列何者最正確？","options":{"A":"能保證判定每筆資料的真實類別","B":"無標註資料可用分群、降維或異常偵測探索潛在結構","C":"必須先提供正確答案","D":"只能做文字生成"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"面對無標註資料時，非監督式學習可透過分群找出相似群體、用降維壓縮特徵、以異常偵測找出離群樣本，藉此探索潛在結構。這類方法不需要正確答案作為輸入，也不保證能判定每筆資料的真實類別。","concept":"非監督式學習","aiExplained":true},{"id":"web-j1-1422","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「強化學習」，下列何者最正確？","options":{"A":"只根據靜態標籤做分類","B":"不需要環境回饋","C":"代理人在環境中透過行動、回饋與獎勵學習策略","D":"等同資料庫查詢"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"強化學習讓代理人在環境中不斷嘗試行動，根據回饋與獎勵調整策略，最終學會使長期報酬最大化的行為。這種互動式學習與依靠靜態標籤的分類完全不同，環境回饋是不可或缺的要素。","concept":"強化學習","aiExplained":true},{"id":"web-j1-1423","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「模型評估」，下列何者最正確？","options":{"A":"準確率永遠是唯一指標","B":"不平衡資料不影響評估","C":"評估只需看訓練集表現","D":"準確率、精確率、召回率與 F1 要依問題成本選擇"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"選擇評估指標時要考量問題的錯誤成本：精確率重視誤報代價，召回率重視漏報代價，F1 則兼顧兩者，準確率只是其中之一。訓練集表現無法反映泛化能力，不平衡資料更會讓單看準確率產生嚴重誤導。","concept":"模型評估指標","aiExplained":true},{"id":"web-j1-1424","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「深度學習」，下列何者最正確？","options":{"A":"多層神經網路適合從大量非結構化資料中自動學習特徵","B":"完全不需要資料與算力","C":"只適用小型表格","D":"一定比所有傳統模型更可解釋"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"多層神經網路能逐層抽取特徵，讓深度學習在影像、語音、文字等大量非結構化資料上表現突出。這類模型依賴充足的資料與算力，可解釋性通常也不如傳統統計模型。","concept":"深度學習","aiExplained":true},{"id":"web-j1-1425","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「自然語言處理」，下列何者最正確？","options":{"A":"NLP 主要處理邊界框定位","B":"NLP 用於理解、分類、摘要、翻譯與分析文字或語音內容","C":"NLP 只能做數值迴歸","D":"NLP 不處理語意脈絡"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"NLP 的應用涵蓋文本理解、文件分類、自動摘要、機器翻譯以及語音內容分析，核心是處理語言的語意與脈絡。邊界框定位是電腦視覺的任務，數值迴歸也只是可能用到的技術手段而非 NLP 的定義。","concept":"自然語言處理","aiExplained":true},{"id":"web-j1-1426","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「電腦視覺」，下列何者最正確？","options":{"A":"主要分析文字情緒","B":"只能處理財務表格","C":"電腦視覺處理影像中的分類、偵測、分割與瑕疵判讀","D":"與影像資料無關"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"影像分類、物件偵測、影像分割與瑕疵判讀是電腦視覺的典型任務，廣泛應用於製造業品檢與安防等場景。文字情緒分析屬於自然語言處理，財務表格分析則屬結構化資料處理，都不是電腦視覺的範疇。","concept":"電腦視覺","aiExplained":true},{"id":"web-j1-1427","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「RAG 與微調」，下列何者最正確？","options":{"A":"RAG 必須重新訓練模型","B":"微調最適合即時更新每月內規","C":"兩者完全沒有差異","D":"RAG 適合查詢快速更新的外部知識，微調適合調整模型風格或任務能力"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"RAG 以檢索外部知識庫的方式為模型提供最新資訊，適合知識快速更新的應用；微調則透過再訓練調整模型的風格與任務能力。兩者定位不同：RAG 不需重新訓練模型，微調也不適合用來即時更新頻繁變動的內規。","concept":"RAG與微調","aiExplained":true},{"id":"web-j1-1428","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「AI 倫理」，下列何者最正確？","options":{"A":"透明性、公平性、問責性、隱私性與安全性是高風險 AI 的核心要求","B":"只要準確率高即可忽略公平性","C":"黑箱模型不需要申訴機制","D":"個資使用不需要告知"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"透明性、公平性、問責性、隱私性與安全性被普遍列為高風險 AI 的核心倫理要求。高準確率不能豁免公平性檢驗，黑箱模型反而更需要申訴機制，個資使用也必須事先告知當事人。","concept":"AI倫理原則","aiExplained":true},{"id":"web-j1-1429","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「AI 安全」，下列何者最正確？","options":{"A":"模型部署後不會被攻擊","B":"AI 系統需防範對抗攻擊、資料污染與供應鏈風險","C":"安全只與硬體故障有關","D":"開源元件不需盤點"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 安全防護的範圍包括對抗攻擊、訓練資料污染，以及開源元件與模型來源帶來的供應鏈風險。部署後的模型仍可能遭受攻擊，安全議題遠不止硬體故障，開源元件更需要完整盤點。","concept":"AI系統安全","aiExplained":true},{"id":"web-j1-1430","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「隱私保護」，下列何者最正確？","options":{"A":"蒐集越多個資越一定合法","B":"匿名化永遠不可能再識別","C":"最小化蒐集、去識別化與授權管理可降低個資風險","D":"隱私只影響行銷部門"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"最小化蒐集、去識別化與授權管理是降低個資風險的三道防線，對應「少收、遮蔽、管好」的原則。蒐集越多個資反而提高法遵風險，匿名化資料仍有再識別的可能，隱私保護更是全組織的責任。","concept":"個資隱私保護","aiExplained":true},{"id":"web-j1-1431","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「AI 導入治理」，下列何者最正確？","options":{"A":"上線後不用監控","B":"可完全省略利害關係人溝通","C":"治理會讓 AI 專案不需要測試","D":"AI 專案需建立資料、模型、風險、監控與人工覆核機制"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 導入治理的完整機制包含資料治理、模型管理、風險控管、持續監控與人工覆核，貫穿專案全生命週期。測試、上線後監控與利害關係人溝通都是必要環節，不會因為建立治理制度而可以省略。","concept":"AI導入治理","aiExplained":true},{"id":"web-j1-1432","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「AI 核心能力」，下列何者最正確？","options":{"A":"AI 系統的價值在於感知資料、推論模式並輔助或自動化決策","B":"AI 一定具有通用人類智慧","C":"AI 只能用於學術研究","D":"AI 僅能處理結構化表格"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"感知資料、推論模式、輔助或自動化決策，是 AI 系統創造價值的三個核心環節。把 AI 視為必然具備通用人類智慧是過度誇大，限縮在學術研究或結構化表格則低估了其應用範圍。","concept":"AI核心能力","aiExplained":true},{"id":"web-j1-1433","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「大數據 5V」，下列何者最正確？","options":{"A":"大數據一定不需要抽樣與統計","B":"Volume、Velocity、Variety 等特性會影響資料蒐集、儲存與即時處理設計","C":"Variety 指模型版本數量","D":"只要資料筆數多就不需要資料品質治理"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"大數據的量（Volume）、速度（Velocity）與多樣性（Variety）等特性，直接牽動資料蒐集策略、儲存架構與即時處理管線的設計。抽樣與統計在大數據時代依然重要，Variety 也與模型版本數量無關。","concept":"大數據5V特性","aiExplained":true},{"id":"web-j1-1434","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「分析類型」，下列何者最正確？","options":{"A":"處方性分析只整理歷史報表","B":"描述性分析會自動下決策指令","C":"描述性、診斷性、預測性與處方性分析分別回答發生什麼、為何發生、將發生什麼、該怎麼做","D":"診斷性分析主要預測未來"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"資料分析依深度可分為四層：描述性（發生什麼）、診斷性（為何發生）、預測性（將發生什麼）與處方性（該怎麼做）。這個框架有助於釐清各類分析的產出與價值，其餘選項都錯置了各類型的功能。","concept":"資料分析四類型","aiExplained":true},{"id":"web-j1-1435","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「監督式學習」，下列何者最正確？","options":{"A":"只用於資料視覺化","B":"只能找未知群集","C":"完全不需要標註資料","D":"有標註答案的資料適合訓練分類或迴歸模型"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"監督式學習依靠標註好答案的訓練資料，讓模型學習輸入與輸出之間的對應關係，典型應用是分類與迴歸。它與尋找未知群集的非監督式學習不同，標註資料正是其必要條件，也不是視覺化工具。","concept":"監督式學習","aiExplained":true},{"id":"web-j1-1436","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「非監督式學習」，下列何者最正確？","options":{"A":"無標註資料可用分群、降維或異常偵測探索潛在結構","B":"必須先提供正確答案","C":"只能做文字生成","D":"能保證判定每筆資料的真實類別"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"在缺乏標註的情況下，非監督式學習以分群、降維與異常偵測等方法挖掘資料的潛在結構。這類方法不需事先提供正確答案，產出的是結構性洞察，而非對真實類別的保證。","concept":"非監督式學習","aiExplained":true},{"id":"web-j1-1437","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「強化學習」，下列何者最正確？","options":{"A":"不需要環境回饋","B":"代理人在環境中透過行動、回饋與獎勵學習策略","C":"等同資料庫查詢","D":"只根據靜態標籤做分類"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"代理人、環境、行動、回饋與獎勵是強化學習的基本要素，代理人透過與環境的互動累積經驗來學習策略。它既不是資料庫查詢，也不是依靜態標籤訓練的分類方法，環境回饋更是必要條件。","concept":"強化學習","aiExplained":true},{"id":"web-j1-1438","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「模型評估」，下列何者最正確？","options":{"A":"不平衡資料不影響評估","B":"評估只需看訓練集表現","C":"準確率、精確率、召回率與 F1 要依問題成本選擇","D":"準確率永遠是唯一指標"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"不同指標對應不同的決策成本：精確率控制誤報、召回率控制漏報、F1 平衡兩者，準確率則較適合類別均衡的情境。因此評估指標必須依問題的錯誤成本挑選，而非固定使用單一指標或只看訓練集表現。","concept":"模型評估指標","aiExplained":true},{"id":"web-j1-1439","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「深度學習」，下列何者最正確？","options":{"A":"只適用小型表格","B":"一定比所有傳統模型更可解釋","C":"完全不需要資料與算力","D":"多層神經網路適合從大量非結構化資料中自動學習特徵"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"深度學習透過多層神經網路自動學習資料的階層式特徵，特別適合影像、語音與文字等大規模非結構化資料。它對資料量與算力有較高需求，可解釋性也不必然優於傳統模型，更不是只適用於小型表格。","concept":"深度學習","aiExplained":true},{"id":"web-j1-1440","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「自然語言處理」，下列何者最正確？","options":{"A":"NLP 用於理解、分類、摘要、翻譯與分析文字或語音內容","B":"NLP 只能做數值迴歸","C":"NLP 不處理語意脈絡","D":"NLP 主要處理邊界框定位"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"理解、分類、摘要、翻譯與分析文字或語音內容，正是自然語言處理的任務全貌。NLP 的強項就在於處理語意與脈絡，邊界框定位則屬於電腦視覺領域，數值迴歸也非其定義性任務。","concept":"自然語言處理","aiExplained":true},{"id":"web-j1-1441","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「電腦視覺」，下列何者最正確？","options":{"A":"只能處理財務表格","B":"電腦視覺處理影像中的分類、偵測、分割與瑕疵判讀","C":"與影像資料無關","D":"主要分析文字情緒"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"電腦視覺以影像為處理對象，涵蓋分類、偵測、分割與瑕疵判讀等任務，常見於智慧製造與品質檢驗。分析文字情緒是 NLP 的工作，處理財務表格則屬於結構化資料分析，兩者都不是電腦視覺的範疇。","concept":"電腦視覺","aiExplained":true},{"id":"web-j1-1442","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「RAG 與微調」，下列何者最正確？","options":{"A":"微調最適合即時更新每月內規","B":"兩者完全沒有差異","C":"RAG 適合查詢快速更新的外部知識，微調適合調整模型風格或任務能力","D":"RAG 必須重新訓練模型"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"RAG 透過檢索外部知識庫，在推論時把最新資料當作上下文提供給模型，因此特別適合處理更新頻繁的知識，例如每月修訂的內規或文件。微調則是調整模型權重，用來改變模型的風格或強化特定任務能力，成本較高且不適合頻繁更新內容。兩者定位不同：一個補知識、一個改能力，選項 C 正確描述了這個分工。","concept":"RAG與微調差異","aiExplained":true},{"id":"web-j1-1443","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「AI 倫理」，下列何者最正確？","options":{"A":"黑箱模型不需要申訴機制","B":"個資使用不需要告知","C":"只要準確率高即可忽略公平性","D":"透明性、公平性、問責性、隱私性與安全性是高風險 AI 的核心要求"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"高風險 AI 系統的治理核心正是透明性、公平性、問責性、隱私性與安全性，這些原則出現在各國 AI 倫理準則與歐盟 AI Act 等規範中。其餘選項如黑箱不需申訴、個資不需告知、只看準確率忽略公平性，都直接違反倫理與法遵要求，因此 D 是唯一正確敘述。","concept":"AI倫理核心原則","aiExplained":true},{"id":"web-j1-1444","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「AI 安全」，下列何者最正確？","options":{"A":"AI 系統需防範對抗攻擊、資料污染與供應鏈風險","B":"安全只與硬體故障有關","C":"開源元件不需盤點","D":"模型部署後不會被攻擊"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 系統的攻擊面涵蓋整個生命週期：對抗樣本攻擊可欺騙模型判斷、資料污染可在訓練階段植入後門、開源元件與供應鏈也可能夾帶漏洞，因此必須全面防範與盤點。其餘選項把安全窄化為硬體問題、忽略開源元件盤點或假設部署後不會被攻擊，都是常見誤解。","concept":"AI安全威脅","aiExplained":true},{"id":"web-j1-1445","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「隱私保護」，下列何者最正確？","options":{"A":"匿名化永遠不可能再識別","B":"最小化蒐集、去識別化與授權管理可降低個資風險","C":"隱私只影響行銷部門","D":"蒐集越多個資越一定合法"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"降低個資風險的三個基本手段就是選項 B 所列：最小化蒐集確保只收必要資料、去識別化降低資料外洩後的傷害、授權管理控制誰能存取。匿名化資料仍可能透過交叉比對被重新識別，隱私議題影響全組織而非只有行銷部門，蒐集越多個資反而增加法遵風險，其餘選項皆錯。","concept":"個資風險控管","aiExplained":true},{"id":"web-j1-1446","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「AI 導入治理」，下列何者最正確？","options":{"A":"可完全省略利害關係人溝通","B":"治理會讓 AI 專案不需要測試","C":"AI 專案需建立資料、模型、風險、監控與人工覆核機制","D":"上線後不用監控"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"完善的 AI 導入治理必須涵蓋資料品質管理、模型驗證、風險評估、上線後持續監控以及人工覆核機制，形成完整的生命週期管控。治理不是取代測試，而是強化它；利害關係人溝通與上線後監控更是不可省略的環節，因此 C 正確。","concept":"AI導入治理","aiExplained":true},{"id":"web-j1-1447","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「AI 核心能力」，下列何者最正確？","options":{"A":"AI 只能用於學術研究","B":"AI 僅能處理結構化表格","C":"AI 一定具有通用人類智慧","D":"AI 系統的價值在於感知資料、推論模式並輔助或自動化決策"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 系統的核心價值鏈是感知（從資料獲取資訊）、推論（找出模式與規律）、決策支援（輔助或自動化行動），選項 D 完整描述了這個流程。現今 AI 已廣泛用於產業而非僅限學術，能處理影像、文字等非結構化資料，且目前仍屬弱 AI，不具通用人類智慧。","concept":"AI核心能力","aiExplained":true},{"id":"web-j1-1448","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「大數據 5V」，下列何者最正確？","options":{"A":"Volume、Velocity、Variety 等特性會影響資料蒐集、儲存與即時處理設計","B":"Variety 指模型版本數量","C":"只要資料筆數多就不需要資料品質治理","D":"大數據一定不需要抽樣與統計"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"大數據的 Volume（量）、Velocity（速度）、Variety（多樣性）等特性直接決定系統架構設計：資料量大需要分散式儲存、產生速度快需要即時串流處理、格式多樣需要彈性的蒐集與整合方案。Variety 指的是資料格式多樣而非模型版本，資料量大更需要品質治理與抽樣統計，故 A 正確。","concept":"大數據5V特性","aiExplained":true},{"id":"web-j1-1449","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「分析類型」，下列何者最正確？","options":{"A":"描述性分析會自動下決策指令","B":"描述性、診斷性、預測性與處方性分析分別回答發生什麼、為何發生、將發生什麼、該怎麼做","C":"診斷性分析主要預測未來","D":"處方性分析只整理歷史報表"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"四種分析類型構成成熟度階梯：描述性分析回答「發生了什麼」、診斷性分析回答「為何發生」、預測性分析回答「將會發生什麼」、處方性分析回答「該怎麼做」，選項 B 的對應完全正確。描述性分析只呈現現況不會自動下決策，診斷性看過去原因而非預測未來，處方性是給行動建議而非整理報表。","concept":"四種分析類型","aiExplained":true},{"id":"web-j1-1450","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「監督式學習」，下列何者最正確？","options":{"A":"只能找未知群集","B":"完全不需要標註資料","C":"有標註答案的資料適合訓練分類或迴歸模型","D":"只用於資料視覺化"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"監督式學習的定義特徵就是使用有標註答案的資料訓練模型：標籤為類別時做分類、標籤為連續數值時做迴歸。尋找未知群集是非監督式學習的任務，不需標註資料也與監督式學習的前提矛盾，因此 C 正確。","concept":"監督式學習","aiExplained":true},{"id":"web-j1-1451","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「非監督式學習」，下列何者最正確？","options":{"A":"只能做文字生成","B":"能保證判定每筆資料的真實類別","C":"必須先提供正確答案","D":"無標註資料可用分群、降維或異常偵測探索潛在結構"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"非監督式學習處理無標註資料，透過分群發現相似樣本的群組、降維壓縮特徵維度、異常偵測找出偏離常態的樣本，目的是探索資料的潛在結構。它無法保證判定真實類別（因為沒有標準答案），也不需要事先提供正確答案，故 D 正確。","concept":"非監督式學習","aiExplained":true},{"id":"web-j1-1452","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「強化學習」，下列何者最正確？","options":{"A":"代理人在環境中透過行動、回饋與獎勵學習策略","B":"等同資料庫查詢","C":"只根據靜態標籤做分類","D":"不需要環境回饋"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"強化學習的核心框架是代理人（Agent）在環境（Environment）中採取行動（Action），根據環境回饋的獎勵（Reward）不斷調整策略（Policy），以最大化長期累積報酬，選項 A 正確描述此機制。它與資料庫查詢無關，也不同於依靠靜態標籤的監督式分類，環境回饋更是不可或缺。","concept":"強化學習機制","aiExplained":true},{"id":"web-j1-1453","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「模型評估」，下列何者最正確？","options":{"A":"評估只需看訓練集表現","B":"準確率、精確率、召回率與 F1 要依問題成本選擇","C":"準確率永遠是唯一指標","D":"不平衡資料不影響評估"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"模型評估指標必須依問題的錯誤成本選擇：例如疾病篩檢重視召回率以免漏診、垃圾郵件過濾重視精確率以免誤殺正常信件，F1 則平衡兩者。只看訓練集會忽略過擬合，而在不平衡資料上準確率會嚴重誤導，因此 B 正確。","concept":"評估指標選擇","aiExplained":true},{"id":"web-j1-1454","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「深度學習」，下列何者最正確？","options":{"A":"一定比所有傳統模型更可解釋","B":"完全不需要資料與算力","C":"多層神經網路適合從大量非結構化資料中自動學習特徵","D":"只適用小型表格"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"深度學習以多層神經網路自動從原始資料中逐層學習特徵表示，特別擅長處理影像、語音、文字等大量非結構化資料，省去人工特徵工程，選項 C 正確。深度模型通常比傳統模型更難解釋、需要大量資料與算力，且在小型表格資料上未必優於傳統方法。","concept":"深度學習特性","aiExplained":true},{"id":"web-j1-1455","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「自然語言處理」，下列何者最正確？","options":{"A":"NLP 不處理語意脈絡","B":"NLP 主要處理邊界框定位","C":"NLP 只能做數值迴歸","D":"NLP 用於理解、分類、摘要、翻譯與分析文字或語音內容"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"自然語言處理（NLP）的任務範圍涵蓋文字與語音內容的理解、分類、摘要、翻譯與情感分析等，選項 D 正確概括其應用。邊界框定位屬於電腦視覺的物件偵測任務，NLP 也不限於數值迴歸，處理語意脈絡更是 NLP 的核心能力。","concept":"NLP應用範圍","aiExplained":true},{"id":"web-j1-1456","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「電腦視覺」，下列何者最正確？","options":{"A":"電腦視覺處理影像中的分類、偵測、分割與瑕疵判讀","B":"與影像資料無關","C":"主要分析文字情緒","D":"只能處理財務表格"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"電腦視覺專門處理影像資料，典型任務包括影像分類、物件偵測、語意分割，以及製造業常見的瑕疵判讀，選項 A 正確。文字情緒分析屬於 NLP 領域，財務表格是結構化資料分析的範疇，電腦視覺與影像資料密不可分。","concept":"電腦視覺任務","aiExplained":true},{"id":"web-j1-1457","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「RAG 與微調」，下列何者最正確？","options":{"A":"兩者完全沒有差異","B":"RAG 適合查詢快速更新的外部知識，微調適合調整模型風格或任務能力","C":"RAG 必須重新訓練模型","D":"微調最適合即時更新每月內規"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"RAG 在推論時檢索外部知識庫並將結果作為上下文，不需重新訓練模型，因此適合更新頻繁的知識；微調則透過調整權重改變模型風格或任務能力，適合穩定不變的能力需求。每月更新的內規用微調成本過高且緩不濟急，用 RAG 更新知識庫即可，故 B 正確。","concept":"RAG與微調差異","aiExplained":true},{"id":"web-j1-1458","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「AI 倫理」，下列何者最正確？","options":{"A":"個資使用不需要告知","B":"只要準確率高即可忽略公平性","C":"透明性、公平性、問責性、隱私性與安全性是高風險 AI 的核心要求","D":"黑箱模型不需要申訴機制"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"透明性、公平性、問責性、隱私性與安全性是國際間對高風險 AI 系統的共同核心要求，涵蓋可解釋、無歧視、可追責、保護個資與防範危害等面向。黑箱模型更需要申訴機制、個資使用必須告知當事人、準確率高不能作為忽略公平性的理由，故 C 正確。","concept":"AI倫理核心原則","aiExplained":true},{"id":"web-j1-1459","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「AI 安全」，下列何者最正確？","options":{"A":"開源元件不需盤點","B":"模型部署後不會被攻擊","C":"安全只與硬體故障有關","D":"AI 系統需防範對抗攻擊、資料污染與供應鏈風險"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 安全必須考量整個生命週期的威脅：對抗攻擊透過刻意設計的輸入欺騙模型、資料污染在訓練資料中植入惡意樣本、供應鏈風險則來自第三方元件與開源套件，選項 D 正確。開源元件需要盤點管理，模型部署後仍持續面臨攻擊，安全絕不只是硬體故障問題。","concept":"AI安全威脅","aiExplained":true},{"id":"web-j1-1460","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「隱私保護」，下列何者最正確？","options":{"A":"最小化蒐集、去識別化與授權管理可降低個資風險","B":"隱私只影響行銷部門","C":"蒐集越多個資越一定合法","D":"匿名化永遠不可能再識別"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"個資保護的三大實務手段是：最小化蒐集（只收必要資料）、去識別化（降低資料連結到個人的風險）、授權管理（控管存取權限），選項 A 正確。隱私義務適用於全組織，蒐集越多個資代表越高的法遵與外洩風險，而匿名化資料仍可能被交叉比對重新識別。","concept":"個資風險控管","aiExplained":true},{"id":"web-j1-1461","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「AI 導入治理」，下列何者最正確？","options":{"A":"治理會讓 AI 專案不需要測試","B":"AI 專案需建立資料、模型、風險、監控與人工覆核機制","C":"上線後不用監控","D":"可完全省略利害關係人溝通"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 專案治理需要建立橫跨資料品質、模型驗證、風險管理、持續監控與人工覆核的完整機制，才能確保系統上線後持續可靠且可問責，選項 B 正確。治理是補強而非免除測試，上線後必須監控模型漂移與異常，利害關係人溝通也是治理不可或缺的一環。","concept":"AI導入治理","aiExplained":true},{"id":"web-j1-1462","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「AI 核心能力」，下列何者最正確？","options":{"A":"AI 僅能處理結構化表格","B":"AI 一定具有通用人類智慧","C":"AI 系統的價值在於感知資料、推論模式並輔助或自動化決策","D":"AI 只能用於學術研究"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 系統的價值在於感知資料（從輸入中提取資訊）、推論模式（發現規律）、並據以輔助或自動化決策，選項 C 完整描述這條價值鏈。AI 已廣泛應用於各產業，能處理非結構化資料，且現階段屬於特定任務的弱 AI，並不具備通用人類智慧。","concept":"AI核心能力","aiExplained":true},{"id":"web-j1-1463","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「大數據 5V」，下列何者最正確？","options":{"A":"只要資料筆數多就不需要資料品質治理","B":"大數據一定不需要抽樣與統計","C":"Variety 指模型版本數量","D":"Volume、Velocity、Variety 等特性會影響資料蒐集、儲存與即時處理設計"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Volume（資料量）、Velocity（產生速度）、Variety（多樣性）等大數據特性會直接影響系統設計：大量資料需要分散式儲存、高速資料需要即時串流處理、多樣格式需要彈性的蒐集與整合架構，選項 D 正確。Variety 指資料格式多樣而非模型版本，資料再多也需要品質治理與統計方法。","concept":"大數據5V特性","aiExplained":true},{"id":"web-j1-1464","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「分析類型」，下列何者最正確？","options":{"A":"描述性、診斷性、預測性與處方性分析分別回答發生什麼、為何發生、將發生什麼、該怎麼做","B":"診斷性分析主要預測未來","C":"處方性分析只整理歷史報表","D":"描述性分析會自動下決策指令"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"分析成熟度的四個層次各有明確定位：描述性分析回答「發生了什麼」、診斷性分析回答「為何發生」、預測性分析回答「將發生什麼」、處方性分析回答「該怎麼做」，選項 A 的對應正確。診斷性分析著重過去原因而非預測，處方性分析提供行動建議而非整理歷史報表，描述性分析也不會自動下決策。","concept":"四種分析類型","aiExplained":true},{"id":"web-j1-1465","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「監督式學習」，下列何者最正確？","options":{"A":"完全不需要標註資料","B":"有標註答案的資料適合訓練分類或迴歸模型","C":"只用於資料視覺化","D":"只能找未知群集"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"監督式學習以有標註答案的資料訓練模型，標籤是離散類別時做分類、是連續數值時做迴歸，選項 B 正確描述其適用情境。它必須依賴標註資料，尋找未知群集是非監督式學習的工作，資料視覺化也不是監督式學習的目的。","concept":"監督式學習","aiExplained":true},{"id":"web-j1-1466","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「非監督式學習」，下列何者最正確？","options":{"A":"能保證判定每筆資料的真實類別","B":"必須先提供正確答案","C":"無標註資料可用分群、降維或異常偵測探索潛在結構","D":"只能做文字生成"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"非監督式學習面對無標註資料，透過分群找出相似樣本、降維壓縮特徵、異常偵測辨識離群點，藉此探索資料的潛在結構，選項 C 正確。由於沒有標準答案，它無法保證判定每筆資料的真實類別，也不需要事先提供正確答案，更不限於文字生成。","concept":"非監督式學習","aiExplained":true},{"id":"web-j1-1467","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「強化學習」，下列何者最正確？","options":{"A":"只根據靜態標籤做分類","B":"不需要環境回饋","C":"等同資料庫查詢","D":"代理人在環境中透過行動、回饋與獎勵學習策略"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"強化學習的運作方式是代理人在環境中執行行動，依據環境回饋的獎勵或懲罰逐步調整策略，以最大化長期累積報酬，選項 D 正確。這與依靜態標籤訓練的監督式分類不同，也完全不同於資料庫查詢，環境回饋更是學習的必要來源。","concept":"強化學習機制","aiExplained":true},{"id":"web-j1-1468","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「模型評估」，下列何者最正確？","options":{"A":"準確率、精確率、召回率與 F1 要依問題成本選擇","B":"準確率永遠是唯一指標","C":"不平衡資料不影響評估","D":"評估只需看訓練集表現"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"選擇評估指標必須考量問題的錯誤成本：漏抓代價高時重視召回率、誤報代價高時重視精確率、需要平衡時用 F1，選項 A 正確。準確率在類別不平衡時會嚴重失真，因此不是唯一指標；評估也必須看測試集而非訓練集，才能反映泛化能力。","concept":"評估指標選擇","aiExplained":true},{"id":"web-j1-1469","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「深度學習」，下列何者最正確？","options":{"A":"完全不需要資料與算力","B":"多層神經網路適合從大量非結構化資料中自動學習特徵","C":"只適用小型表格","D":"一定比所有傳統模型更可解釋"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"深度學習利用多層神經網路逐層抽取特徵，能自動從大量影像、語音、文字等非結構化資料中學習表示，免除人工特徵工程，選項 B 正確。深度模型需要可觀的資料與算力，可解釋性通常低於傳統模型，在小型表格資料上也不一定佔優勢。","concept":"深度學習特性","aiExplained":true},{"id":"web-j1-1470","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「自然語言處理」，下列何者最正確？","options":{"A":"NLP 主要處理邊界框定位","B":"NLP 只能做數值迴歸","C":"NLP 用於理解、分類、摘要、翻譯與分析文字或語音內容","D":"NLP 不處理語意脈絡"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"NLP 的核心應用是對文字或語音內容進行理解、分類、摘要、翻譯與分析，選項 C 正確概括。邊界框定位是電腦視覺的物件偵測任務，NLP 不限於數值迴歸，而處理語意脈絡正是現代 NLP 模型的強項而非弱點。","concept":"NLP應用範圍","aiExplained":true},{"id":"web-j1-1471","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「電腦視覺」，下列何者最正確？","options":{"A":"主要分析文字情緒","B":"只能處理財務表格","C":"與影像資料無關","D":"電腦視覺處理影像中的分類、偵測、分割與瑕疵判讀"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"電腦視覺專注於影像資料的處理，涵蓋影像分類、物件偵測、語意分割以及工業瑕疵判讀等任務，選項 D 正確。文字情緒分析屬於 NLP，財務表格屬於結構化資料分析，電腦視覺的本質就是與影像資料緊密相關。","concept":"電腦視覺任務","aiExplained":true},{"id":"web-j2-1472","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某電商平台導入 CLIP（Contrastive Language-Image Pre-training）模型，讓使用者能直接輸入文字描述來搜尋商品圖片。請問 CLIP 模型是透過哪一種方式來衡第二科：生成式 AI 應用與規劃量文字描述與圖片之間的相符程度？","options":{"A":"餘弦相似度（Cosine Similarity） ，計算文字與圖片在向量空間中的方向相似程度","B":"BLEU 分數，衡量文字描述與圖片標題之間的詞彙重疊程度","C":"交叉熵損失（Cross-Entropy Loss） ，用於衡量模型預測機率與實際標籤之間的差異","D":"F1 分數（F1 Score） ，綜合評估搜尋結果的精確率與召回率"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"CLIP 以對比學習訓練文字編碼器與影像編碼器，把文字和圖片映射到同一個向量空間，再用餘弦相似度衡量兩個向量方向的接近程度，作為文字與圖片的相符分數。BLEU 用於機器翻譯評估、交叉熵是訓練時的損失函數、F1 是分類檢索的評估指標，都不是 CLIP 衡量圖文相符度的方式。","concept":"CLIP餘弦相似度","aiExplained":true},{"id":"web-j2-1473","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某新創公司希望針對特定醫療診斷任務微調語言模型，但受限於資料取得困難，目前僅收集到少量已標註的診斷病例。在標註資料極為有限的條件下，強化微調（Reinforcement Fine-Tuning, RFT）相較於監督式微調（Supervised Fine- 第二科：生成式 AI 應用與規劃 Tuning, SFT)）最主要的優勢為何？","options":{"A":"RFT 需仰賴大量高品質標註資料進行訓練，因此在資料有限時仍能維持較佳穩定性","B":"RFT 透過獎懲回饋機制引導模型優化，對大量標註資料的依賴相對較低，較適用於資料有限的情境","C":"RFT 與 SFT 在資料需求上本質相同，主要差異僅在訓練效率，資料量不影響兩者適用性","D":"RFT 可直接從未標註的診斷資料中自動產生正確標註，因此在資料有限時可完全取代 SFT"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"監督式微調需要大量高品質的標註資料直接示範正確輸出，資料稀少時容易過擬合。強化微調改以獎懲回饋訊號引導模型優化，只需要能評分對錯的獎勵機制，對標註資料量的依賴相對較低，因此在少量標註病例的情境下更具優勢。RFT 並非不需資料，也無法自動產生正確標註完全取代 SFT，故 B 正確。","concept":"RFT與SFT比較","aiExplained":true},{"id":"web-j2-1474","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司開發一個 AI 助理，能長期記住使用者的重要資訊（例如偏好與歷史需求） ，並在後續對話中加以利用。系統設計採用Titans 架構的 Memory as Context（MAC）機制，希望模型在回應時能同時參考目前對話與過去記憶。請第二科：生成式 AI 應用與規劃問在此設計下，長期記憶最可能是下列哪一種使用方式？","options":{"A":"將記憶模組整合進模型內部，讓每一層都使用記憶資訊","B":"利用記憶調整模型的注意力強弱，使部分內容被優先關注","C":"將記憶整理成重點內容，與目前輸入一起提供給模型作為額外參考","D":"不使用記憶模組，而是單純增加模型可處理的文字長度"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Titans 架構的 Memory as Context（MAC）機制，是把長期記憶模組檢索出的重點內容當作額外上下文，與當前輸入串接後一起餵給模型處理，讓模型同時參考目前對話與過去記憶。這不同於把記憶整合進模型每一層（Memory as Layer）或用記憶調整注意力門控（Memory as Gate），也不是單純加長上下文視窗，故 C 正確。","concept":"Titans MAC機制","aiExplained":true},{"id":"web-j2-1475","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某研究團隊希望評估大型語言模型在不同學科領域的整體理解能力，包含法律、醫學、數學與歷史等，並要求模型在未見過的題型中仍能正確推理與作答。下列何者最符合此類評測設計的核心概念？ 第二科：生成式 AI 應用與規劃","options":{"A":"單一領域專業知識記憶測驗","B":"多領域、多任務之語言理解能力評估","C":"對話流暢度與語言生成品質測試","D":"資料檢索準確率評估"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"題目描述的評測橫跨法律、醫學、數學、歷史等多個學科，並要求模型在未見過的題型上仍能推理作答，這正是 MMLU 這類「多領域、多任務語言理解」基準的核心設計理念，目的在衡量模型的廣泛知識與泛化推理能力。單一領域記憶測驗、對話流暢度或檢索準確率評估都無法涵蓋此需求，故 B 正確。","concept":"多任務理解評測","aiExplained":true},{"id":"web-j2-1476","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某物流公司計劃導入生成式 AI 來預測交通流量並優化配送路線，預期每月處理 500 萬筆路況資料。在進行成本效益評估時，下列何者不屬於 TCO（Total Cost 第二科：生成式 AI 應用與規劃 of Ownership）分析中的直接成本考量？","options":{"A":"模型推理過程中 API 呼叫所產生的 Token 使用費用","B":"為支援即時路況分析所需的雲端運算與儲存資源成本","C":"導入系統後因配送效率提升所帶來的燃油與車輛維運成本下降","D":"為模型訓練與優化所投入的 GPU 運算資源與相關基礎設施成本"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"TCO 的直接成本是指為建置與營運系統實際支出的費用，例如 API Token 使用費、雲端運算與儲存資源、GPU 訓練基礎設施等，A、B、D 都屬於此類。選項 C 的燃油與維運成本下降是導入後產生的效益（Benefit），屬於成本效益分析中的收益面，而非 TCO 的成本項目，故為正確答案。","concept":"TCO直接成本","aiExplained":true},{"id":"web-j2-1477","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「No-Code / Low-Code」，下列何者最正確？","options":{"A":"No-Code/Low-Code 以視覺化元件加速應用開發，但仍受平台能力、整合性與治理限制","B":"完全不需要治理","C":"一定能取代所有專業程式開發","D":"封閉平台不會造成鎖定風險"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"No-Code/Low-Code 平台以視覺化元件與拖拉介面加速應用開發、降低技術門檻，但仍受限於平台提供的能力範圍、與既有系統的整合性，以及企業治理要求，選項 A 的描述最完整平衡。這類平台無法取代所有專業開發，仍需納入治理管控，封閉平台更存在廠商鎖定風險。","concept":"低程式碼平台","aiExplained":true},{"id":"web-j2-1478","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「流程自動化」，下列何者最正確？","options":{"A":"所有流程只能人工觸發","B":"條件分支、迴圈、格式化與聚合元件可組合成事件驅動流程","C":"條件分支用來儲存向量","D":"迴圈只能做模型訓練"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"現代流程自動化工具提供條件分支（依條件走不同路徑）、迴圈（重複處理）、格式化與聚合（整理資料）等元件，這些元件可以組合成由事件觸發的自動化流程，選項 B 正確。流程可由排程或事件自動觸發而非只能人工啟動，條件分支是控制流程走向而非儲存向量，迴圈也不是用來訓練模型。","concept":"流程自動化元件","aiExplained":true},{"id":"web-j2-1479","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「API 與 Token」，下列何者最正確？","options":{"A":"Token 與費用無關","B":"Token 是資料庫主鍵","C":"Token 是模型處理文字的基本單位，影響上下文長度、輸入輸出與費用","D":"上下文長度不受 Token 限制"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Token 是語言模型切分與處理文字的基本單位，一段文字會被切成多個 Token 後才進入模型。模型的上下文長度以 Token 數計算，API 計費也依輸入與輸出的 Token 數量收費，因此 Token 直接影響可處理的文字量與使用成本，選項 C 正確。它不是資料庫主鍵，與費用和上下文長度都密切相關。","concept":"Token與API計費","aiExplained":true},{"id":"web-j2-1480","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「提示工程」，下列何者最正確？","options":{"A":"提示越模糊越好","B":"範例一定會降低表現","C":"輸出格式不需指定","D":"清楚任務、角色、格式、限制與範例能提高 LLM 輸出穩定性"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"有效的提示工程要素包括：明確描述任務目標、指定模型扮演的角色、規範輸出格式、設下限制條件，並提供少量範例（few-shot），這些都能顯著提高 LLM 輸出的穩定性與品質，選項 D 正確。提示越模糊輸出越不可控，恰當的範例通常提升而非降低表現，輸出格式更應明確指定。","concept":"提示工程要素","aiExplained":true},{"id":"web-j2-1481","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「RAG」，下列何者最正確？","options":{"A":"RAG 透過檢索外部知識提供上下文，適合企業文件與規範快速更新","B":"RAG 會永久改寫模型權重","C":"RAG 不需要知識庫品質","D":"RAG 只適合影像辨識"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"RAG 在回答前先從外部知識庫檢索相關內容，將檢索結果作為上下文提供給模型生成答案，因此企業文件或規範更新時只需更新知識庫，不必重新訓練模型，選項 A 正確。RAG 不會改寫模型權重，其效果高度依賴知識庫的品質與檢索準確度，且主要應用於文字知識問答而非影像辨識。","concept":"RAG檢索增強","aiExplained":true},{"id":"web-j2-1482","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「向量資料庫」，下列何者最正確？","options":{"A":"Embedding 是人工輸入標籤","B":"Embedding 將文字轉為向量，讓系統能以語意相似度檢索資料","C":"向量檢索只比對檔名","D":"語意相似度與檢索無關"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Embedding 的核心是把文字轉換成高維向量，讓語意相近的內容在向量空間中距離較近，系統因此能以語意相似度檢索資料。其餘選項把 Embedding 說成人工輸入的標籤、把檢索限縮為比對檔名，或否定語意相似度與檢索的關聯，都與向量資料庫的運作原理相反。","concept":"語意向量檢索","aiExplained":true},{"id":"web-j2-1483","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「微調」，下列何者最正確？","options":{"A":"微調最適合每小時更新知識","B":"微調不需要資料品質","C":"Fine-tuning 適合讓模型學特定格式、風格或任務模式，但不適合頻繁更新事實知識","D":"微調能保證沒有幻覺"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Fine-tuning 是以特定資料調整模型參數，最適合讓模型學會固定的格式、風格或任務模式。由於每次微調都需重新訓練與驗證，成本高、週期長，並不適合用來頻繁更新事實知識；同時微調高度依賴資料品質，也無法保證消除幻覺。","concept":"模型微調適用性","aiExplained":true},{"id":"web-j2-1484","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「AI Agent」，下列何者最正確？","options":{"A":"Agent 不需要權限控管","B":"Agent 等於單次文字生成","C":"工具呼叫不需驗證結果","D":"Agent 可根據目標規劃步驟並呼叫工具/API，但需要權限、日誌與安全邊界"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI Agent 的特徵是能根據目標自主規劃步驟，並呼叫工具或 API 執行任務，這與單次文字生成有本質差異。正因為 Agent 具備實際行動能力，必須配套權限控管、操作日誌與安全邊界，工具呼叫的結果也需要驗證，才能安全落地。","concept":"AI代理與治理","aiExplained":true},{"id":"web-j2-1485","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「生成式 AI 應用」，下列何者最正確？","options":{"A":"生成式 AI 可用於摘要、客服、文案、程式輔助與多模態內容產製","B":"只能做資料庫報表","C":"不能處理非結構化文字","D":"只適合離線單機使用"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"生成式 AI 擅長處理非結構化文字與多模態內容，典型應用涵蓋摘要、客服、文案、程式輔助與內容產製。其餘選項把它限縮為資料庫報表、離線單機使用，或宣稱不能處理非結構化文字，都低估了生成式 AI 的實際應用範圍。","concept":"生成式AI應用","aiExplained":true},{"id":"web-j2-1486","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「AI 治理」，下列何者最正確？","options":{"A":"人人可任意接入模型","B":"企業導入生成式 AI 需建立使用規範、模型清單、審核流程與風險分級","C":"敏感資料可直接貼入外部服務","D":"治理與風險無關"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"企業導入生成式 AI 時，治理的基本配套包括使用規範、模型清單、審核流程與風險分級，確保應用在可控範圍內。若放任人人任意接入模型，或將敏感資料直接貼入外部服務，都會帶來資安與合規風險，因此治理與風險管理密不可分。","concept":"生成式AI治理","aiExplained":true},{"id":"web-j2-1487","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「資安與個資」，下列何者最正確？","options":{"A":"模型回覆不會洩漏資訊","B":"個資可作為公開訓練資料","C":"生成式 AI 應避免外洩敏感資訊，並控制資料留存、權限與稽核","D":"稽核紀錄沒有必要"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"使用生成式 AI 應避免敏感資訊外洩，並針對資料留存、存取權限與稽核紀錄建立控制機制。模型回覆有可能夾帶訓練資料或上下文中的資訊，個資不得未經同意作為公開訓練資料，稽核紀錄更是事後追查與問責的必要依據。","concept":"資安與個資","aiExplained":true},{"id":"web-j2-1488","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「黑箱與責任」，下列何者最正確？","options":{"A":"黑箱不影響醫療金融場景","B":"錯誤結果無需追蹤","C":"使用 AI 後人類不用負責","D":"高風險場景需可解釋、可追溯與人工覆核，以釐清責任"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"在醫療、金融等高風險場景，AI 的黑箱特性會直接影響信任與問責，因此需要可解釋性、可追溯性與人工覆核機制來釐清責任。錯誤結果必須能追蹤原因，而使用 AI 之後最終責任仍在人與組織身上，不能因黑箱而免責。","concept":"可解釋與問責","aiExplained":true},{"id":"web-j2-1489","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「導入評估」，下列何者最正確？","options":{"A":"導入前應評估問題適配性、資料可得性、成本、風險、維運與成效指標","B":"先導入再找需求","C":"不需設定 KPI","D":"資料品質不影響專案"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 專案導入前應先評估問題適配性、資料可得性、成本、風險、維運能量與成效指標，確認值得投入再啟動。先導入再找需求容易做出沒人用的系統；不設 KPI 就無法衡量成效，而資料品質更是直接決定專案成敗的關鍵。","concept":"AI導入評估","aiExplained":true},{"id":"web-j2-1490","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「監控與維運」，下列何者最正確？","options":{"A":"部署完成即專案結束","B":"上線後需監控品質、漂移、成本、延遲與使用者回饋","C":"成本不需監控","D":"使用者回饋無助於改善"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 系統部署上線不是專案終點，而是維運的起點。上線後需持續監控輸出品質、資料與模型漂移、成本與延遲，並收集使用者回饋作為改善依據，才能確保服務長期穩定且符合預期成效。","concept":"監控與維運","aiExplained":true},{"id":"web-j2-1491","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「著作權與合規」，下列何者最正確？","options":{"A":"AI 產出必然不受著作權影響","B":"授權條款可忽略","C":"生成式 AI 應注意訓練資料來源、輸出侵權風險與授權條款","D":"資料來源不需紀錄"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"生成式 AI 的合規重點包括訓練資料來源是否合法、輸出內容是否有侵權風險，以及是否遵守授權條款。資料來源應留下紀錄以利追溯，AI 產出也可能涉及既有著作的權利，不能假設必然不受著作權影響。","concept":"著作權與合規","aiExplained":true},{"id":"web-j2-1492","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「No-Code / Low-Code」，下列何者最正確？","options":{"A":"一定能取代所有專業程式開發","B":"封閉平台不會造成鎖定風險","C":"完全不需要治理","D":"No-Code/Low-Code 以視覺化元件加速應用開發，但仍受平台能力、整合性與治理限制"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"No-Code/Low-Code 平台透過視覺化元件與拖拉組裝加速應用開發，有效降低技術門檻。但它仍受平台能力、系統整合性與治理要求的限制，無法完全取代專業程式開發，封閉平台也可能造成供應商鎖定風險，導入時仍需納入治理。","concept":"低程式碼平台","aiExplained":true},{"id":"web-j2-1493","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「流程自動化」，下列何者最正確？","options":{"A":"條件分支、迴圈、格式化與聚合元件可組合成事件驅動流程","B":"條件分支用來儲存向量","C":"迴圈只能做模型訓練","D":"所有流程只能人工觸發"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"流程自動化工具中，條件分支負責依條件走不同路徑，迴圈處理重複作業，搭配格式化與聚合元件即可組合成事件驅動的自動化流程。這些元件的用途與模型訓練或向量儲存無關，流程也可由事件自動觸發，不限於人工啟動。","concept":"流程自動化","aiExplained":true},{"id":"web-j2-1494","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「API 與 Token」，下列何者最正確？","options":{"A":"Token 是資料庫主鍵","B":"Token 是模型處理文字的基本單位，影響上下文長度、輸入輸出與費用","C":"上下文長度不受 Token 限制","D":"Token 與費用無關"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Token 是語言模型處理文字的基本單位，模型會將輸入與輸出切分成 token 來運算。上下文長度以 token 數為上限，API 費用通常也依輸入與輸出的 token 量計價，因此 token 直接影響可處理的文字長度與成本，與資料庫主鍵無關。","concept":"Token與成本","aiExplained":true},{"id":"web-j2-1495","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「提示工程」，下列何者最正確？","options":{"A":"範例一定會降低表現","B":"輸出格式不需指定","C":"清楚任務、角色、格式、限制與範例能提高 LLM 輸出穩定性","D":"提示越模糊越好"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"提示工程的核心是把任務目標、角色設定、輸出格式、限制條件與範例寫清楚，讓 LLM 的輸出更穩定、更符合預期。提示越模糊輸出越不可控，適當的範例通常能提升而非降低表現，指定輸出格式也有助於後續系統處理。","concept":"提示工程","aiExplained":true},{"id":"web-j2-1496","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「RAG」，下列何者最正確？","options":{"A":"RAG 不需要知識庫品質","B":"RAG 只適合影像辨識","C":"RAG 會永久改寫模型權重","D":"RAG 透過檢索外部知識提供上下文，適合企業文件與規範快速更新"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"RAG 透過檢索外部知識庫，把相關內容作為上下文提供給模型，不會改寫模型權重，因此適合企業文件與規範這類需要快速更新的知識。它主要應用於文字知識問答而非影像辨識，且檢索效果高度依賴知識庫的品質。","concept":"RAG檢索增強","aiExplained":true},{"id":"web-j2-1497","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「向量資料庫」，下列何者最正確？","options":{"A":"Embedding 將文字轉為向量，讓系統能以語意相似度檢索資料","B":"向量檢索只比對檔名","C":"語意相似度與檢索無關","D":"Embedding 是人工輸入標籤"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"向量資料庫的基礎是 Embedding：將文字轉為向量後，語意相近的內容在向量空間中彼此靠近，系統便能以語意相似度找出相關資料。Embedding 是模型計算產生的表示，不是人工輸入的標籤，檢索比對的是語意向量而非檔名。","concept":"語意向量檢索","aiExplained":true},{"id":"web-j2-1498","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「微調」，下列何者最正確？","options":{"A":"微調不需要資料品質","B":"Fine-tuning 適合讓模型學特定格式、風格或任務模式，但不適合頻繁更新事實知識","C":"微調能保證沒有幻覺","D":"微調最適合每小時更新知識"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"微調適合讓模型內化特定格式、風格或任務模式，例如固定的公文格式或客服語氣。但事實知識若需要每天甚至每小時更新，重新微調的成本與時效都不划算，這類需求應改用 RAG；微調同時仰賴高品質資料，也無法保證杜絕幻覺。","concept":"模型微調適用性","aiExplained":true},{"id":"web-j2-1499","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「AI Agent」，下列何者最正確？","options":{"A":"Agent 等於單次文字生成","B":"工具呼叫不需驗證結果","C":"Agent 可根據目標規劃步驟並呼叫工具/API，但需要權限、日誌與安全邊界","D":"Agent 不需要權限控管"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI Agent 能依據目標拆解並規劃步驟，再呼叫工具或 API 逐步完成任務，因此不等於單次文字生成。也正因它能實際執行操作，必須建立權限控管、日誌紀錄與安全邊界，並對工具呼叫的結果加以驗證，避免錯誤行動造成損害。","concept":"AI代理與治理","aiExplained":true},{"id":"web-j2-1500","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「生成式 AI 應用」，下列何者最正確？","options":{"A":"不能處理非結構化文字","B":"只適合離線單機使用","C":"只能做資料庫報表","D":"生成式 AI 可用於摘要、客服、文案、程式輔助與多模態內容產製"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"生成式 AI 的應用範圍涵蓋摘要、客服、文案、程式輔助與多模態內容產製，核心優勢正是處理非結構化文字與生成多樣內容。將其限縮為只能做報表、只能離線單機，或說不能處理非結構化文字，都是對技術能力的誤解。","concept":"生成式AI應用","aiExplained":true},{"id":"web-j2-1501","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「AI 治理」，下列何者最正確？","options":{"A":"企業導入生成式 AI 需建立使用規範、模型清單、審核流程與風險分級","B":"敏感資料可直接貼入外部服務","C":"治理與風險無關","D":"人人可任意接入模型"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"導入生成式 AI 的治理配套應包含使用規範、模型清單、審核流程與風險分級，讓組織清楚知道誰在用什麼模型、用在哪些場景、風險等級為何。敏感資料直接貼入外部服務或放任任意接入，正是治理要防範的典型風險行為。","concept":"生成式AI治理","aiExplained":true},{"id":"web-j2-1502","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「資安與個資」，下列何者最正確？","options":{"A":"個資可作為公開訓練資料","B":"生成式 AI 應避免外洩敏感資訊，並控制資料留存、權限與稽核","C":"稽核紀錄沒有必要","D":"模型回覆不會洩漏資訊"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"生成式 AI 的資安重點在於防止敏感資訊外洩，並對資料留存、存取權限與稽核建立完整控管。模型回覆並非絕對安全，可能洩漏先前輸入的資訊；個資也不能任意作為公開訓練資料，稽核紀錄則是合規與追責的基礎。","concept":"資安與個資","aiExplained":true},{"id":"web-j2-1503","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「黑箱與責任」，下列何者最正確？","options":{"A":"錯誤結果無需追蹤","B":"使用 AI 後人類不用負責","C":"高風險場景需可解釋、可追溯與人工覆核，以釐清責任","D":"黑箱不影響醫療金融場景"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"高風險場景（如醫療、金融）使用 AI 時，必須具備可解釋、可追溯與人工覆核機制，才能在出錯時釐清責任歸屬。黑箱特性在這些場景影響重大，錯誤結果需要追蹤，最終決策責任仍由人類承擔，不因使用 AI 而移轉。","concept":"可解釋與問責","aiExplained":true},{"id":"web-j2-1504","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「導入評估」，下列何者最正確？","options":{"A":"不需設定 KPI","B":"資料品質不影響專案","C":"先導入再找需求","D":"導入前應評估問題適配性、資料可得性、成本、風險、維運與成效指標"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"導入評估應在專案啟動前完成，內容包括問題適配性、資料可得性、成本、風險、維運與成效指標。順序不能倒過來先導入再找需求；KPI 是衡量成效的必要工具，資料品質則直接影響模型表現與專案成敗。","concept":"AI導入評估","aiExplained":true},{"id":"web-j2-1505","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「監控與維運」，下列何者最正確？","options":{"A":"上線後需監控品質、漂移、成本、延遲與使用者回饋","B":"成本不需監控","C":"使用者回饋無助於改善","D":"部署完成即專案結束"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 服務上線後需要持續監控品質、模型漂移、成本、延遲與使用者回饋，這是維運階段的核心工作。部署完成只是開始，成本若不監控可能快速失控，使用者回饋更是持續改善模型與流程的重要輸入。","concept":"監控與維運","aiExplained":true},{"id":"web-j2-1506","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「著作權與合規」，下列何者最正確？","options":{"A":"授權條款可忽略","B":"生成式 AI 應注意訓練資料來源、輸出侵權風險與授權條款","C":"資料來源不需紀錄","D":"AI 產出必然不受著作權影響"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"使用生成式 AI 時，應注意訓練資料來源的合法性、輸出內容的侵權風險，以及各項授權條款的遵循。授權條款不可忽略，資料來源需要留存紀錄，AI 產出也可能牽涉他人著作權，不能假設一律不受影響。","concept":"著作權與合規","aiExplained":true},{"id":"web-j2-1507","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「No-Code / Low-Code」，下列何者最正確？","options":{"A":"封閉平台不會造成鎖定風險","B":"完全不需要治理","C":"No-Code/Low-Code 以視覺化元件加速應用開發，但仍受平台能力、整合性與治理限制","D":"一定能取代所有專業程式開發"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"No-Code/Low-Code 以視覺化元件加速應用開發，讓非工程背景人員也能組裝流程與介面，但其能力受限於平台功能、整合性與治理要求。它不能取代所有專業開發，封閉平台存在鎖定風險，導入後仍需要治理機制管控。","concept":"低程式碼平台","aiExplained":true},{"id":"web-j2-1508","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「流程自動化」，下列何者最正確？","options":{"A":"迴圈只能做模型訓練","B":"所有流程只能人工觸發","C":"條件分支用來儲存向量","D":"條件分支、迴圈、格式化與聚合元件可組合成事件驅動流程"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"自動化流程由條件分支、迴圈、格式化與聚合等元件組合而成，並可由事件驅動自動執行。條件分支的功能是路徑判斷而非儲存向量，迴圈是重複執行邏輯而非模型訓練，流程觸發方式也包含排程與事件，不限人工。","concept":"流程自動化","aiExplained":true},{"id":"web-j2-1509","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「API 與 Token」，下列何者最正確？","options":{"A":"Token 是模型處理文字的基本單位，影響上下文長度、輸入輸出與費用","B":"上下文長度不受 Token 限制","C":"Token 與費用無關","D":"Token 是資料庫主鍵"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Token 是模型處理文字的基本單位，輸入與輸出都會被切分成 token 計算。模型的上下文長度以 token 數為限制，API 計費也多以 token 用量為基準，因此 token 同時影響可處理長度與使用費用，並非資料庫主鍵。","concept":"Token與成本","aiExplained":true},{"id":"web-j2-1510","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「提示工程」，下列何者最正確？","options":{"A":"輸出格式不需指定","B":"清楚任務、角色、格式、限制與範例能提高 LLM 輸出穩定性","C":"提示越模糊越好","D":"範例一定會降低表現"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"要讓 LLM 輸出穩定，提示中應清楚交代任務、角色、輸出格式、限制條件並附上範例，這正是提示工程的基本功。模糊的提示會讓輸出品質不穩定，恰當的範例通常能改善表現，指定格式則讓結果更容易被系統化利用。","concept":"提示工程","aiExplained":true},{"id":"web-j2-1511","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「RAG」，下列何者最正確？","options":{"A":"RAG 只適合影像辨識","B":"RAG 會永久改寫模型權重","C":"RAG 透過檢索外部知識提供上下文，適合企業文件與規範快速更新","D":"RAG 不需要知識庫品質"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"RAG 的做法是先從外部知識庫檢索相關內容，再作為上下文餵給模型生成答案，因此知識更新只需維護知識庫，不必重新訓練模型，特別適合企業文件與規範等經常變動的內容。它不會永久改寫模型權重，效果也高度依賴知識庫品質。","concept":"RAG檢索增強","aiExplained":true},{"id":"web-j2-1512","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「向量資料庫」，下列何者最正確？","options":{"A":"語意相似度與檢索無關","B":"Embedding 是人工輸入標籤","C":"向量檢索只比對檔名","D":"Embedding 將文字轉為向量，讓系統能以語意相似度檢索資料"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Embedding 將文字轉換為向量表示，使語意相近的內容在向量空間中距離接近，向量資料庫據此以語意相似度進行檢索。這是模型自動計算的結果而非人工標籤，比對的對象是語意向量，不是檔名，語意相似度正是檢索的核心。","concept":"語意向量檢索","aiExplained":true},{"id":"web-j2-1513","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「微調」，下列何者最正確？","options":{"A":"Fine-tuning 適合讓模型學特定格式、風格或任務模式，但不適合頻繁更新事實知識","B":"微調能保證沒有幻覺","C":"微調最適合每小時更新知識","D":"微調不需要資料品質"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Fine-tuning 讓模型透過訓練內化特定格式、風格或任務模式，適合輸出型態固定的場景。但它不適合承載需要頻繁更新的事實知識，因為每次更新都得重新訓練；微調成效取決於資料品質，也不能保證消除幻覺。","concept":"模型微調適用性","aiExplained":true},{"id":"web-j2-1514","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「AI Agent」，下列何者最正確？","options":{"A":"工具呼叫不需驗證結果","B":"Agent 可根據目標規劃步驟並呼叫工具/API，但需要權限、日誌與安全邊界","C":"Agent 不需要權限控管","D":"Agent 等於單次文字生成"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI Agent 能根據目標自主規劃步驟並呼叫工具或 API，行為能力遠超過單次文字生成，因此權限、日誌與安全邊界是必要配套。工具呼叫的結果同樣需要驗證，否則錯誤輸出可能被 Agent 直接拿去執行後續動作，放大風險。","concept":"AI代理與治理","aiExplained":true},{"id":"web-j2-1515","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「生成式 AI 應用」，下列何者最正確？","options":{"A":"只適合離線單機使用","B":"只能做資料庫報表","C":"生成式 AI 可用於摘要、客服、文案、程式輔助與多模態內容產製","D":"不能處理非結構化文字"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"摘要、客服、文案、程式輔助與多模態內容產製都是生成式 AI 的典型應用，其強項正是理解與生成非結構化內容。說它只能做報表、只適合離線單機或不能處理非結構化文字，都與實際能力不符。","concept":"生成式AI應用","aiExplained":true},{"id":"web-j2-1516","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「AI 治理」，下列何者最正確？","options":{"A":"治理與風險無關","B":"人人可任意接入模型","C":"敏感資料可直接貼入外部服務","D":"企業導入生成式 AI 需建立使用規範、模型清單、審核流程與風險分級"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"企業級的生成式 AI 治理需要建立使用規範、模型清單、審核流程與風險分級，把應用納入可管理的框架。治理的目的正是控制風險，因此不可能與風險無關；任意接入模型或把敏感資料貼入外部服務，都是治理要禁止的行為。","concept":"生成式AI治理","aiExplained":true},{"id":"web-j2-1517","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「資安與個資」，下列何者最正確？","options":{"A":"生成式 AI 應避免外洩敏感資訊，並控制資料留存、權限與稽核","B":"稽核紀錄沒有必要","C":"模型回覆不會洩漏資訊","D":"個資可作為公開訓練資料"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"生成式 AI 的資安管理重點是避免敏感資訊外洩，並控制資料留存、權限與稽核。個資未經合法依據不得作為公開訓練資料，模型回覆存在洩漏資訊的可能，稽核紀錄則是發現異常與釐清責任不可或缺的機制。","concept":"資安與個資","aiExplained":true},{"id":"web-j2-1518","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「黑箱與責任」，下列何者最正確？","options":{"A":"使用 AI 後人類不用負責","B":"高風險場景需可解釋、可追溯與人工覆核，以釐清責任","C":"黑箱不影響醫療金融場景","D":"錯誤結果無需追蹤"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"高風險場景需要可解釋、可追溯與人工覆核，才能在 AI 出錯時釐清責任。使用 AI 不代表人類免責，最終決策責任仍在人；黑箱問題在醫療、金融場景影響尤其重大，錯誤結果更必須能夠追蹤與矯正。","concept":"可解釋與問責","aiExplained":true},{"id":"web-j2-1519","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「導入評估」，下列何者最正確？","options":{"A":"資料品質不影響專案","B":"先導入再找需求","C":"導入前應評估問題適配性、資料可得性、成本、風險、維運與成效指標","D":"不需設定 KPI"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"導入 AI 前的評估清單包括問題適配性、資料可得性、成本、風險、維運與成效指標，先確認可行性與價值再投入資源。資料品質直接影響專案成敗，KPI 是驗收成效的依據，先導入再找需求則是常見的失敗模式。","concept":"AI導入評估","aiExplained":true},{"id":"web-j2-1520","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「監控與維運」，下列何者最正確？","options":{"A":"使用者回饋無助於改善","B":"部署完成即專案結束","C":"成本不需監控","D":"上線後需監控品質、漂移、成本、延遲與使用者回饋"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"上線後的監控項目涵蓋輸出品質、漂移、成本、延遲與使用者回饋，這些是維運階段判斷系統健康與否的關鍵訊號。部署完成並非專案結束，成本需要持續控管，使用者回饋則是迭代改善最直接的來源。","concept":"監控與維運","aiExplained":true},{"id":"web-j2-1521","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「著作權與合規」，下列何者最正確？","options":{"A":"生成式 AI 應注意訓練資料來源、輸出侵權風險與授權條款","B":"資料來源不需紀錄","C":"AI 產出必然不受著作權影響","D":"授權條款可忽略"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"生成式 AI 的著作權與合規管理，應涵蓋訓練資料來源的合法性、輸出侵權風險的評估，以及授權條款的遵循。授權條款具有法律拘束力不可忽略，資料來源需記錄以利追溯，AI 產出也可能涉及著作權爭議。","concept":"著作權與合規","aiExplained":true},{"id":"web-j2-1522","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「No-Code / Low-Code」，下列何者最正確？","options":{"A":"完全不需要治理","B":"No-Code/Low-Code 以視覺化元件加速應用開發，但仍受平台能力、整合性與治理限制","C":"一定能取代所有專業程式開發","D":"封閉平台不會造成鎖定風險"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"No-Code/Low-Code 平台以視覺化元件與拖拉設定加速應用開發，降低技術門檻，但仍受限於平台本身的能力、與既有系統的整合性以及治理要求。它無法完全取代所有專業程式開發，封閉平台也確實存在供應商鎖定風險，因此導入時仍需治理與評估。","concept":"低程式碼開發","aiExplained":true},{"id":"web-j2-1523","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「流程自動化」，下列何者最正確？","options":{"A":"所有流程只能人工觸發","B":"條件分支用來儲存向量","C":"條件分支、迴圈、格式化與聚合元件可組合成事件驅動流程","D":"迴圈只能做模型訓練"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"流程自動化的核心是將條件分支、迴圈、格式化與聚合等元件組合起來，並可由事件觸發執行，形成事件驅動流程。流程並非只能人工觸發，條件分支是用來控制邏輯走向而非儲存向量，迴圈也可用於各種資料處理，不限於模型訓練。","concept":"流程自動化","aiExplained":true},{"id":"web-j2-1524","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「API 與 Token」，下列何者最正確？","options":{"A":"Token 與費用無關","B":"Token 是資料庫主鍵","C":"上下文長度不受 Token 限制","D":"Token 是模型處理文字的基本單位，影響上下文長度、輸入輸出與費用"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Token 是語言模型處理文字的基本單位，模型的上下文長度以 Token 數計算，API 計費也通常依輸入與輸出的 Token 數量計價。因此 Token 直接影響上下文長度、輸入輸出規模與使用費用，它不是資料庫主鍵，與費用更是密切相關。","concept":"Token與費用","aiExplained":true},{"id":"web-j2-1525","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「提示工程」，下列何者最正確？","options":{"A":"清楚任務、角色、格式、限制與範例能提高 LLM 輸出穩定性","B":"提示越模糊越好","C":"範例一定會降低表現","D":"輸出格式不需指定"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"提示工程強調把任務目標、角色設定、輸出格式、限制條件與示範範例寫清楚，讓 LLM 的輸出更穩定、更符合預期。提示越模糊反而越難控制結果，適當的範例通常能提升表現，指定輸出格式更是實務上的基本功。","concept":"提示工程","aiExplained":true},{"id":"web-j2-1526","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「RAG」，下列何者最正確？","options":{"A":"RAG 會永久改寫模型權重","B":"RAG 透過檢索外部知識提供上下文，適合企業文件與規範快速更新","C":"RAG 不需要知識庫品質","D":"RAG 只適合影像辨識"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"RAG 在生成回答前先從外部知識庫檢索相關內容，作為上下文提供給模型參考，因此不會改寫模型權重，特別適合企業文件與規範這類需要快速更新的知識。其效果高度依賴知識庫品質，且主要應用於文字知識問答而非影像辨識。","concept":"檢索增強生成","aiExplained":true},{"id":"web-j2-1527","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「向量資料庫」，下列何者最正確？","options":{"A":"Embedding 是人工輸入標籤","B":"向量檢索只比對檔名","C":"Embedding 將文字轉為向量，讓系統能以語意相似度檢索資料","D":"語意相似度與檢索無關"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Embedding 是由模型自動將文字轉換成高維向量的過程，向量資料庫再以向量間的距離衡量語意相似度，讓系統能依語意而非關鍵字或檔名檢索資料。它不是人工輸入的標籤，語意相似度正是這類檢索的核心依據。","concept":"向量資料庫","aiExplained":true},{"id":"web-j2-1528","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「微調」，下列何者最正確？","options":{"A":"微調最適合每小時更新知識","B":"微調不需要資料品質","C":"微調能保證沒有幻覺","D":"Fine-tuning 適合讓模型學特定格式、風格或任務模式，但不適合頻繁更新事實知識"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Fine-tuning 是用特定資料調整模型權重，適合讓模型學會特定格式、風格或任務模式；但每次更新都要重新訓練，成本高、週期長，不適合頻繁更新事實知識，這類需求更適合用 RAG。微調同樣依賴資料品質，也無法保證消除幻覺。","concept":"模型微調","aiExplained":true},{"id":"web-j2-1529","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「AI Agent」，下列何者最正確？","options":{"A":"Agent 可根據目標規劃步驟並呼叫工具/API，但需要權限、日誌與安全邊界","B":"Agent 不需要權限控管","C":"Agent 等於單次文字生成","D":"工具呼叫不需驗證結果"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI Agent 能根據目標自主規劃步驟、呼叫工具或 API 並依結果調整行動，已超越單次文字生成的範疇。正因它具備實際行動能力，實務上必須配套權限控管、操作日誌與安全邊界，工具呼叫的結果也需要驗證，才能安全落地。","concept":"AI代理","aiExplained":true},{"id":"web-j2-1530","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「生成式 AI 應用」，下列何者最正確？","options":{"A":"只能做資料庫報表","B":"生成式 AI 可用於摘要、客服、文案、程式輔助與多模態內容產製","C":"不能處理非結構化文字","D":"只適合離線單機使用"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"生成式 AI 的強項正是處理非結構化文字與多模態內容，常見應用包括文件摘要、智慧客服、行銷文案、程式輔助與圖文影音產製。它並不限於資料庫報表，也不限於離線單機使用，多以雲端服務或 API 形式整合進工作流程。","concept":"生成式AI應用","aiExplained":true},{"id":"web-j2-1531","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「AI 治理」，下列何者最正確？","options":{"A":"人人可任意接入模型","B":"敏感資料可直接貼入外部服務","C":"企業導入生成式 AI 需建立使用規範、模型清單、審核流程與風險分級","D":"治理與風險無關"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"企業導入生成式 AI 時，治理是控管風險的基礎：需建立使用規範、盤點核可的模型清單、設計審核流程並依情境做風險分級。若人人可任意接入模型、敏感資料直接貼入外部服務，將造成資料外洩與合規風險，治理與風險管理密不可分。","concept":"AI治理","aiExplained":true},{"id":"web-j2-1532","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「資安與個資」，下列何者最正確？","options":{"A":"模型回覆不會洩漏資訊","B":"個資可作為公開訓練資料","C":"稽核紀錄沒有必要","D":"生成式 AI 應避免外洩敏感資訊，並控制資料留存、權限與稽核"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"使用生成式 AI 時應避免將敏感資訊或個資輸入外部服務造成外洩，並針對資料留存、存取權限與稽核紀錄建立控管機制。模型回覆仍可能洩漏訓練或上下文中的資訊，個資未經同意不可作為公開訓練資料，稽核紀錄則是追蹤與究責的必要基礎。","concept":"資安與個資","aiExplained":true},{"id":"web-j2-1533","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「黑箱與責任」，下列何者最正確？","options":{"A":"高風險場景需可解釋、可追溯與人工覆核，以釐清責任","B":"黑箱不影響醫療金融場景","C":"錯誤結果無需追蹤","D":"使用 AI 後人類不用負責"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"在醫療、金融等高風險場景，AI 決策若是黑箱將難以釐清責任，因此需要可解釋性、可追溯的決策紀錄與人工覆核機制。錯誤結果必須能被追蹤與矯正，而且使用 AI 並不免除人類與組織的最終責任。","concept":"可解釋與責任","aiExplained":true},{"id":"web-j2-1534","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「導入評估」，下列何者最正確？","options":{"A":"先導入再找需求","B":"導入前應評估問題適配性、資料可得性、成本、風險、維運與成效指標","C":"不需設定 KPI","D":"資料品質不影響專案"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"導入 AI 前應先確認問題是否適合用 AI 解決（問題適配性）、資料是否可得且品質足夠，並評估成本、風險、後續維運與成效指標。先導入再找需求容易導致專案失敗，資料品質更是直接影響專案成敗的關鍵。","concept":"導入評估","aiExplained":true},{"id":"web-j2-1535","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「監控與維運」，下列何者最正確？","options":{"A":"部署完成即專案結束","B":"成本不需監控","C":"上線後需監控品質、漂移、成本、延遲與使用者回饋","D":"使用者回饋無助於改善"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 系統部署上線不是專案終點，而是維運的起點：需持續監控輸出品質、資料與模型漂移、成本與延遲，並收集使用者回饋作為改善依據。若忽略成本與回饋的監控，系統效益與品質都會隨時間劣化。","concept":"監控與維運","aiExplained":true},{"id":"web-j2-1536","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「著作權與合規」，下列何者最正確？","options":{"A":"AI 產出必然不受著作權影響","B":"授權條款可忽略","C":"資料來源不需紀錄","D":"生成式 AI 應注意訓練資料來源、輸出侵權風險與授權條款"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"生成式 AI 的合規重點包括：確認訓練與輸入資料的來源合法性、注意輸出內容可能構成的侵權風險，以及遵守模型與素材的授權條款。AI 產出並非必然免除著作權疑慮，資料來源與授權紀錄都應留存以供查核。","concept":"著作權合規","aiExplained":true},{"id":"web-j2-1537","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「No-Code / Low-Code」，下列何者最正確？","options":{"A":"No-Code/Low-Code 以視覺化元件加速應用開發，但仍受平台能力、整合性與治理限制","B":"一定能取代所有專業程式開發","C":"封閉平台不會造成鎖定風險","D":"完全不需要治理"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"No-Code/Low-Code 平台以視覺化元件與拖拉設定加速應用開發，降低技術門檻，但仍受限於平台本身的能力、與既有系統的整合性以及治理要求。它無法完全取代所有專業程式開發，封閉平台也確實存在供應商鎖定風險，因此導入時仍需治理與評估。","concept":"低程式碼開發","aiExplained":true},{"id":"web-j2-1538","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「流程自動化」，下列何者最正確？","options":{"A":"條件分支用來儲存向量","B":"條件分支、迴圈、格式化與聚合元件可組合成事件驅動流程","C":"迴圈只能做模型訓練","D":"所有流程只能人工觸發"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"流程自動化的核心是將條件分支、迴圈、格式化與聚合等元件組合起來，並可由事件觸發執行，形成事件驅動流程。流程並非只能人工觸發，條件分支是用來控制邏輯走向而非儲存向量，迴圈也可用於各種資料處理，不限於模型訓練。","concept":"流程自動化","aiExplained":true},{"id":"web-j2-1539","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「API 與 Token」，下列何者最正確？","options":{"A":"Token 是資料庫主鍵","B":"上下文長度不受 Token 限制","C":"Token 是模型處理文字的基本單位，影響上下文長度、輸入輸出與費用","D":"Token 與費用無關"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Token 是語言模型處理文字的基本單位，模型的上下文長度以 Token 數計算，API 計費也通常依輸入與輸出的 Token 數量計價。因此 Token 直接影響上下文長度、輸入輸出規模與使用費用，它不是資料庫主鍵，與費用更是密切相關。","concept":"Token與費用","aiExplained":true},{"id":"web-j2-1540","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「提示工程」，下列何者最正確？","options":{"A":"範例一定會降低表現","B":"輸出格式不需指定","C":"提示越模糊越好","D":"清楚任務、角色、格式、限制與範例能提高 LLM 輸出穩定性"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"提示工程強調把任務目標、角色設定、輸出格式、限制條件與示範範例寫清楚，讓 LLM 的輸出更穩定、更符合預期。提示越模糊反而越難控制結果，適當的範例通常能提升表現，指定輸出格式更是實務上的基本功。","concept":"提示工程","aiExplained":true},{"id":"web-j2-1541","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「RAG」，下列何者最正確？","options":{"A":"RAG 透過檢索外部知識提供上下文，適合企業文件與規範快速更新","B":"RAG 不需要知識庫品質","C":"RAG 只適合影像辨識","D":"RAG 會永久改寫模型權重"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"RAG 在生成回答前先從外部知識庫檢索相關內容，作為上下文提供給模型參考，因此不會改寫模型權重，特別適合企業文件與規範這類需要快速更新的知識。其效果高度依賴知識庫品質，且主要應用於文字知識問答而非影像辨識。","concept":"檢索增強生成","aiExplained":true},{"id":"web-j2-1542","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「向量資料庫」，下列何者最正確？","options":{"A":"向量檢索只比對檔名","B":"Embedding 將文字轉為向量，讓系統能以語意相似度檢索資料","C":"語意相似度與檢索無關","D":"Embedding 是人工輸入標籤"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Embedding 是由模型自動將文字轉換成高維向量的過程，向量資料庫再以向量間的距離衡量語意相似度，讓系統能依語意而非關鍵字或檔名檢索資料。它不是人工輸入的標籤，語意相似度正是這類檢索的核心依據。","concept":"向量資料庫","aiExplained":true},{"id":"web-j2-1543","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「微調」，下列何者最正確？","options":{"A":"微調不需要資料品質","B":"微調能保證沒有幻覺","C":"Fine-tuning 適合讓模型學特定格式、風格或任務模式，但不適合頻繁更新事實知識","D":"微調最適合每小時更新知識"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Fine-tuning 是用特定資料調整模型權重，適合讓模型學會特定格式、風格或任務模式；但每次更新都要重新訓練，成本高、週期長，不適合頻繁更新事實知識，這類需求更適合用 RAG。微調同樣依賴資料品質，也無法保證消除幻覺。","concept":"模型微調","aiExplained":true},{"id":"web-j2-1544","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「AI Agent」，下列何者最正確？","options":{"A":"Agent 等於單次文字生成","B":"工具呼叫不需驗證結果","C":"Agent 不需要權限控管","D":"Agent 可根據目標規劃步驟並呼叫工具/API，但需要權限、日誌與安全邊界"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI Agent 能根據目標自主規劃步驟、呼叫工具或 API 並依結果調整行動，已超越單次文字生成的範疇。正因它具備實際行動能力，實務上必須配套權限控管、操作日誌與安全邊界，工具呼叫的結果也需要驗證，才能安全落地。","concept":"AI代理","aiExplained":true},{"id":"web-j2-1545","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「生成式 AI 應用」，下列何者最正確？","options":{"A":"生成式 AI 可用於摘要、客服、文案、程式輔助與多模態內容產製","B":"不能處理非結構化文字","C":"只適合離線單機使用","D":"只能做資料庫報表"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"生成式 AI 的強項正是處理非結構化文字與多模態內容，常見應用包括文件摘要、智慧客服、行銷文案、程式輔助與圖文影音產製。它並不限於資料庫報表，也不限於離線單機使用，多以雲端服務或 API 形式整合進工作流程。","concept":"生成式AI應用","aiExplained":true},{"id":"web-j2-1546","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「AI 治理」，下列何者最正確？","options":{"A":"敏感資料可直接貼入外部服務","B":"企業導入生成式 AI 需建立使用規範、模型清單、審核流程與風險分級","C":"治理與風險無關","D":"人人可任意接入模型"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"企業導入生成式 AI 時，治理是控管風險的基礎：需建立使用規範、盤點核可的模型清單、設計審核流程並依情境做風險分級。若人人可任意接入模型、敏感資料直接貼入外部服務，將造成資料外洩與合規風險，治理與風險管理密不可分。","concept":"AI治理","aiExplained":true},{"id":"web-j2-1547","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「資安與個資」，下列何者最正確？","options":{"A":"個資可作為公開訓練資料","B":"稽核紀錄沒有必要","C":"生成式 AI 應避免外洩敏感資訊，並控制資料留存、權限與稽核","D":"模型回覆不會洩漏資訊"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"使用生成式 AI 時應避免將敏感資訊或個資輸入外部服務造成外洩，並針對資料留存、存取權限與稽核紀錄建立控管機制。模型回覆仍可能洩漏訓練或上下文中的資訊，個資未經同意不可作為公開訓練資料，稽核紀錄則是追蹤與究責的必要基礎。","concept":"資安與個資","aiExplained":true},{"id":"web-j2-1548","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「黑箱與責任」，下列何者最正確？","options":{"A":"錯誤結果無需追蹤","B":"使用 AI 後人類不用負責","C":"黑箱不影響醫療金融場景","D":"高風險場景需可解釋、可追溯與人工覆核，以釐清責任"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"在醫療、金融等高風險場景，AI 決策若是黑箱將難以釐清責任，因此需要可解釋性、可追溯的決策紀錄與人工覆核機制。錯誤結果必須能被追蹤與矯正，而且使用 AI 並不免除人類與組織的最終責任。","concept":"可解釋與責任","aiExplained":true},{"id":"web-j2-1549","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「導入評估」，下列何者最正確？","options":{"A":"導入前應評估問題適配性、資料可得性、成本、風險、維運與成效指標","B":"不需設定 KPI","C":"資料品質不影響專案","D":"先導入再找需求"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"導入 AI 前應先確認問題是否適合用 AI 解決（問題適配性）、資料是否可得且品質足夠，並評估成本、風險、後續維運與成效指標。先導入再找需求容易導致專案失敗，資料品質更是直接影響專案成敗的關鍵。","concept":"導入評估","aiExplained":true},{"id":"web-j2-1550","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「監控與維運」，下列何者最正確？","options":{"A":"成本不需監控","B":"上線後需監控品質、漂移、成本、延遲與使用者回饋","C":"使用者回饋無助於改善","D":"部署完成即專案結束"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 系統部署上線不是專案終點，而是維運的起點：需持續監控輸出品質、資料與模型漂移、成本與延遲，並收集使用者回饋作為改善依據。若忽略成本與回饋的監控，系統效益與品質都會隨時間劣化。","concept":"監控與維運","aiExplained":true},{"id":"web-j2-1551","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「著作權與合規」，下列何者最正確？","options":{"A":"授權條款可忽略","B":"資料來源不需紀錄","C":"生成式 AI 應注意訓練資料來源、輸出侵權風險與授權條款","D":"AI 產出必然不受著作權影響"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"生成式 AI 的合規重點包括：確認訓練與輸入資料的來源合法性、注意輸出內容可能構成的侵權風險，以及遵守模型與素材的授權條款。AI 產出並非必然免除著作權疑慮，資料來源與授權紀錄都應留存以供查核。","concept":"著作權合規","aiExplained":true},{"id":"web-j2-1552","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「No-Code / Low-Code」，下列何者最正確？","options":{"A":"封閉平台不會造成鎖定風險","B":"完全不需要治理","C":"一定能取代所有專業程式開發","D":"No-Code/Low-Code 以視覺化元件加速應用開發，但仍受平台能力、整合性與治理限制"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"No-Code/Low-Code 平台以視覺化元件與拖拉設定加速應用開發，降低技術門檻，但仍受限於平台本身的能力、與既有系統的整合性以及治理要求。它無法完全取代所有專業程式開發，封閉平台也確實存在供應商鎖定風險，因此導入時仍需治理與評估。","concept":"低程式碼開發","aiExplained":true},{"id":"web-j2-1553","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「流程自動化」，下列何者最正確？","options":{"A":"條件分支、迴圈、格式化與聚合元件可組合成事件驅動流程","B":"迴圈只能做模型訓練","C":"所有流程只能人工觸發","D":"條件分支用來儲存向量"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"流程自動化的核心是將條件分支、迴圈、格式化與聚合等元件組合起來，並可由事件觸發執行，形成事件驅動流程。流程並非只能人工觸發，條件分支是用來控制邏輯走向而非儲存向量，迴圈也可用於各種資料處理，不限於模型訓練。","concept":"流程自動化","aiExplained":true},{"id":"web-j2-1554","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「API 與 Token」，下列何者最正確？","options":{"A":"上下文長度不受 Token 限制","B":"Token 是模型處理文字的基本單位，影響上下文長度、輸入輸出與費用","C":"Token 與費用無關","D":"Token 是資料庫主鍵"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Token 是語言模型處理文字的基本單位，模型的上下文長度以 Token 數計算，API 計費也通常依輸入與輸出的 Token 數量計價。因此 Token 直接影響上下文長度、輸入輸出規模與使用費用，它不是資料庫主鍵，與費用更是密切相關。","concept":"Token與費用","aiExplained":true},{"id":"web-j2-1555","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「提示工程」，下列何者最正確？","options":{"A":"輸出格式不需指定","B":"提示越模糊越好","C":"清楚任務、角色、格式、限制與範例能提高 LLM 輸出穩定性","D":"範例一定會降低表現"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"提示工程強調把任務目標、角色設定、輸出格式、限制條件與示範範例寫清楚，讓 LLM 的輸出更穩定、更符合預期。提示越模糊反而越難控制結果，適當的範例通常能提升表現，指定輸出格式更是實務上的基本功。","concept":"提示工程","aiExplained":true},{"id":"web-j2-1556","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「RAG」，下列何者最正確？","options":{"A":"RAG 只適合影像辨識","B":"RAG 會永久改寫模型權重","C":"RAG 不需要知識庫品質","D":"RAG 透過檢索外部知識提供上下文，適合企業文件與規範快速更新"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"RAG 在生成回答前先從外部知識庫檢索相關內容，作為上下文提供給模型參考，因此不會改寫模型權重，特別適合企業文件與規範這類需要快速更新的知識。其效果高度依賴知識庫品質，且主要應用於文字知識問答而非影像辨識。","concept":"檢索增強生成","aiExplained":true},{"id":"web-j2-1557","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「向量資料庫」，下列何者最正確？","options":{"A":"Embedding 將文字轉為向量，讓系統能以語意相似度檢索資料","B":"語意相似度與檢索無關","C":"Embedding 是人工輸入標籤","D":"向量檢索只比對檔名"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Embedding 是由模型自動將文字轉換成高維向量的過程，向量資料庫再以向量間的距離衡量語意相似度，讓系統能依語意而非關鍵字或檔名檢索資料。它不是人工輸入的標籤，語意相似度正是這類檢索的核心依據。","concept":"向量資料庫","aiExplained":true},{"id":"web-j2-1558","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「微調」，下列何者最正確？","options":{"A":"微調能保證沒有幻覺","B":"Fine-tuning 適合讓模型學特定格式、風格或任務模式，但不適合頻繁更新事實知識","C":"微調最適合每小時更新知識","D":"微調不需要資料品質"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Fine-tuning 是用特定資料調整模型權重，適合讓模型學會特定格式、風格或任務模式；但每次更新都要重新訓練，成本高、週期長，不適合頻繁更新事實知識，這類需求更適合用 RAG。微調同樣依賴資料品質，也無法保證消除幻覺。","concept":"模型微調","aiExplained":true},{"id":"web-j2-1559","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「AI Agent」，下列何者最正確？","options":{"A":"工具呼叫不需驗證結果","B":"Agent 不需要權限控管","C":"Agent 可根據目標規劃步驟並呼叫工具/API，但需要權限、日誌與安全邊界","D":"Agent 等於單次文字生成"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI Agent 能根據目標自主規劃步驟、呼叫工具或 API 並依結果調整行動，已超越單次文字生成的範疇。正因它具備實際行動能力，實務上必須配套權限控管、操作日誌與安全邊界，工具呼叫的結果也需要驗證，才能安全落地。","concept":"AI代理","aiExplained":true},{"id":"web-j2-1560","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「生成式 AI 應用」，下列何者最正確？","options":{"A":"只適合離線單機使用","B":"只能做資料庫報表","C":"不能處理非結構化文字","D":"生成式 AI 可用於摘要、客服、文案、程式輔助與多模態內容產製"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"生成式 AI 的強項正是處理非結構化文字與多模態內容，常見應用包括文件摘要、智慧客服、行銷文案、程式輔助與圖文影音產製。它並不限於資料庫報表，也不限於離線單機使用，多以雲端服務或 API 形式整合進工作流程。","concept":"生成式AI應用","aiExplained":true},{"id":"web-j2-1561","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「AI 治理」，下列何者最正確？","options":{"A":"企業導入生成式 AI 需建立使用規範、模型清單、審核流程與風險分級","B":"治理與風險無關","C":"人人可任意接入模型","D":"敏感資料可直接貼入外部服務"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"企業導入生成式 AI 時，治理是控管風險的基礎：需建立使用規範、盤點核可的模型清單、設計審核流程並依情境做風險分級。若人人可任意接入模型、敏感資料直接貼入外部服務，將造成資料外洩與合規風險，治理與風險管理密不可分。","concept":"AI治理","aiExplained":true},{"id":"web-j2-1562","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「資安與個資」，下列何者最正確？","options":{"A":"稽核紀錄沒有必要","B":"生成式 AI 應避免外洩敏感資訊，並控制資料留存、權限與稽核","C":"模型回覆不會洩漏資訊","D":"個資可作為公開訓練資料"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"導入生成式 AI 時，敏感資訊一旦輸入外部服務就可能外洩，因此必須從源頭控管：避免將機密與個資送入模型，並針對資料留存期限、存取權限與稽核紀錄建立管理機制。其餘選項如「稽核紀錄沒有必要」「模型回覆不會洩漏資訊」「個資可作為公開訓練資料」都違反基本的資安與個資保護原則。","concept":"資安與個資治理","aiExplained":true},{"id":"web-j2-1563","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「黑箱與責任」，下列何者最正確？","options":{"A":"使用 AI 後人類不用負責","B":"黑箱不影響醫療金融場景","C":"高風險場景需可解釋、可追溯與人工覆核，以釐清責任","D":"錯誤結果無需追蹤"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"在醫療、金融等高風險場景，AI 的黑箱特性會讓錯誤難以歸責，因此必須要求可解釋性、決策可追溯，並保留人工覆核機制，才能在出錯時釐清責任歸屬。認為「使用 AI 後人類不用負責」或「錯誤結果無需追蹤」都是治理上的常見誤用，責任最終仍在導入與使用 AI 的人與組織身上。","concept":"可解釋性與問責","aiExplained":true},{"id":"web-j2-1564","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「導入評估」，下列何者最正確？","options":{"A":"資料品質不影響專案","B":"先導入再找需求","C":"不需設定 KPI","D":"導入前應評估問題適配性、資料可得性、成本、風險、維運與成效指標"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 導入前的評估重點在於：問題是否適合用 AI 解決、資料是否可得且品質足夠、成本與風險是否可承受，以及上線後的維運與成效指標如何衡量，這是一套完整的可行性評估流程。反觀「先導入再找需求」是本末倒置，而資料品質與 KPI 更是專案成敗的關鍵，不可忽略。","concept":"AI導入評估","aiExplained":true},{"id":"web-j2-1565","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「監控與維運」，下列何者最正確？","options":{"A":"上線後需監控品質、漂移、成本、延遲與使用者回饋","B":"使用者回饋無助於改善","C":"部署完成即專案結束","D":"成本不需監控"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI 服務上線並非專案終點，而是維運的起點：必須持續監控輸出品質、資料與模型漂移、運算成本、回應延遲，並收集使用者回饋作為迭代改善的依據。認為部署即結束、成本不用管、回饋沒有用，都會讓系統品質隨時間劣化而無人察覺。","concept":"模型監控維運","aiExplained":true},{"id":"web-j2-1566","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「著作權與合規」，下列何者最正確？","options":{"A":"資料來源不需紀錄","B":"生成式 AI 應注意訓練資料來源、輸出侵權風險與授權條款","C":"AI 產出必然不受著作權影響","D":"授權條款可忽略"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"使用生成式 AI 時的合規重點包含三塊：訓練資料的來源是否合法、生成內容是否有侵害他人著作權的風險，以及所使用模型與服務的授權條款限制。資料來源需要留存紀錄以備查核，AI 產出也可能涉及侵權爭議，因此授權條款絕不能忽略。","concept":"著作權授權合規","aiExplained":true},{"id":"web-j2-1567","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「No-Code / Low-Code」，下列何者最正確？","options":{"A":"完全不需要治理","B":"一定能取代所有專業程式開發","C":"No-Code/Low-Code 以視覺化元件加速應用開發，但仍受平台能力、整合性與治理限制","D":"封閉平台不會造成鎖定風險"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"No-Code/Low-Code 的價值在於用視覺化元件降低開發門檻、加速應用落地，但它並非萬能：仍受限於平台提供的能力、與既有系統的整合性，以及企業治理要求。封閉平台還可能帶來廠商鎖定風險，也不可能完全取代所有專業程式開發。","concept":"低程式碼平台","aiExplained":true},{"id":"web-j2-1568","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「流程自動化」，下列何者最正確？","options":{"A":"所有流程只能人工觸發","B":"條件分支用來儲存向量","C":"迴圈只能做模型訓練","D":"條件分支、迴圈、格式化與聚合元件可組合成事件驅動流程"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"流程自動化的核心是把條件分支、迴圈、資料格式化與聚合等元件組合起來，並由事件觸發執行，形成不需人工介入的自動化流程。其餘選項混淆了元件的功能定位：條件分支是控制流程走向，不是儲存向量；迴圈是重複執行邏輯，不限於模型訓練。","concept":"流程自動化元件","aiExplained":true},{"id":"web-j2-1569","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「API 與 Token」，下列何者最正確？","options":{"A":"Token 是模型處理文字的基本單位，影響上下文長度、輸入輸出與費用","B":"Token 與費用無關","C":"Token 是資料庫主鍵","D":"上下文長度不受 Token 限制"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Token 是大型語言模型切分與處理文字的基本單位，模型的上下文長度以 Token 數計算，API 計費也依輸入與輸出的 Token 量收費。因此 Token 直接影響能塞入多少內容以及使用成本，說它與費用無關或不限制上下文長度都是錯的，它也與資料庫主鍵完全無關。","concept":"Token與上下文","aiExplained":true},{"id":"web-j2-1570","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某專案經理正在審查 AI 系統設計文件，希望避免常見誤用。 關於「提示工程」，下列何者最正確？","options":{"A":"提示越模糊越好","B":"清楚任務、角色、格式、限制與範例能提高 LLM 輸出穩定性","C":"範例一定會降低表現","D":"輸出格式不需指定"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"提示工程的核心原則是把任務目標、角色設定、輸出格式、限制條件講清楚，必要時再附上範例（few-shot），讓 LLM 的輸出更穩定、更符合預期。提示越模糊，模型的自由發揮空間越大，輸出品質反而越不可控，因此明確與結構化才是關鍵。","concept":"提示工程原則","aiExplained":true},{"id":"web-j2-1571","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某顧問協助客戶準備 iPAS 初級考試，想確認基本概念是否理解正確。 關於「RAG」，下列何者最正確？","options":{"A":"RAG 會永久改寫模型權重","B":"RAG 不需要知識庫品質","C":"RAG 透過檢索外部知識提供上下文，適合企業文件與規範快速更新","D":"RAG 只適合影像辨識"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"RAG 的做法是先從外部知識庫檢索相關內容，再把它作為上下文交給模型生成回答，模型權重完全不變，因此特別適合企業文件、規範這類需要快速更新的知識。也正因為答案來自檢索結果，知識庫的品質直接決定回答品質，絕非不需要品質管理。","concept":"RAG檢索增強","aiExplained":true},{"id":"web-j2-1572","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某公司上線 AI 服務前，召開跨部門會議討論風險與成效。 關於「向量資料庫」，下列何者最正確？","options":{"A":"Embedding 是人工輸入標籤","B":"向量檢索只比對檔名","C":"語意相似度與檢索無關","D":"Embedding 將文字轉為向量，讓系統能以語意相似度檢索資料"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Embedding 是由模型自動將文字轉換成高維向量，語意相近的內容在向量空間中距離也相近，系統因此能以語意相似度檢索資料，而不是只靠關鍵字或檔名比對。它不是人工輸入的標籤，而語意相似度正是向量檢索的核心依據。","concept":"向量嵌入檢索","aiExplained":true},{"id":"web-j2-1573","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某團隊比較多個 AI 解決方案，需從應用情境判斷正確敘述。 關於「微調」，下列何者最正確？","options":{"A":"Fine-tuning 適合讓模型學特定格式、風格或任務模式，但不適合頻繁更新事實知識","B":"微調最適合每小時更新知識","C":"微調不需要資料品質","D":"微調能保證沒有幻覺"},"answer":"A","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"Fine-tuning 是用特定資料調整模型權重，適合讓模型學會固定的格式、語氣風格或任務模式；但每次更新都要重新訓練，因此不適合承載需要頻繁更新的事實知識，這類需求更適合用 RAG。微調同樣仰賴高品質資料，而且無法保證消除幻覺。","concept":"微調適用時機","aiExplained":true},{"id":"web-j2-1574","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某單位建立內部教育訓練題庫，希望用情境題檢查觀念。 關於「AI Agent」，下列何者最正確？","options":{"A":"Agent 不需要權限控管","B":"Agent 可根據目標規劃步驟並呼叫工具/API，但需要權限、日誌與安全邊界","C":"Agent 等於單次文字生成","D":"工具呼叫不需驗證結果"},"answer":"B","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"AI Agent 的特徵是能根據目標自主規劃步驟，並實際呼叫工具或 API 執行，這與單次文字生成有本質差異。也正因為 Agent 會採取行動，必須配套權限控管、操作日誌與安全邊界，工具呼叫的結果也需要驗證，才能避免失控風險。","concept":"AI Agent治理","aiExplained":true},{"id":"web-j2-1575","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某企業正在規劃導入 AI 應用，專案團隊需判斷最適合的技術或治理作法。 關於「生成式 AI 應用」，下列何者最正確？","options":{"A":"只能做資料庫報表","B":"不能處理非結構化文字","C":"生成式 AI 可用於摘要、客服、文案、程式輔助與多模態內容產製","D":"只適合離線單機使用"},"answer":"C","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"生成式 AI 擅長處理非結構化內容，典型應用涵蓋文件摘要、智慧客服、行銷文案、程式開發輔助，以及文字、圖像、聲音等多模態內容產製。說它只能做報表、不能處理非結構化文字或只能離線單機使用，都嚴重低估了它的應用範圍。","concept":"生成式AI應用","aiExplained":true},{"id":"web-j2-1576","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某部門在導入數位工具時，發現現場需求與資料條件有所限制。 關於「AI 治理」，下列何者最正確？","options":{"A":"人人可任意接入模型","B":"敏感資料可直接貼入外部服務","C":"治理與風險無關","D":"企業導入生成式 AI 需建立使用規範、模型清單、審核流程與風險分級"},"answer":"D","needsContext":false,"source":"網路題庫 · ipas.dawsonwang.com","srcUrl":"https://ipas.dawsonwang.com/","explanation":"企業導入生成式 AI 必須建立治理框架：制定使用規範、盤點核准的模型清單、設置審核流程，並依應用場景做風險分級管理。若放任人人任意接入模型、敏感資料直接貼入外部服務，就會產生資料外洩與合規風險，治理與風險管理密不可分。","concept":"生成式AI治理","aiExplained":true},{"id":"web-j1-1577","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某企業四個部門提出分析需求，哪一個最接近「預測性分析(Predictive Analysis)」的特性？","options":{"A":"視覺化過去月銷售走勢與標準差，觀察分佈與波動","B":"資料比對找出去年母親節促銷失效的地區與品類","C":"建構模型推算下一季主力商品銷量，以規劃備貨","D":"用熱圖分析廣告成本與訂單轉換率的潛在關聯"},"answer":"C","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"預測性分析的特徵是利用歷史資料建構模型，推估未來會發生的事，選項中「建構模型推算下一季主力商品銷量以規劃備貨」正是對未來數值的預測。其餘選項分別屬於描述性分析（視覺化過去走勢）與診斷性分析（找出促銷失效原因、分析變數關聯），都是針對過去或現況，而非未來。","concept":"預測性分析","aiExplained":true},{"id":"web-j1-1578","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某模型使用 K-近鄰演算法(KNN)，K 設為 3。新資料最接近的 3 筆鄰居類別為：A、B、A。模型會將這筆資料預測為哪一類？","options":{"A":"類別 A","B":"類別 B","C":"類別 A 與 B 各一半，無法分類","D":"類別 A 或 B，視距離遠近加權而定"},"answer":"A","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"KNN 的基本分類規則是多數決：找出最接近的 K 筆鄰居，以其中出現最多的類別作為預測結果。K=3 時鄰居類別為 A、B、A，類別 A 佔兩票、類別 B 佔一票，因此預測為類別 A。距離加權是 KNN 的變形做法，題目描述的標準 KNN 直接採多數決即可。","concept":"KNN多數決","aiExplained":true},{"id":"web-j1-1579","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某團隊想用循環神經網路(RNN)建構長期氣候數據的預測模型，以下哪一項最符合使用 RNN 可能遇到的挑戰？","options":{"A":"RNN 無法處理可變長度的序列輸入，實務限制極大","B":"RNN 在長序列訓練中可能出現梯度消失，影響模型效果","C":"RNN 無法捕捉時間上的依賴關係，因此預測準確度低","D":"RNN 只能用於分類任務，不能應用於時間序列預測"},"answer":"B","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"RNN 訓練時梯度需沿時間步反覆連乘回傳，序列越長，梯度越容易指數級縮小而消失，導致模型難以學到長期依賴，這正是長期氣候數據這類長序列任務的典型挑戰。其餘選項都是錯誤描述：RNN 本來就能處理可變長度序列、能捕捉時間依賴，也廣泛用於時間序列預測而非僅限分類。","concept":"RNN梯度消失","aiExplained":true},{"id":"web-j1-1580","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"智慧投資系統依市場變化自動決定買進/持有/賣出，並依每次交易盈虧逐步優化策略，不依賴事先標記資料，而是依歷次行動的獎勵調整。最可能採用哪種學習方法？","options":{"A":"強化式學習(Reinforcement Learning)","B":"監督式學習(Supervised Learning)","C":"非監督式學習(Unsupervised Learning)","D":"遷移學習(Transfer Learning)"},"answer":"A","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"題目描述的系統不依賴事先標記的資料，而是透過每次交易的盈虧（獎勵訊號）逐步調整買賣策略，這正是強化式學習「代理人與環境互動、依獎勵優化行動策略」的核心特徵。監督式需要標註答案、非監督式在找資料內在結構、遷移學習則是知識搬移，都不符合此情境。","concept":"強化學習","aiExplained":true},{"id":"web-j1-1581","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在訓練機器學習模型時，若任務為預測房價，應選用下列哪一種損失函數來衡量預測誤差？","options":{"A":"均方誤差(MSE)","B":"交叉熵損失(Cross-Entropy Loss)","C":"Hinge 損失(Hinge Loss)","D":"KL 散度(Kullback-Leibler Divergence)"},"answer":"A","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"預測房價是輸出連續數值的迴歸任務，均方誤差（MSE）衡量預測值與實際值差距的平方平均，是迴歸最標準的損失函數。交叉熵用於分類任務、Hinge 損失是 SVM 的分類損失、KL 散度衡量兩個機率分布的差異，都不適合連續數值的誤差衡量。","concept":"迴歸損失函數","aiExplained":true},{"id":"web-j1-1582","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某醫院依患者年齡、血壓與 BMI 預測罹患糖尿病的機率(0~1)，並依是否超過 0.5 做風險警示。下列哪一種模型最適合此分類任務？","options":{"A":"邏輯迴歸(Logistic Regression)","B":"支援向量機(Support Vector Machine)","C":"決策樹(Decision Tree)","D":"K 平均演算法(K-means)"},"answer":"A","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"題目要求輸出 0 到 1 之間的罹病機率，再依 0.5 門檻做警示，邏輯迴歸透過 Sigmoid 函數天生就輸出機率值，完全貼合這個需求。SVM 與決策樹主要輸出類別而非校準過的機率，K-means 則是非監督式分群演算法，根本不適用於此分類任務。","concept":"邏輯迴歸分類","aiExplained":true},{"id":"web-j1-1583","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某違約風險預測系統，特徵數量眾多，希望提升預測的穩定性與泛化能力，下列哪一種鑑別式 AI 模型最適合？","options":{"A":"邏輯迴歸(Logistic Regression)","B":"支援向量機(Support Vector Machine)","C":"決策樹(Decision Tree)","D":"隨機森林(Random Forest)"},"answer":"D","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"隨機森林以多棵決策樹的集成投票做預測，透過樣本與特徵的隨機抽樣降低單一模型的變異，在特徵數量眾多時仍能維持穩定性與良好的泛化能力，正符合題目需求。單一決策樹容易過擬合，邏輯迴歸與 SVM 面對大量特徵與複雜交互作用時的穩健性也不如集成方法。","concept":"隨機森林集成","aiExplained":true},{"id":"web-j1-1584","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在保持 GPT-OSS 模型架構不變的前提下，若將參數量從 20 億提升至 120 億，且假設有足夠訓練資料，下列敘述何者最正確？","options":{"A":"參數增加會線性提升效能，即使訓練資料不變也不會遇到瓶頸","B":"參數越多推理越快，因為每層可並行計算更多參數","C":"較大的參數量能提升表達能力與預測效能，但需足夠訓練資料支持","D":"增加參數量不影響記憶體使用，只會影響計算速度"},"answer":"C","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"在架構不變的前提下增加參數量，模型的表達能力與預測效能通常會提升，但這有前提：必須有足夠的訓練資料支撐，否則容易過擬合或效益遞減。效能提升並非線性且會遇到瓶頸，參數越多推理計算量與記憶體需求反而越大，因此只有「需足夠資料支持」的敘述最正確。","concept":"模型規模法則","aiExplained":true},{"id":"web-j1-1585","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在深度學習模型的微調(Fine-tuning)過程中，可能出現「災難性遺忘(Catastrophic Forgetting)」。此現象最可能造成哪種情況？","options":{"A":"因資源或步驟不足，模型微調無法完整收斂，學習效果受限","B":"微調後模型表現變得隨機，無法記憶新學到的模式","C":"微調後部分權重偏移，導致無法針對較長文字回應","D":"模型過度適應微調資料分佈，逐漸遺忘預訓練獲得的廣泛知識，在原任務上表現變差"},"answer":"D","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"災難性遺忘指模型在微調時權重被新資料分佈大幅改寫，過度適應微調任務，導致預訓練階段學到的廣泛知識逐漸流失，在原本任務上的表現明顯退步。它的重點是「新知識覆蓋舊知識」，而不是無法收斂、輸出隨機或無法處理長文字。","concept":"災難性遺忘","aiExplained":true},{"id":"web-j1-1586","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"在大型 Transformer 模型的效能優化中，常見方法之一是「剪枝(Pruning)」。下列哪一項最符合該方法的核心概念？","options":{"A":"將所有權重按比例縮小，使其更接近零，以降低計算量","B":"移除模型中影響較小或冗餘的權重參數，以減少模型大小並提升推理效率","C":"訓練時僅更新部分權重而凍結其他，減少需調整的參數","D":"依注意力分數動態跳過部分輸入 Token，以減少前向傳播計算"},"answer":"B","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"剪枝的核心概念是找出模型中貢獻度低或冗餘的權重參數並將其移除，藉此縮小模型體積、降低推理計算量。將權重按比例縮小接近零是類似正則化的做法、凍結部分權重是參數高效微調的概念、動態跳過 Token 則是注意力層的加速技巧，都不是剪枝的定義。","concept":"模型剪枝","aiExplained":true},{"id":"web-j1-1587","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在「可解釋人工智慧(XAI)」領域中，LIME(Local Interpretable Model-agnostic Explanations)方法最核心的應用目的是什麼？","options":{"A":"解釋單一樣本（局部預測）的黑箱模型決策過程","B":"全面提升黑箱模型整體的預測準確度","C":"將黑箱模型轉換成完全可解釋的模型作為替代","D":"用於生成大量擬真數據來替代訓練集"},"answer":"A","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"LIME 的名稱已點出重點：Local（局部）、Model-agnostic（不限模型種類），它在單一樣本附近用可解釋的簡單模型近似黑箱模型的行為，解釋該筆預測的決策依據。它不會提升模型準確度，也不是把黑箱整個換成可解釋模型，更與生成擬真數據無關。","concept":"LIME局部解釋","aiExplained":true},{"id":"web-j1-1588","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"在醫療診斷決策支援系統等高風險領域中，「可解釋人工智慧(XAI)」的核心價值最主要呈現在哪個面向？","options":{"A":"透過提供可理解的決策依據，促進患者與醫療人員對系統診斷結果的信任與接受度","B":"以可解釋性方法優化臨床資料蒐集流程，降低醫療作業成本","C":"利用解釋機制增強模型預測的統計顯著性與準確度","D":"透過透明化運作過程，減輕臨床人員負擔並提升服務效率"},"answer":"A","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"在醫療診斷這類高風險領域，XAI 的核心價值是提供可理解的決策依據，讓醫療人員能檢視系統為何做出該診斷，患者也更能接受建議，進而建立對系統的信任。降低成本、提升統計準確度或減輕人員負擔都只是可能的附帶效果，並非 XAI 的核心目的。","concept":"XAI信任價值","aiExplained":true},{"id":"web-j1-1589","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在信貸決策系統中導入反事實解釋(Counterfactual Explanation)時，實際部署常伴隨技術與監管挑戰。下列哪一項最符合該情境下的核心挑戰？","options":{"A":"需建立完整客戶行為預測模型估算改變成本，並整合進風險管理系統","B":"必須用聯邦學習保護隱私，同時在分散式環境計算跨機構的反事實解釋","C":"需建構時間序列因果圖處理信用狀況動態變化，並預測信用評分軌跡","D":"生成的反事實樣本須滿足特徵間因果與業務邏輯約束，且建議在現實中可操作並符合公平放貸法規"},"answer":"D","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"反事實解釋要告訴客戶「改變哪些條件就能通過信貸」，因此生成的反事實樣本必須滿足特徵間的因果與業務邏輯約束（例如年資不能倒退），建議在現實中可實際操作，同時還要符合公平放貸法規，這正是信貸場景部署的核心挑戰。其餘選項描述的是其他技術議題，並非反事實解釋本身的關鍵難點。","concept":"反事實解釋","aiExplained":true},{"id":"web-j1-1590","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"工業物聯網的設備預測性維護中，若異常事件頻率極低、樣本高度不平衡，下列哪一種方法最能兼顧模型穩定性與異常偵測效能？","options":{"A":"將異常資料複製多次提升敏感度，搭配全序列訓練模型（如 LSTM）","B":"對時間序列差分與標準化後，用傳統監督式模型（如 SVM）分類","C":"用時間序列特化的 SMOTE 生成異常樣本以平衡比例","D":"採用基於重建誤差的自編碼器(Seq2Seq Autoencoder)做異常偵測，僅用正常資料訓練"},"answer":"D","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"當異常事件極少、樣本高度不平衡時，與其勉強做監督式分類，不如只用充足的正常資料訓練自編碼器學習正常模式，推論時以重建誤差偏高來偵測異常，既穩定又不依賴稀少的異常標註。單純複製異常樣本容易過擬合，SMOTE 在時間序列上生成的合成樣本也可能破壞時序結構。","concept":"重建誤差偵測","aiExplained":true},{"id":"web-j1-1591","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"資料倉儲中多個欄位儲存相同的購買金額（如 amount_usd、total_price、transaction_value），但單位、命名與格式不一致，導致特徵工程混淆。針對此跨欄位語義重疊與冗餘問題，下列哪一種策略最合適且可行？","options":{"A":"用資料探勘自動選最敏感欄位，其他捨棄，避免過度清理","B":"保留所有相似欄位，交由高階模型自動學習關聯，無需手動處理","C":"建立命名標準、統一單位與格式，進行欄位正規化與語義合併，減少重複資訊影響特徵重要性","D":"將重複欄位視為類別欄位做 One-hot 編碼後輸入模型"},"answer":"C","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"多個欄位語義重疊時，正確做法是建立命名標準、統一單位與格式，將重複欄位正規化並做語義合併，才能避免相同資訊重複進入模型而扭曲特徵重要性。放任模型自行學習或隨意捨棄欄位都缺乏治理依據，而把數值金額欄位當類別做 One-hot 更是完全錯誤的處理方式。","concept":"欄位正規化合併","aiExplained":true},{"id":"web-j1-1592","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"商品推薦模型訓練資料中，高價商品樣本極少、低價商品集中。若此不平衡未妥善處理，下列何種狀況最可能在實際推薦結果中發生？","options":{"A":"模型傾向輸出稀有類別，雖捕捉到少數樣本但精確率顯著下降","B":"因類別分布不均難以建立線性分離邊界，無法收斂","C":"模型過度聚焦稀有類別，導致對多數類別預測能力下降","D":"模型決策邊界由多數類別主導，忽視稀有類別，使該類別召回率大幅降低"},"answer":"D","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"類別不平衡時，模型為了最小化整體誤差，決策邊界會被佔多數的低價商品樣本主導，稀有的高價商品類別因此被系統性忽視，該類別的召回率大幅下降。模型的偏向是往多數類別靠攏，而不是傾向或過度聚焦稀有類別，這是判斷此題的關鍵。","concept":"類別不平衡","aiExplained":true},{"id":"web-j1-1593","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"電商團隊取得使用者點擊、購買紀錄、流量來源與轉換率，希望先進行探索性資料分析(EDA)，下列哪一項最符合 EDA 的做法？","options":{"A":"建立隨機森林模型，預測使用者是否會完成購買","B":"用 K-means 分群後立即制定對應促銷策略","C":"繪製各類流量來源對轉換率的關聯圖，尋找潛在關係","D":"對不同購物路徑設定統計假設並進行雙樣本 t 檢定"},"answer":"C","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"EDA 的精神是在建模之前，透過視覺化與統計摘要探索資料的分佈、關聯與異常，「繪製流量來源對轉換率的關聯圖尋找潛在關係」正是典型做法。建立隨機森林預測、分群後立即制定策略、進行 t 檢定驗證假設，都已進入建模或推論確認階段，超出探索性分析的範疇。","concept":"探索性資料分析","aiExplained":true},{"id":"web-j1-1594","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"風險控管模型發現樣本間存在明顯時間序列相關性，導致偵測新交易時誤判率升高。若要同時改善詐騙比例推估準確性並提升穩健性，下列哪一種做法最為合適？","options":{"A":"擴充樣本量但維持既有隨機抽樣方式不變","B":"採時間序列敏感的抽樣策略，如依交易時間區間分層，以保存時間結構","C":"將資料完全隨機打散，以降低序列相關性對訓練的影響","D":"評估時對相鄰時間區段合併誤差，以整體估計修正詐騙比例"},"answer":"B","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"樣本存在時間序列相關性時，完全隨機抽樣會破壞時間結構，導致訓練與評估失真；正確做法是採用時間敏感的抽樣策略，例如依交易時間區間分層抽樣，保留時序特性，才能同時改善詐騙比例推估的準確性與模型穩健性。單純擴充樣本量或把資料打散，都無法解決時間結構被忽略的根本問題。","concept":"時序分層抽樣","aiExplained":true},{"id":"web-j1-1595","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"基於檢索增強生成(RAG)的知識查詢系統，回應偶爾過時，且每次更新文件都需完整重建索引導致更新期間無法服務。若要解決並提升穩健性，下列哪項做法最適合？","options":{"A":"調整生成模型的回應隨機性參數，以降低答案偏差","B":"提升檢索與索引運算效能，以縮短查詢與更新時間","C":"採用索引的增量或分段更新，使新資料即時納入而不需全部重建","D":"建立常見問題的標準答案集，以快速檢索回應降低模型負擔"},"answer":"C","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"題目的兩個痛點是回應過時與更新期間服務中斷，根本原因在於索引必須整批重建；改採增量或分段更新索引，新文件可即時納入檢索範圍，且更新過程不影響既有服務。調整生成參數或建立 FAQ 標準答案都無法讓知識真正更新，單純提升運算效能也只是縮短中斷時間而非消除問題。","concept":"索引增量更新","aiExplained":true},{"id":"web-j1-1596","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"住院日數預測模型中，多數病人集中 3–7 天，少數重症明顯偏長。希望兼顧多數病人準確度又確保重症個案預測穩健，下列哪一種方法最符合此需求？","options":{"A":"模型檢核時同時呈現平均絕對誤差(MAE)與重症子群的誤差指標","B":"僅針對一般病人樣本做交叉驗證，避免重症拉高誤差","C":"將所有住院日數標準化，以減少數值範圍差異","D":"只採用整體決定係數(R²)作為判斷依據"},"answer":"A","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"住院日數分佈集中於 3 至 7 天、重症偏長，單一整體指標會被多數樣本主導而掩蓋重症的預測誤差；同時呈現整體 MAE 與重症子群的誤差指標，才能兼顧多數病人的準確度與重症個案的穩健性。排除重症樣本或只看整體 R² 都會讓少數關鍵族群的表現無從檢視。","concept":"子群誤差評估","aiExplained":true},{"id":"web-j1-1597","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"關於監督式學習與非監督式學習的目標，下列敘述何者錯誤？(1)非監督式核心在發掘資料內在結構，如分群、關聯規則與降維，不依賴外部標籤。(2)監督式典型應用為分類與迴歸，通常不適合應用於異常偵測。(3)非監督式若搭配少量標註資料，即會完全轉化為監督式。(4)監督式仰賴已標註資料，透過最小化輸出與真實標籤差距學習對應函數。(5)所有監督式任務都必須要有大量完整標註資料，否則無法進行任何有效訓練。(6)非監督式不需目標變數，僅透過輸入資料本身的特徵分布進行模式學習。","options":{"A":"3、5、6","B":"1、4、6","C":"2、4、6","D":"2、3、5"},"answer":"D","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"敘述(2)錯誤，因為只要有標註資料，監督式學習同樣可用於異常偵測；敘述(3)錯誤，非監督式搭配少量標註是半監督式學習，並非完全轉化為監督式；敘述(5)錯誤，透過遷移學習、少樣本學習等技術，不一定需要大量完整標註才能有效訓練。敘述(1)(4)(6)則正確描述了兩種學習方式的核心特性，因此錯誤的組合是 2、3、5。","concept":"監督與非監督","aiExplained":true},{"id":"web-j1-1598","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"旅遊平台預測顧客是否再次訂房，欄位含主要交通方式（火車/飛機/自駕/公車）等。下列哪一種特徵工程方法最適合處理「主要交通方式」欄位？","options":{"A":"布林轉換(Boolean Conversion)","B":"序數編碼(Ordinal Encoding)","C":"數值標準化(Numerical Standardization)","D":"One-hot 編碼(One-hot Encoding)"},"answer":"D","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"「主要交通方式」是火車、飛機、自駕、公車這類彼此沒有大小順序的名目型類別變數，One-hot 編碼將每個類別展開成獨立的 0/1 欄位，能避免模型誤把類別當成有序數值。序數編碼會引入不存在的順序關係，布林轉換僅適用二元欄位，數值標準化則只適用於連續數值特徵。","concept":"One-hot編碼","aiExplained":true},{"id":"web-j1-1599","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"跨國醫療機構想用各地醫院資料建模，但原始資料因法規無法集中。哪一種方法最能同時滿足「各醫院資料不外流」與「模型仍能跨院學習」？","options":{"A":"資料匿名化(Data Anonymization)","B":"差分隱私(Differential Privacy)","C":"聯邦學習(Federated Learning)","D":"交叉驗證(Cross-validation)"},"answer":"C","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"聯邦學習讓各醫院在本地用自家資料訓練模型，只上傳模型參數或梯度到中央彙整，原始資料完全不離開醫院，同時又能讓模型吸收跨院的知識，正好同時滿足題目的兩項要求。匿名化與差分隱私處理的是資料揭露時的隱私保護，交叉驗證則是模型評估方法，都無法達成「資料不外流仍能跨院學習」。","concept":"聯邦學習","aiExplained":true},{"id":"web-j1-1600","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"員工離職風險模型含「年度績效分數(1–5)」「平均每月加班時數(0–80)」「年齡(20–65)」等數值特徵，範圍差異極大，直接輸入梯度下降的邏輯迴歸可能收斂緩慢或權重偏斜。下列哪一種方法最適合？","options":{"A":"布林轉換(Boolean Conversion)","B":"時間序列分解(Time Series Decomposition)","C":"One-hot 編碼(One-hot Encoding)","D":"數值標準化(Numerical Standardization)"},"answer":"D","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"績效分數、加班時數與年齡的數值範圍差異極大，梯度下降在尺度懸殊的特徵空間中收斂緩慢，權重也容易偏向大範圍特徵；數值標準化將各特徵轉換到相近尺度（如均值 0、標準差 1），可改善收斂速度與權重平衡。這些欄位都是連續數值，One-hot 編碼與布林轉換不適用，時間序列分解更與此無關。","concept":"數值標準化","aiExplained":true},{"id":"web-j1-1601","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"某團隊蒐集病患「收縮壓」數據，檢驗顯示大致呈常態分布。進行模型分析前希望妥善處理可能的極端血壓值，下列哪一種做法最為合適？","options":{"A":"將所有極端偏高/偏低的數據直接刪除，以保留代表性樣本","B":"使用對數轉換將數據壓縮至更接近常態，降低極端值影響","C":"透過 Z 分數或標準差範圍檢測異常值，並依研究需求決定是否調整或移除","D":"將離群值以 Label Encoding 編碼為序號標籤以避免影響分布"},"answer":"C","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"收縮壓資料大致呈常態分布，最合適的做法是用 Z 分數或標準差範圍客觀檢測異常值，再依研究需求決定調整或移除，兼顧統計嚴謹性與領域判斷。直接刪除所有極端值可能誤刪真實的高風險病患資料；對數轉換適用於右偏分布而非已近常態的資料；Label Encoding 是類別編碼方法，用於離群值處理完全錯誤。","concept":"離群值處理","aiExplained":true},{"id":"web-j1-1602","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"電商想選出對購買結果最有預測價值的特徵以提升模型效能。下列哪一種描述最符合監督式特徵選擇(Supervised Feature Selection)的概念？","options":{"A":"根據特徵的整體分布、變異度或資訊量篩選，不直接參考目標變數","B":"評估每個特徵與目標變數的相關性，選對預測結果貢獻最大的特徵","C":"用模型評估特徵對預測結果的重要性，保留對目標變數影響較大的欄位","D":"用降維方法（如 PCA）將特徵轉換為新特徵再訓練"},"answer":"B","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"監督式特徵選擇的關鍵在於利用目標變數來評估特徵的價值，直接衡量各特徵與購買結果之間的關聯強度，挑出對預測貢獻最大的欄位，因此B最貼近其基本概念。選項A不參考目標變數，屬於非監督式作法；D的PCA是特徵轉換而非特徵選擇；C雖也在監督式範疇內，但偏向以模型為核心的嵌入式方法，並非概念層次的直接定義。","concept":"監督式特徵選擇","aiExplained":true},{"id":"web-j1-1603","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在訓練神經網路時，為提升收斂速度與穩定性、避免梯度消失或爆炸，下列哪一種做法最常被使用？","options":{"A":"對輸入資料隨機旋轉或水平翻轉，以增加資料多樣性","B":"選用 ReLU 或其變體作為隱藏層的啟動函數，以改善梯度傳播","C":"減少樣本量提升訓練速度","D":"對目標變數或特徵進行標準化"},"answer":"B","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"ReLU及其變體在正區間的梯度恆為1，能有效緩解深層網路反向傳播時的梯度消失問題，使訓練收斂更快、更穩定，因此成為隱藏層啟動函數的主流選擇。資料旋轉翻轉屬於資料增強，目的在增加多樣性而非改善梯度傳播；減少樣本量與僅對目標變數標準化都無法直接解決梯度消失或爆炸。","concept":"ReLU啟動函數","aiExplained":true},{"id":"web-j1-1604","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"若希望檢視某一連續型數據的分布情形（如集中程度、偏態或是否多峰），下列哪一種應用情境最適合使用直方圖(Histogram)?","options":{"A":"探討顧客年齡資料的整體分布，並檢視是否存在異常集中或分散","B":"比較不同商品各月份的銷售額變化趨勢，觀察季節性波動","C":"追蹤公司近一年營收的時間序列變化，了解成長趨勢","D":"檢視產品價格與月銷售量之間的關聯性，評估是否線性相關"},"answer":"A","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"直方圖將連續型資料切成組距並統計各區間的頻數，最適合觀察單一變數的分布形狀，例如集中程度、偏態或是否出現多峰，因此檢視顧客年齡的整體分布是典型應用。至於各月銷售額與營收的時間變化適合折線圖，價格與銷量的關聯性則應使用散布圖。","concept":"直方圖應用","aiExplained":true},{"id":"web-j1-1605","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"某雲端公司以批次推論(Batch Inference)每日處理上百萬筆請求。評估挑戰時，下列哪一項通常不會被視為批次推論階段的主要難題？","options":{"A":"如何確保訓練語料的涵蓋性與標註品質，以避免模型偏差影響輸出","B":"當批次規模增大時，如何降低推論延遲並保持即時回應能力","C":"推論過程中有效管理與分配龐大輸入資料量以避免資源壅塞","D":"在叢集環境中精確安排推論任務，以提升 GPU/TPU 等硬體利用率"},"answer":"A","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"批次推論屬於模型部署後的推論階段，主要挑戰集中在龐大輸入資料的管理與分配、叢集任務排程與GPU/TPU利用率，以及批次規模擴大時的延遲控制。訓練語料的涵蓋性與標註品質是模型訓練階段的議題，不屬於批次推論階段的難題，故A為正確選項。","concept":"批次推論挑戰","aiExplained":true},{"id":"web-j2-1606","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某公司開發的智慧車載語音助理，可透過語音辨識(ASR)辨識駕駛語音，再由 LLM 生成回答並查詢車載 API。測試中發現：ASR 對汽車專業術語辨識錯誤率高；LLM 的回覆常不精確；系統回覆延遲雖存在但仍可接受。若目標是「優先提升準確性與回答品質」，下列改進步驟的最合理執行順序為何？步驟：1.擴充並標註汽車領域語音資料，微調 ASR 模型；2.微調 LLM 並加入檢索增強(RAG)；3.優化系統架構，引入批次推論降低延遲；4.動態調整生成溫度，平衡準確度與多樣性。","options":{"A":"1 → 2 → 4 → 3","B":"2 → 1→ 3 → 4","C":"1 → 3 → 2 → 4","D":"3 → 1 → 2 → 4"},"answer":"A","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"題目要求優先提升準確性與回答品質，應先處理最上游的錯誤來源：先擴充領域語料微調ASR，降低辨識錯誤（步驟1），再微調LLM並導入RAG改善回覆精確度（步驟2），接著調整生成溫度平衡準確與多樣性（步驟4）。延遲目前仍可接受，故批次推論等架構優化（步驟3）合理地排在最後。","concept":"系統優化順序","aiExplained":true},{"id":"web-j2-1607","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某大型物流公司計畫導入 AI 系統，以改善客服與配送作業的效率。專案團隊規劃了以下四個步驟，請問正確的執行順序為何？步驟：1.建立符合公司服務流程的 AI 對話邏輯與應答範本，確保顧客體驗一致；2.明確定義導入 AI 的目標並設定關鍵績效指標(KPI)；3.蒐集與清理過往客服紀錄與配送相關資料，作為模型訓練素材；4.評估並選擇合適的 AI 技術供應商或開源方案，確立技術方向與架構。","options":{"A":"2 → 3 → 4 → 1","B":"3 → 2 → 1 → 4","C":"2 → 1 → 3 → 4","D":"1 → 4 → 3 → 2"},"answer":"A","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"AI導入專案應先明確定義目標並設定KPI（步驟2），才有後續規劃的依據；接著蒐集與清理歷史客服與配送資料作為訓練素材（步驟3），再依據資料與需求評估供應商或開源方案、確立技術架構（步驟4），最後建立對話邏輯與應答範本進入實作（步驟1）。此順序符合先訂目標、後備資料、再選技術、終落地的專案邏輯。","concept":"AI導入流程","aiExplained":true},{"id":"web-j2-1608","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"某企業希望利用含敏感資訊的資料進行 AI 模型訓練，但政策要求原始資料不得外洩，且資料可集中於安全環境中處理。同時，企業希望在資料使用過程中，即使資料處於加密狀態，仍能完成模型計算。在此需求下，下列哪一種技術最為適合？","options":{"A":"聯邦學習(Federated Learning)","B":"同態加密(Homomorphic Encryption)","C":"零知識證明(Zero-knowledge Proof)","D":"資料匿名化(Data Anonymization)"},"answer":"B","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"題目關鍵在於資料可集中於安全環境，且要求在加密狀態下仍能完成模型計算，這正是同態加密的核心特性：可直接對密文執行運算，解密後結果與明文運算一致。聯邦學習是資料不集中、在各端分散訓練的架構，與題意不符；零知識證明用於驗證而非運算，匿名化也無法支援加密狀態下的計算。","concept":"同態加密","aiExplained":true},{"id":"web-j2-1609","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某金融監理機構規劃導入生成式 AI 以協助內部人員分析申報文件與監理報告，系統需處理大量涉及企業敏感資料與未公開資訊。主管機關明確要求「資料安全與法規遵循必須優先於導入速度與成本考量」。在此條件下，下列哪一種策略最為適當？","options":{"A":"採用雲端大型語言模型 API，並透過資料遮罩與加密機制降低外洩風險","B":"導入開源模型進行私有化部署，以兼顧成本彈性與模型可控性","C":"自行訓練並私有化部署模型，同時建立存取控管與稽核機制","D":"先驗證模型效益，再逐步補強合規與資安架構"},"answer":"C","needsContext":false,"source":"網路題庫 · yazelin/ipas-ai-quiz","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"在資料安全與法規遵循明確優先於速度與成本的前提下，自行訓練並私有化部署可將敏感資料完全留在內部環境，再搭配存取控管與稽核機制，最能滿足監理要求。雲端API即使遮罩加密仍有資料外流疑慮，開源私有化偏重成本彈性考量，先驗證效益再補合規則直接違反題目的優先順序。","concept":"私有化部署策略","aiExplained":true},{"id":"web-j1-1626","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"關於 AI 的定義，下列敘述何者較為正確？","options":{"A":"AI 僅限於深度學習技術","B":"AI 包括各種技術，例如機器學習、專家系統等","C":"AI 系統只能在學術研究中應用","D":"AI 無法應用於金融領域"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"AI是一個涵蓋廣泛的領域，包含機器學習、深度學習、專家系統、知識表示等多種技術路線，深度學習只是其中一個分支。AI也早已廣泛應用於金融、醫療、製造等產業，並不限於學術研究，因此B的敘述最為正確。","concept":"AI定義範疇","aiExplained":true},{"id":"web-j1-1627","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"為了提升 AI 系統的透明性，下列哪種措施是適當的？","options":{"A":"不需對外揭露任何有關 AI 系統的資訊","B":"規劃透過發布報告、技術文件或網站揭露 AI 系統的相關資訊","C":"僅對內部員工進行透明性說明","D":"將所有 AI 系統資訊保密"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"透明性的重點是讓外部利害關係人能了解AI系統的運作方式與影響，透過發布報告、技術文件或網站揭露相關資訊，是具體且適當的透明性措施。完全保密或僅對內部員工說明，都無法達成對外透明的目的。","concept":"AI透明性","aiExplained":true},{"id":"web-j1-1628","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"下列何者不適合做為資料分布估計？","options":{"A":"直方圖(Histogram)","B":"散布圖(Scatter plot)","C":"雷達圖(Radar chart)","D":"四分位數(Quartile)"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"直方圖與四分位數是估計資料分布的基本工具，散布圖也能呈現資料點的分散與集中情形。雷達圖的用途是比較多個變數在不同維度上的表現輪廓，並非用來估計資料的分布形狀，因此最不適合。","concept":"資料分布視覺化","aiExplained":true},{"id":"web-j1-1629","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"K-Means 聚類算法中，K 代表什麼？","options":{"A":"數據集中特徵的數量","B":"數據集中樣本的數量","C":"所需劃分的群組數量","D":"迭代次數"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"K-Means中的K是使用者事先指定的群組數量，演算法會將所有樣本劃分為K個群，並反覆更新各群中心直到收斂。K既不是特徵數或樣本數，也不是迭代次數。","concept":"K-Means分群","aiExplained":true},{"id":"web-j1-1630","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"深度學習模型中，下列哪一項通常用來降低過擬合問題？","options":{"A":"增加訓練數據量","B":"增加模型的複雜度","C":"增加學習率","D":"增加正則化項"},"answer":"D","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"在損失函數中加入正則化項（如L1、L2）會懲罰過大的權重，限制模型複雜度，使模型不易記住訓練資料中的雜訊，是深度學習中降低過擬合的典型手段。反之，增加模型複雜度或提高學習率不僅無助於過擬合，反而可能使問題惡化。","concept":"正則化","aiExplained":true},{"id":"web-j1-1631","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"生成式人工智慧最核心的能力是什麼？","options":{"A":"從大量數據中學習","B":"執行複雜的數學計算","C":"生成新的、原創的內容","D":"控制機器人"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"生成式AI最核心的能力在於學習資料的分布之後，產生訓練資料中不存在的全新內容，例如文字、圖像或音樂。從大量數據中學習是所有機器學習方法的共通基礎，並非生成式AI獨有的核心特徵。","concept":"生成式AI能力","aiExplained":true},{"id":"web-j1-1632","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"下列哪項技術是生成式 AI 發展的重要基礎？","options":{"A":"決策樹","B":"神經網路","C":"線性迴歸","D":"貝氏分類"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"生成式AI的代表技術如GAN、擴散模型與大型語言模型，都建立在神經網路特別是深度神經網路的架構之上，其強大的表徵學習能力是生成式AI發展的重要基礎。決策樹、線性迴歸與貝氏分類屬於傳統方法，並非生成式AI的技術基石。","concept":"神經網路基礎","aiExplained":true},{"id":"web-j1-1633","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"關於 AI，下列敘述何者較為正確？","options":{"A":"AI 僅限於深度學習技術","B":"AI 包括各種技術，例如機器學習、專家系統等","C":"AI 系統只能在學術研究中應用","D":"AI 無法應用於金融領域"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"AI是涵蓋多種技術的總稱，機器學習、專家系統、知識推理等都屬於AI的範疇，深度學習僅是其中一種方法。AI的應用遍及金融、醫療與製造等實務領域，並非只能存在於學術研究，故B最正確。","concept":"AI定義範疇","aiExplained":true},{"id":"web-j1-1634","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在 AI 治理中，下列何者是國際合作的重要性？","options":{"A":"統一 AI 發展標準","B":"避免 AI 技術的濫用","C":"促進 AI 技術的轉移","D":"以上皆是"},"answer":"D","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"國際合作在AI治理中同時扮演多重角色：協調各國建立一致的發展與安全標準、共同防範AI技術被濫用，並促進技術與經驗的交流轉移。三個選項都是國際合作的重要面向，因此答案為以上皆是。","concept":"AI治理國際合作","aiExplained":true},{"id":"web-j1-1635","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"下列何者「並非」K 平均數(k-means)集群法的特點？","options":{"A":"原理相對其他集群法較為複雜","B":"可結合其他方法，使用上較為彈性","C":"在特定情況下，能將集群的任務處理得足夠好","D":"不適合非球形、數據密度變化大或有離群數據的集群問題"},"answer":"A","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"K-means的優點正是原理簡單、直觀易實作，因此「原理相對其他集群法較為複雜」並非其特點，A為正確選項。其餘敘述皆屬實：它可結合其他方法彈性使用、在資料呈球形群聚時能把任務處理得夠好，但確實不適合非球形、密度變化大或含離群值的資料。","concept":"K-means特性","aiExplained":true},{"id":"web-j1-1636","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"驗證性資料分析 ( Confirmatory Data Analysis, CDA ) 與探索性資料分析 (Exploratory Data Analysis, EDA)相比，主要著重於下列哪一項？","options":{"A":"對資料進行初步描述和視覺化","B":"驗證先前生成的假設並進行深入挖掘","C":"排除資料中的極端值以提高準確性","D":"探索數據中潛在的模式和異常"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"驗證性資料分析（CDA）著重以統計檢定等方法驗證事先提出的假設，並針對特定問題進行深入挖掘與確認；探索性資料分析（EDA）才是著重初步描述、視覺化與尋找潛在模式。選項A與D是EDA的內容，排除極端值僅屬資料前處理，故B最能區分兩者。","concept":"驗證性資料分析","aiExplained":true},{"id":"web-j1-1637","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"以下哪種情況下，使用中位數來描述資料的集中趨勢最為合適？","options":{"A":"一組考試成績，大部分學生分數集中在 80 分左右","B":"一組房屋價格數據，其中包含少數豪宅的極端高價","C":"一組產品銷售量數據，每個產品的銷量差異不大","D":"一組學生身高數據，呈現出常態分布"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"中位數不受極端值影響，當房價資料中含少數豪宅的極端高價時，平均數會被明顯拉高而失真，中位數更能代表整體房價的集中趨勢。其餘情境的資料分布相對對稱或差異不大，使用平均數即可妥善描述。","concept":"中位數應用","aiExplained":true},{"id":"web-j1-1638","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"一組數據中，如果平均數小於中位數，那麼這組數據的分布可能是下列哪一種？","options":{"A":"對稱分布","B":"正偏態分布","C":"負偏態分布","D":"無法判斷"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"平均數容易被極端值拉動：當平均數小於中位數時，代表左側存在較小的極端值將平均數往下拉，分布尾巴向左延伸，屬於負偏態（左偏）分布。若為正偏態則平均數會大於中位數，對稱分布時兩者大致相等。","concept":"負偏態分布","aiExplained":true},{"id":"web-j1-1639","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"當我們進行一次假設檢定，得到的 p 值為 0.03，而我們事先設定的顯著性水準為 0.05。以下哪一個敘述最合乎統計檢定的意義？","options":{"A":"我們有 97%的信心拒絕虛無假設","B":"我們在 95%的信心水準下拒絕虛無假設","C":"我們無法拒絕虛無假設","D":"我們犯型一錯誤的機率為 5%"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"當p值0.03小於事先設定的顯著性水準0.05時，即可在此顯著性水準（相當於95%信心水準）下拒絕虛無假設，這是統計檢定的標準表述。p值本身並非「有97%信心」的機率，也不等於實際犯型一錯誤的機率，故B最合乎統計意義。","concept":"假設檢定與p值","aiExplained":true},{"id":"web-j1-1640","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"一組資料中，若平均數大於中位數，則這組資料的分布可能是下列哪一種？","options":{"A":"對稱分布","B":"負偏態分布","C":"正偏態分布","D":"無法判斷"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"平均數對極端值敏感：當平均數大於中位數時，表示右側有較大的極端值將平均數往上拉，分布尾巴向右延伸，屬於正偏態（右偏）分布。這與平均數小於中位數的負偏態情形恰好相反。","concept":"正偏態分布","aiExplained":true},{"id":"web-j1-1641","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t2","stem":"下列哪一個敘述關於四分位距(IQR)是正確的？","options":{"A":"四分位距會受到極端值的影響","B":"四分位距代表資料中所有數據的分散程度","C":"四分位距是第三四分位數與第一四分位數的差","D":"四分位距與平均數一樣，容易受到極端值影響"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"四分位距（IQR）的定義就是第三四分位數Q3減去第一四分位數Q1，描述中間50%資料的分散範圍。由於只取中段資料，IQR天生對極端值不敏感，故A與D錯誤；它也不代表所有數據的分散程度，B亦不正確。","concept":"四分位距","aiExplained":true},{"id":"web-j1-1642","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"以下哪一種情況最適合用眾數來描述資料的集中趨勢？","options":{"A":"一組學生身高資料，呈現出常態分布","B":"一組產品銷售量資料，其中一種產品的銷量遠高於其他產品","C":"一組考試成績資料，大部分學生的分數集中在 80 分左右","D":"一組房屋價格資料，其中包含少數豪宅的極端高價"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"眾數代表出現頻率最高的數值，當某一產品的銷量遠高於其他產品時，眾數能直接指出最典型、最常見的情形，是描述此類資料集中趨勢的合適指標。常態分布或分數集中的資料用平均數即可，含極端高價的房價資料則較適合中位數。","concept":"眾數應用","aiExplained":true},{"id":"web-j1-1643","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"機器學習的三個核心要素是什麼？","options":{"A":"數據、模型、損失函數","B":"訓練集、測試集、驗證集","C":"特徵工程、優化演算法、正則化","D":"超參數調整、模型選擇、數據處理"},"answer":"A","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"機器學習的三大核心要素為資料、模型與損失函數：資料提供學習素材，模型定義從輸入到輸出的假設空間，損失函數衡量預測與真實值的差距並引導參數優化。其餘選項屬於資料切分方式或訓練技巧，並非最核心的三要素。","concept":"機器學習三要素","aiExplained":true},{"id":"web-j1-1644","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"下列哪一項屬於監督式學習的特點？","options":{"A":"數據集中包含標記訊息","B":"僅需探索數據內部的結構","C":"使用代理與環境互動進行學習","D":"不需要驗證集來調整參數"},"answer":"A","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"監督式學習的定義特徵就是訓練資料附有標記，模型透過輸入與正確答案的配對學習對應關係。僅探索資料內部結構屬於非監督式學習，使用代理與環境互動學習則是強化學習的特點。","concept":"監督式學習","aiExplained":true},{"id":"web-j1-1645","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"機器學習模型過擬合的主要原因是什麼？","options":{"A":"模型的複雜度不足","B":"訓練數據樣本過多","C":"模型過度學習數據中的雜訊","D":"使用過於簡單的損失函數"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"過擬合的主因是模型過度貼合訓練資料，連其中的雜訊與偶然模式也一併學進去，導致對新資料的泛化能力下降。模型複雜度不足造成的是欠擬合，而訓練樣本越多通常反而有助於緩解過擬合。","concept":"過擬合成因","aiExplained":true},{"id":"web-j1-1646","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"機器學習的梯度下降演算法主要用於什麼？","options":{"A":"減少模型的計算複雜度","B":"優化模型參數以最小化損失函數","C":"減少數據中的雜訊干擾","D":"增強數據特徵的表示能力"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"梯度下降透過計算損失函數對參數的梯度，沿梯度反方向逐步更新參數，使損失函數值不斷下降，是最常用的參數優化演算法。它的目的在於優化模型參數，而非降低計算複雜度、去除資料雜訊或增強特徵表示。","concept":"梯度下降","aiExplained":true},{"id":"web-j1-1647","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"決策樹的最大優勢是什麼？","options":{"A":"適合大規模數據的訓練","B":"具有良好的可解釋性","C":"不需要進行數據標準化","D":"適用於圖像生成任務"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"決策樹以一連串「若…則…」的分支規則進行判斷，整條決策路徑可以被人直接閱讀與理解，因此良好的可解釋性是其最大優勢。它在大規模資料訓練與圖像生成任務上並不突出，不需資料標準化只是次要的便利性。","concept":"決策樹可解釋性","aiExplained":true},{"id":"web-j1-1648","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"隨機森林(Random Forest)改進了單一決策樹的缺陷，主要透過什麼方法實現？","options":{"A":"使用核函數映射高維空間","B":"集成多棵隨機生成的決策樹並投票","C":"增加模型參數以減少偏差","D":"採用生成模型替代分類器"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"隨機森林透過自助抽樣與隨機特徵選取建立多棵彼此差異化的決策樹，再以投票或平均整合預測結果，有效降低單一決策樹容易過擬合、變異大的缺陷。核函數映射是SVM的技巧，與隨機森林無關。","concept":"隨機森林","aiExplained":true},{"id":"web-j1-1649","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"下列何者為鑑別式 AI 的主要目標？","options":{"A":"學習數據的生成過程","B":"生成類似真實數據的新樣本","C":"分類或迴歸數據","D":"創建多樣化的數據分佈"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"鑑別式AI的目標是學習輸入與輸出之間的判別邊界，即條件機率P(y|x)，專門用於分類或迴歸等預測任務。學習資料的生成過程與產生新樣本，則屬於生成式AI的範疇。","concept":"鑑別式AI目標","aiExplained":true},{"id":"web-j1-1650","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"下列何者屬於生成式 AI 使用之模型？","options":{"A":"支援向量機(SVM)","B":"邏輯迴歸(Logistic Regression)","C":"生成對抗網路(GAN)","D":"隨機森林(Random Forest)"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"生成對抗網路（GAN）透過生成器與鑑別器的對抗訓練學習資料分布並產生新樣本，是典型的生成式模型。SVM、邏輯迴歸與隨機森林皆屬判別式模型，只負責分類或迴歸，不具備生成新資料的能力。","concept":"生成式模型","aiExplained":true},{"id":"web-j1-1651","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"生成對抗網路(GAN)的兩個核心組件是什麼？","options":{"A":"編碼器與解碼器","B":"分類器與生成器","C":"生成器與鑑別器","D":"訓練器與推斷器"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"GAN由生成器與鑑別器兩個網路組成：生成器負責產生以假亂真的樣本，鑑別器負責判斷樣本是真實資料還是生成資料，兩者在對抗過程中共同進步。編碼器與解碼器是自編碼器的組件，並非GAN的核心結構。","concept":"GAN架構","aiExplained":true},{"id":"web-j1-1652","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"關於鑑別式 AI，下列敘述何者較為正確？","options":{"A":"學習數據的聯合概率 P(x,y)","B":"專注於數據的分類或迴歸任務","C":"主要用於生成新數據","D":"適合處理無標記數據"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"鑑別式AI直接學習條件機率P(y|x)或決策邊界，專注於分類與迴歸等判別任務，且通常需要標記資料訓練。學習聯合機率P(x,y)與生成新數據是生成式模型的特性，故B的敘述最正確。","concept":"鑑別式AI特性","aiExplained":true},{"id":"web-j1-1653","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"在醫學影像中，生成式 AI 和鑑別式 AI 的整合應用主要目的是什麼？","options":{"A":"減少標記數據需求","B":"自動生成診斷結論","C":"提高診斷準確性和數據多樣性","D":"完全取代醫生的判斷"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"在醫學影像應用中，生成式AI可合成或增強影像以擴充資料多樣性，鑑別式AI則負責病灶分類與偵測，兩者整合的主要目的就是提高診斷準確性並改善資料多樣性。整合系統是輔助醫師決策的工具，並非完全取代醫師判斷。","concept":"生成鑑別整合","aiExplained":true},{"id":"web-j1-1654","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"下列哪種方法能解決生成式模型的訓練不穩定性問題？","options":{"A":"使用更大的數據集","B":"採用 Waserstein GAN(WGAN)","C":"提高硬體效能","D":"增加模型層數"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"WGAN以Wasserstein距離取代原始GAN的JS散度作為損失衡量，能提供更平滑且有意義的梯度訊號，有效改善GAN訓練不穩定與模式崩潰的問題。單純加大資料集、提升硬體效能或增加層數，都無法從根本解決訓練不穩定性。","concept":"WGAN","aiExplained":true},{"id":"web-j1-1655","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"在整合應用中，生成式 AI 提供的數據增強主要解決了哪個問題？","options":{"A":"模型過擬合","B":"數據稀缺或不平衡","C":"訓練過程的時間延遲","D":"數據隱私問題"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"生成式AI能合成貼近真實分布的新樣本來擴充訓練集，主要解決資料稀缺與類別不平衡的問題，讓鑑別式模型獲得更充足、均衡的學習素材。它並非直接處理過擬合、訓練延遲或資料隱私等議題。","concept":"資料增強","aiExplained":true},{"id":"web-j1-1656","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"未來整合鑑別式 AI 和生成式 AI 的關鍵方向是什麼？","options":{"A":"增加生成模型的參數數量","B":"開發更高效的整合框架","C":"減少對標記數據的依賴","D":"將兩者獨立使用"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"整合鑑別式與生成式AI的未來關鍵方向，在於開發更高效的整合框架，讓兩類模型能在統一架構下協同運作、互補優勢，例如生成模型擴充資料、鑑別模型精準判別。單純增加生成模型參數或將兩者獨立使用，都不是整合發展的重點。","concept":"整合框架趨勢","aiExplained":true},{"id":"web-j2-1657","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"關於 No Code 與 Low Code 的基本概念，以下哪一項最為正確？","options":{"A":"No Code 平台完全不需要任何技術知識，Low Code 平台僅適合專業開發者使用","B":"No Code 平台主要依靠圖形化介面(UI)進行開發，而 Low Code 平台結合了簡單程式設計與視覺化工具","C":"No Code 與 Low Code 平台主要針對傳統 IT 團隊而設計","D":"Low Code 平台完全不需要程式設計知識"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"No Code平台以圖形化介面與拖拉設定為主，讓非技術人員也能快速開發應用；Low Code則在視覺化工具之外保留少量程式撰寫空間，兼顧開發速度與客製彈性，故B的描述最正確。No Code仍需要基本的邏輯與工具操作知識，Low Code也並非完全不需程式設計。","concept":"低程式碼開發","aiExplained":true},{"id":"web-j2-1658","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"No Code / Low Code 技術的主要優勢不包括以下哪一項？","options":{"A":"加速開發流程，降低企業開發成本","B":"幫助非技術人員創建應用和自動化流程","C":"完全消除對專業技術人員的需求","D":"加速企業數位轉型並提升競爭力"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"No Code/Low Code 的核心價值在於降低開發門檻、加速流程並讓非技術人員也能建置應用，但複雜系統仍需專業人才進行架構設計、整合與維運，因此「完全消除對專業技術人員的需求」是過度誇大的說法，並非其真正優勢。","concept":"No Code優勢認知","aiExplained":true},{"id":"web-j2-1659","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"關於 No Code 平台，下列敘述何者較為準確？","options":{"A":"已經完全取代傳統的 AI 開發模式","B":"只適用於大型企業","C":"是一種降低 AI 技術複雜性和開發成本的新興方法","D":"工具都具有完全相同的功能和效能"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"No Code 平台的本質是透過視覺化介面與預建模組，降低使用AI技術的複雜度與開發成本，讓更多人能參與應用建置，並非取代所有傳統開發或僅限大型企業使用，各平台功能也存在差異。","concept":"No Code平台定位","aiExplained":true},{"id":"web-j2-1660","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"下列哪一項不是 No Code / Low Code 平台在推動 AI 民主化過程中的挑戰？","options":{"A":"使用者缺乏對 AI 的深層理解","B":"可能引發模型偏差或誤用","C":"需要加強人員相關教育和規範","D":"提供昂貴的開發工具"},"answer":"D","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"No Code/Low Code 平台在推動AI民主化時面臨的真正挑戰在於使用者對AI理解不足、可能誤用而產生模型偏差，以及需要加強配套教育與規範；而該類平台的訴求恰恰是降低成本、提供親民工具，故「提供昂貴的開發工具」並非其挑戰。","concept":"AI民主化挑戰","aiExplained":true},{"id":"web-j2-1661","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"生成式 AI 在金融業的應用不包括以下哪一項？","options":{"A":"風險評估與管理","B":"投資組合優化","C":"自動化生成病歷","D":"提供個人化投資建議"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"生成式AI在金融業的應用多聚焦於風險評估、投資組合優化與個人化投資建議等領域，屬於金融核心業務範疇；自動化生成病歷則屬於醫療領域的應用，與金融業務無關。","concept":"生成式AI產業應用","aiExplained":true},{"id":"web-j2-1662","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"No Code 平台的設計目標是降低技術門檻，使哪一類使用者能夠開發應用程式，而無需撰寫程式碼？","options":{"A":"技術專家","B":"非技術背景的使用者","C":"資深開發者","D":"系統管理員"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"No Code 平台設計的初衷就是拆解程式撰寫的技術門檻，讓不具備程式背景的使用者也能透過拖拉介面或設定流程來完成應用開發，這正是其核心訴求。","concept":"No Code設計目標","aiExplained":true},{"id":"web-j2-1663","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t1","stem":"在選擇 No Code / Low Code 平台時，下列何者為考慮功能與擴展性時最重要因素？","options":{"A":"平台的購買成本","B":"平台的技術整合能力和自訂性","C":"使用者的程式設計能力","D":"平台的市場評價"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"評估平台的功能與擴展性時，最關鍵的是其技術整合能力與可自訂彈性，能否串接既有系統、依需求擴充功能，才是決定平台長期可用性的關鍵，購買成本與市場評價屬於次要考量。","concept":"平台選型考量","aiExplained":true},{"id":"web-j2-1664","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"下列何者是使用生成式 AI 進行圖像生成時需要考慮的問題？","options":{"A":"生成圖像的解析度","B":"版權和合法性","C":"模型的推論時間","D":"以上皆是"},"answer":"D","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"生成式AI圖像生成涉及多重面向，包括產出圖像的解析度品質、版權與合法性風險，以及模型推論所需時間等效能因素，這些都是實務導入時必須一併評估的問題，因此答案為「以上皆是」。","concept":"圖像生成考量要素","aiExplained":true},{"id":"web-j2-1665","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"下列哪一種方式可以有效幫助現職員工提升 AI 應用能力？","options":{"A":"提高薪資來吸引 AI 人才","B":"安排跨部門交流和測試專案","C":"減少員工的工作負擔","D":"員工視需求選擇性自學 AI 技術"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"安排跨部門交流與實際測試專案，能讓現職員工在實作中接觸不同場域的AI應用情境，累積實戰經驗並強化能力，相較於單純調薪吸才、減輕工作量或放任員工自學，更能系統性提升其AI應用能力。","concept":"員工AI能力提升","aiExplained":true},{"id":"web-j2-1666","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"下列何者為企業導入 AI 技術後最直接的影響？","options":{"A":"增加人力需求","B":"提升生產力和效率","C":"減少數據處理能力","D":"降低市場競爭力"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"企業導入AI技術後，最直接且普遍可見的效益是流程自動化與決策輔助帶來的生產力與效率提升，這也是企業投入AI的主要動機，其餘選項則與AI導入的實際效果相悖。","concept":"AI導入效益","aiExplained":true},{"id":"web-j2-1667","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"下列何者是人工智慧未來發展中最迫切需要解決的挑戰？","options":{"A":"計算資源的過剩","B":"資料隱私與道德規範問題","C":"人才培育與跨領域合作的不足","D":"無法應用於小型企業場景"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"隨著AI應用日益普及，資料隱私外洩與演算法倫理、責任歸屬等議題已成為各國監管與產業界最關切的核心問題，相較於人才或應用場景等課題，隱私與道德規範更具急迫性與全球性。","concept":"AI發展挑戰","aiExplained":true},{"id":"web-j2-1668","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"使用生成式 AI 生成的內容時，應採取什麼措施以確保內容品質？","options":{"A":"使用內容直接進行學術報告","B":"適當標注引用來源","C":"減少人工參與的審查過程","D":"排除所有生成的資料"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"使用生成式AI產出的內容時，應適當標注資料來源與生成方式，維持透明度並保留人工審查空間，才能確保內容品質與可信度，而非未經查核便直接引用或全盤排除生成內容。","concept":"生成內容品質管控","aiExplained":true},{"id":"web-j2-1669","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"企業導入生成式 AI 的第一步應是什麼？","options":{"A":"確保硬體設備升級","B":"設定可量化、可追蹤的經營目標","C":"安排員工進行 AI 相關培訓","D":"購買生成式 AI 相關軟體"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"企業導入生成式AI前，應先設定可量化、可追蹤的經營目標，讓後續的技術選型、資源投入與成效評估都能有明確依據，避免流於為導入而導入。","concept":"AI導入第一步","aiExplained":true},{"id":"web-j2-1670","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"以下哪一項屬於企業在評估導入生成式 AI 時需識別的問題領域？","options":{"A":"市場趨勢預測能力有限","B":"設計更高效能的運算資源","C":"增加銷售團隊人力","D":"減少 AI 模型參數數量"},"answer":"A","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"評估導入生成式AI時，企業須先盤點自身業務中能力不足之處，例如市場趨勢預測能力有限，這類「問題領域」正是後續選擇AI應用場景的出發點，而非單純的技術規格調整或人力配置。","concept":"導入問題領域識別","aiExplained":true},{"id":"web-j2-1671","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"成功導入生成式 AI 的關鍵在於哪三個因素？","options":{"A":"提供更多數據、加強合作、減少成本","B":"清晰定義痛點、技術匹配、培養人才","C":"投資高端設備、增加技術人員、縮短流程","D":"推行技術改革、調整市場策略、強化品牌"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"生成式AI導入成功與否，關鍵在於能否清楚定義企業痛點、確認技術與需求相互匹配，並同步培養具備相關能力的人才，三者缺一不可，光靠增加資料或壓低成本並無法保證導入成效。","concept":"AI導入成功要素","aiExplained":true},{"id":"web-j2-1672","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在導入生成式 AI 的構想階段，企業應首先專注於什麼？","options":{"A":"提升內部資料儲存容量","B":"明確經營目標與核心價值","C":"進行員工 AI 基礎培訓","D":"購買市面上的 AI 軟體"},"answer":"B","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"構想階段是整體導入流程的起點，企業應先釐清經營目標與核心價值，確立為何導入、要解決什麼問題，之後才能據此規劃資源投入與技術選擇，而非一開始就先採購工具或訓練人員。","concept":"AI導入構想階段","aiExplained":true},{"id":"web-j2-1673","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在 AI 導入正式實施階段，企業應優先進行的活動是什麼？","options":{"A":"增加行銷預算","B":"調整產品價格","C":"確保相關人員熟悉新流程與工具","D":"減少生產規模以減少風險"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"正式實施階段的重點在於落地執行，因此企業應優先確保相關人員熟悉新流程與工具的操作方式，降低導入後的適應阻力，才能讓系統真正發揮效益。","concept":"AI導入實施階段","aiExplained":true},{"id":"web-j2-1674","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"下列何者為風險分析階段的主要目的？","options":{"A":"找到更多的數據來源","B":"增強模型的效能","C":"評估風險的影響與發生可能性","D":"降低模型運行成本"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"風險分析階段的核心任務是評估各項潛在風險發生的可能性及其可能造成的影響程度，藉此排定因應的優先順序，而非著重於資料蒐集或模型效能本身。","concept":"風險分析目的","aiExplained":true},{"id":"web-j2-1675","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"為了確保風險管理的持續有效性，企業應如何應對風險管理策略的效果下降？","options":{"A":"繼續沿用原策略","B":"停止 AI 應用以防意外","C":"快速調整並進行必要改進","D":"將策略移交給外部顧問"},"answer":"C","needsContext":false,"source":"官方學習指引樣題","srcUrl":"https://github.com/yazelin/ipas-ai-quiz/blob/master/questions.json","explanation":"當既有風險管理策略成效下滑時，企業應保持敏捷，即時檢視原因並快速調整改進措施，而非墨守成規、貿然喊停AI應用，或將責任完全外包給顧問。","concept":"風險管理持續改善","aiExplained":true},{"id":"web-j1-1788","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某醫院希望開發一個系統，根據患者的年齡、血壓與BMI 等資訊，預測 114 年第四次AI 應用規劃師-初級能力鑑定【公告試題】其罹患糖尿病的機率（0~1），並依據預測值是否超過0.5 做出風險警示。下列哪一種模型最適合用於此分類任務？","options":{"A":"邏輯迴歸（Logistic Regression）","B":"支援向量機（Support Vector Machine）","C":"決策樹（Decision Tree）","D":"K 平均演算法（K-means）"},"answer":"A","needsContext":false,"source":"網路題庫 · vidioyin/IPAS_AI","srcUrl":"https://github.com/vidioyin/IPAS_AI/blob/main/exams_data.json","explanation":"此案例要預測的是罹病「機率」（0~1的連續值），再以固定門檻（0.5）轉換為二元分類結果，這正是邏輯迴歸的典型應用情境，其輸出經sigmoid函數轉換後即為機率值，SVM、決策樹與K-means皆非以機率輸出為設計核心。","concept":"邏輯迴歸機率分類","aiExplained":true},{"id":"web-j1-1789","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t1","stem":"在自然語言處理任務中，為了減少訓練語料中偏見對模型的影響，下列 114 年第四次AI 應用規劃師-初級能力鑑定【公告試題】哪種資料處理策略屬於常見的「資料去偏（Data Debiasing）」做法？","options":{"A":"讓模型在訓練時隨機替換輸出，以抵消資料中存在的系統性偏差","B":"增加模型的參數量，依賴更大的模型自動消除原始資料中的偏見","C":"調整或擴充訓練語料，使不同群體或類型資料的比例更加平衡，避免模型過度偏向出現頻率高的類別","D":"對訓練資料施加額外正則化或噪音，使模型在學習過程中對偏見敏感度降低"},"answer":"C","needsContext":false,"source":"網路題庫 · vidioyin/IPAS_AI","srcUrl":"https://github.com/vidioyin/IPAS_AI/blob/main/exams_data.json","explanation":"資料去偏最常見的作法是檢視並調整訓練語料中不同群體或類別的比例，透過擴充或重新取樣讓資料分布更加均衡，避免模型因訓練資料偏頗而學到系統性偏見，這與單純增加模型參數或對輸出加雜訊的做法不同。","concept":"資料去偏方法","aiExplained":true},{"id":"web-j1-1790","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"某醫院計畫開發住院日數預測模型，以協助病房調度。多數病人的住院日數集中在 3–7 天，但仍有少數重症患者因治療需求而住院日數明顯偏長。醫院希望採用一種合適的評估方式，既能兼顧大部分病人的預測準確度，也能確保對重症個案的預測維持穩健。下列哪一種方法最符合此需求？ 114 年第四次AI 應用規劃師-初級能力鑑定【公告試題】","options":{"A":"在模型檢核時，同時呈現平均絕對誤差（MAE）與重症子群的誤差指標","B":"僅針對一般病人樣本進行交叉驗證，以避免重症個案拉高誤差","C":"將所有病人的住院日數進行標準化處理，以減少數值範圍差異的影響","D":"只採用單一的整體決定係數 (R²) 作為模型優劣的判斷依據"},"answer":"A","needsContext":false,"source":"網路題庫 · vidioyin/IPAS_AI","srcUrl":"https://github.com/vidioyin/IPAS_AI/blob/main/exams_data.json","explanation":"面對多數集中、少數極端偏長的住院日數分布，模型檢核時應同時檢視整體的平均絕對誤差以掌握一般病人的預測準確度，並另外呈現重症子群的誤差指標以確保極端個案的預測穩健度，兩者兼顧才符合醫院的實際需求。","concept":"分群模型評估","aiExplained":true},{"id":"web-j1-1791","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t3","stem":"一家跨國醫療研究機構希望利用各地醫院的病患資料，建立一個能夠預測疾病早期風險的機器學習模型。由於各國法規限制，病患的原始資 114 年第四次AI 應用規劃師-初級能力鑑定【公告試題】料無法集中到單一伺服器。在此情境下，下列哪一種方法最能同時滿足「各醫院保留資料不外流」與「模型仍能跨院學習」的需求？","options":{"A":"資料匿名化（Data Anonymization）","B":"差分隱私（Differential Privacy）","C":"聯邦學習（Federated Learning）","D":"交叉驗證（Cross-validation）"},"answer":"C","needsContext":false,"source":"網路題庫 · vidioyin/IPAS_AI","srcUrl":"https://github.com/vidioyin/IPAS_AI/blob/main/exams_data.json","explanation":"聯邦學習的核心設計正是讓各醫院在資料不離開本地端的前提下，僅交換模型參數或梯度資訊來共同訓練模型，藉此同時滿足資料不外流與跨機構協同學習的雙重需求。","concept":"聯邦學習","aiExplained":true},{"id":"web-j1-1792","subject":"J1","subjectName":"人工智慧基礎概論","topic":"j1-t4","stem":"某雲端服務公司計畫將大型語言模型部署於線上系統，並以批次推論 114 年第四次AI 應用規劃師-初級能力鑑定【公告試題】（Batch Inference）方式處理每日上百萬筆用戶請求。專案團隊在評估可能遇到的挑戰時，下列哪一項通常不會被視為批次推論階段的主要難題？","options":{"A":"如何確保訓練語料的涵蓋性與標註品質，以避免模型偏差影響輸出","B":"當批次規模增大時，如何降低推論延遲並保持即時回應能力","C":"在推論過程中，有效管理與分配龐大的輸入資料量以避免資源壅塞","D":"在叢集環境中精確安排推論任務，以提升GPU/TPU 等硬體資源的利用率《以下空白》"},"answer":"A","needsContext":false,"source":"網路題庫 · vidioyin/IPAS_AI","srcUrl":"https://github.com/vidioyin/IPAS_AI/blob/main/exams_data.json","explanation":"訓練語料的涵蓋性與標註品質屬於模型訓練階段需要把關的課題，而批次推論階段真正面對的難題在於延遲控制、巨量輸入資料的管理排程，以及叢集硬體資源的有效調度，兩者屬於不同階段的關注重點。","concept":"批次推論挑戰","aiExplained":true},{"id":"web-j2-1793","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在超長上下文任務中使用自動提示工程（Automatic Prompt Engineer, 114 年第四次AI 應用規劃師-初級能力鑑定【公告試題】 APE）時，可能面臨的最大限制是什麼？","options":{"A":"迭代優化難以因應上下文的不斷變動，導致調整失效","B":"模型的記憶容量有限，無法完整保留所有長篇資訊","C":"提示內容難以有效分解，無法支援複雜任務拆解","D":"回饋機制通常僅針對局部片段，難以全面評估最終輸出品質"},"answer":"D","needsContext":false,"source":"網路題庫 · vidioyin/IPAS_AI","srcUrl":"https://github.com/vidioyin/IPAS_AI/blob/main/exams_data.json","explanation":"自動提示工程仰賴回饋機制來評分並反覆優化提示，但在超長上下文任務中，回饋通常只能針對片段輸出進行評估，難以綜觀檢視整份長篇輸出的一致性與完整品質，這正是其應用於長文本情境時最大的限制。","concept":"APE長文本限制","aiExplained":true},{"id":"web-j2-1794","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某保險公司計畫導入生成式 AI 的內部合約查詢系統，協助業務員與法務部門快速解讀保單條款與理賠規範。高層特別強調客戶資料隱私與合規風險控管，即使需要投入較多資源，也必須確保資料不會外洩。在 114 年第四次AI 應用規劃師-初級能力鑑定【公告試題】此情況下，下列哪一種策略最符合公司的資料安全與合規優先考量？","options":{"A":"導入開源模型並由 IT 團隊自建，後續再逐步補強隱私與合規控管","B":"在需求確認階段即納入法遵與稽核單位，設定準確率 KPI，並透過 MVP 驗證成效","C":"優先使用雲端大型 API 模型快速部署，並根據使用數據持續調整","D":"投入資源自訓並私有化部署 LLM，並同步建立自動化風控機制"},"answer":"D","needsContext":false,"source":"網路題庫 · vidioyin/IPAS_AI","srcUrl":"https://github.com/vidioyin/IPAS_AI/blob/main/exams_data.json","explanation":"題幹明確指出公司即使投入更多資源也要確保資料不外洩，代表資料安全與合規已是最優先考量，因此應選擇自行訓練並私有化部署模型、同時建立自動化風控機制，才能真正將資料留在企業內部並持續監控合規風險，相較之下採用雲端API或先求快後補強的做法都存在資料外洩疑慮。","concept":"私有化部署合規策略","aiExplained":true},{"id":"web-j2-1795","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"在即時客服系統的效能測試中，若針對延遲測試（Latency Testing）進行評估，下列哪一項指標最能反映系統是否符合用戶即時互動需求？ 114 年第四次AI 應用規劃師-初級能力鑑定【公告試題】","options":{"A":"AI 模型在同一分鐘內可完成的回覆訊息數量","B":"客戶從輸入問題到收到第一個完整回應所需的時間","C":"客服系統能連續提供服務的運行時長","D":"AI 產生回答時用詞的多樣性與表達創意程度"},"answer":"B","needsContext":false,"source":"網路題庫 · vidioyin/IPAS_AI","srcUrl":"https://github.com/vidioyin/IPAS_AI/blob/main/exams_data.json","explanation":"延遲測試關注的是使用者實際感受到的等待時間，因此客戶從輸入問題到收到第一個完整回應所需的時間，最能直接反映系統是否符合即時互動的需求，至於回覆訊息數量或運行時長則屬於吞吐量與可用性等不同面向的指標。","concept":"延遲測試指標","aiExplained":true},{"id":"web-j2-1796","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t2","stem":"在提示工程（Prompt Engineering）的應用中，Chain-of-Thought（CoT）與 Tree of Thoughts（ToT）各適用於不同的推理情境，請問以下兩個情境，分別最適合採用哪一種方法？ 114 年第四次AI 應用規劃師-初級能力鑑定【公告試題】情境一：電商公司開發客服助理，用來協助客戶查詢退款流程與相關規範情境二：活動策劃團隊使用AI 協助規劃多場跨部門行銷活動，需要同時考量預算、場地、時程與人力資源，並比較不同方案的可行性。","options":{"A":"情境一採用 CoT，情境二採用ToT","B":"情境一採用 ToT，情境二採用CoT","C":"情境一與情境二都適合 CoT","D":"情境一與情境二都適合 ToT"},"answer":"A","needsContext":false,"source":"網路題庫 · vidioyin/IPAS_AI","srcUrl":"https://github.com/vidioyin/IPAS_AI/blob/main/exams_data.json","explanation":"情境一僅涉及單一、線性的退款流程查詢，適合以Chain-of-Thought逐步推理即可得到答案；情境二則需同時考量預算、場地、時程與人力等多重變數並比較不同方案的可行性，屬於需要分支探索與比較評估的任務，更適合以Tree of Thoughts展開多路徑推理。","concept":"CoT與ToT應用情境","aiExplained":true},{"id":"web-j2-1797","subject":"J2","subjectName":"生成式AI應用與規劃","topic":"j2-t3","stem":"某開發團隊在建置企業內部知識檢索系統時，選擇採用多向量檢索器（Multi-vector Retriever），下列何者為協助提升系統查詢的完整性 114 年第四次AI 應用規劃師-初級能力鑑定【公告試題】與精準度的主要方式？","options":{"A":"支援同時處理多種資訊表示，提升跨文本型態的檢索效果","B":"透過多向量壓縮與共享權重方式，降低檢索過程的運算與儲存成本","C":"以切分並過濾文件片段，減少上下文長度帶來的 Token 負擔","D":"透過調整生成階段的溫度參數，使模型在回覆時更穩定一致"},"answer":"A","needsContext":false,"source":"網路題庫 · vidioyin/IPAS_AI","srcUrl":"https://github.com/vidioyin/IPAS_AI/blob/main/exams_data.json","explanation":"多向量檢索器的核心優勢在於能為同一份文件建立多種向量表示（如摘要向量、片段向量等），使系統能同時處理多種資訊型態，進而提升跨文本類型查詢的檢索完整性與精準度，這與降低成本或調整生成溫度等目的並不相同。","concept":"多向量檢索器","aiExplained":true}];
